window.ASBAB_NUZUL_CACHE["4"] = {"asbab_nuzul":{"3":[{"ar":"عَنْ عَائِشَةَ رضي الله عنها: أَنَّ رَجُلًا كَانَتْ لَهُ يَتِيمَةٌ فَنَكَحَهَا، وَكَانَ لَهَا عَذْقٌ، وَكَانَ يُمْسِكُهَا عَلَيْهِ، وَلَمْ يَكُنْ لَهَا مِنْ نَفْسِهِ شَيْءٌ، فَنَزَلَتْ فِيهِ { وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا۟ فِى ٱلْيَتَـٰمَىٰ فَٱنكِحُوا۟ } أَحْسِبُهُ قَالَ: كَانَتْ شَرِيكَتَهُ فِي ذَلِكَ الْعَذْقِ وَفِي مَالِهِ.","id":""}],"11":[{"ar":"عَنْ جَابِرٍ رضي الله عنه قَالَ: عَادَنِي النَّبِيُّ ﷺ وَأَبُو بَكْرٍ فِي بَنِي سَلِمَةَ مَاشِيَيْنِ، فَوَجَدَنِي النَّبِيُّ ﷺ لَا أَعْقِلُ شَيْئاً، فَدَعَا بِمَاءٍ فَتَوَضَّأَ مِنْهُ، ثُمَّ رَشَّ عَلَيَّ فَأَفَقْتُ، فَقُلْتُ: مَا تَأْمُرُنِي أَنْ أَصْنَعَ فِي مَالِي يَا رَسُولَ اللَّهِ؟ فَنَزَلَتْ { يُوصِيكُمُ ٱللَّهُ فِىٓ أَوْلَـٰدِكُمْ ۖ }.","id":""},{"ar":"وللآية سبب آخر للنزول: عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رضي الله عنهما قَالَ: جَاءَتِ امْرَأَةُ سَعْدِ بْنِ الرَّبِيعِ بِابْنَتَيْهَا مِنْ سَعْدٍ إِلَى رَسُولِ اللَّهِ ﷺ، فَقَالَتْ: يَا رَسُولَ اللَّهِ، هَاتَانِ ابْنَتَا سَعْدِ بْنِ الرَّبِيعِ، قُتِلَ أَبُوهُمَا مَعَكَ يَوْمَ أُحُدٍ شَهِيداً، وَإِنَّ عَمَّهُمَا أَخَذَ مَالَهُمَا فَلَمْ يَدَعْ لَهُمَا مَالًا، وَلَا تُنْكَحَانِ إِلَّا وَلَهُمَا مَالٌ؟ قَالَ: « يَقْضِي اللَّهُ فِي ذَلِكَ ». فَنَزَلَتْ آيَةُ الْمِيرَاثِ، فَبَعَثَ رَسُولُ اللهِ ﷺ إِلَى عَمِّهِمَا فَقَالَ: « أَعْطِ ابْنَتَيْ سَعْدٍ الثَّلُثَيْنِ، وَأَعْطِ أُمَّهُمَا الثُّمُنَ، وَمَا بَقِيَ فَهُوَ لَكَ »، واللفظ للترمذي.","id":""}],"19":[{"ar":"عن أبي أمامة بن سهل بن حنيف قال: لما توفي أبو قيس بن الأسلت، أراد ابنه أن يتزوج امرأته من بعده، وكان ذلك لهم في الجاهلية فأنزل الله عز و جل { لَا يَحِلُّ لَكُمْ أَن تَرِثُوا۟ ٱلنِّسَآءَ كَرْهًا ۖ }.","id":""}],"24":[{"ar":"عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رضي الله عنه: أَنَّ نَبِيَّ اللَّهِ ﷺ بَعَثَ جَيْشَاً إِلَى أَوْطَاسٍ فَلَقُوا عَدُوًّا، فَقَاتَلُوهُمْ، وَظَهَرُوا عَلَيْهِمْ، فَأَصَابُوا لَهُمْ سَبَايَا لَهُنَّ أَزْوَاجٌ فِي الْمُشْرِكِينَ، فَكَانَ الْمُسْلِمُونَ تَحَرَّجُوا مِنْ غِشْيَانِهِنَّ، فَأَنْزَلَ اللَّهُ عز و جل: { وَٱلْمُحْصَنَـٰتُ مِنَ ٱلنِّسَآءِ إِلَّا مَا مَلَكَتْ أَيْمَـٰنُكُمْ ۖ }، أَيْ: هَذَا لَكُمْ حَلالٌ إِذَا انْقَضَتْ عِدَّتُهُنَّ.","id":""},{"ar":"وقد جاء من حديث ابن عباس رضي الله عنهما شبيهاً به.","id":""}],"32":[{"ar":"عَنْ أُمِّ سَلَمَةَ رضي الله عنها أَنَّهَا قَالَتْ: يَغْزُو الرِّجَالُ وَلَا تَغْزُو النِّسَاءُ، وَإِنَّمَا لَنَا نِصْفُ الْمِيرَاثِ، فَأَنْزَلَ اللهُ تَبَارَكَ وَتَعَالَى { وَلَا تَتَمَنَّوْا۟ مَا فَضَّلَ ٱللَّهُ بِهِۦ بَعْضَكُمْ عَلَىٰ بَعْضٍ ۚ }.","id":""},{"ar":"وقد جاء من حديث ابن عباس رضي الله عنهما شبيهاً به.","id":""}],"37":[{"ar":"عن ابن عباس رضي الله عنهما قال: كان كردم بن زيد حليف كعب بن الأشرف، وأسامة بن حبيب، ونافع بن أبي نافع، وبحري بن عمرو، وحي بن أخطب، ورفاعة بن زيد بن التابوت، يأتون رجالاً من الأنصار، وكانوا يخالطونهم يتنصحون لهم من أصحاب رسول الله ﷺ، فيقولون لهم: لا تنفقوا أموالكم فإنا نخشى عليكم الفقر في ذهابها، ولا تسارعوا في النفقة فإنكم لا تدرون ما يكون، فأنزل الله فيهم: { ٱلَّذِينَ يَبْخَلُونَ وَيَأْمُرُونَ ٱلنَّاسَ بِٱلْبُخْلِ وَيَكْتُمُونَ مَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضْلِهِۦ ۗ }، أي من النبوة التي فيها تصديق ما جاء به محمد ﷺ { وَأَعْتَدْنَا لِلْكَـٰفِرِينَ عَذَابًا مُّهِينًا }.","id":""}],"43":[{"ar":"عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رضي الله عنه قَالَ: صَنَعَ لَنَا عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ طَعَاماً، فَدَعَانَا وَسَقَانَا مِنْ الْخَمْرِ، فَأَخَذَتِ الْخَمْرُ مِنَّا وَحَضَرَتِ الصَّلَاةُ، فَقَدَّمُونِي فَقَرَأْتُ: { قُلْ يَـٰٓأَيُّهَا ٱلْكَـٰفِرُونَ ﴿١﴾ لَآ أَعْبُدُ مَا تَعْبُدُونَ ﴿٢﴾ و نحن نعبد ما تعبدون }، قَالَ: فَأَنْزِلَ اللهُ تَعَالَى { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَقْرَبُوا۟ ٱلصَّلَوٰةَ وَأَنتُمْ سُكَـٰرَىٰ حَتَّىٰ تَعْلَمُوا۟ مَا تَقُولُونَ }. واللفظ للترمذي.","id":""},{"ar":"وقد جاء من حديث عبد الله بن حبيب شبيهاً به.","id":""}],"48":[{"ar":"عن أبي أيوب رضي الله عنه قال: جاء رجل إلى النبي ﷺ فقال: إن لي ابن أخ لا ينتهي عن حرام، قال: « ما دينه » قال: يوحد الله ويصلي، قال: « فاستوهب منه دينه فإن أبى فابتعه منه » فطلب ذلك الرجل منه دينه فأبي عليه، فأتى النبي ﷺ فقال: وجدته شحيحاً على دينه، فنزلت { إِنَّ ٱللَّهَ لَا يَغْفِرُ أَن يُشْرَكَ بِهِۦ وَيَغْفِرُ مَا دُونَ ذَٰلِكَ لِمَن يَشَآءُ ۚ }","id":""}],"51":[{"ar":"عن ابن عباس رضي الله عنهما قال: لما قدم كعب بن الأشرف مكة، قالت قريش: ألا ترى هذا الصنبور المنبتر من قومه؟ يزعم أنه خير منا، ونحن أهل الحجيج وأهل السدانة وأهل السقاية!! قال: أنتم خير، قال: فنزلت فيهم { إِنَّ شَانِئَكَ هُوَ ٱلْأَبْتَرُ ﴿٣﴾ } ونزل { أَلَمْ تَرَ إِلَى ٱلَّذِينَ أُوتُوا۟ نَصِيبًا مِّنَ ٱلْكِتَـٰبِ } إلى { نَصِيرًا }.","id":""},{"ar":"وجاء عن عكرمة شبيهاً به.","id":""}],"59":[{"ar":"وجاء عن عكرمة شبيهاً به.عَنْ ابْنِ عَبَّاسِ رضي الله عنهما: { أَطِيعُوا۟ ٱللَّهَ وَأَطِيعُوا۟ ٱلرَّسُولَ وَأُو۟لِى ٱلْأَمْرِ مِنكُمْ ۖ  } قَالَ: نَزَلَتْ فِي عَبْدِ اللَّهِ بْنِ حُذَافَةَ بْنِ قَيْسِ بْنِ عَدِيِّ، إِذْ بَعَثَهُ النَّبِيُّ ﷺ فِي سَرِيَّةٍ. واللفظ للبخاري.","id":""}],"60":[{"ar":"عن ابن عباس رضي الله عنهما قال: كان أبو برزة الأسلمي كاهناً يقضي بين اليهود فيما يتنافرون فيه، فتنافر إليه ناس من المشركين، فأنزل الله عز و جل { أَلَمْ تَرَ إِلَى ٱلَّذِينَ يَزْعُمُونَ أَنَّهُمْ ءَامَنُوا۟ بِمَآ أُنزِلَ إِلَيْكَ وَمَآ أُنزِلَ مِن قَبْلِكَ } إِلى قوله إن { إِنْ أَرَدْنَآ إِلَّآ إِحْسَـٰنًا وَتَوْفِيقًا }.","id":""},{"ar":"ومن شواهده ما جاء عن الشعبي رحمه الله قال: كانت بين رجل ممن يزعم أنه مسلم وبين رجل من اليهود خصومة، فقال اليهودي: أحاكمك إلى أهل دينك، أو قال إلى النبي، لأنه قد علم أن رسول الله ﷺ لا يأخذ الرشوة في الحكم، فاختلفا، فاتفقا على أن يأتيا كاهناً في جهينة، قال: فنزلت { أَلَمْ تَرَ إِلَى ٱلَّذِينَ يَزْعُمُونَ أَنَّهُمْ ءَامَنُوا۟ بِمَآ أُنزِلَ إِلَيْكَ }، يعني الذي من الأنصار، { وَمَآ أُنزِلَ مِن قَبْلِكَ } يعني اليهودي، { يُرِيدُونَ أَن يَتَحَاكَمُوٓا۟ إِلَى ٱلطَّـٰغُوتِ } إلى الكاهن، { وَقَدْ أُمِرُوٓا۟ أَن يَكْفُرُوا۟ بِهِۦ } يعني أمر هذا في كتابه، وأمر هذا في كتابه، و تلا { وَيُرِيدُ ٱلشَّيْطَٰنُ أَن يُضِلَّهُمْ ضَلَـٰلًۢا بَعِيدًا }، وقرأ { فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ } إلى { وَيُسَلِّمُوا۟ تَسْلِيمًا }.","id":""},{"ar":"وجاء عن قتادة شبيهاً به.","id":""}],"65":[{"ar":"عن عُرْوَةَ بْنِ الزُّبَيْرِ رحمه الله: أَنَّ الزُّبَيْرَ رضي الله عنه كَانَ يُحَدِّثُ: أَنَّهُ خَاصَمَ رَجُلًا مِنْ الْأَنْصَارِ قَدْ شَهِدَ بَدْراً، إِلَى رَسُولِ اللَّهِ ﷺ فِي شِرَاجٍ مِنْ الْحَرَّةِ، كَانَا يَسْقِيَانِ بِهِ كِلَاهُمَا، فَقَالَ رَسُولُ الله ﷺ لِلزُّبَيْرِ: « اسْقِ يَا زُبَيْرُ، ثُمَّ أَرْسِلْ إِلَى جَارِكَ »، فَغَضِبَ الْأَنْصَارِيُّ، فَقَالَ: يَا رَسُولَ اللَّهِ، أَنْ كَانَ ابْنَ عَمَّتِكَ؟ فَتَلَوَّنَ وَجْهُ رَسُولِ اللهِ ﷺ، ثُمَّ قَالَ: « اسْقِ، ثُمَّ احْبِسُ حَتَّى يَبْلُغَ الْجَدْرَ ». فَاسْتَوْعَى رَسُولُ اللهِ ﷺ حِينَئِذٍ حَقَّهُ لِلْزُّبَيْرِ، وَكَانَ رَسُولُ اللَّهِ ﷺ قَبْلَ ذَلِكَ أَشَارَ عَلَى الزُّبَيْرِ بِرَأْي سَعَةٍ لَهُ وَلِلْأَنْصَارِيِّ، فَلَمَّا أَحْفَظَ الْأَنْصَارِيُّ رَسُولَ اللهِ ﷺ اسْتَوْعَى لِلْزُّبَيْرِ حَقَّهُ فِي صَرِيحِ الْحُكْمِ. قَالَ عُرْوَةُ: قَالَ الزُّبَيْرُ: وَاللَّهِ مَا أَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ إِلَّا فِي ذَلِكَ، { فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ } الآية. واللفظ للبخاري.","id":""},{"ar":"وجاء عَنْ عَبْدِ اللهِ بْنِ الزُّبَيْرِ لا شبيهاً به.","id":""},{"ar":"وجاء عن أم سلمة شبيهاً به أيضاً.","id":""}],"69":[{"ar":"عن عائشة رضي الله عنها قالت: جاء رجل إلى النبي ﷺ فقال: يا رسول الله، إنك لأحب إلي من نفسي، وإنك لأحب إلي من ولدي، وإني لأكون في البيت فأذكرك فما أصبر حتى آتي، فأنظر إليك، وإذا ذكرت موتي وموتك عرفت أنك إذا دخلت الجنة رفعت مع النبيين، وأني إذا دخلت الجنة خشيت أن لا أراك. فلم يرد عليه النبي ﷺ شيئاً، حتى نزل جبريل بهذه الآية { وَمَن يُطِعِ ٱللَّهَ وَٱلرَّسُولَ فَأُو۟لَٰٓئِكَ مَعَ ٱلَّذِينَ أَنْعَمَ ٱللَّهُ عَلَيْهِم مِّنَ ٱلنَّبِيِّـۧنَ وَٱلصِّدِّيقِينَ وَٱلشُّهَدَآءِ وَٱلصَّـٰلِحِينَ ۚ }.","id":""},{"ar":"ومن شواهده عن ابن عباس رضي الله عنهما شبيهاً به.","id":""},{"ar":"وعن الربيع شبيهاً به.","id":""}],"77":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما: أَنَّ عَبْدَ الرَّحْمَنِ بْنِ عَوْفٍ وَأَصْحَابِاً لَهُ أَتَوْا النَّبِيَّ ﷺ بِمَكَّةَ، فَقَالُوا: يَا رَسُولَ اللَّهِ إِنَّا كُنَّا فِي عِزٍّ وَنَحْنُ مُشْرِكُونَ، فَلَمَّا آمَنَّا صِرْنَا أَذِلَّةٌ، فَقَالَ: « إِنِّي أُمِرْتُ بِالْعَفْوِ، فَلَا تُقَاتِلُوا »، فَلَمَّا حَوَّلَنَا اللَّهُ إِلَى الْمَدِينَةِ أَمَرَنَا بِالْقِتَالِ، فَكَفُّوا، فَأَنْزَلَ اللهُ عز و جل { أَلَمْ تَرَ إِلَى ٱلَّذِينَ قِيلَ لَهُمْ كُفُّوٓا۟ أَيْدِيَكُمْ وَأَقِيمُوا۟ ٱلصَّلَوٰةَ }. واللفظ للنسائي.","id":""}],"83":[{"ar":"عَنْ عَبْدِ اللهِ بْنِ عَبَّاسٍ رضي الله عنهما: حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِ رضي الله عنه قَالَ: لَمَّا اعْتَزَلَ نَبِيُّ اللَّهِ ﷺ نِسَاءَهُ، قَالَ: ( دَخَلْتُ الْمَسَجِدَ... ) (... فَقُلْتُ يَا رَسُولَ اللَّهِ، أَطَلَّقْتَهُنَّ؟ قَالَ: « لاَ »، قُلْتُ: يَا رَسُولَ اللَّهِ، إِنِّي دَخَلْتُ الْمَسْجِدَ وَالْمُسْلِمُونَ يَنْكُتُونَ بِالْحَصَى، يَقُولُونَ: طَلَّقَ رَسُولُ اللَّهِ ﷺ نِسَاءَهُ، أَفَأَنْزِلُ فَأَخْبِرَهُمْ أَنَّكَ لَمْ تُطَلِّقَهُنَّ؟ قَالَ: « نَعَمْ، إِ��ْ شِئْتَ »، فَلَمْ أَزَلْ أُحَدِّثُهُ حَتَّى تَحَسَّرَ الْغَضَبُ عَنْ وَجْهِهِ، وَحَتَّى كَشَرَ فَضَحِكَ - وَكَانَ مِنْ أَحْسَنِ النَّاسِ تَغْراً - ثُمَّ نَزَلَ نَبِيُّ اللَّهِ ﷺ وَنَزَلْتُ، فَنَزَلْتُ أَتَشَبَّثُ بِالْجِذْعِ، وَنَزَلَ رَسُولُ اللَّهِ ﷺ كَأَنَّمَا يَمْشِي عَلَى الْأَرْضِ مَا يَمَسُّهُ بِيَدِهِ، فَقُلْتُ: يَا رَسُولَ اللَّهِ، إِنَّمَا كُنْتَ فِي الْغُرْفَةِ تِسْعَةً وَعِشْرِينَ، قَالَ: « إِنَّ الشَّهْرَ يَكُونُ تِسْعاً وَعِشْرِينَ »، فَقُمْتُ عَلَى بَابِ الْمَسْجِدِ، فَنَادَيْتُ بِأَعْلَى صَوْتِي: لَمْ يُطَلِّقُ رَسُولُ اللَّهِ ﷺ نِسَاءَهُ، وَنَزَلَتْ هَذِهِ الْآيَةُ: { وَإِذَا جَآءَهُمْ أَمْرٌ مِّنَ ٱلْأَمْنِ أَوِ ٱلْخَوْفِ أَذَاعُوا۟ بِهِۦ ۖ وَلَوْ رَدُّوهُ إِلَى ٱلرَّسُولِ وَإِلَىٰٓ أُو۟لِى ٱلْأَمْرِ مِنْهُمْ لَعَلِمَهُ ٱلَّذِينَ يَسْتَنۢبِطُونَهُۥ مِنْهُمْ ۗ }، فَكُنْتُ أَنَا اسْتَنبَطْتُ ذَلِكَ الْأَمْرَ وَأَنْزَلَ اللهُ عز و جل آية التخيير ). واللفظ لمسلم.","id":""}],"88":[{"ar":"عَنْ زَيْدِ بْنِ ثَابِتٍ رضي الله عنه قَالَ: لَمَّا خَرَجَ النَّبِيُّ ﷺ إِلَى أُحُدٍ، رَجَعَ نَاسٌ مِمَّنْ خَرَجَ مَعَهُ، وَكَانَ أَصْحَابُ النَّبِيِّ ﷺ فِرْقَتَيْنِ: فِرْقَةً تَقُولُ: نُقَاتِلُهُمْ، وَفِرْقَةً تَقُولُ: لَا تُقَاتِلُهُمْ، فنزلت { فَمَا لَكُمْ فِى ٱلْمُنَـٰفِقِينَ فِئَتَيْنِ وَٱللَّهُ أَرْكَسَهُم بِمَا كَسَبُوٓا۟ ۚ }، وَقَالَ: « إِنَّهَا طَيْبَةٌ تَنْفِي الذُّنُوبَ، كَمَا تَنْفِي النَّارُ خَبَثَ الْفِضَّةِ ». واللفظ للبخاري.","id":""},{"ar":"وهناك سبب آخر لنزول هذه الآية: فقد جاء عن مجاهد رحمه الله {  فَمَا لَكُمْ فِى ٱلْمُنَـٰفِقِينَ فِئَتَيْنِ } قال: هم قوم خرجوا من مكة، حتى جاؤوا المدينة يزعمون أنهم مهاجرون، ثم ارتدوا بعد ذلك، فاستأذنوا النبي ﷺ إلى مكة ليأتوا ببضائع لهم يتجرون فيها، فاختلف فيهم المؤمنون: فقائل يقول: هم منافقون، وقائل يقول: هم مؤمنون. فبين الله نفاقهم وأنزل هذه الآية، وأمر بقتلهم في قوله: { فَإِن تَوَلَّوْا۟ فَخُذُوهُمْ وَٱقْتُلُوهُمْ حَيْثُ وَجَدتُّمُوهُمْ ۖ }، فجاءوا ببضائعهم يريدون هلال بن عويمر الأسلمي وبينه وبين النبي ﷺ حلف، وهو الذي حصر صدره أن يقاتل المؤمنين، فرفع عنهم القتل بقوله تعالى: { إِلَّا ٱلَّذِينَ يَصِلُونَ إِلَىٰ قَوْمِۭ } الآية.","id":""}],"94":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما: { وَلَا تَقُولُوا۟ لِمَنْ أَلْقَىٰٓ إِلَيْكُمُ ٱلسَّلَـٰمَ لَسْتَ مُؤْمِنًا } قَالَ: قَالَ ابْنُ عَبَّاسٍ: كَانَ رَجُلٌ فِي غُنَيْمَةٍ لَهُ، فَلَحِقَهُ الْمُسْلِمُونَ، فَقَالَ: السَّلَامُ عَلَيْكُمْ، فَقَتَلُوهُ وَأَخَذُوا غُنَيْمَتَهُ، فَأَنْزَلَ اللَّهُ فِي ذَلِكَ إلَى قَوْلِهِ: { تَبْتَغُونَ عَرَضَ ٱلْحَيَوٰةِ ٱلدُّنْيَا } تِلْكَ الْغُنَيْمَة، قَالَ: قَرَأَ ابْنُ عَبَّاسٍ السَّلامَ.\n\nوجاء من لفظ آخر عن ابن عباس.","id":""},{"ar":"وهناك سبب آخر لنزول هذه الآية: فقد جاء عَنْ عَبْدِ اللَّهِ بْنِ أَبِي حَدْرَدٍ رضي الله عنه قَالَ: بَعَثَنَا رَسُولُ اللهِ ﷺ إِلَى إِضَمَ، فَخَرَجْتُ فِي نَفَرٍ مِنْ الْمسلِمِينَ، فِيهِمْ أَبُو قَتَادَةَ الْحَارِثُ بْنُ رِبْعِيٍّ، وَمُحَلَّمُ بْنُ جَثَّامَةَ بْنِ قَيْسٍ، فَخَرَجْنَا حَتَّى إِذَا كُنَّا بِبَطْنِ إِضَمَ، مَرَّ بِنَا عَامِرٌ الْأَشْجَعِيُّ عَلَى قَعُودٍ لَهُ، مَعَهُ مُتَيْعٌ، وَوَطْبٌ مِنْ لَبَنٍ، فَلَمَّا مَرَّ بِنَا سَلَّمَ عَلَيْنَا، فَأَمْسَكْنَا عَنْهُ، وَحَمَلَ عَلَيْهِ مُحَلَّمُ بْنُ جَثَّامَةَ فَقَتَلَهُ بِشَيْءٍ كَانَ بَيْنَهُ وَبَيْنَهُ، وَأَخَذَ بَعِيرَهُ وَمُتَيْعَهُ، فَلَمَّا قَدِمْنَا عَلَى رَسُولِ اللَّهِ ﷺ وَأَخْبَرْنَاهُ الْخَبَرَ نَزَلَ فِينَا الْقُرْآنُ: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا ضَرَبْتُمْ فِى سَبِيلِ ٱللَّهِ فَتَبَيَّنُوا۟ وَلَا تَقُولُوا۟ لِمَنْ أَلْقَىٰٓ إِلَيْكُمُ ٱلسَّلَـٰمَ لَسْتَ مُؤْمِنًا تَبْتَغُونَ عَرَضَ ٱلْحَيَوٰةِ ٱلدُّنْيَا فَعِندَ ٱللَّهِ مَغَانِمُ كَثِيرَةٌ ۚ كَذَٰلِكَ كُنتُم مِّن قَبْلُ فَمَنَّ ٱللَّهُ عَلَيْكُمْ فَتَبَيَّنُوٓا۟ ۚ إِنَّ ٱللَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيرًا ﴿٩٤﴾ }.","id":""}],"95":[{"ar":"عَنِ الْبَرَاءِ رضي الله عنه قَالَ: ( لَمَّا نَزَلَتْ { لَّا يَسْتَوِى ٱلْقَٰعِدُونَ مِنَ ٱلْمُؤْمِنِينَ وَٱلْمُجَـٰهِدُونَ فِى سَبِيلِ ٱللَّهِ } قَالَ النَّبِيُّ ﷺ: « ادْعُ لِي زَيْداً، وَلْيَجِيءْ بِاللَّوْحِ وَالدَّوَاةِ وَالْكَتِفِ، - أَوْ، الْكَتِفِ وَالدَّوَاةِ - » ثُمَّ قَالَ: اكْتُبْ: { لَّا يَسْتَوِى ٱلْقَـٰعِدُونَ }. وَخَلْفَ ظَهْرِ النَّبِيِّ ﷺ عَمْرُو بْنُ أُمِّ مَكْتُومٍِ الْأَعْمَى، قَالَ: يَا رَسُولَ اللهِ، فَمَا تَأْمُرُنِي، فَإِنِّي رَجُلٌ ضَرِيرُ الْبَصَرِ؟ فَنَزَلَتْ مَكَانَهَا: {   لَّا يَسْتَوِى ٱلْقَـٰعِدُونَ مِنَ ٱلْمُؤْمِنِينَ غَيْرُ أُو۟لِى ٱلضَّرَرِ وَٱلْمُجَـٰهِدُونَ فِى سَبِيلِ ٱللَّهِ } ) واللفظ للبخاري.\n\nوجاء عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما شبيهاً به.","id":""},{"ar":"عن سَهْلِ بْنِ سَعْدٍ رضي الله عنه قَالَ: رَأَيْتُ مَرْوَانَ بْنَ الْحَكَمِ جَالِساً فِي الْمَسْجِدِ، فَأَقْبَلْتُ حَتَّى جَلَسْتُ إِلَى جَنْبِهِ، فَأَخْبَرَنَا أَنَّ زَيْدَ بْنَ ثَابِتٍ أَخْبَرَهُ: أَنَّ النَّبِيَّ ﷺ أَمْلَى عَلَيْهِ: لَا { لَّا يَسْتَوِى ٱلْقَٰعِدُونَ مِنَ ٱلْمُؤْمِنِينَ وَٱلْمُجَـٰهِدُونَ فِى سَبِيلِ ٱللَّهِ } قَالَ: فَجَاءَهُ ابْنُ أُمِّ مَكْتُومٍ وَهُوَ يُمْلِيهَا عَلَيَّ، فَقَالَ: يَا رَسُولَ اللهِ، وَاللهِ لَوْ أَسْتَطِيعُ الْجِهَادَ لَجَاهَدْتُ، وَكَانَ رَجُلًا أَعْمَى، فَأَنْزَلَ اللهُ عَلَى رَسُولِهِ ﷺ وَفَخِذُهُ عَلَى فَخِذِي، فَثَقُلَتْ حَتَّى هَمَّتْ تَرُضُّ فَخِذِي، ثُمَّ سُرِّيَ عَنْهُ، فَأَنْزَلَ اللهُ عَلَيْهِ: { غَيْرُ أُو۟لِى ٱلضَّرَرِ }.\n\nوجاء بلفظ أطول عن خارجة بن زيد عن زيد بن ثابت.\n\nوجاء عن الفلتان بن عاصم له شبيهاً بما سبق.\n\nوعن زيد بن أرقم له شبيهاً به.","id":""}],"97":[{"ar":"عن مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ أَبُو الْأَسْوَدِ قَالَ: قُطِعَ عَلَى أَهْلِ الْمَدِينَةِ بَعْثٌ، فَاكْتُتِبْتُ فِيهِ، فَلَقِيتُ عِكْرِمَةَ مَوْلَى ابْنِ عَبَّاسٍ فَأَخْبَرْتُهُ، فَنَهَانِي عَنْ ذَلِكَ أَشَدَّ النَّهْي، ثُمَّ قَالَ: أَخْبَرَنِي ابْنُ عَبَّاسٍ: أَنَّ نَاساً مِنَ الْمُسْلِمِينَ كَانُوا مَعَ الْمُشْرِكِينَ، يُكَثِّرُونَ سَوَادَ الْمُشْرِكِينَ عَلَى عَهْدِ رَسُولِ اللهِ ﷺ، يَأْتِي السَّهْمُ فَيُرْمَى بِهِ، فَيُصِيبُ أَحَدَهُمْ فَيَقْتُلُهُ، أَوْ يُضْرَبُ فَيُقْتَلُ، فَأَنْزَلَ اللهُ { إِنَّ ٱلَّذِينَ تَوَفَّىٰهُمُ ٱلْمَلَٰٓئِكَةُ ظَالِمِىٓ أَنفُسِهِمْ } الآية. واللفظ للبخاري.\n\nوفي لفظ آخر أطول منه: جاء عن ابن عباس رضي الله عنهما قريباً منه.","id":""}],"100":[{"ar":"عن ابن عباس رضي الله عنهما قال: خرج ضمرة بن جندب من بيته مهاجراً، فقال لأهله احملوني فأخرجوني من أرض المشركين إلى رسول الله، فمات في الطريق قبل أن يصل إلى النبي، فنزل الوحي { وَمَن يَخْرُجْ مِنۢ بَيْتِهِۦ مُهَاجِرًا إِلَى ٱللَّهِ وَرَسُولِهِۦ ثُمَّ يُدْرِكْهُ ٱلْمَوْتُ } حتى بلغ { وَكَانَ ٱللَّهُ غَفُورًا رَّحِيمًا }.","id":""}],"102":[{"ar":"عَنْ أَبِي عَيَّاشٍ الزُّرَقِي رضي الله عنه قَالَ:\nكُنَّا مَعَ رَسُولِ اللَّهِ ﷺ بِعُسْفَانَ، فَاسْتَقْبَلَنَا الْمُشْرِكُونَ عَلَيْهِمْ خَالِدُ بْنُ الْوَلِيدِ، وَهُمْ بَيْنَنَا وَبَيْنَ الْقِبْلَةِ، فَصَلَّى بِنَا رَسُولُ اللهِ ﷺ الظُّهْرَ، فَقَالُوا: قَدْ كَانُوا عَلَى حَالٍ لَوْ أَصَبْنَا غِرَّتَهُمْ، ثُمَّ قَالُوا: تَأْتِي عَلَيْهِمُ الْآنَ صَلَاةٌ هِيَ أَحَبُّ إِلَيْهِمْ مِنْ أَبْنَائِهِمْ وَأَنْفُسِهِمْ، قَالَ: فَنَزَلَ جِبْرِيلُ عليه السلام بِهَذِهِ الْآيات بَيْنَ الظُّهْرِ وَالْعَصْرِ: { وَإِذَا كُنتَ فِيهِمْ فَأَقَمْتَ لَهُمُ ٱلصَّلَوٰةَ } قَالَ: فَحَضَرَتْ فَأَمَرَهُمْ رَسُولُ اللهِ ﷺ فَأَخَذُوا السِّلَاحَ، قَالَ: فَصَفَفْنَا خَلْفَهُ صَفَّيْنِ، قَالَ: ثُمَّ رَكَعَ فَرَكَعْنَا جَمِيعاً، ثُمَّ رَفَعَ فَرَفَعْنَا جَمِيعاً، ثُمَّ سَجَدَ النَّبِيُّ ﷺ بِالصَّفِّ الَّذِي يَلِيهِ وَالْآخَرُونَ قِيَامٌ يَحْرُسُونَهُمْ، فَلَمَّا سَجَدُوا وَقَامُوا جَلَسَ الْآخَرُونَ فَسَجَدُوا فِي مَكَانِهِمْ، ثُمَّ تَقَدَّمَ هَؤُلَاءِ إِلَى مَصَافِّ هَؤُلَاءِ وَجَاءَ هَؤُلَاءِ إِلَى مَصَافِّ هَؤُلَاءِ، قَالَ: ثُمَّ رَكَعَ، فَرَكَعُوا جَمِيعاً، ثُمَّ رَفَعَ، فَرَفَعُوا جَمِيعاً، ثُمَّ سَجَدَ النَّبِيُّ ﷺ وَالصَّفُّ الَّذِي يَلِيهِ، وَالْآخَرُونَ قِيَامٌ يَحْرُسُونَهُمْ، فَلَمَّا جَلَسَ جَلَسَ الْآخَرُونَ فَسَجَدُوا فَسَلَّمَ عَلَيْهِمْ، ثُمَّ انْصَرَفَ، قَالَ: فَصَلَّاهَا رَسُولُ اللهِ ﷺ مَرَّتَيْنِ، مَرَّةً بِعُسْفَانَ، وَمَرَّةً بِأَرْضِ بَنِي سُلَيْمٍ. واللفظ لأحمد.\n\nوجاء عن جابر بن عبد الله رضي الله عنهما شبيهاً به.","id":""},{"ar":"عن عبد الله بن عباس رضي الله عنهما قال: في قوله تعالى: { إِن كَانَ بِكُمْ أَذًى مِّن مَّطَرٍ أَوْ كُنتُم مَّرْضَىٰٓ } قال: نزلت في عبد الرحمن بن عوف كان جريحاً.","id":""}],"105":[{"ar":"عَنْ قَتَادَة بنِ النُّعْمَانِ رضي الله عنه قَالَ: كَانَ أَهْلُ بَيْتٍ مِنَّا يُقَالُ لَهُمْ: بَنُو أُبَيْرِقٍ: بِشْرٌ، وَبُشَيْرٌ، وَمُبَشِّرٌ، وَكَانَ بُشَيْرٌ رَجُلًا مُنَافِقاً، يَقُولُ الشِّعْرَ يَهْجُو بِهِ أَصْحَابَ رَسُولِ اللهِ ﷺ ثُمَّ يَنْحَلُهُ بَعْضَ الْعَرَبِ ثُمَّ يَقُولُ: قَالَ فُلَانٌ كَذَا وَكَذَا، قَالَ فُلَانٌ كَذَا وَكَذَا، فَإِذَا سَمِعَ أَصْحَابُ رَسُولِ اللهِ ﷺ ذَلِكَ الشِّعْرَ قَالُوا: وَاللهِ مَا يَقُولُ هَذَا الشِّعْرَ إِلَّا هَذَا الْخَبِيثُ أَوْ كَمَا قَالَ الرَّجُلُ، وَقَالُوا: ابْنُ الْأُبَيْرِقِ قَالَهَا، قَالَ: وَكَانُوا أَهْلَ بَيْتِ حَاجَةٍ وَفَاقَةٍ فِي الْجَاهِلِيَّةِ وَالْإِسْلَامِ، وَكَانَ النَّاسُ إِنَّمَا طَعَامُهُمْ بِالْمَدِينَةِ التَّمْرُ وَالشَّعِيرُ، وَكَانَ الرَّجُلُ إِذَا كَانَ لَهُ يَسَارٌ فَقَدِمَتْ ضَافِطَةٌ مِنْ الشَّامِ مِنْ الدَّرْمَكِ ابْتَاعَ الرَّجُلُ مِنْهَا فَخَصَّ بِهَا نَفْسَهُ، وَأَمَّا الْعِبَالُ فَإِنَّمَا طَعَامُهُمُ التَّمْرُ وَالشَّعِيرُ، فَقَدِمَتْ ضَافِطَةٌ مِنْ الشَّامِ فَابْتَاعَ عَمِّي رِفَاعَةُ بْنُ زَيْدٍ حِمْلًا مِنْ الدَّرْمَكِ فَجَعَلَهُ فِي مَشْرَبَةٍ لَهُ وَفِي الْمَشْرَبَةِ سِلَاحُ وَدِرْعٌ وَسَيْفٌ، فَعُدِيَ عَلَيْهِ مِنْ تَحْتِ الْبَيْتِ فَنُقِبَتِ الْمَشْرَبَةُ، وَأُخِذَ الطَّعَامُ وَالسِّلَاحُ، فَلَمَّا أَصْبَحَ أَتَانِي عَمِّي رِفَاعَةُ، فَقَالَ: يَا ابْنَ أَخِي إِنَّهُ قَدْ عُدِيَ عَلَيْنَا فِي لَيْلَتِنَا هَذِهِ، فَنُقِبَتْ مَشْرَبَتُنَا وَذُهِبَ بِطَعَامِنَا وَسِلَاحِنَا، قَالَ: فَتَحَسَّسْنَا فِي الدَّارِ وَسَأَلْنَا، فَقِيلَ لَنَا: قَدْ رَأَيْنَا بَنِي أُبَيْرِقٍ اسْتَوْقَدُوا فِي هَذِهِ اللَّيْلَةَ، وَلَا نَرَى فِيمَا نَرَى إِلَّا عَلَى بَعْضِ طَعَامِكُمْ، قَالَ: وَكَانَ بَنُو أُبَيْرِقٍ قَالُوا وَنَحْنُ نَسْأَلُ فِي الدَّارِ: وَاللهِ مَا نُرَى صَاحِبَكُمْ إِلَّا لَبِيدَ بْنَ سَهْلٍ، رَجُلٌ مِنَّا، لَهُ صَلَاحٌ وَإِسْلَامٌ، فَلَمَّا سَمِعَ لَبِيدٌ اخْتَرَطَ سَيْفَهُ وَقَالَ: أَنَا أَسْرِقُ؟ فَوَاللهِ لَيُخَالِطَنَّكُمْ هَذَا السَّيْفُ أَوْ لَتُبَيِّنُنَّ هَذِهِ السَّرِقَةَ، قَالُوا: إِلَيْكَ عَنْهَا أَيُّهَا الرَّجُلُ، فَمَا أَنْتَ بِصَاحِبِهَا، فَسَأَلْنَا فِي الدَّارِ حَتَّى لَمْ نَشُكَّ أَنَّهُمْ أَصْحَابُهَا، فَقَالَ لِي عَمِّي: يَا ابْنَ أَخِي لَوْ أَتَيْتَ رَسُولَ اللهِ ﷺ فَذَكَرْتَ ذَلِكَ لَهُ.\n\nقَالَ قَتَادَةُ: فَأَتَيْتُ رَسُولَ اللهِ ﷺ فَقُلْتُ: إِنَّ أَهْلَ بَيْتٍ مِنَّا أَهْلَ جَفَاءٍ، عَمَدُوا إِلَى عَمِّي رِفَاعَةَ بْنِ زَيْدٍ فَنَقَبُوا مَشْرَبَةً لَهُ، وَأَخَذُوا سِلَاحَهُ وَطَعَامَهُ، فَلْيَرُدُّوا عَلَيْنَا سِلَاحَنَا، فَأَمَّا الطَّعَامُ فَلَا حَاجَةَ لَنَا فِيهِ، فَقَالَ النَّبِيُّ ﷺ: « سَآمُرُ فِي ذَلِكَ »، فَلَمَّا سَمِعَ بَنُو أُبَيْرِقٍ أَتَوْا رَجُلًا مِنْهُمْ يُقَالُ لَهُ أُسَيْرُ بْنُ عُرْوَةَ فَكَلَّمُوهُ فِي ذَلِكَ، فَاجْتَمَعَ فِي ذَلِكَ نَاسٌ مِنْ أَهْلِ الدَّارِ، فَقَالُوا: يَا رَسُولَ اللهِ، إِنَّ قَتَادَةَ بْنَ النُّعْمَانِ وَعَمَّهُ عَمَدًا إِلَى أَهْلِ بَيْتٍ مِنَّا، أَهْلِ إِسْلَامٍ وَصَلَاحٍ، يَرْمُونَهُمْ بِالسَّرِقَةِ مِنْ غَيْرِ بَيِّنَةٍ وَلَا ثَبَتٍ.\n\nقَالَ قَتَادَةُ: فَأَتَيْتُ رَسُولَ اللهِ ﷺ فَكَلَّمْتُهُ فَقَالَ: « عَمَدْتَ إِلَى أَهْلِ بَيْتِ ذُكِرَ مِنْهُمْ إِسْلَامٌ وَصَلَاحٌ، تَرْمِهِمْ بِالسَّرِقَةِ عَلَى غَيْرِ ثَبَتٍ  َلَا بَيْنَةٍ »، قَالَ: فَرَجَعْتُ وَلَوَدِدْتُ أَنِّي خَرَجْتُ مِنْ بَعْضِ مَالِي، وَلَمْ أُكَلِّمْ رَسُولَ اللَّهِ ﷺ فِي ذَلِكَ، فَأَتَانِي عَمِّي رِفَاعَةُ فَقَالَ: يَا ابْنَ أَخِي مَا صَنَعْتَ؟ فَأَخْبَرْتُهُ بِمَا قَالَ لِي رَسُولُ اللهِ ﷺ، فَقَالَ: اللهُ الْمُسْتَعَانُ، فَلَمْ يَلْبَتْ أَنْ نَزَلَ الْقُرْآنِ: { إِنَّآ أَنزَلْنَآ إِلَيْكَ ٱلْكِتَٰبَ بِٱلْحَقِّ لِتَحْكُمَ بَيْنَ ٱلنَّاسِ بِمَآ أَرَىٰكَ ٱللَّهُ ۚ وَلَا تَكُن لِّلْخَآئِنِينَ خَصِيمًا ﴿١٠٥﴾ } بَنِي أُبَيْرِقِ { وَٱسْتَغْفِرِ ٱللَّهَ ۖ } أَيْ مِمَّا قُلْتَ لِقَتَادَةَ { إِنَّ ٱللَّهَ كَانَ غَفُورًا رَّحِيمًا ﴿١٠٦﴾ وَلَا تُجَـٰدِلْ عَنِ ٱلَّذِينَ يَخْتَانُونَ أَنفُسَهُمْ ۚ إِنَّ ٱللَّهَ لَا يُحِبُّ مَن كَانَ خَوَّانًا أَثِيمًا ﴿١٠٧﴾ يَسْتَخْفُونَ مِنَ ٱلنَّاسِ وَلَا يَسْتَخْفُونَ مِنَ ٱللَّهِ } إِلَى قَوْلِهِ { غَفُورًا رَّحِيمًا } أَيْ: لَوْ اسْتَغْفَرُوا اللهَ لَغَفَرَ لَهُمْ { مَن يَكْسِبْ إِثْمًا فَإِنَّمَا يَكْسِبُهُۥ عَلَىٰ نَفْسِهِۦ ۚ } إِلَى قَوْلِهِ { إِثْمًا مُّبِينًا } قَوْلَهُمْ لِلبِيدٍ، { وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكَ وَرَحْمَتُهُۥ } إِلَى قَوْلِهِ { فَسَوْفَ نُؤْتِيهِ أَجْرًا عَظِيمًا }.\n\nفَلَمَّا نَزَلَ الْقُرْآنُ أَتَى رَسُولُ اللهِ ﷺ بِالسِّلَاحِ فَرَدَّهُ إِلَى رِفَاعَةَ، فَقَالَ قَتَادَةُ: لَمَّا أَتَيْتُ عَمِّي بِالسِّلَاحِ، وَكَانَ شَيْخاً قَدْ عَشَا أَوْ عَسَى فِي الْجَاهِلِيَّةِ، وَكُنْتُ أَرَى إِسْلَامَهُ مَدْخُولًا، فَلَمَّا أَتَيْتُهُ بِالسِّلَاحِ قَالَ: يَا ابْنَ أَخِي هُوَ فِي سَبِيلِ اللَّهِ. فَعَرَفْتُ أَنَّ إِسْلَامَهُ كَانَ صَحِيحاً. فَلَمَّا نَزَلَ الْقُرْآنُ لَحِقَ بُشَيْرٌ بِالْمُشْرِكِينَ، فَنَزَلَ عَلَى سُلافَةَ بِنْتِ سَعْدِ بْنِ سُمَيَّةَ فَأَنْزَلَ اللهُ: { وَمَن يُشَاقِقِ ٱلرَّسُولَ مِنۢ بَعْدِ مَا تَبَيَّنَ لَهُ ٱلْهُدَىٰ وَيَتَّبِعْ غَيْرَ سَبِيلِ ٱلْمُؤْمِنِينَ نُوَلِّهِۦ مَا تَوَلَّىٰ وَنُصْلِهِۦ جَهَنَّمَ ۖ وَسَآءَتْ مَصِيرًا ﴿١١٥﴾ إِنَّ ٱللَّهَ لَا يَغْفِرُ أَن يُشْرَكَ بِهِۦ وَيَغْفِرُ مَا دُونَ ذَٰلِكَ لِمَن يَشَآءُ ۚ وَمَن يُشْرِكْ بِٱللَّهِ فَقَدْ ضَلَّ ضَلَـٰلًۢا بَعِيدًا ﴿١١٦﴾ } فَلَمَّا نَزَلَ عَلَى سُلَافَةَ رَمَاهَا حَسَّانُ بْنُ ثَابِتٍ بِأَبْيَاتٍ مِنْ شِعْرِهِ، فَأَخَذَتْ رَحْلَهُ فَوَضَعَتْهُ عَلَى رَأْسِهَا، ثُمَّ خَرَجَتْ بِهِ فَرَمَتْ بِهِ فِي الأَبْطَحِ، ثُمَّ قَالَتْ: أَهْدَيْتَ لِي شِعْرَ حَسَّانَ؟ مَا كُنْتَ تَأْتِينِي بِخَيْرٍ. واللفظ للترمذي.","id":""}],"123":[{"ar":"عن مسروق في قوله: { لَّيْسَ بِأَمَانِيِّكُمْ وَلَآ أَمَانِىِّ أَهْلِ ٱلْكِتَـٰبِ ۗ } قال: احتج المسلمون وأهل الكتاب، فقال المسلمون: نحن أهدى منكم، وقال أهل الكتاب: نحن أهدى منكم فأنزل الله: { لَّيْسَ بِأَمَانِيِّكُمْ وَلَآ أَمَانِىِّ أَهْلِ ٱلْكِتَـٰبِ ۗ } قال: ففلج عليهم المسلمون بهذه الآية، { وَمَن يَعْمَلْ مِنَ ٱلصَّـٰلِحَـٰتِ مِن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌ } إلى آخـــــر الآيتين.\n\nوجاء عن قتادة شبيهاً به.\n\nوجاء عن أبي صالح شبيهاً به.","id":""}],"127":[{"ar":".. قَالَ عُرْوَةُ رحمه الله: قَالَتْ عَائِشَةُ رضي الله عنها: ثُمَّ إِنَّ النَّاسَ اسْتَفْتَوْا رَسُولَ اللهِ ﷺ بَعْدَ هَذِهِ الْآيَةِ (بعد نزول آية رقم: 3 من سورة النساء.): فَأَنْزَلَ اللهُ { وَيَسْتَفْتُونَكَ فِى ٱلنِّسَآءِ ۖ } إِلَى قَوْلِهِ { وَتَرْغَبُونَ أَن تَنكِحُوهُنَّ }...","id":""}],"128":[{"ar":"عَنْ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: خَشِيَتْ سَوْدَةُ أَنْ يُطَلِّقَهَا النَّبِيُّ ﷺ، فَقَالَتْ: لَا تُطَلِّقُنِي، وَأَمْسِكْنِي وَاجْعَلْ يَوْمِي لِعَائِشَةَ، فَفَعَلَ، فَنَزَلَتْ { فَلَا جُنَاحَ عَلَيْهِمَآ أَن يُصْلِحَا بَيْنَهُمَا صُلْحًا ۚ وَٱلصُّلْحُ خَيْرٌ ۗ }، فَمَا اصْطَلَحَا عَلَيْهِ مِنْ شَيْءٍ فَهُوَ جَائِزٌ. كَأَنَّهُ مِنْ قَوْلِ ابْنِ عَبَّاسٍ.","id":""},{"ar":"عَنْ عُرْوَةَ، عَنْ عَائِشَة رضي الله عنها أَنها قَالَت لَهُ: يَا ابنَ أُخْتِي، كَانَ رَسُولُ اللهِ ﷺ لَا يُفَضِّلُ بَعْضَنَا عَلَى بَعْضٍ فِي مُكثِهِ عِنْدَنَا، وَكَانَ قَلَّ يَومٌ إِلَّا وَهُوَ يَطُوفُ عَلَينا، فَيدنُو مِنْ كُلِّ امرأَةٍ مِنْ غَيْرِ مَسيسٍ حتى يَبْلُغَ إِلَى مَنْ هُوَ يَوْمُهَا فَيبِيتَ عِنْدَها، وَلَقَدْ قَالَتْ سَوْدَةٌ بنتُ زَمعَةَ - حِينَ أَسَنَّتْ وَفَرِقَتْ أَنْ يُفارِقَهَا رَسُولُ اللهِ ﷺ: يَا رَسُولَ اللهِ، يَوْمِي هَذَا لِعَائِشَةَ، فَقَبِلَ ذَلِكَ رَسُولُ اللهِ ﷺ، قَالَتْ: فَفِي ذَلكَ أنزلَ اللهُ: { وَإِنِ ٱمْرَأَةٌ خَافَتْ مِنۢ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا }.","id":""},{"ar":"ولها سبب آخر: عن ابن المسيب رحمه الله: أن بنت محمد بن مسلمة كانت عند رافع بن خديج، فكره منها أمراً إما كبراً أو غيره، فأراد طلاقها فقالت: لا تطلقني وأقسم لي ما بدا لك، فأنزل الله عز و جل: { وَإِنِ ٱمْرَأَةٌ خَافَتْ مِنۢ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا } الآية.","id":""},{"ar":"ورواه الحاكم بأطول من هذا السياق: عن رافع بن خديج رضي الله عنه: أنه كانت تحته امرأة قد خلا من سنها، فتزوج عليها شابة، فآثر البكر عليها، فأبت امرأته الأولى أن تقرّ على ذلك، فطلقها تطليقة حتى إذا بقي من أجلها يسير، قال: إن شئت راجعتك وصبرت على الأثرة، وإن شئت تركتك حتى يخلو أجلك، قالت بل راجعني، أصبر على الأثرة، فراجعها ثم آثر عليها، فلم تصبر على الأثرة، فطلقها الأخرى وآثر عليها الشابة، قال: فذلك الصلح الذي بلغنا أن الله قد نزل فيه { وَإِنِ ٱمْرَأَةٌ خَافَتْ مِنۢ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا فَلَا جُنَاحَ عَلَيْهِمَآ أَن يُصْلِحَا بَيْنَهُمَا صُلْحًا ۚ }.","id":""}],"176":[{"ar":"عن جَابِرَ بْنِ عَبْدِ اللهِ رضي الله عنهما يَقُولُ: مَرِضْتُ فَأَتَانِي رَسُولُ اللهِ ﷺ يَعُودُنِي، فَوَجَدَنِي قَدْ أُغْمِيَ عَلَيَّ، فَأَتَى وَمَعَهُ أَبُو بَكْرٍ وَعُمَرُ وَهُمَا مَاشِيَانِ، فَتَوَضَّأَ رَسُولُ اللهِ ﷺ فَصَبَّ عَلَيَّ مِنْ وَضُوئِهِ، فَأَفَقْتُ، فَقُلْتُ: يَا رَسُولَ اللهِ كَيْفَ أَقْضِي فِي مَالِي؟ أَوْ كَيْفَ أَصْنَعُ فِي مَالِي فَلَمْ يُجِبْنِي شَيْئاً، وَكَانَ لَهُ تِسْعُ أَخَوَاتٍ حَتَّى نَزَلَتْ آيَةُ الْمِيرَاثِ: { يَسْتَفْتُونَكَ قُلِ ٱللَّهُ يُفْتِيكُمْ فِى ٱلْكَلَـٰلَةِ ۚ } الْآيَةَ قَالَ جَابِرٌ: فِيَّ نَزَلَتْ.","id":""}]},"mapping_ayat":{"4:1":[{"p":"Nasa'i","n":1378,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ يُحَدِّثُ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَّمَنَا خُطْبَةَ الْحَاجَةِ الْحَمْدُ لِلَّهِ نَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا وَسَيِّئَاتِ أَعْمَالِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَقْرَأُ ثَلَاثَ آيَاتٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَثَّ مِنْهُمَا رِجَالًا كَثِيرًا وَنِسَاءً وَاتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ وَالْأَرْحَامَ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا }قَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو عُبَيْدَةَ لَمْ يَسْمَعْ مِنْ أَبِيهِ شَيْئًا وَلَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَلَا عَبْدُ الْجَبَّارِ بْنُ وَائِلِ بْنِ حُجْرٍ","trj":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Abu Ishaq] menceritakan dari [Abu 'Ubaidah] dari ['Abdullah] dari Nabi Shalallahu 'Alaihi Wa Sallam. Abdullah berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam telah mengajarkan Khutbah Hajah kepada kami, yaitu, 'Segala puji bagi Allah, kita memohon pertolongan dan ampunan kepadanya, berlindung kepadanya dari kejahatan jiwa kami dan kejelekan perbuatan-perbuatan kami. Barang siapa yang diberikan petunjuk oleh Allah, maka tidak akan ada yang bisa menyesatkannya. Barangsiapa yang telah Allah sesatkan, maka tidak akan ada yang bisa memberinya petunjuk. Aku bersaksi tiada tuhan (yang berhak disembah) kecuali Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusannya'. Kemudian beliau membaca tiga ayat berikut ini: 'Wahai orang-orang yang beriman, bertakwalah kepada Allah dengan sebenar-benar takwa kepadanya, dan janganlah kamu mati melainkan dalam keadaan beragama Islam'. (Qs. Ali 'Imran (3): 102). 'Hai kalian manusia, bertakwalah kepada tuhanmu yang telah menciptakanmu dari diri yang satu, dan daripadanya Allah menciptakan istrinya, dan daripada keduanya Allah memperkembangbiakan laki-laki dan perempuan yang banyak, dan bertakwalah kepada Allah dengan (mempergunakan) nama-Nya kamu saling meminta satu dengan yang lain, dan (periharalah) hubungan Silaturrahim. Sesungguhnya Allah selalu menjaga dan mengawasimu'.\"(Qs. An-Nisaa'(4): 1). 'Hai orang-orang yang beriman, bertakwalah kepada Allah dan katakanlah perkataan yang benar'.\"(Qs. Al Ahzaab (33): 70). Abu Abdurrahman berkata; Abu Ubaidah tidak pernah mendengar dari Bapaknya sedikitpun, demikian juga Abdurrahman bin Abdullah bin Mas'ud dan Abdul Jabbar bin Wa'il bin Hujr. "}],"4:2":[{"p":"Abu Dawud","n":3717,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ الْحُسَيْنِ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَاللَّاتِي يَأْتِينَ الْفَاحِشَةَ مِنْ نِسَائِكُمْ فَاسْتَشْهِدُوا عَلَيْهِنَّ أَرْبَعَةً مِنْكُمْ فَإِنْ شَهِدُوا فَأَمْسِكُوهُنَّ فِي الْبُيُوتِ حَتَّى يَتَوَفَّاهُنَّ الْمَوْتُ أَوْ يَجْعَلَ اللَّهُ لَهُنَّ سَبِيلًا }وَذَكَرَ الرَّجُلَ بَعْدَ الْمَرْأَةِ ثُمَّ جَمَعَهُمَا فَقَالَ{ وَاللَّذَانِ يَأْتِيَانِهَا مِنْكُمْ فَآذُوهُمَا فَإِنْ تَابَا وَأَصْلَحَا فَأَعْرِضُوا عَنْهُمَا }فَنَسَحَ ذَلِكَ بِآيَةِ الْجَلْدِ فَقَالَ{ الزَّانِيَةُ وَالزَّانِي فَاجْلِدُوا كُلَّ وَاحِدٍ مِنْهُمَا مِائَةَ جَلْدَةٍ }حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ حَدَّثَنَا مُوسَى يَعْنِي ابْنَ مَسْعُودٍ عَنْ شِبْلٍ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجِاهِدٍ قَالَ السَّبِيلُ الْحَدُّ قَالَ سُفْيَانُ{ فَآذُوهُمَا }الْبِكْرَانِ{ فَأَمْسِكُوهُنَّ فِي الْبُيُوتِ }الثَّيِّبَاتُ","trj":"Telah menceritakan kepada kami [Amad bin Muhammad bin Tsabit Al Marwazi] berkata, telah menceritakan kepadaku [Ali bin Al Husain] dari [Bapaknya] dari [Yazid bin An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata tentang firman Allah: '(Dan (terhadap) para wanita yang mengerjakan perbuatan keji, hendaklah ada empat orang saksi diantara kamu (yang menyaksikannya). Kemudian apabila mereka telah memberi persaksian, maka kurunglah mereka (wanita-wanita itu) dalam rumah sampai mereka menemui ajalnya, atau sampai Allah memberi jalan lain kepadanya) ' -Qs. An Nisa: 15-. Allah menyebutkan laki-laki setelah perempuan, kemudian Dia menggabungkan keduanya. Allah berfirman: '(Dan terhadap dua orang yang melakukan perbuatan keji di antara kamu, maka berilah hukuman kepada keduanya, kemudian jika keduanya bertaubat dan memperbaiki diri, maka biarkanlah mereka..) ' -Qs. An Nisa: 16-. Ayat ini kemudian dihapus dengan ayat cambuk, Allah berfirman: '(perempuan yang berzina dan laki-laki yang berzina, maka deralah tiap-tiap seorang dari keduanya seratus kali dera…) ' -Qs. An Nuur: 2-. Telah menceritakan kepada kami Ahmad bin Muhammad bin Tsabit berkata, telah menceritakan kepada kami Musa -maksudnya Musa bin Mas'ud- dari Syibl dari Ibnu Abu Najih dari Mujahid ia berkata, \"Kata 'as sabil' maksudnya adalah hukuman had.\" Mujahid berkata, \"Firman Allah 'maka berilah hukuman kepada keduanya', maksudnya adalah pezina yang masih lajang. Sementara firman Allah 'maka kurunglah mereka (wanita-wanita itu) dalam rumah', maksudnya adalah para janda.\""}],"4:3":[{"p":"Bukhari","n":2314,"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْعَامِرِيُّ الْأُوَيْسِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ أَنَّهُ سَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّهُسَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ قَوْلِ اللَّهِ تَعَالَى{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا إِلَى وَرُبَاعَ }فَقَالَتْ يَا ابْنَ أُخْتِي هِيَ الْيَتِيمَةُ تَكُونُ فِي حَجْرِ وَلِيِّهَا تُشَارِكُهُ فِي مَالِهِ فَيُعْجِبُهُ مَالُهَا وَجَمَالُهَا فَيُرِيدُ وَلِيُّهَا أَنْ يَتَزَوَّجَهَا بِغَيْرِ أَنْ يُقْسِطَ فِي صَدَاقِهَا فَيُعْطِيهَا مِثْلَ مَا يُعْطِيهَا غَيْرُهُ فَنُهُوا أَنْ يُنْكِحُوهُنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ وَيَبْلُغُوا بِهِنَّ أَعْلَى سُنَّتِهِنَّ مِنْ الصَّدَاقِ وَأُمِرُوا أَنْ يَنْكِحُوا مَا طَابَ لَهُمْ مِنْ النِّسَاءِ سِوَاهُنَّ قَالَ عُرْوَةُ قَالَتْ عَائِشَةُ ثُمَّ إِنَّ النَّاسَ اسْتَفْتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ هَذِهِ الْآيَةِ فَأَنْزَلَ اللَّهُ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ إِلَى قَوْلِهِ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }وَالَّذِي ذَكَرَ اللَّهُ أَنَّهُ يُتْلَى عَلَيْكُمْ فِي الْكِتَابِ الْآيَةُ الْأُولَى الَّتِي قَالَ فِيهَا{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ عَائِشَةُ وَقَوْلُ اللَّهِ فِي الْآيَةِ الْأُخْرَى{ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }يَعْنِي هِيَ رَغْبَةُ أَحَدِكُمْ لِيَتِيمَتِهِ الَّتِي تَكُونُ فِي حَجْرِهِ حِينَ تَكُونُ قَلِيلَةَ الْمَالِ وَالْجَمَالِ فَنُهُوا أَنْ يَنْكِحُوا مَا رَغِبُوا فِي مَالِهَا وَجَمَالِهَا مِنْ يَتَامَى النِّسَاءِ إِلَّا بِالْقِسْطِ مِنْ أَجْلِ رَغْبَتِهِمْ عَنْهُنَّ","trj":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah Al 'Amiriy Al Uwaisiy] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Shalih] dari [Ibnu Syihab] telah menceritakan kepadaku ['Urwah] bahwa dia bertanya kepada ['Aisyah radliallahu 'anha]. Dan [Al Laits] berkata, telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] be telah menceritakan kapadaku ['Urwah bin Az Zubair] bahwa dia bertanya kepada ['Aisyah radliallahu 'anha] tentang firman Allah yang artinya: (\"Jika kamu khawatir tidak dapat berlaku adil …. seterusnya hingga …empat-empat\". (QS. An-Nisaa ayat 3), maka ia menjawab: \"Wahai anak saudariku, yang dimaksud ayat itu adalah seorang anak perempuan yatim yang berada pada asuhan walinya, hartanya ada pada walinya, dan walinya ingin memiliki harta itu dan menikahinya namun ia tidak bisa berbuat adil dalam memberikan maharnya, yaitu memberi seperti ia memberikan untuk yang lainnya, maka mereka dilarang untuk menikahinya kecuali jika mereka bisa berbuat adil pada mereka, dan mereka memberikan mahar terbaik kepadanya, mereka diperintahkan untuk menikahi wanita-wanita yang baik untuk mereka selain anak-anak yatim itu\". 'Urwah berkata, lalu 'Aisyah berkata, kemudian orang-orang meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam setelah turunnya ayat ini; wayastaftuunaka finnisaa' (dan mereka meminta fatwa kepadamu tentang para wanita) hingga firmanNya; watarghobuuna antankihuuhunna (dan kalian ingin menikahi mereka) dan yang disebutkan Allah pada firmanNya bahwa; yutla 'alaikum fil kitab (telah disebutkan untuk kalian di dalam Al Quran) ayat pertama yang Allah berfirman didalamnya ada kalimat; wa in khiftum allaa tuqsituu fil yataamaa fankihuu maa thaoba lakum minan nisaa' (jika kalian tidak bisa berbuat adil kepada anak-anak yatim, maka nikahilah wanita-wanita yang baik untuk kalian), 'Aisyah berkata, dan firman Allah pada ayat yang lain; watarghobuuna an tankihuuhunna (dan kalian ingin untuk menikahi mereka) yaitu keinginan kalian untuk menikahi anak perempuan yatim yang kalian asuh ketika ia sedikit hartanya dan kurang menarik wajahya, maka mereka dilarang untuk menikahi mereka karena semata hartanya dan kecantikannya dari anak-anak perempuan yatim kecuali dengan adil disebabkan ketidak tertarikan mereka kepada perempuan yatim itu\"."},{"p":"Bukhari","n":2557,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ كَانَ عُرْوَةُ بْنُ الزُّبَيْرِ يُحَدِّثُ أَنَّهُ سَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ هِيَ الْيَتِيمَةُ فِي حَجْرِ وَلِيِّهَا فَيَرْغَبُ فِي جَمَالِهَا وَمَالِهَا وَيُرِيدُ أَنْ يَتَزَوَّجَهَا بِأَدْنَى مِنْ سُنَّةِ نِسَائِهَا فَنُهُوا عَنْ نِكَاحِهِنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ فِي إِكْمَالِ الصَّدَاقِ وَأُمِرُوا بِنِكَاحِ مَنْ سِوَاهُنَّ مِنْ النِّسَاءِ قَالَتْ عَائِشَةُ ثُمَّ اسْتَفْتَى النَّاسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ قُلْ اللَّهُ يُفْتِيكُمْ فِيهِنَّ }قَالَتْ فَبَيَّنَ اللَّهُ فِي هَذِهِ الْآيَةِ أَنَّ الْيَتِيمَةَ إِذَا كَانَتْ ذَاتَ جَمَالٍ وَمَالٍ رَغِبُوا فِي نِكَاحِهَا وَلَمْ يُلْحِقُوهَا بِسُنَّتِهَا بِإِكْمَالِ الصَّدَاقِ فَإِذَا كَانَتْ مَرْغُوبَةً عَنْهَا فِي قِلَّةِ الْمَالِ وَالْجَمَالِ تَرَكُوهَا وَالْتَمَسُوا غَيْرَهَا مِنْ النِّسَاءِ قَالَ فَكَمَا يَتْرُكُونَهَا حِينَ يَرْغَبُونَ عَنْهَا فَلَيْسَ لَهُمْ أَنْ يَنْكِحُوهَا إِذَا رَغِبُوا فِيهَا إِلَّا أَنْ يُقْسِطُوا لَهَا الْأَوْفَى مِنْ الصَّدَاقِ وَيُعْطُوهَا حَقَّهَا","trj":"Telah bercerita kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata ['Urwah bin Az Zubair] bercerita bahwa dia pernah bertanya kepada ['Aisyah radliallahu 'anha] tentaang firman Allah QS an-Nisaa' ayat 3 yang artinya: (Dan jika kamu takut tidak akan dapat berlaku adil terhadap (hak-hak) perempuan yang yatim (bilamana kamu mengawininya), maka kawinilah wanita-wanita (lain) yang kamu senangi …). 'Aisyah menjawab: \"Yang dimaksud ayat itu adalah seorang anak perempuan yatim yang berada pada asuhan walinya, lalu walinya itu tertarik dengan kecantikan dan hartanya dan berhasrat untuk mengawininya namun memberikan haknya lebih rendah dari yang biasa diberikan kepada istri-istrinya sebelumnya maka mereka dilarang menikahinya kecuali bila mereka dapat berlaku adil kepada mereka, dan mereka diperintahkan untuk menikahi wanita-wanita lain selain mereka\". 'Aisyah berkata: \"Kemudian orang-orang meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam setelah itu, maka Allah 'azza wajalla menurunkan firman-Nya QS an-Nisaa' ayat 126 yang artinya (dan mereka meminta fatwa kepadamu tentang para wanita. Katakanlah; Allah akan memberikan fatwa kepada kalian tentang mereka..) 'Aisyah berkata: \"Maka Allah menjelaskan dalam ayat ini bahwa seorang anak yatim perempuan jika memiliki kecantikan dan harta lalu walinya berhasrat menikahinya namun tidak memberikan haknya dengan melengkapi mahar sebagaimana semestinya. Namun bila anak yatim perempuan itu tidak memiliki harta dan kecantikan mereka meninggalkannya dan mencari wanita selain mereka\". Beliau bersabda: \"Sebagaimana mereka tidak menyukainya disebabkan sedikit hartanya dan tidak cantik lalu meninggalkannya maka mereka juga tidak boleh menikahinya saat tertarik kecuali bila mereka dapat berlaku adil kepadanya dengan menunaikan maharnya secara wajar serta memberikan hak-haknya\"."},{"p":"Bukhari","n":4371,"ar":"حَدَّثَنَا عَلِيٌّ سَمِعَ حَسَّانَ بْنَ إِبْرَاهِيمَ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ أَنَّهُ سَأَلَ عَائِشَةَعَنْ قَوْلِهِ تَعَالَى{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ مَثْنَى وَثُلَاثَ وَرُبَاعَ فَإِنْ خِفْتُمْ أَلَّا تَعْدِلُوا فَوَاحِدَةً أَوْ مَا مَلَكَتْ أَيْمَانُكُمْ ذَلِكَ أَدْنَى أَلَّا تَعُولُوا }قَالَتْ يَا ابْنَ أُخْتِي الْيَتِيمَةُ تَكُونُ فِي حَجْرِ وَلِيِّهَا فَيَرْغَبُ فِي مَالِهَا وَجَمَالِهَا يُرِيدُ أَنْ يَتَزَوَّجَهَا بِأَدْنَى مِنْ سُنَّةِ صَدَاقِهَا فَنُهُوا أَنْ يَنْكِحُوهُنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ فَيُكْمِلُوا الصَّدَاقَ وَأُمِرُوا بِنِكَاحِ مَنْ سِوَاهُنَّ مِنْ النِّسَاءِ","trj":"Telah menceritakan kepada kami [Ali] Ia telah mendengar [Hassan bin Ibrahim] dari [Yunus bin Yazid] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Urwah] bahwa ia bertanya kepada [Aisyah] tentang firman Allah Ta'ala: \"Dan jika kalian khawatir tidak bisa berlaku adil terhadap anak yatim, maka nikahilah wanita yang baik-baik, dua, tiga, atau empat, jika kalian tidak bisa berlaku adil, maka kawinilah satu saja, atau hamba sahaya kalian, itu lebih dekat agar kalian tidak melanggar batas (QS. Annisa' 3). Maka Aisyah menjelaskan, \"Wahai anak saudaraku, maksudnya adalah seorang anak perempuan yatim bertempat tinggal di rumah walinya. Lalu ia pun menginginkan harta dan juga kecantikannya. Ia ingin menikahinya dengan mahar yang sedikit, maka mereka dilarang untuk menikahinya kecuali mereka dapat berbuat adil terhadap mereka dan menyempurnakan mahar. Karena itu, mereka diperintahkan untuk menikahi wanita-wanita selain mereka.\""}],"4:6":[{"p":"Bukhari","n":2060,"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا ابْنُ نُمَيْرٍ أَخْبَرَنَا هِشَامٌ ح و حَدَّثَنِي مُحَمَّدُ بْنُ سَلَّامٍ قَالَ سَمِعْتُ عُثْمَانَ بْنَ فَرْقَدٍ قَالَ سَمِعْتُ هِشَامَ بْنَ عُرْوَةَ يُحَدِّثُ عَنْ أَبِيهِ أَنَّهُ سَمِعَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاتَقُولُ{ وَمَنْ كَانَ غَنِيًّا فَلْيَسْتَعْفِفْ وَمَنْ كَانَ فَقِيرًا فَلْيَأْكُلْ بِالْمَعْرُوفِ }أُنْزِلَتْ فِي وَالِي الْيَتِيمِ الَّذِي يُقِيمُ عَلَيْهِ وَيُصْلِحُ فِي مَالِهِ إِنْ كَانَ فَقِيرًا أَكَلَ مِنْهُ بِالْمَعْرُوفِ","trj":"Telah menceritakan kepada saya [Ishaq] telah menceritakan kepada kami [Ibnu Numair] telah mengabarkan kepada kami [Hisyam] dan diriwayatkan pula telah menceritakan kepada saya [Muhammad bin Salam] berkata; Aku mendengar ['Utsman bin Farqad] berkata; Aku mendengar [Hisyam bin 'Urwah] menceritakan dari [Bapaknya] bahwa dia mendengar ['Aisyah radliallahu 'anha] berkata, (tentang ayat QS. An-Nisaa' ayat 6 yang artinya (barangsiapa diantara pemelihara itu yang mampu maka hendaknya ia menehan diri dari memakan harta anak yatim itu, dan barangsiapa yang miskin maka ia boleh makan harta itu menurut yang patut), ayat ini turun pada wali anak yatim yang memelihara dan menjaga hartanya, dan jika ia seorang miskin maka ia boleh memakannya dengan cara ma'ruf (yang patut)."}],"4:10":[{"p":"Nasa'i","n":3509,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ قَالَ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ عَطَاءٍ وَهُوَ ابْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَقْرَبُوا مَالَ الْيَتِيمِ إِلَّا بِالَّتِي هِيَ أَحْسَنُ }وَ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ اجْتَنَبَ النَّاسُ مَالَ الْيَتِيمِ وَطَعَامَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَشَكَوْا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَيَسْأَلُونَكَ عَنْ الْيَتَامَى قُلْ إِصْلَاحٌ لَهُمْ خَيْرٌ إِلَى قَوْلِهِ لَأَعْنَتَكُمْ }","trj":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] berkata; telah menceritakan kepada kami [Muhammad bin Ash Shalt] berkata; telah menceritakan kepada kami [Abu Kudainah] dari ['Atha] -yaitu Ibnu As Saib- dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Tatkala turun ayat: '(Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat) ' (Qs. Al Israa': 34), serta '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ibnu Abbas berkata, \"Maka orang-orang menjauhi harta anak yatim dan makanannya, sehingga hal tersebut terasa berat atas orang-orang muslim. Maka mereka mengadukan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, kemudian Allah menurunkan ayat: '(Dan mereka bertanya kepadamu tentang anak yatim, katakalah: \"Mengurus urusan mereka secara patut adalah baik, dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu; dan Allah mengetahui siapa yang membuat kerusakan dari yang mengadakan perbaikan. Dan jikalau Allah menghendaki, niscaya Dia dapat mendatangkan kesulitan kepadamu) ' (Qs. Al Baqarah: 220)."},{"p":"Nasa'i","n":3510,"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عِمْرَانُ بْنُ عُيَيْنَةَ قَالَ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ كَانَ يَكُونُ فِي حَجْرِ الرَّجُلِ الْيَتِيمُ فَيَعْزِلُ لَهُ طَعَامَهُ وَشَرَابَهُ وَآنِيَتَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَإِنْ تُخَالِطُوهُمْ فَإِخْوَانُكُمْ }فِي الدِّينِ فَأَحَلَّ لَهُمْ خُلْطَتَهُمْ","trj":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Imran bin 'Uyainah] berkata; telah menceritakan kepada kami ['Atha bin As Saib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] mengenaii firman Allah: '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ia berkata, \"Dahulu terdapat seorang anak yatim dalam pemeliharaan seorang laki-laki, kemudian laki-laki tersebut menjauhi makanan serta minuman dan bejananya, sehingga hal tersebut terasa berat bagi orang-orang muslim. Kemudian Allah 'azza wajalla menurunkan ayat: '(dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu) ' (Qs. Al Baqarah: 220), yaitu seagama, maka Allah pun menghalalkan bagi mereka untuk bergaul dengan mereka.\""}],"4:11":[{"p":"Tirmidzi","n":2830,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَال سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُمَرِضْتُ فَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي وَقَدْ أُغْمِيَ عَلَيَّ فَلَمَّا أَفَقْتُ قُلْتُ كَيْفَ أَقْضِي فِي مَالِي فَسَكَتَ عَنِّي حَتَّى نَزَلَتْ{ يُوصِيكُمُ اللَّهُ فِي أَوْلَادِكُمْ لِلذَّكَرِ مِثْلُ حَظِّ الْأُنْثَيَيْنِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ حَدَّثَنَا الْفَضْلُ بْنُ الصَّبَّاحِ الْبَغْدَادِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَفِي حَدِيثِ الْفَضْلِ بْنِ الصَّبَّاحِ كَلَامٌ أَكْثَرُ مِنْ هَذَا","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Muhammad bin Al Munkadir] ia berkata; Aku mendengar [Jabir bin Abdullah] berkata; \"Rasulullah shallallahu 'alaihi wasallam datang menjengukku ketika aku sakit dan jatuh pingsan. Setelah siuman, aku bertanya; \"Bagaimana aku akan menunaikan semua hartaku?\" beliau terdiam, akhirnya turunlah ayat: Allah mensyari'atkan bagimu tentang (pembagian pusaka untuk) anak-anakmu. Yaitu, bagian seorang anak lelaki sama dengan bagian dua orang anak perempuan. QS An-Nisa`: 11. Abu Isa mengatakan bahwa hadits ini hasan shahih. Dan telah meriwayatkan lebih dari satu orang dari Muhammad bin Al Munkadir, telah menceritakan kepada kami [Al Fadlal bin Ash Shabbah] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Munkadir] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam seperti itu, dan di dalam hadits Al Fadlal bin Ash Shabbah perkataannya lebih banyak dari ini."}],"4:12":[{"p":"Tirmidzi","n":2020,"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ أَنَّهُ قَالَإِنَّكُمْ تَقْرَءُونَ هَذِهِ الْآيَةَ{ مِنْ بَعْدِ وَصِيَّةٍ تُوصُونَ بِهَا أَوْ دَيْنٍ }وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالدَّيْنِ قَبْلَ الْوَصِيَّةِ وَإِنَّ أَعْيَانَ بَنِي الْأُمِّ يَتَوَارَثُونَ دُونَ بَنِي الْعَلَّاتِ الرَّجُلُ يَرِثُ أَخَاهُ لِأَبِيهِ وَأُمِّهِ دُونَ أَخِيهِ لِأَبِيهِحَدَّثَنَا بُنْدَارٌ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا زَكَرِيَّا بْنُ أَبِي زَائِدَةَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","trj":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami [Yazid bin Harun]; telah mengabarkan kepada kami [Sufyan] dari [Abu Ishaq] dari [Al Harits] dari ['Ali] bahwasanya dia berkata; Sesungguhnya kalian telah sering membaca ayat ini, \"MIM BA'DI WASHIYYATIN TUUSHUUNA BIHAA AUW DA`IN.\" setelah (dipenuhi) wasiat yang mereka buat atau (dan setelah dbayar) utangnya) (QS. An Nisaa`: 12) Dan sesungguhnya Rasulullah shallallahu 'alaihi wasallam lebih dahulu mengedepankan pembayaran hutang sebelum wasiat. Sesungguhnya saudara-saudara kandung saling mewarisi lain halnya dengan saudara-saudara yang tidak sekandung. Seorang laki-laki mewarisi saudaranya sebapak dan seibuknya, namun saudaranya sebapak tidak demikian. Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami [Yazid bin Harun]; telah mengabarkan kepada kami [Zakariya bin Abu Zaidah] dari [Abu Ishaq] dari [Al Harits] dari ['Ali] dari Nabi shallallahu 'alaihi wasallam sepertinya."},{"p":"Tirmidzi","n":2043,"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا الْأَشْعَثُ بْنُ جَابِرٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ حَدَّثَهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الرَّجُلَ لَيَعْمَلُ وَالْمَرْأَةُ بِطَاعَةِ اللَّهِ سِتِّينَ سَنَةً ثُمَّ يَحْضُرُهُمَا الْمَوْتُ فَيُضَارَّانِ فِي الْوَصِيَّةِ فَتَجِبُ لَهُمَا النَّارُ ثُمَّ قَرَأَ عَلَيَّ أَبُو هُرَيْرَةَ{ مِنْ بَعْدِ وَصِيَّةٍ يُوصَى بِهَا أَوْ دَيْنٍ غَيْرَ مُضَارٍّ وَصِيَّةً مِنْ اللَّهِ إِلَى قَوْلِهِ ذَلِكَ الْفَوْزُ الْعَظِيمُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَنَصْرُ بْنُ عَلِيٍّ الَّذِي رَوَى عَنْ الْأَشْعَثِ بْنِ جَابِرٍ هُوَ جَدُّ نَصْرِ بْنِ عَلِيٍّ الْجَهْضَمِيِّ","trj":"Telah menceritakan kepada kami [Nashr bin 'Ali Al Jahdhami]; telah menceritakan kepada kami ['Abdush Shamad bin 'Abdul Warits]; telah menceritakan kepada kami [Nashr bin 'Ali]; telah menceritakan kepada kami [Al Asy'ats bin Jabir] dari [Syahr bin Hausyab] dari [Abu Hurairah] bahwasanya dia menceritakan kepadanya dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang lelaki dan perempuan bisa jadi beramal ketaatan kepada Allah selama enam puluh tahun, kemudian ketika tiba ajal keduanya melakukan sesuatu yang membahayakan bagi ahli waritsnya, sehingga mengharuskan keduanya masuk ke dalam neraka.\" Kemudian Abu Hurairah membacakan ayat kepadaku: \"MIM BA'DI WASIYYATIY YUUSHAA BIHAA AU DAININ GHAIRA MUDLAARRIW WASIYYATAM MINALLAAH (sesudah dipenuhi wasiat yang dibuat olehnya atau sesudah dibayar hutangnya dengan tidak memberi mudharat kepada ahli waris. (Allah menetapkan yang demikian itu sebagai) syari`at yang benar-benar dari Allah).\" (QS An Nisa': 12) sampai firman Allah, \"DZALIKAL FAUZUL 'ADZIIM (dan itulah kemenangan yang besar).\" (QS An Nisa': 13) Abu Isa berkata; Hadits ini adalah hasan shahih gharib, adapun Nashr bin Ali yang meriwayatkan dari Ats'ats bin Jabir dia adalah kakeknya Nahsr bin Ali Al Jahdlami."}],"4:13":[{"p":"Tirmidzi","n":2043,"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا الْأَشْعَثُ بْنُ جَابِرٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ حَدَّثَهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الرَّجُلَ لَيَعْمَلُ وَالْمَرْأَةُ بِطَاعَةِ اللَّهِ سِتِّينَ سَنَةً ثُمَّ يَحْضُرُهُمَا الْمَوْتُ فَيُضَارَّانِ فِي الْوَصِيَّةِ فَتَجِبُ لَهُمَا النَّارُ ثُمَّ قَرَأَ عَلَيَّ أَبُو هُرَيْرَةَ{ مِنْ بَعْدِ وَصِيَّةٍ يُوصَى بِهَا أَوْ دَيْنٍ غَيْرَ مُضَارٍّ وَصِيَّةً مِنْ اللَّهِ إِلَى قَوْلِهِ ذَلِكَ الْفَوْزُ الْعَظِيمُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَنَصْرُ بْنُ عَلِيٍّ الَّذِي رَوَى عَنْ الْأَشْعَثِ بْنِ جَابِرٍ هُوَ جَدُّ نَصْرِ بْنِ عَلِيٍّ الْجَهْضَمِيِّ","trj":"Telah menceritakan kepada kami [Nashr bin 'Ali Al Jahdhami]; telah menceritakan kepada kami ['Abdush Shamad bin 'Abdul Warits]; telah menceritakan kepada kami [Nashr bin 'Ali]; telah menceritakan kepada kami [Al Asy'ats bin Jabir] dari [Syahr bin Hausyab] dari [Abu Hurairah] bahwasanya dia menceritakan kepadanya dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang lelaki dan perempuan bisa jadi beramal ketaatan kepada Allah selama enam puluh tahun, kemudian ketika tiba ajal keduanya melakukan sesuatu yang membahayakan bagi ahli waritsnya, sehingga mengharuskan keduanya masuk ke dalam neraka.\" Kemudian Abu Hurairah membacakan ayat kepadaku: \"MIM BA'DI WASIYYATIY YUUSHAA BIHAA AU DAININ GHAIRA MUDLAARRIW WASIYYATAM MINALLAAH (sesudah dipenuhi wasiat yang dibuat olehnya atau sesudah dibayar hutangnya dengan tidak memberi mudharat kepada ahli waris. (Allah menetapkan yang demikian itu sebagai) syari`at yang benar-benar dari Allah).\" (QS An Nisa': 12) sampai firman Allah, \"DZALIKAL FAUZUL 'ADZIIM (dan itulah kemenangan yang besar).\" (QS An Nisa': 13) Abu Isa berkata; Hadits ini adalah hasan shahih gharib, adapun Nashr bin Ali yang meriwayatkan dari Ats'ats bin Jabir dia adalah kakeknya Nahsr bin Ali Al Jahdlami."}],"4:15":[{"p":"Abu Dawud","n":3717,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ الْحُسَيْنِ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَاللَّاتِي يَأْتِينَ الْفَاحِشَةَ مِنْ نِسَائِكُمْ فَاسْتَشْهِدُوا عَلَيْهِنَّ أَرْبَعَةً مِنْكُمْ فَإِنْ شَهِدُوا فَأَمْسِكُوهُنَّ فِي الْبُيُوتِ حَتَّى يَتَوَفَّاهُنَّ الْمَوْتُ أَوْ يَجْعَلَ اللَّهُ لَهُنَّ سَبِيلًا }وَذَكَرَ الرَّجُلَ بَعْدَ الْمَرْأَةِ ثُمَّ جَمَعَهُمَا فَقَالَ{ وَاللَّذَانِ يَأْتِيَانِهَا مِنْكُمْ فَآذُوهُمَا فَإِنْ تَابَا وَأَصْلَحَا فَأَعْرِضُوا عَنْهُمَا }فَنَسَحَ ذَلِكَ بِآيَةِ الْجَلْدِ فَقَالَ{ الزَّانِيَةُ وَالزَّانِي فَاجْلِدُوا كُلَّ وَاحِدٍ مِنْهُمَا مِائَةَ جَلْدَةٍ }حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ حَدَّثَنَا مُوسَى يَعْنِي ابْنَ مَسْعُودٍ عَنْ شِبْلٍ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجِاهِدٍ قَالَ السَّبِيلُ الْحَدُّ قَالَ سُفْيَانُ{ فَآذُوهُمَا }الْبِكْرَانِ{ فَأَمْسِكُوهُنَّ فِي الْبُيُوتِ }الثَّيِّبَاتُ","trj":"Telah menceritakan kepada kami [Amad bin Muhammad bin Tsabit Al Marwazi] berkata, telah menceritakan kepadaku [Ali bin Al Husain] dari [Bapaknya] dari [Yazid bin An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata tentang firman Allah: '(Dan (terhadap) para wanita yang mengerjakan perbuatan keji, hendaklah ada empat orang saksi diantara kamu (yang menyaksikannya). Kemudian apabila mereka telah memberi persaksian, maka kurunglah mereka (wanita-wanita itu) dalam rumah sampai mereka menemui ajalnya, atau sampai Allah memberi jalan lain kepadanya) ' -Qs. An Nisa: 15-. Allah menyebutkan laki-laki setelah perempuan, kemudian Dia menggabungkan keduanya. Allah berfirman: '(Dan terhadap dua orang yang melakukan perbuatan keji di antara kamu, maka berilah hukuman kepada keduanya, kemudian jika keduanya bertaubat dan memperbaiki diri, maka biarkanlah mereka..) ' -Qs. An Nisa: 16-. Ayat ini kemudian dihapus dengan ayat cambuk, Allah berfirman: '(perempuan yang berzina dan laki-laki yang berzina, maka deralah tiap-tiap seorang dari keduanya seratus kali dera…) ' -Qs. An Nuur: 2-. Telah menceritakan kepada kami Ahmad bin Muhammad bin Tsabit berkata, telah menceritakan kepada kami Musa -maksudnya Musa bin Mas'ud- dari Syibl dari Ibnu Abu Najih dari Mujahid ia berkata, \"Kata 'as sabil' maksudnya adalah hukuman had.\" Mujahid berkata, \"Firman Allah 'maka berilah hukuman kepada keduanya', maksudnya adalah pezina yang masih lajang. Sementara firman Allah 'maka kurunglah mereka (wanita-wanita itu) dalam rumah', maksudnya adalah para janda.\""}],"4:16":[{"p":"Abu Dawud","n":3717,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ الْحُسَيْنِ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَاللَّاتِي يَأْتِينَ الْفَاحِشَةَ مِنْ نِسَائِكُمْ فَاسْتَشْهِدُوا عَلَيْهِنَّ أَرْبَعَةً مِنْكُمْ فَإِنْ شَهِدُوا فَأَمْسِكُوهُنَّ فِي الْبُيُوتِ حَتَّى يَتَوَفَّاهُنَّ الْمَوْتُ أَوْ يَجْعَلَ اللَّهُ لَهُنَّ سَبِيلًا }وَذَكَرَ الرَّجُلَ بَعْدَ الْمَرْأَةِ ثُمَّ جَمَعَهُمَا فَقَالَ{ وَاللَّذَانِ يَأْتِيَانِهَا مِنْكُمْ فَآذُوهُمَا فَإِنْ تَابَا وَأَصْلَحَا فَأَعْرِضُوا عَنْهُمَا }فَنَسَحَ ذَلِكَ بِآيَةِ الْجَلْدِ فَقَالَ{ الزَّانِيَةُ وَالزَّانِي فَاجْلِدُوا كُلَّ وَاحِدٍ مِنْهُمَا مِائَةَ جَلْدَةٍ }حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ حَدَّثَنَا مُوسَى يَعْنِي ابْنَ مَسْعُودٍ عَنْ شِبْلٍ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجِاهِدٍ قَالَ السَّبِيلُ الْحَدُّ قَالَ سُفْيَانُ{ فَآذُوهُمَا }الْبِكْرَانِ{ فَأَمْسِكُوهُنَّ فِي الْبُيُوتِ }الثَّيِّبَاتُ","trj":"Telah menceritakan kepada kami [Amad bin Muhammad bin Tsabit Al Marwazi] berkata, telah menceritakan kepadaku [Ali bin Al Husain] dari [Bapaknya] dari [Yazid bin An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata tentang firman Allah: '(Dan (terhadap) para wanita yang mengerjakan perbuatan keji, hendaklah ada empat orang saksi diantara kamu (yang menyaksikannya). Kemudian apabila mereka telah memberi persaksian, maka kurunglah mereka (wanita-wanita itu) dalam rumah sampai mereka menemui ajalnya, atau sampai Allah memberi jalan lain kepadanya) ' -Qs. An Nisa: 15-. Allah menyebutkan laki-laki setelah perempuan, kemudian Dia menggabungkan keduanya. Allah berfirman: '(Dan terhadap dua orang yang melakukan perbuatan keji di antara kamu, maka berilah hukuman kepada keduanya, kemudian jika keduanya bertaubat dan memperbaiki diri, maka biarkanlah mereka..) ' -Qs. An Nisa: 16-. Ayat ini kemudian dihapus dengan ayat cambuk, Allah berfirman: '(perempuan yang berzina dan laki-laki yang berzina, maka deralah tiap-tiap seorang dari keduanya seratus kali dera…) ' -Qs. An Nuur: 2-. Telah menceritakan kepada kami Ahmad bin Muhammad bin Tsabit berkata, telah menceritakan kepada kami Musa -maksudnya Musa bin Mas'ud- dari Syibl dari Ibnu Abu Najih dari Mujahid ia berkata, \"Kata 'as sabil' maksudnya adalah hukuman had.\" Mujahid berkata, \"Firman Allah 'maka berilah hukuman kepada keduanya', maksudnya adalah pezina yang masih lajang. Sementara firman Allah 'maka kurunglah mereka (wanita-wanita itu) dalam rumah', maksudnya adalah para janda.\""}],"4:24":[{"p":"Tirmidzi","n":2831,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ عَنْ أَبِي الْخَلِيلِ عَنْ أَبِي عَلْقَمَةَ الْهَاشِمِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَلَمَّا كَانَ يَوْمُ أَوْطَاسٍ أَصَبْنَا نِسَاءً لَهُنَّ أَزْوَاجٌ فِي الْمُشْرِكِينَ فَكَرِهَهُنَّ رِجَالٌ مِنَّا فَأَنْزَلَ اللَّهُ{ وَالْمُحْصَنَاتُ مِنْ النِّسَاءِ إِلَّا مَا مَلَكَتْ أَيْمَانُكُمْ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Habban bin HIilal] telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dari [Abu Al Khalil] dari [Abu 'Alqamah Al Hasyimi] dari [Abu Sa'id Al Khudri] ia berkata; \"Ketika terjadi perang Authas, kami menggauli para wanita (tawanan) yang memiliki suami kaum musyrikin, maka sebagian orang diantara kami membenci mereka. Lalu Allah menurunkan ayat: Dan (diharamkan juga kamu mengawini) wanita yang bersuami, kecuali budak-budak yang kamu miliki. QS An-Nisa`: 24. Abu Isa mengatakan bahwa hadits ini hasan shahih."}],"4:29":[{"p":"Abu Dawud","n":3182,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ لَا تَأْكُلُوا أَمْوَالَكُمْ بَيْنَكُمْ بِالْبَاطِلِ إِلَّا أَنْ تَكُونَ تِجَارَةً عَنْ تَرَاضٍ مِنْكُمْ }فَكَانَ الرَّجُلُ يَحْرَجُ أَنْ يَأْكُلَ عِنْدَ أَحَدٍ مِنْ النَّاسِ بَعْدَ مَا نَزَلَتْ هَذِهِ الْآيَةُ فَنَسَخَ ذَلِكَ الْآيَةُ الَّتِي فِي النُّورِ قَالَ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَأْكُلُوا مِنْ بُيُوتِكُمْ إِلَى قَوْلِهِ أَشْتَاتًا كَانَ الرَّجُلُ الْغَنِيُّ يَدْعُو الرَّجُلَ مِنْ أَهْلِهِ إِلَى الطَّعَامِ قَالَ إِنِّي لَأَجَّنَّحُ أَنْ آكُلَ مِنْهُ وَالتَّجَنُّحُ الْحَرَجُ وَيَقُولُ الْمِسْكِينُ أَحَقُّ بِهِ مِنِّي فَأُحِلَّ فِي ذَلِكَ أَنْ يَأْكُلُوا مِمَّا ذُكِرَ اسْمُ اللَّهِ عَلَيْهِ وَأُحِلَّ طَعَامُ أَهْلِ الْكِتَابِ","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepadaku [Ali bin Al Husain bin Waqid] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Firman Allah: '(Janganlah kamu saling memakan harta sesamamu dengan jalan yang batil, kecuali dengan jalan perniagaan yang berlaku dengan suka sama-suka di antara kamu) ' (Qs. An Nisaa: 29), maka setelah ayat tersebut turun, seseorang merasa tidak enak untuk makan di rumah orang lain, kemudian hal tersebut dihapuskan oleh ayat yang ada dalam Surat An Nuur: '(dan tidak (pula) ada halangan bagi dirimu sendiri untuk makan (bersama-sama mereka) di rumah kamu sendiri atau di rumah bapak-bapakmu, di rumah ibu-ibumu, di rumah saudara- saudaramu yang laki-laki, di rumah saudaramu yang perempuan, di rumah saudara bapakmu yang laki-laki, di rumah saudara bapakmu yang perempuan, di rumah saudara ibumu yang laki-laki, di rumah saudara ibumu yang perempuan, di rumah yang kamu miliki kuncinya atau di rumah kawan-kawanmu. Tidak ada halangan bagi kamu makan bersama-sama mereka atau sendirian) '. Maka orang yang kaya mengundang seseorang dari keluarganya untuk makan. Ia berkata, \"Sungguh aku merasa ada ganjalan untuk makan darinya.\" Tajannuh adalah perasaan mengganjal dalam hati. Ia berkata; orang miskin lebih berhak daripada diriku. Kemudian dihalalkan dalam hal tersebut untuk maka apa yang disebutkan padanya nama Allah, dan telah dihalalkan makanan ahli kitab.\""},{"p":"Ahmad","n":1773,"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ ثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَبِيبٍ عَن عِمْرَانَ بْنِ أَبِي أَنَسٍ عَن عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَن عَمْرِو بْنِ الْعَاصِ أَنَّهُ قَالَلَمَّا بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ ذَاتِ السَّلَاسِلِ قَالَ احْتَلَمْتُ فِي لَيْلَةٍ بَارِدَةٍ شَدِيدَةِ الْبَرْدِ فَأَشْفَقْتُ إِنْ اغْتَسَلْتُ أَنْ أَهْلَكَ فَتَيَمَّمْتُ ثُمَّ صَلَّيْتُ بِأَصْحَابِي صَلَاةَ الصُّبْحِ قَالَ فَلَمَّا قَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرْتُ ذَلِكَ لَهُ فَقَالَ يَا عَمْرُو صَلَّيْتَ بِأَصْحَابِكَ وَأَنْتَ جُنُبٌ قَالَ قُلْتُ نَعَمْ يَا رَسُولَ اللَّهِ إِنِّي احْتَلَمْتُ فِي لَيْلَةٍ بَارِدَةٍ شَدِيدَةِ الْبَرْدِ فَأَشْفَقْتُ إِنْ اغْتَسَلْتُ أَنْ أَهْلَكَ وَذَكَرْتُ قَوْلَ اللَّهِ عَزَّ وَجَلَّ{ وَلَا تَقْتُلُوا أَنْفُسَكُمْ إِنَّ اللَّهَ كَانَ بِكُمْ رَحِيمًا }فَتَيَمَّمْتُ ثُمَّ صَلَّيْتُ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَقُلْ شَيْئًا","trj":"Telah menceritakan kepada kami [Hasan bin Musa] ia berkata, Telah menceritakan kepada kami [Ibnu Lahi'ah] Telah menceritakan kepada kami [Yazid bin Abu Habib] dari [Imran bin Abu Anas] dari [Abdurrahman bin Jubair] dari [Amru bin Ash] berkata saat Rasulullah shallallahu 'alaihi wasallam mengutusnya pada tahun Dzatu Salasil, \"Pada suatu malam yang sangat dingin saya mimpi basah, jika mandi maka saya khawatir akan jatuh sakit. Maka saya pun bertayammum kemudian shalat Subuh berjama'ah bersama sahabat-sahabatku. Saat kami menemui Rasulullah shallallahu 'alaihi wasallam, maka saya pun menuturkan hal itu kepada beliau. Beliau bertanya: \"Wahai Amru, apakah kamu shalat bersama sahabat-sahabatmu sedangkan kamu dalam keadaan junub?\" saya menjawab, \"Benar. Wahai Rasulullah, saya mimpi basah pada malam yang sangat dingin sekali, jika mandi saya khawatir akan jatuh sakit. Lalu saya teringat firman Allah, '(Dan janganlah kamu membunuh dirimu. Sesungguhnya Allah adalah Maha Penyayang kepadamu) ' (Qs. An Nisa: 29) Maka saya pun bertayammum dan shalat.\" Rasulullah shallallahu 'alaihi wasallam tertawa dan beliau tidak berkata sesuatu pun."},{"p":"Muslim","n":3196,"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ زُهَيْرٌ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ رَبِّ الْكَعْبَةِ قَالَ دَخَلْتُ الْمَسْجِدَ فَإِذَا عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ الْعَاصِ جَالِسٌ فِي ظِلِّ الْكَعْبَةِ وَالنَّاسُ مُجْتَمِعُونَ عَلَيْهِ فَأَتَيْتُهُمْ فَجَلَسْتُ إِلَيْهِ فَقَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَنَزَلْنَا مَنْزِلًا فَمِنَّا مَنْ يُصْلِحُ خِبَاءَهُ وَمِنَّا مَنْ يَنْتَضِلُ وَمِنَّا مَنْ هُوَ فِي جَشَرِهِ إِذْ نَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ جَامِعَةً فَاجْتَمَعْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ لَمْ يَكُنْ نَبِيٌّ قَبْلِي إِلَّا كَانَ حَقًّا عَلَيْهِ أَنْ يَدُلَّ أُمَّتَهُ عَلَى خَيْرِ مَا يَعْلَمُهُ لَهُمْ وَيُنْذِرَهُمْ شَرَّ مَا يَعْلَمُهُ لَهُمْ وَإِنَّ أُمَّتَكُمْ هَذِهِ جُعِلَ عَافِيَتُهَا فِي أَوَّلِهَا وَسَيُصِيبُ آخِرَهَا بَلَاءٌ وَأُمُورٌ تُنْكِرُونَهَا وَتَجِيءُ فِتْنَةٌ فَيُرَقِّقُ بَعْضُهَا بَعْضًا وَتَجِيءُ الْفِتْنَةُ فَيَقُولُ الْمُؤْمِنُ هَذِهِ مُهْلِكَتِي ثُمَّ تَنْكَشِفُ وَتَجِيءُ الْفِتْنَةُ فَيَقُولُ الْمُؤْمِنُ هَذِهِ هَذِهِ فَمَنْ أَحَبَّ أَنْ يُزَحْزَحَ عَنْ النَّارِ وَيُدْخَلَ الْجَنَّةَ فَلْتَأْتِهِ مَنِيَّتُهُ وَهُوَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَلْيَأْتِ إِلَى النَّاسِ الَّذِي يُحِبُّ أَنْ يُؤْتَى إِلَيْهِ وَمَنْ بَايَعَ إِمَامًا فَأَعْطَاهُ صَفْقَةَ يَدِهِ وَثَمَرَةَ قَلْبِهِ فَلْيُطِعْهُ إِنْ اسْتَطَاعَ فَإِنْ جَاءَ آخَرُ يُنَازِعُهُ فَاضْرِبُوا عُنُقَ الْآخَرِفَدَنَوْتُ مِنْهُ فَقُلْتُ لَهُ أَنْشُدُكَ اللَّهَ آنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَهْوَى إِلَى أُذُنَيْهِ وَقَلْبِهِ بِيَدَيْهِ وَقَالَ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي فَقُلْتُ لَهُ هَذَا ابْنُ عَمِّكَ مُعَاوِيَةُ يَأْمُرُنَا أَنْ نَأْكُلَ أَمْوَالَنَا بَيْنَنَا بِالْبَاطِلِ وَنَقْتُلَ أَنْفُسَنَا وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَأْكُلُوا أَمْوَالَكُمْ بَيْنَكُمْ بِالْبَاطِلِ إِلَّا أَنْ تَكُونَ تِجَارَةً عَنْ تَرَاضٍ مِنْكُمْ وَلَا تَقْتُلُوا أَنْفُسَكُمْ إِنَّ اللَّهَ كَانَ بِكُمْ رَحِيمًا }قَالَ فَسَكَتَ سَاعَةً ثُمَّ قَالَ أَطِعْهُ فِي طَاعَةِ اللَّهِ وَاعْصِهِ فِي مَعْصِيَةِ اللَّهِ و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالُوا حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ كِلَاهُمَا عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ نَحْوَهُ و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو الْمُنْذِرِ إِسْمَعِيلُ بْنُ عُمَرَ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي السَّفَرِ عَنْ عَامِرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ رَبِّ الْكَعْبَةِ الصَّائِدِيِّ قَالَ رَأَيْتُ جَمَاعَةً عِنْدَ الْكَعْبَةِ فَذَكَرَ نَحْوَ حَدِيثِ الْأَعْمَشِ","trj":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim], Ishaq berkata; telah mengabarkan kepada kami, sedangkan Zuhair berkata; telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Zaid bin Wahb] dari [Abdurrahman bin Abd Rabbil Ka'bah] dia berkata, \"Ketika saya masuk masjid, maka terlihat olehku [Abdullah bin 'Amru bin 'Ash] duduk di bawah naungan ka'bah di kelilingi orang banyak. Lalu aku datangi mereka dan duduk di dekat Abadullah. Dia berkata, \"Kami pernah mengadakan suatu perjalanan bersama Rasulullah shallallahu 'alaihi wasallam, lalu di suatu tempat pemberhentian kami berhenti. Sebagian kami ada yang memperbaiki tempat tidur, sebagian lagi berlatih memanah, sebagian lagi memberi makan hewan dan sebagainya. Tiba-tiba terdengar utusan Rasulullah shallallahu 'alaihi wasallam menyeru, memanggil kami untuk shalat berjama'ah, lalu kami berkumpul di dekat beliau. Beliau bersabda: \"Para Nabi sebelum saya diutus menuntun umatnya kepada kebaikan yang telah diajarkan Allah kepada mereka, dan memingatkan bahaya yang mengancam mereka. Ummatku yang sempurna dan selamat ialah angkatan yang pertama-tama, angkatan sesudah itu akan ditimpa berbagai cobaan berupa hal-hal yang tidak disenanginya, seperti timbulnya fitnah. Di mana-mana sebagian mereka menghina sebagian yang lain, oleh karena itu timbullah bencana. Orang-orang mukmin berkata, 'Inilah kiranya yang membinasakanku', Setelah hilang bencana tersebut, timbul pula bencana yang lain. Dan orang mukmin berkata, 'Ini..! Ini..!\" Siapa yang ingin bebas dari neraka dan ingin masuk ke surga, hendaklah dia menemui kematiannya dalam keimanan kepada Allah dan hari akhirat, dan hendaklah dia berjasa kepada ummat manusia sesuai dengan yang diinginkan oleh masyarakat itu. Siapa yang baik dengan seorang pemimpin (penguasa) lalu dia memenuhi bai'atnya dengan sepenuh hati, hendaklah dia mematuhi pemimpin itu semampunya. Jika yang lain datang memberontak, penggallah lehernya.\" Abdurrahman berkata, \"Aku lebih mendekat lagi kepada 'Amru, lalu saya berkata, \"Dengan nama Allah, saya bertanya kepada anda, 'Apakah kamu mendengar sendiri hadits ini dari Rasulullah shallallahu 'alaihi wasallam? ' dia menunjuk tangannya ke telinga dan hatinya seraya berkata, \"Saya mendengarnya dengan kedua telingaku dan kusimpan ke dalam hatiku.\" Lalu kukatakan kepadanya, \"Ini anak pamanmu, Mu'awiyah! Dia menyuruh kami memakan harta sesama dengan cara yang haram dan memerintahkan untuk saling membunuh sesama. Padahal Allah telah berfirman: '(Wahai orang-orang yang beriman, janganlah kamu memakan harta sesamamu dengan cara yang haram, kecuali berjual beli dengan cara suka sama suka sesamamu, dan janganlah kamu membunuh saudaramu (sesama muslim). Sesungguhnya Allah Maha penyayang kepadamu) ' (Qs. An Nisaa`: 29). 'Amru diam sebentar kemudian dia berkata, \"Patuhilah perintahnya bila sesuai dengan perintah Allah dan langgarlah perintahnya bila melanggar perintah Allah!\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ibnu Numair] serta [Abu Sa'id Al Asyaj] mereka berkata; telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah] keduanya dari [Al A'masy] dengan isnad seperti ini.\" Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu Al Mundzir Isma'il bin 'Umar] telah menceritakan kepada kami [Yunus bin Abu Ishaq Al Hamdani] telah menceritakan kepada kami [Abdullah bin Abu As Safar] dari ['Amir] dari [Abdurrahman bin Abd Rabbil Ka'bah Ash Sha`idi] dia berkata, \"Saya melihat sekelompok orang di sisi Ka'bah…kemudian dia menyebutkan seperti hadits Al A'masy.\""}],"4:32":[{"p":"Tirmidzi","n":2835,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أُمِّ سَلَمَةَ أَنَّهَا قَالَتْيَغْزُو الرِّجَالُ وَلَا تَغْزُو النِّسَاءُ وَإِنَّمَا لَنَا نِصْفُ الْمِيرَاثِ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ وَلَا تَتَمَنَّوْا مَا فَضَّلَ اللَّهُ بِهِ بَعْضَكُمْ عَلَى بَعْضٍ }قَالَ مُجَاهِدٌ وَأَنْزَلَ فِيهَا{ إِنَّ الْمُسْلِمِينَ وَالْمُسْلِمَاتِ }وَكَانَتْ أُمُّ سَلَمَةَ أَوَّلَ ظَعِينَةٍ قَدِمَتْ الْمَدِينَةَ مُهَاجِرَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ مُرْسَلٌ وَرَوَاهُ بَعْضُهُمْ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ مُرْسَلٌ أَنَّ أُمَّ سَلَمَةَ قَالَتْ كَذَا وَكَذَا","trj":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] dari [Ummu Salamah] ia berkata; \"Laki-laki pergi berperang, sedangkan wanita tidak berperang, dan (bagian) kami hanya setengah dari harta warisan.\" lalu Allah menurunkan Dan janganlah kamu iri hati terhadap apa yang dikaruniakan Allah kepada sebahagian kamu lebih banyak dari sebahagian yang lain QS An-Nisa`: 32, Mujahid mengatakan; Berkenaan dengan hal itu, ayat berikut turun Sesungguhnya laki-laki dan perempuan yang muslim, laki-laki dan perempuan yang mu'min. QS An-Nisa`: 35, Ummu Salamah adalah seorang wanita pertama kali ikut berhijrah ke Madinah. Abu Isa mengatakan bahwa hadits ini mursal."}],"4:33":[{"p":"Bukhari","n":3409,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ أَوْ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى قَالَ سَلْ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ مَا أَمْرُهُمَا{ وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ لَمَّا أُنْزِلَتْ الَّتِي فِي الْفُرْقَانِ قَالَ مُشْرِكُو أَهْلِ مَكَّةَ فَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَقَدْ أَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ }الْآيَةَ فَهَذِهِ لِأُولَئِكَ وَأَمَّا الَّتِي فِي النِّسَاءِ الرَّجُلُ إِذَا عَرَفَ الْإِسْلَامَ وَشَرَائِعَهُ ثُمَّ قَتَلَ فَجَزَاؤُهُ جَهَنَّمُفَذَكَرْتُهُ لِمُجَاهِدٍ فَقَالَإِلَّا مَنْ نَدِمَ","trj":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] telah menceritakan kepadaku [Sa'id bin Jubair] -atau dia berkata, telah menceritakan kepadaku [Al Hakam] dari [Sa'id bin Jubair] berkata, - 'Abdurrahman bin Abza menyuruhku, katanya; \"Tanyalah kepada Ibnu 'Abbas tentang dua ayat ini dan apa maksudnya, yaitu yang pertama firman Allah dalam QS al Isra` ayat 33; (\"Dan janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan haq (alasan yang benar) \" dan yang kedua firman Allah dalam QS an Nisaa' ayat 93: (\"Dan barangsiapa yang membunuh orang beriman dengan sengaja...\"). Maka aku bertanya kepada [Ibnu 'Abbas], maka dia menjelaskan; Ketika turun firman Allah yang serupa ini pada surah al Furqan, orang-orang musyrik penduduk Makkah berkata; \"Sungguh kita telah membunuh jiwa yang diharamkan Allah dan kita juga menyembah selain Allah dan kita telah banyak berbuat maksiat, maka Allah menurunkan firman-Nya yang artinya: \"...kecuali siapa yang bertaubat dan beriman...\" (QS al Furqan ayat 70). Nah, ayat-ayat ini turun untuk mereka. Adapun ayat yang ada dalam surah an Nisaa' adalah bila seseorang telah mengenal Islam dan syari'atnya, kemudian dia membunuh seseorang dengan sengaja maka balasan baginya adalah neraka jahannam\". Kemudian keterangan ini aku sampaikan kepada Mujahidmaka dia berkata; \"Kecuali siapa yang menyesali perbuartannya\"."}],"4:34":[{"p":"Nasa'i","n":3509,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ قَالَ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ عَطَاءٍ وَهُوَ ابْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَقْرَبُوا مَالَ الْيَتِيمِ إِلَّا بِالَّتِي هِيَ أَحْسَنُ }وَ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ اجْتَنَبَ النَّاسُ مَالَ الْيَتِيمِ وَطَعَامَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَشَكَوْا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَيَسْأَلُونَكَ عَنْ الْيَتَامَى قُلْ إِصْلَاحٌ لَهُمْ خَيْرٌ إِلَى قَوْلِهِ لَأَعْنَتَكُمْ }","trj":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] berkata; telah menceritakan kepada kami [Muhammad bin Ash Shalt] berkata; telah menceritakan kepada kami [Abu Kudainah] dari ['Atha] -yaitu Ibnu As Saib- dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Tatkala turun ayat: '(Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat) ' (Qs. Al Israa': 34), serta '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ibnu Abbas berkata, \"Maka orang-orang menjauhi harta anak yatim dan makanannya, sehingga hal tersebut terasa berat atas orang-orang muslim. Maka mereka mengadukan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, kemudian Allah menurunkan ayat: '(Dan mereka bertanya kepadamu tentang anak yatim, katakalah: \"Mengurus urusan mereka secara patut adalah baik, dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu; dan Allah mengetahui siapa yang membuat kerusakan dari yang mengadakan perbaikan. Dan jikalau Allah menghendaki, niscaya Dia dapat mendatangkan kesulitan kepadamu) ' (Qs. Al Baqarah: 220)."}],"4:35":[{"p":"Tirmidzi","n":2835,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أُمِّ سَلَمَةَ أَنَّهَا قَالَتْيَغْزُو الرِّجَالُ وَلَا تَغْزُو النِّسَاءُ وَإِنَّمَا لَنَا نِصْفُ الْمِيرَاثِ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ وَلَا تَتَمَنَّوْا مَا فَضَّلَ اللَّهُ بِهِ بَعْضَكُمْ عَلَى بَعْضٍ }قَالَ مُجَاهِدٌ وَأَنْزَلَ فِيهَا{ إِنَّ الْمُسْلِمِينَ وَالْمُسْلِمَاتِ }وَكَانَتْ أُمُّ سَلَمَةَ أَوَّلَ ظَعِينَةٍ قَدِمَتْ الْمَدِينَةَ مُهَاجِرَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ مُرْسَلٌ وَرَوَاهُ بَعْضُهُمْ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ مُرْسَلٌ أَنَّ أُمَّ سَلَمَةَ قَالَتْ كَذَا وَكَذَا","trj":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] dari [Ummu Salamah] ia berkata; \"Laki-laki pergi berperang, sedangkan wanita tidak berperang, dan (bagian) kami hanya setengah dari harta warisan.\" lalu Allah menurunkan Dan janganlah kamu iri hati terhadap apa yang dikaruniakan Allah kepada sebahagian kamu lebih banyak dari sebahagian yang lain QS An-Nisa`: 32, Mujahid mengatakan; Berkenaan dengan hal itu, ayat berikut turun Sesungguhnya laki-laki dan perempuan yang muslim, laki-laki dan perempuan yang mu'min. QS An-Nisa`: 35, Ummu Salamah adalah seorang wanita pertama kali ikut berhijrah ke Madinah. Abu Isa mengatakan bahwa hadits ini mursal."}],"4:40":[{"p":"Bukhari","n":6533,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقُلْنَا يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ قَالَ هَلْ تُضَارُونَ فِي رُؤْيَةِ الشَّمْسِ وَالْقَمَرِ إِذَا كَانَتْ صَحْوًا قُلْنَا لَا قَالَ فَإِنَّكُمْ لَا تُضَارُونَ فِي رُؤْيَةِ رَبِّكُمْ يَوْمَئِذٍ إِلَّا كَمَا تُضَارُونَ فِي رُؤْيَتِهِمَا ثُمَّ قَالَ يُنَادِي مُنَادٍ لِيَذْهَبْ كُلُّ قَوْمٍ إِلَى مَا كَانُوا يَعْبُدُونَ فَيَذْهَبُ أَصْحَابُ الصَّلِيبِ مَعَ صَلِيبِهِمْ وَأَصْحَابُ الْأَوْثَانِ مَعَ أَوْثَانِهِمْ وَأَصْحَابُ كُلِّ آلِهَةٍ مَعَ آلِهَتِهِمْ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ وَغُبَّرَاتٌ مِنْ أَهْلِ الْكِتَابِ ثُمَّ يُؤْتَى بِجَهَنَّمَ تُعْرَضُ كَأَنَّهَا سَرَابٌ فَيُقَالُ لِلْيَهُودِ مَا كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ عُزَيْرَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ قَالُوا نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ ثُمَّ يُقَالُ لِلنَّصَارَى مَا كُنْتُمْ تَعْبُدُونَ فَيَقُولُونَ كُنَّا نَعْبُدُ الْمَسِيحَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ فَيَقُولُونَ نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ فَيُقَالُ لَهُمْ مَا يَحْبِسُكُمْ وَقَدْ ذَهَبَ النَّاسُ فَيَقُولُونَ فَارَقْنَاهُمْ وَنَحْنُ أَحْوَجُ مِنَّا إِلَيْهِ الْيَوْمَ وَإِنَّا سَمِعْنَا مُنَادِيًا يُنَادِي لِيَلْحَقْ كُلُّ قَوْمٍ بِمَا كَانُوا يَعْبُدُونَ وَإِنَّمَا نَنْتَظِرُ رَبَّنَا قَالَ فَيَأْتِيهِمْ الْجَبَّارُ فِي صُورَةٍ غَيْرِ صُورَتِهِ الَّتِي رَأَوْهُ فِيهَا أَوَّلَ مَرَّةٍ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ أَنْتَ رَبُّنَا فَلَا يُكَلِّمُهُ إِلَّا الْأَنْبِيَاءُ فَيَقُولُ هَلْ بَيْنَكُمْ وَبَيْنَهُ آيَةٌ تَعْرِفُونَهُ فَيَقُولُونَ السَّاقُ فَيَكْشِفُ عَنْ سَاقِهِ فَيَسْجُدُ لَهُ كُلُّ مُؤْمِنٍ وَيَبْقَى مَنْ كَانَ يَسْجُدُ لِلَّهِ رِيَاءً وَسُمْعَةً فَيَذْهَبُ كَيْمَا يَسْجُدَ فَيَعُودُ ظَهْرُهُ طَبَقًا وَاحِدًا ثُمَّ يُؤْتَى بِالْجَسْرِ فَيُجْعَلُ بَيْنَ ظَهْرَيْ جَهَنَّمَ قُلْنَا يَا رَسُولَ اللَّهِ وَمَا الْجَسْرُ قَالَ مَدْحَضَةٌ مَزِلَّةٌ عَلَيْهِ خَطَاطِيفُ وَكَلَالِيبُ وَحَسَكَةٌ مُفَلْطَحَةٌ لَهَا شَوْكَةٌ عُقَيْفَاءُ تَكُونُ بِنَجْدٍ يُقَالُ لَهَا السَّعْدَانُ الْمُؤْمِنُ عَلَيْهَا كَالطَّرْفِ وَكَالْبَرْقِ وَكَالرِّيحِ وَكَأَجَاوِيدِ الْخَيْلِ وَالرِّكَابِ فَنَاجٍ مُسَلَّمٌ وَنَاجٍ مَخْدُوشٌ وَمَكْدُوسٌ فِي نَارِ جَهَنَّمَ حَتَّى يَمُرَّ آخِرُهُمْ يُسْحَبُ سَحْبًا فَمَا أَنْتُمْ بِأَشَدَّ لِي مُنَاشَدَةً فِي الْحَقِّ قَدْ تَبَيَّنَ لَكُمْ مِنْ الْمُؤْمِنِ يَوْمَئِذٍ لِلْجَبَّارِ وَإِذَا رَأَوْا أَنَّهُمْ قَدْ نَجَوْا فِي إِخْوَانِهِمْ يَقُولُونَ رَبَّنَا إِخْوَانُنَا كَانُوا يُصَلُّونَ مَعَنَا وَيَصُومُونَ مَعَنَا وَيَعْمَلُونَ مَعَنَا فَيَقُولُ اللَّهُ تَعَالَى اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ دِينَارٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ وَيُحَرِّمُ اللَّهُ صُوَرَهُمْ عَلَى النَّارِ فَيَأْتُونَهُمْ وَبَعْضُهُمْ قَدْ غَابَ فِي النَّارِ إِلَى قَدَمِهِ وَإِلَى أَنْصَافِ سَاقَيْهِ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ نِصْفِ دِينَارٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ ذَرَّةٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا قَالَ أَبُو سَعِيدٍ فَإِنْ لَمْ تُصَدِّقُونِي فَاقْرَءُوا{ إِنَّ اللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍ وَإِنْ تَكُ حَسَنَةً يُضَاعِفْهَا }فَيَشْفَعُ النَّبِيُّونَ وَالْمَلَائِكَةُ وَالْمُؤْمِنُونَ فَيَقُولُ الْجَبَّارُ بَقِيَتْ شَفَاعَتِي فَيَقْبِضُ قَبْضَةً مِنْ النَّارِ فَيُخْرِجُ أَقْوَامًا قَدْ امْتُحِشُوا فَيُلْقَوْنَ فِي نَهَرٍ بِأَفْوَاهِ الْجَنَّةِ يُقَالُ لَهُ مَاءُ الْحَيَاةِ فَيَنْبُتُونَ فِي حَافَتَيْهِ كَمَا تَنْبُتُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ قَدْ رَأَيْتُمُوهَا إِلَى جَانِبِ الصَّخْرَةِ وَإِلَى جَانِبِ الشَّجَرَةِ فَمَا كَانَ إِلَى الشَّمْسِ مِنْهَا كَانَ أَخْضَرَ وَمَا كَانَ مِنْهَا إِلَى الظِّلِّ كَانَ أَبْيَضَ فَيَخْرُجُونَ كَأَنَّهُمْ اللُّؤْلُؤُ فَيُجْعَلُ فِي رِقَابِهِمْ الْخَوَاتِيمُ فَيَدْخُلُونَ الْجَنَّةَ فَيَقُولُ أَهْلُ الْجَنَّةِ هَؤُلَاءِ عُتَقَاءُ الرَّحْمَنِ أَدْخَلَهُمْ الْجَنَّةَ بِغَيْرِ عَمَلٍ عَمِلُوهُ وَلَا خَيْرٍ قَدَّمُوهُ فَيُقَالُ لَهُمْ لَكُمْ مَا رَأَيْتُمْ وَمِثْلَهُ مَعَهُوَقَالَ حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُحْبَسُ الْمُؤْمِنُونَ يَوْمَ الْقِيَامَةِ حَتَّى يُهِمُّوا بِذَلِكَ فَيَقُولُونَ لَوْ اسْتَشْفَعْنَا إِلَى رَبِّنَا فَيُرِيحُنَا مِنْ مَكَانِنَا فَيَأْتُونَ آدَمَ فَيَقُولُونَ أَنْتَ آدَمُ أَبُو النَّاسِ خَلَقَكَ اللَّهُ بِيَدِهِ وَأَسْكَنَكَ جَنَّتَهُ وَأَسْجَدَ لَكَ مَلَائِكَتَهُ وَعَلَّمَكَ أَسْمَاءَ كُلِّ شَيْءٍ لِتَشْفَعْ لَنَا عِنْدَ رَبِّكَ حَتَّى يُرِيحَنَا مِنْ مَكَانِنَا هَذَا قَالَ فَيَقُولُ لَسْتُ هُنَاكُمْ قَالَ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ أَكْلَهُ مِنْ الشَّجَرَةِ وَقَدْ نُهِيَ عَنْهَا وَلَكِنْ ائْتُوا نُوحًا أَوَّلَ نَبِيٍّ بَعَثَهُ اللَّهُ إِلَى أَهْلِ الْأَرْضِ فَيَأْتُونَ نُوحًا فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ سُؤَالَهُ رَبَّهُ بِغَيْرِ عِلْمٍ وَلَكِنْ ائْتُوا إِبْرَاهِيمَ خَلِيلَ الرَّحْمَنِ قَالَ فَيَأْتُونَ إِبْرَاهِيمَ فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ ثَلَاث�� كَلِمَاتٍ كَذَبَهُنَّ وَلَكِنْ ائْتُوا مُوسَى عَبْدًا آتَاهُ اللَّهُ التَّوْرَاةَ وَكَلَّمَهُ وَقَرَّبَهُ نَجِيًّا قَالَ فَيَأْتُونَ مُوسَى فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ قَتْلَهُ النَّفْسَ وَلَكِنْ ائْتُوا عِيسَى عَبْدَ اللَّهِ وَرَسُولَهُ وَرُوحَ اللَّهِ وَكَلِمَتَهُ قَالَ فَيَأْتُونَ عِيسَى فَيَقُولُ لَسْتُ هُنَاكُمْ وَلَكِنْ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدًا غَفَرَ اللَّهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ فَيَأْتُونِي فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي فَيَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ أَيْضًا يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّانِيَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّالِثَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَهْ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَقَدْ سَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ حَتَّى مَا يَبْقَى فِي النَّارِ إِلَّا مَنْ حَبَسَهُ الْقُرْآنُ أَيْ وَجَبَ عَلَيْهِ الْخُلُودُ قَالَ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ عَسَى أَنْ يَبْعَثَكَ رَبُّكَ مَقَامًا مَحْمُودًا }قَالَ وَهَذَا الْمَقَامُ الْمَحْمُودُ الَّذِي وُعِدَهُ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Allaits bin Sa'd] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Zaid] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudzri] berkata, \"Kami bertanya, \"Ya Rasulullah, apakah kita akan melihat Tuhan kita pada hari kiamat?\" Nabi balik bertanya: \"Apakah kalian merasa kesulitan melihat matahari dan bulan ketika terang benderang?\" kami menjawab, \"Tidak.\" Nabi meneruskan: \"Begitulah kalian tidak kesulitan melihat melihat Tuhan kalian ketika itu, selain sebagaimana kesulitan kalian melihat keduanya.\" Kemudian beliau berkata: \"Lantas ada seorang penyeru memanggil-manggil, \"Hendaklah setiap kaum pergi menemui yang disembahnya!\" Maka pemuja salib pergi bersama salib mereka, dan pemuja patung menemui patung-patung mereka, dan setiap pemuja Tuhan bersama tuhan-tuhan mereka hingga tinggal orang-orang yang menyembah Allah, entah baik atau durhaka dan ahli kitab terdahulu. Kemudian jahannam didatangkan dan dipasang, ia seolah-olah fatamorgana, lantas orang-orang yahudi ditanya, \"Apa yang dahulu kalian sembah?\" Mereka menjawab, \"Kami dahulu menyembah Uzair anak Allah.\" Lalu ada suara, \"Kalian dusta! Allah sama sekali tidak mempunyai isteri dan tidak pula anak.\" Lalu apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin jika Engkau memberi kami minuman!\" Lantas ada suara, \"Minumlah kalian!\" Lalu mereka berjatuhan di neraka jahannam. Lantas orang-orang Nashara diseru, \"Apa yang kalian dahulu sembah?\" Mereka menjawab, \"Kami dahulu menyembah Isa al Masih, anak Anak Allah.\" Mereka dijawab, \"Kamu semua bohong! Allah sama sekali tidak mempunyai isteri atau bahkan anak, dan apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin agar Engkau memberi kami minuman!\" Lalu dijawab, \"Minumlah kalian!\" Dan langsung mereka berjatuhan di neraka jahannam hingga tersisa manusia yang menyembah Allah, entah yang baik atau berbuat durhaka. Mereka ditanya, \"Apa yang menyebabkan kalian tertahan padahal manusia lainnya sudah pergi?\" Mereka menjawab, \"Kami memisahkan diri dari mereka dan kami adalah manusia yang paling membutuhkan-Nya, kami dengar ada seorang juru seru menyerukan diri, \"Hendaklah setiap kaum menemui yang mereka sembah! Hanyasanya kami menunggu-nunggu Tuhan kami.\" Beliau melanjutkan, \"Lantas Allah (Al jabbar) mendatangi mereka dengan bentuk yang belum pernah mereka lihat pertama kali, lalu Allah firmankan: 'Akulah Tuhan kalian.' Mereka menjawab, 'Engkau adalah rabb kami, dan tidak ada yang berani mengajak-Nya bicara selain para nabi shallallahu 'alaihi wasallam, lantas para nabi berkata, 'Bukankah di antara kalian dan Allah ada tanda yang kalian mengenalnya? ' Mereka menjawab, 'Ya, yaitu betis, ' maka Allah pun menyingkap betis-Nya sehingga setiap mukmin bersujud kepada-Nya. Lalu tersisalah orang-orang yang sujud kepada Allah karena riya dan sum'ah sehingga ia pergi sujud dan punggungnya kembali menjadi satu bagian, kemudian titian (jembatan) jahannam didatangkan dan dipasang antara dua tepi jahannam, kami bertanya, 'Wahai Rasulullah, memang jembatan jahannam tersebut misterinya apa? ' Nabi menjawab: 'Jembatan itu bisa menggelincirkan, menjatuhkan, ada pengait-pengait besi, ada duri-duri yang lebar dan tajam, durinya besok yang terbuat dari kayu berduri namanya Sa'dan (kayu berduri tajam). Orang mukmin yang melewatinya sedemikian cepat, ada yang bagaikan kedipan mata, ada yang bagaikan kilat, ada yang bagaikan angin, dan ada yang bagaikan kuda pilihan. Ada yang bagaikan kuda tunggangan, ada yang selamat dengan betul-betul terselamatkan, namun ada juga yang selamat setelah tercabik-cabik oleh besi-besi pengait itu, atau terlempar karenanya di neraka jahannam, hingga manusia terakhir kali melewati dengan diseret seret, dan kalian tidak bisa sedemikian gigihnya menyumpahiku terhadap kebenaran yang jelas bagi kalian daripada terhadap seorang mukmin ketika itu kepada Allah Al Jabbar. Jika mereka melihat bahwasanya mereka telah selamat di kalangan teman-teman mereka, mereka berkata, 'Ya Tuhan kami, sesungguhnya kawan-kawan kami mendirikn shalat bersama kami dan berpuasa bersama kami, dan beramal bersama kami! ' Allah Ta'ala berfirman, 'Pergilah kalian, siapa diantara kalian dapatkan dalam hatinya masih ada seberat dinar keimanan, maka keluarkanlah dia', dan Allah mengharamkan bentuk mereka dalam neraka. Maka mereka datangi kawan-kawan mereka sedang sebagian mereka telah terendam dalam neraka ada yang sampai telapak kakinya, setengah betisnya, sehingga mereka keluarkan siapa saja yang mereka, kemudian mereka kembali dan Allah berkata, 'Pergilah kalian sekali lagi, dan siapa yang kalian temukan dalam hatinya seberat atom keimanan, maka keluarkanlah dia.' Maka mereka keluarkan siapa saja yang mereka kenal.\" Rasulullah berkata: 'Jika kalian tidak mempercayaiku, maka bacalah: '(Allah tidak menzhalimi seberat biji sawi pun, jika ada kebaikan, maka Allah melipatgandakan balasannya) ' (Qs. An nisaa': 40), maka para nabi shallallahu 'alaihi wasallam, malaikat dan orang-orang yang beriman, kesemuanya memberi syafaat. Kemudian Allah Al Jabbar berkata, syafaat-Ku masih ada. Lantas Allah menggenggam segenggam dari neraka dan mengentaskan beberapa kaum yang mereka telah terbakar, lantas mereka dilempar ke sebuah sungai di pintu surga yang namanya 'Sungai kehidupan' sehingga mereka tumbuh dalam kedua tepinya sebagaimana biji-bijian tumbuh dalam genangan sungai yang kalian sering melihatnya di samping batu karang dan samping pohon, apa yang diantaranya condong kepada matahari, maka berwarna hijau, dan apa yang diantaranya condong kepada bayangan, maka berwarna putih, lantas mereka muncul seolah-olah mutiara dan dalam tengkuk mereka terdapat cincin-cincin. Mereka kemudian masuk surga hingga penghuni surga berkata, 'Mereka adalah 'utaqa' Ar Rahman (orang-orang yang dibebaskan Arrahman), Allah memasukkan mereka bukan karena amal yang mereka lakukan, dan bukan pula karena kebaikan yang mereka persembahkan sehingga mereka memperoleh jawaban 'Bagimu yang kau lihat dan semisalnya'.\" [Hajjaj bin Minhal] berkata; telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dari [Anas] radliyallahu'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: 'Pada hari kiamat nanti orang-orang mukmin ditahan hingga yang demikian menjadikan mereka sedih. Mereka katakan, 'Duh, sekiranya kita meminta syafaat kepada Tuhan kami sehingga Dia menjadikan kita merasa nyaman dari tempat kita ini.' Mereka pun mendatangi Adam dan berkata, 'Engkau hai Adam, Engkau adalah nenek moyang seluruh manusia, Allah menciptamu dengan tangan-Nya, menjadikan surga sebagai tempat hunianmu dan menjadikan malaikat bertunduk sujud kepadamu, Allah juga mengajarimu nama-nama segala sesuatu agar engkau bisa memberi syafaat kepada kami disisi Tuhanmu sehingga engkau bisa memberi kenyamanan di tempat kami ini. Namun Adam hanya menjawab, 'Disini saya tak berhak memberi syafaat untuk kalian'.\" Rasulullah melanjutkan: \"Lantas Adam mengingatkan kesalahan yang pernah dilakukannya, yaitu memakan pohon larangan padahal telah dilarang, dan ia katakan 'Coba kalian datangi Nuh, sebab ia adalah nabi shallallahu 'alaihi wasallam pertama-tama yang Allah utus kepada penduduk bumi.' Mereka pun mendatangi Nuh, namun Nuh juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', dan Nuh menyebutkan kesalahan yang pernah dilakukannya, yaitu bertanya kepada Rabbnya dengan tanpa ilmu sambil ia katakan, 'Cobalah kalian datangi Ibrahim, sebab ia adalah Khalilurrahman (kekasih Arrahman).\" Rasulullah melanjutkan lagi kisahnya: \"Mereka pun mendatangi Ibrahim, hanya Ibrahim juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', Ibrahim lantas menyebutkan kesalahannya, yaitu tiga kebohongan yang pernah dilakukannya sambil berkata, 'Cobalah kalian datangi Musa, seorang hamba yang Allah memberinya taurat, mengajaknya bicara dan mendekatkannya kepada-Nya sedekat-dekatnya'.\" Rasulullah lanjutkan: \"Mereka pun mendatangi Musa, hanya Musa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil Musa mengingatkan kesalahan yang pernah dilakukannya, yaitu membunuh jiwa tanpa alasan yang dibenarkan, sambil ia katakan, 'Coba kalian datangi Isa, seorang hamba Allah dan rasul-Nya, ruh Allah dan kalimah-Nya. Merekapun mendatangi Isa, namun 'Isa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil ia katakan 'Cobalah kalian datangi Muhammad Shallallahu'alaihiwasallam, seorang hamba yang Allah telah mengampuni dosanya yang terdahulu dan yang akan datang.' Lantas mereka mendatangi aku (Muhammad) dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud, Allah lalu membiarkan aku sekehendak Dia membiarkaku. Allah lantas berkata, 'Angkat kepalamu hai Muhammad, katakanlah, engkau didengar, mintailah syafaat, engkau diberi syafaat, mintalah, engkau diberi.' Aku lalu angkat kepalaku dan aku memuji Tuhanku dengan pujian yang Ia ajarkannya kepadaku, kemudian aku memberi syafaat dan Dia memberiku batasan. Kemudian aku keluar dan memasukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku juga mendengarnya menyebutkan, \"Aku lalu keluar, kemudian aku keluarkan mereka dari neraka dan kumasukkan ke dalam surga. Setelah itu aku kembali untuk kali kedua dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan untuk menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud. Allah lantas membiarkanku sekehendak Allah membiarkan, kemudian Allah berkata, 'Angkatlah kepalamu hai Muhammad dan katakanlah engkau akan didengar, dan berilah syafaat engkau akan diberi syafaat, dan mintalah engkau akan diberi.' Aku lalu angkat kepalaku dan memanjatkan pujian dan pujaan terhadap tuhanku sebagaimana yang diajakrkan-Nya kepadaku. Kemudian aku memberi syafaat, dan Ia memberiku batasan sehingga aku keluar dan aku masukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, \"Dan aku berangkat sehingga aku keluarkan mereka dari neraka, lalu mereka aku masukkan ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, 'Maka aku berangkat dan aku keluarkan mereka dari neraka, untuk kemudian aku masukkan mereka ke dalam surga, hingga tidak tersisa dalam neraka selain yang digi ditahan oleh alquran, atau maksudnya ia wajib abadi, kemudian beliau membaca ayat ini '(semoga Tuhanmu membangkitkankmu di tempat yang terpuji) ' (Qs. Al Isra': 79). Nabi mengatakan, \"Inilah maqam terpuji yang dijanjikan untuk nabi shallallahu 'alaihi wasallam kalian.\""},{"p":"Muslim","n":266,"ar":"و حَدَّثَنِي سُوَيْدُ بْنُ سَعِيدٍ قَالَ حَدَّثَنِي حَفْصُ بْنُ مَيْسَرَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ نَاسًا فِي زَمَنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ قَالَ هَلْ تُضَارُّونَ فِي رُؤْيَةِ الشَّمْسِ بِالظَّهِيرَةِ صَحْوًا لَيْسَ مَعَهَا سَحَابٌ وَهَلْ تُضَارُّونَ فِي رُؤْيَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ صَحْوًا لَيْسَ فِيهَا سَحَابٌ قَالُوا لَا يَا رَسُولَ اللَّهِ قَالَ مَا تُضَارُّونَ فِي رُؤْيَةِ اللَّهِ تَبَارَكَ وَتَعَالَى يَوْمَ الْقِيَامَةِ إِلَّا كَمَا تُضَارُّونَ فِي رُؤْيَةِ أَحَدِهِمَا إِذَا كَانَ يَوْمُ الْقِيَامَةِ أَذَّنَ مُؤَذِّنٌ لِيَتَّبِعْ كُلُّ أُمَّةٍ مَا كَانَتْ تَعْبُدُ فَلَا يَبْقَى أَحَدٌ كَانَ يَعْبُدُ غَيْرَ اللَّهِ سُبْحَانَهُ مِنْ الْأَصْنَامِ وَالْأَنْصَابِ إِلَّا يَتَسَاقَطُونَ فِي النَّارِ حَتَّى إِذَا لَمْ يَبْقَ إِلَّا مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ وَفَاجِرٍ وَغُبَّرِ أَهْلِ الْكِتَابِ فَيُدْعَى الْيَهُودُ فَيُقَالُ لَهُمْ مَا كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ عُزَيْرَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ مَا اتَّخَذَ اللَّهُ مِنْ صَاحِبَةٍ وَلَا وَلَدٍ فَمَاذَا تَبْغُونَ قَالُوا عَطِشْنَا يَا رَبَّنَا فَاسْقِنَا فَيُشَارُ إِلَيْهِمْ أَلَا تَرِدُونَ فَيُحْشَرُونَ إِلَى النَّارِ كَأَنَّهَا سَرَابٌ يَحْطِمُ بَعْضُهَا بَعْضًا فَيَتَسَاقَطُونَ فِي النَّارِ ثُمَّ يُدْعَى النَّصَارَى فَيُقَالُ لَهُمْ مَا كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ الْمَسِيحَ ابْنَ اللَّهِ فَيُقَالُ لَهُمْ كَذَبْتُمْ مَا اتَّخَذَ اللَّهُ مِنْ صَاحِبَةٍ وَلَا وَلَدٍ فَيُقَالُ لَهُمْ مَاذَا تَبْغُونَ فَيَقُولُونَ عَطِشْنَا يَا رَبَّنَا فَاسْقِنَا قَالَ فَيُشَارُ إِلَيْهِمْ أَلَا تَرِدُونَ فَيُحْشَرُونَ إِلَى جَهَنَّمَ كَأَنَّهَا سَرَابٌ يَحْطِمُ بَعْضُهَا بَعْضًا فَيَتَسَاقَطُونَ فِي النَّارِ حَتَّى إِذَا لَمْ يَبْقَ إِلَّا مَنْ كَانَ يَعْبُدُ اللَّهَ تَعَالَى مِنْ بَرٍّ وَفَاجِرٍ أَتَاهُمْ رَبُّ الْعَالَمِينَ سُبْحَانَهُ وَتَعَالَى فِي أَدْنَى صُورَةٍ مِنْ الَّتِي رَأَوْهُ فِيهَا قَالَ فَمَا تَنْتَظِرُونَ تَتْبَعُ كُلُّ أُمَّةٍ مَا كَانَتْ تَعْبُدُ قَالُوا يَا رَبَّنَا فَارَقْنَا النَّاسَ فِي الدُّنْيَا أَفْقَرَ مَا كُنَّا إِلَيْهِمْ وَلَمْ نُصَاحِبْهُمْ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ نَعُوذُ بِاللَّهِ مِنْكَ لَا نُشْرِكُ بِاللَّهِ شَيْئًا مَرَّتَيْنِ أَوْ ثَلَاثًا حَتَّى إِنَّ بَعْضَهُمْ لَيَكَادُ أَنْ يَنْقَلِبَ فَيَقُولُ هَلْ بَيْنَكُمْ وَبَيْنَهُ آيَةٌ فَتَعْرِفُونَهُ بِهَا فَيَقُولُونَ نَعَمْ فَيُكْشَفُ عَنْ سَاقٍ فَلَا يَبْقَى مَنْ كَانَ يَسْجُدُ لِلَّهِ مِنْ تِلْقَاءِ نَفْسِهِ إِلَّا أَذِنَ اللَّهُ لَهُ بِالسُّجُودِ وَلَا يَبْقَى مَنْ كَانَ يَسْجُدُ اتِّقَاءً وَرِيَاءً إِلَّا جَعَلَ اللَّهُ ظَهْرَهُ طَبَقَةً وَاحِدَةً كُلَّمَا أَرَادَ أَنْ يَسْجُدَ خَرَّ عَلَى قَفَاهُ ثُمَّ يَرْفَعُونَ رُءُوسَهُمْ وَقَدْ تَحَوَّلَ فِي صُورَتِهِ الَّتِي رَأَوْهُ فِيهَا أَوَّلَ مَرَّةٍ فَقَالَ أَنَا رَبُّكُمْ فَيَقُولُونَ أَنْتَ رَبُّنَا ثُمَّ يُضْرَبُ الْجِسْرُ عَلَى جَهَنَّمَ وَتَحِلُّ الشَّفَاعَةُ وَيَقُولُونَ اللَّهُمَّ سَلِّمْ سَلِّمْ قِيلَ يَا رَسُولَ اللَّهِ وَمَا الْجِسْرُ قَالَ دَحْضٌ مَزِلَّةٌ فِيهِ خَطَاطِيفُ وَكَلَالِيبُ وَحَسَكٌ تَكُونُ بِنَجْدٍ فِيهَا شُوَيْكَةٌ يُقَالُ لَهَا السَّعْدَانُ فَيَمُرُّ الْمُؤْمِنُونَ كَطَرْفِ الْعَيْنِ وَكَالْبَرْقِ وَكَالرِّيحِ وَكَالطَّيْرِ وَكَأَجَاوِيدِ الْخَيْلِ وَالرِّكَابِ فَنَاجٍ مُسَلَّمٌ وَمَخْدُوشٌ مُرْسَلٌ وَمَكْدُوسٌ فِي نَارِ جَهَنَّمَ حَتَّى إِذَا خَلَصَ الْمُؤْمِنُونَ مِنْ النَّارِ فَوَالَّذِي نَفْسِي بِيَدِهِ مَا مِنْكُمْ مِنْ أَحَدٍ بِأَشَدَّ مُنَاشَدَةً لِلَّهِ فِي اسْتِقْصَاءِ الْحَقِّ مِنْ الْمُؤْمِنِينَ لِلَّهِ يَوْمَ الْقِيَامَةِ لِإِخْوَانِهِمْ الَّذِينَ فِي النَّارِ يَقُولُونَ رَبَّنَا كَانُوا يَصُومُونَ مَعَنَا وَيُصَلُّونَ وَيَحُجُّونَ فَيُقَالُ لَهُمْ أَخْرِجُوا مَنْ عَرَفْتُمْ فَتُحَرَّمُ صُوَرُهُمْ عَلَى النَّارِ فَيُخْرِجُونَ خَلْقًا كَثِيرًا قَدْ أَخَذَتْ النَّارُ إِلَى نِصْفِ سَاقَيْهِ وَإِلَى رُكْبَتَيْهِ ثُمَّ يَقُولُونَ رَبَّنَا مَا بَقِيَ فِيهَا أَحَدٌ مِمَّنْ أَمَرْتَنَا بِهِ فَيَقُولُ ارْجِعُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ دِينَارٍ مِنْ خَيْرٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ خَلْقًا كَثِيرًا ثُمَّ يَقُولُونَ رَبَّنَا لَمْ نَذَرْ فِيهَا أَحَدًا مِمَّنْ أَمَرْتَنَا ثُمَّ يَقُولُ ارْجِعُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ نِصْفِ دِينَارٍ مِنْ خَيْرٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ خَلْقًا كَثِيرًا ثُمَّ يَقُولُونَ رَبَّنَا لَمْ نَذَرْ فِيهَا مِمَّنْ أَمَرْ��َنَا أَحَدًا ثُمَّ يَقُولُ ارْجِعُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ ذَرَّةٍ مِنْ خَيْرٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ خَلْقًا كَثِيرًا ثُمَّ يَقُولُونَ رَبَّنَا لَمْ نَذَرْ فِيهَا خَيْرًا وَكَانَ أَبُو سَعِيدٍ الْخُدْرِيُّ يَقُولُ إِنْ لَمْ تُصَدِّقُونِي بِهَذَا الْحَدِيثِ فَاقْرَءُوا إِنْ شِئْتُمْ{ إِنَّ اللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍ وَإِنْ تَكُ حَسَنَةً يُضَاعِفْهَا وَيُؤْتِ مِنْ لَدُنْهُ أَجْرًا عَظِيمًا }فَيَقُولُ اللَّهُ عَزَّ وَجَلَّ شَفَعَتْ الْمَلَائِكَةُ وَشَفَعَ النَّبِيُّونَ وَشَفَعَ الْمُؤْمِنُونَ وَلَمْ يَبْقَ إِلَّا أَرْحَمُ الرَّاحِمِينَ فَيَقْبِضُ قَبْضَةً مِنْ النَّارِ فَيُخْرِجُ مِنْهَا قَوْمًا لَمْ يَعْمَلُوا خَيْرًا قَطُّ قَدْ عَادُوا حُمَمًا فَيُلْقِيهِمْ فِي نَهَرٍ فِي أَفْوَاهِ الْجَنَّةِ يُقَالُ لَهُ نَهَرُ الْحَيَاةِ فَيَخْرُجُونَ كَمَا تَخْرُجُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ أَلَا تَرَوْنَهَا تَكُونُ إِلَى الْحَجَرِ أَوْ إِلَى الشَّجَرِ مَا يَكُونُ إِلَى الشَّمْسِ أُصَيْفِرُ وَأُخَيْضِرُ وَمَا يَكُونُ مِنْهَا إِلَى الظِّلِّ يَكُونُ أَبْيَضَ فَقَالُوا يَا رَسُولَ اللَّهِ كَأَنَّكَ كُنْتَ تَرْعَى بِالْبَادِيَةِ قَالَ فَيَخْرُجُونَ كَاللُّؤْلُؤِ فِي رِقَابِهِمْ الْخَوَاتِمُ يَعْرِفُهُمْ أَهْلُ الْجَنَّةِ هَؤُلَاءِ عُتَقَاءُ اللَّهِ الَّذِينَ أَدْخَلَهُمْ اللَّهُ الْجَنَّةَ بِغَيْرِ عَمَلٍ عَمِلُوهُ وَلَا خَيْرٍ قَدَّمُوهُ ثُمَّ يَقُولُ ادْخُلُوا الْجَنَّةَ فَمَا رَأَيْتُمُوهُ فَهُوَ لَكُمْ فَيَقُولُونَ رَبَّنَا أَعْطَيْتَنَا مَا لَمْ تُعْطِ أَحَدًا مِنْ الْعَالَمِينَ فَيَقُولُ لَكُمْ عِنْدِي أَفْضَلُ مِنْ هَذَا فَيَقُولُونَ يَا رَبَّنَا أَيُّ شَيْءٍ أَفْضَلُ مِنْ هَذَا فَيَقُولُ رِضَايَ فَلَا أَسْخَطُ عَلَيْكُمْ بَعْدَهُ أَبَدًاقَالَ مُسْلِم قَرَأْتُ عَلَى عِيسَى بْنِ حَمَّادٍ زُغْبَةَ الْمِصْرِيِّ هَذَا الْحَدِيثَ فِي الشَّفَاعَةِ وَقُلْتُ لَهُ أُحَدِّثُ بِهَذَا الْحَدِيثِ عَنْكَ أَنَّكَ سَمِعْتَ مِنَ اللَّيْثِ بْنِ سَعْدٍ فَقَالَ نَعَمْ قُلْتُ لِعِيسَى بْنِ حَمَّادٍ أَخْبَرَكُمُ اللَّيْثُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ أَنَرَى رَبَّنَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ تُضَارُّونَ فِي رُؤْيَةِ الشَّمْسِ إِذَا كَانَ يَوْمٌ صَحْوٌ قُلْنَا لَا وَسُقْتُ الْحَدِيثَ حَتَّى انْقَضَى آخِرُهُ وَهُوَ نَحْوُ حَدِيثِ حَفْصِ بْنِ مَيْسَرَةَ وَزَادَ بَعْدَ قَوْلِهِ بِغَيْرِ عَمَلٍ عَمِلُوهُ وَلَا قَدَمٍ قَدَّمُوهُ فَيُقَالُ لَهُمْ لَكُمْ مَا رَأَيْتُمْ وَمِثْلُهُ مَعَهُ قَالَ أَبُو سَعِيدٍ بَلَغَنِي أَنَّ الْجِسْرَ أَدَقُّ مِنْ الشَّعْرَةِ وَأَحَدُّ مِنْ السَّيْفِ وَلَيْسَ فِي حَدِيثِ اللَّيْثِ فَيَقُولُونَ رَبَّنَا أَعْطَيْتَنَا مَا لَمْ تُعْطِ أَحَدًا مِنْ الْعَالَمِينَ وَمَا بَعْدَهُ فَأَقَرَّ بِهِ عِيسَى بْنُ حَمَّادٍ و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ بِإِسْنَادِهِمَا نَحْوَ حَدِيثِ حَفْصِ بْنِ مَيْسَرَةَ إِلَى آخِرِهِ وَقَدْ زَادَ وَنَقَصَ شَيْئًا","trj":"Dan telah menceritakan kepadaku [Suwaid bin Sa'id] dia berkata, telah menceritakan kepadaku [Hafsh bin maisarah] dari [Zaid bin Aslam] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudri] bahwa sekelompok manusia pada zaman Rasulullah shallallahu 'alaihi wasallam bertanya, 'Wahai Rasulullah! Apakah kami melihat Rabb kami pada Hari Kiamat?\" Beliau menjawab, \"Apakah kalian berdesak-desakan dalam melihat matahari di siang hari yang terang tanpa awan?\" Mereka menjawab, \"Tidak wahai Rasulullah.\" Beliau pun berkata, \"Apakah kalian berdesak-desakan dalam melihat bulan di malam purnama yang tidak ada awannya?\" Mereka menjawab, \"Tidak.\" Lalu beliau bersabda: \"Tidaklah kalian berdesak-desakan dalam melihat Rabb kalian, melainkan sebagaimana kalian (tidak) berdesak-desakan dalam melihat salah satu dari keduanya. Pada hari kiamat, seorang penyeru akan menyerukan 'Hendaklah setiap umat mengikuti sesuatu yang dahulu mereka sembah', hingga tidaklah ada seorang pun yang menyembah selain Allah berupa berhala, dan patung melainkan mereka akan terjerumus ke dalam neraka, hingga tidak ada yang tersisa seorang pun kecuali orang yang menyembah Allah; baik itu orang yang baik dan buruk, dan sisa Ahli Kitab, lalu orang Yahudi dipanggil dan ditanyakan kepada mereka, 'Apa yang dahulu kalian sembah? ' Mereka menjawab, 'Kami dahulu menyembah Uzair, putera Allah.' Maka dikatakan, 'Kalian telah berdusta, Allah tidak menjadikan isteri dan anak. Lalu apa yang kalian inginkan? ' Mereka menjawab, 'Kami haus wahai Rabb kami, maka berilah kami minum.' Lalu mereka diberi isyarat pada sesuatu yang membuat mereka hilang dahaganya, mereka kemudian digiring hingga ke neraka, seakan-akan fatamorgana, sebagian memukul sebagian yang lain, lalu mereka terjerumus ke dalam neraka.' Kemudian kaum Nashrani dipanggil, lalu mereka ditanya, 'Apa yang dahulu kalian sembah? ' mereka menjawab, 'Kami dahulu menyembah al-Masih, putera Allah.' Lalu dikatakan kepada mereka, 'Kalian telah berbohong. Allah tidak mengambil istri dan anak.' Maka dikatakan kepada mereka, 'Apa yang kalian inginkan? ' Mereka menjawab, 'Kami haus wahai Rabb kami, berilah kami minum.' Beliau bersabda: \"Lalu diisyaratkan kepada mereka. 'Tidakkah kalian minum.' dan mereka dikumpulkan di neraka Jahannam, seakan-akan neraka tersebut fatamorgana yang mana sebagian mereka memukul sebagian yang lain, lalu jatuh ke dalam neraka, hingga tidak tersisa melainkan orang yang menyembah Allah dari kalangan orang baik dan orang fajir. Allah lalu mendatangi mereka dalam bentuk yang paling ringan yang dapat mereka lihat. Allah berfirman; “apa yang kalian tunggu, padahal setiap umat mengikuti apa yang mereka sembah?.” Mereka berkata; “wahai Rabb kami, kami memisahkan diri dari manusia di dunia ketika kami membutuhkan apa yang kami butuhkan kepada mereka, akan tetapi kami tidak berteman dengan mereka.” Maka Allah berfirman; “aku adalah rabb kalian.” Maka mereka berkata; “aku berlindung kepada Allah dari-Mu, kami tidak akan menyekutukan Allah dengan sesuatupun.” Mereka ucapakan dua kalia atau tiga kali, sehingga sebagian mereka hampir-hampir berbalik, maka Allah bertanya; “apakah diantara kalian dan Dia mempunyai tanda-tanda, yang dapat kalian kenal dengan tanda-tanda itu?” mereka menjawab; “ya” maka di singkaplah betis-Nya, sehingga tidak tersisa orang yang sebelumnya bersujud kepada Allah dari dalam dirinya (ikhlas) kecuali Allah izinkan baginya untuk bersujud. Dan tidak tersisa orang yang sebelumnya bersujud karena ego dan riya` kecuali Allah jadikan punggungnya menjadi satu lipatan, setiap kali hendak bersujud maka dia tersungkur diatas tengkuknya. Kemudian mereka mengangkat kepala  mereka dan Allah telah berubah ke bentuk yang dapat mereka lihat pertama kalinya, Allah berfirman:v “aku adalah Rabb kalian.” Maka mereka berkata; “Engkau Rabb kami.” Kemudian di bentangkan jembatan di atas Jahannam, dan berlakulah syafa'at pada saat itu, mereka berguman; “ya Allah, selamatkanlah, selamatkanlah.” Ada yang bertanya; 'wahai Rasulullah, apakah jembatan itu?” beliau menjawab; “tempat yang licin yang dapat menggelincirkan, disana terdapat besi-besi pencakar, besi-besi pengait dan duri besi yang terbuat dari pohon-pohon berduri. Maka orang-orang mu'min akan melewatinya seperti kedipan mata, seperti kilat, seperti angin, seperti burung, seperti kuda-kuda yang berlari kencang, dan hewan tunggangan. Maka orang muslim akan ada yang selamat, ada yang tercabik-cabik tertunda dan ada yang terlempar kedalam neraka jahannam. Sehingga ketika orang-orang mu'min terbebas dari neraka, maka demi Dzat yang jiwaku berada ditangan-Nya, tidaklah salah seorang dari kalian yang begitu gigih memohon kepada Allah didalam menuntut al haq  pada hari kiamat untuk saudara-saudaranya yang berada di dalam neraka, mereka berseru; wahai rabb kami, mereka selalu berpuasa bersama kami, salat bersama kami, dan berhaji bersama kami.” Maka dikatakan kepada mereka; “keluarkanlah orang-orang yang kalian ketahui.” Maka bentuk-bentuk mereka hitam kelam karena terpanggang api neraka, kemudian mereka mengeluarkan begitu banyak orang yang telah di makan neraka sampai pada pertengahan betisnya dan sampai kedua lututnya. Kemudian mereka berkata; “ wahai rabb kami tidak tersisa lagi seseorang pun yang telah engkau perintahkan kepada kami.” Kemudian Allah berfirman; “kembalilah kalian, maka barangsiapa yang kalian temukan didalam hatinya kebaikan seberat dinar, maka keluarkanlah dia.” Mereka pun mengeluarkan jumlah yang begitu banyak, kemudian mereka berkata; “wahai rabb kami, kami tidak meninggalkan di dalamnya seorangpun yang telah Engkau perintahkan kepada kami.” Kemudian Allah berfirman; “kembalilah kalian, maka barangsiapa yang kalian temukan didalam hatinya kebaikan seberat setengah dinar, maka keluarkanlah dia.” Maka mereka pun mengeluarkan jumlah yang banyak. Kemudian mereka berkata lagi; “wahai Rabb kami, kami tidak menyisakan di dalamnya seorang pun yang telah Engkau perintahkan kepada kami.” Kemudian Allah berfirman; “kembalilah kalian, maka siapa saja yang kalian temukan didalam hatinya kebaikan seberat biji jagung, keluarkanlah.” Maka merekapun kembali mengeluarkan jumlah yang begitu banyak. Kemudian mereka berkata; “wahai Rabb kami, kami tidak menyisakan di dalamnya kebaikan sama sekali.” Abu Sa'id al Khudri berkata, \"Jika kalian tidak mempercayai hadits ini silahkan kalian baca ayat: (Sesungguhnya Allah tidak menganiaya seseorang walaupun sebesar zarrah, dan jika ada kebajikan sebesar zarrah, niscaya Allah akan melipat gandakannya dan memberikan dari sisi-Nya pahala yang besar.) (Qs. An Nisa: 40). Allah lantas berfirman: \"Para Malaikat, Nabi dan orang-orang yang beriman telah memberi syafaat, sekarang yang belum memberikan syafaat adalah Dzat Yang Maha Pengasih.\" Kemudian Allah menggenggam satu genggaman dari dalam neraka, dari dalam tersebut Allah mengeluarkan suatu kaum yang sama sekali tidak melakukan kebaikan, dan mereka pun sudah berbentuk seperti arang hitam. Allah kemudian melemparkan mereka ke dalam sungai di depan surga yang disebut dengan sungai kehidupan. Mereka kemudian keluar dari dalam sungai layaknya biji yang tumbuh di aliran sungai, tidakkah kalian lihat ia tumbuh (merambat) di bebatuan atau pepohonan mengejar (sinar) matahari. Kemudian mereka (yang tumbuh layaknya biji) ada yang berwarna kekuningan dan kehijauan, sementara yang berada di bawah bayangan akan berwarna putih.\" Para sahabat kemudian bertanya, \"Seakan-akan baginda sedang menggembala di daerah orang-orang badui?' Beliau melanjutkan: \"Mereka kemudian keluar seperti mutiara, sementara di lutut-lutut mereka terdapat cincin yang bisa diketahui oleh penduduk surga. Dan mereka adalah orang-orang yang Allah merdekakan dan Allah masukkan ke dalam surga tanpa dengan amalan dan kebaikan sama sekali. Allah kemudian berkata: \"Masuklah kalian ke dalam surga. Apa yang kalian lihat maka itu akan kalian miliki.\" Mereka pun menjawab, \"Wahai Rabb kami, sungguh Engkau telah memberikan kepada kami sesuatu yang belum pernah Engkau berikan kepada seorang pun dari penduduk bumi.\" Allah kemudian berkata: \"(Bahkan) apa yang telah Kami siapkan untuk kalian lebih baik dari ini semua.\" Mereka kembali berkata, \"Wahai Rabb, apa yang lebih baik dari ini semua!\" Allah menjawab: \"Ridla-Ku, selamanya Aku tidak akan pernah murka kepada kalian.\" Muslim berkata, \"Aku membacakan hadits ini di hadapan [Isa bin Hammad Zughbah al Mishri] berkenaan dengan syafaat. Aku katakan kepadanya, \"Aku sampaikan hadits ini darimu, bahwa engkau pernah mendengar dari [Laits bin Sa'd] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Zaid bin Aslam] dari [Atha bin Yasar] dari [Abu Sa'id Al Khudri] bahwasanya ia berkata, \"Wahai Rasulullah, apakah kami akan melihat Rabb kami?\" Rasulullah Shallallahu 'alaihi wa Sallam balik bertanya: \"Apakah kalian mendapatkan bahaya dalam melihat matahari di hari yang cerah?\" kami menjawab; 'Tidak.\" Kemudian aku melanjutkan hadits tersebut hingga selesai. Dan hadits tersebut semisal hadits Hafsh bin Maisarah.\" Dan ia menambahkan setelah perkataannya, \"tanpa dengan amalan dan kebaikan sama sekali.\" Kemudian dikatakan kepada mereka, \"Bagi kalian apa yang kalian lihat dan seperti itu bersamanya.\" Abu Sa'id berkata, \"telah sampai kepadaku bahwa jembatan lebih kecil dari rambut dan lebih tajam dari pedang.\"  Dan dalam hadits Laits tidak ada redaksi: \"Mereka berkata, 'Wahai rabb kami, engkau telah memberikan kepada kami sesuatu yang tidak diberikan kepada seorang pun di atas alam.\" Dan kalimat setelahnya. Dan Isa bin Hammad menyepakatinya.\" Telah menceritakannya kepada kami [Abu bakar bin Abu Syaibah] telah menceritakan kepada kami [Ja'far bin Aun] telah menceritakan kepada kami [Hisyam bin Sa'd] telah menceritakan kepada kami [Zaid bin Aslam] sama dengan isnad keduanya seperti hadits Hafsh bin Maisarah, sampai kepada kalimat yang terakhir, dan di sana terdapat penambahan dan pengurangan.\""}],"4:41":[{"p":"Abu Dawud","n":3105,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ سُورَةَ النِّسَاءِ قَالَ قُلْتُ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أُحِبُّ أَنْ أَسْمَعَهُ مِنْ غَيْرِي قَالَ فَقَرَأْتُ عَلَيْهِ حَتَّى إِذَا انْتَهَيْتُ إِلَى قَوْلِهِ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ }الْآيَةَ فَرَفَعْتُ رَأْسِي فَإِذَا عَيْنَاهُ تَهْمِلَانِ","trj":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al A'masy] dari [Ibrahim] dari ['Abidah] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Bacakan kepadaku Surat An Nisa!\" Aku katakan, \"Apakah aku akan membacakan kepadamu sementara Al Qur'an turun kepadamu?\" Beliau bersabda: \"Aku senang untuk mendengarnya dari selainku.\" Abdullah berkata, \"Kemudian aku membacakan Al Qur'an kepadanya hingga sampai pada firman-Nya: '(Maka bagaimanakah (halnya orang kafir nanti), apabila Kami mendatangkan seseorang saksi (rasul) …) ' (Qs. An Nisa: 41) Kemudian aku angkat kepalaku dan ternyata kedua mata beliau telah berurai dengan air mata.\""},{"p":"Abu Dawud","n":3108,"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ عَلَيْهِ السَّلَامأَنَّ رَجُلًا مِنْ الْأَنْصَارِ دَعَاهُ وَعَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ فَسَقَاهُمَا قَبْلَ أَنْ تُحَرَّمَ الْخَمْرُ فَأَمَّهُمْ عَلِيٌّ فِي الْمَغْرِبِ فَقَرَأَ قُلْ يَا أَيُّهَا الْكَافِرُونَ فَخَلَطَ فِيهَا فَنَزَلَتْ{ لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى حَتَّى تَعْلَمُوا مَا تَقُولُونَ }","trj":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepada kami ['Atha bin As Saib] dari [Abu Abdurrahman As Sulami] dari [Ali bin Abu Thalib] bahwa seorang laki-laki Anshar memanggil dirinya dan Abdurrahman bin 'Auf, lalu ia memberi mereka minum khamer sebelum khamer diharamkan. Setelah itu Ali mengimami mereka dalam Shalat Maghrib. Ketika ia membaca Surat Al Ikhlash dan terbolak-balik dalam membacanya, maka turunlah ayat: '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk, sehingga kamu mengerti apa yang kamu ucapkan…) ' (Qs. An Nisaa`: 41). "},{"p":"Abu Dawud","n":3109,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيِّ حَدَّثَنَا عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }وَ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ وَمَنَافِعُ لِلنَّاسِ }نَسَخَتْهُمَا الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا الْخَمْرُ وَالْمَيْسِرُ وَالْأَنْصَابُ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepada kami [Ali bin Husain] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia membaca: '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…) ' (Qs. An Nisaa`: 41). Dan ayat: '(Mereka bertanya kepadamu tentang khamer dan judi. Katakanlah: \"Pada keduanya terdapat dosa yang besar dan beberapa manfaat bagi manusia.....) ' (Qs. Al Baqarah: 219), ia berkata, \"Kedua ayat tersebut dihapus dan digantikan oleh ayat yang terdapat dalam Surat Al Maaidah: 91: '(Sesungguhnya (meminum) khamar, berjudi, (berkorban untuk) berhala…) '. "},{"p":"Ibnu Majah","n":4145,"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ فَقَرَأْتُ عَلَيْهِ بِسُورَةِ النِّسَاءِ حَتَّى إِذَا بَلَغْتُ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }فَنَظَرْتُ إِلَيْهِ فَإِذَا عَيْنَاهُ تَدْمَعَانِ","trj":"Telah menceritakan kepada kami [Al Hannad bin As Sarri] telah menceritakan kepada kami [Abu Al Ahwash] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah bersabda kepadaku: \"Bacakanlah (ayat) untukku! \" Maka saya membaca surat An Nisaa, ketika sampai ayat: '(Maka bagaimanakah (halnya orang kafir nanti), apabila kami mendatangkan seseorang saksi (rasul) dari tiap-tiap umat dan kami mendatangkan kamu (Muhammad) sebagai saksi atas mereka itu (sebagai umatmu) ' (Qs. An Nisaa: 41), maka saya melihat kedua air mata beliau meneteskan air mata.\""},{"p":"Tirmidzi","n":2837,"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ فَقُلْتُ يَا رَسُولَ اللَّهِ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أُحِبُّ أَنْ أَسْمَعَهُ مِنْ غَيْرِي فَقَرَأْتُ سُورَةَ النِّسَاءِ حَتَّى إِذَا بَلَغْتُ{ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }قَالَ فَرَأَيْتُ عَيْنَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَهْمِلَانِقَالَ أَبُو عِيسَى هَذَا أَصَحُّ مِنْ حَدِيثِ أَبِي الْأَحْوَصِ حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ نَحْوَ حَدِيثِ مُعَاوِيَةَ بْنِ هِشَامٍ","trj":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah menceritakan kepada kami [Sufyan Ats Tsauri] dari [Al A'masy] dari [Ibrahim] dari ['Abidah] dari [Abdullah] ia berkata; Rasulullah Shallallahu 'alahi wasallam bersabda kepadaku: \"Bacalah (al Qur'an) untukku.\" Aku menjawab; \"Wahai Rasulullah, haruskah aku membacanya, sementara (Al Qur'an) diturunkan kepadamu?\" beliau bersabda: \"Aku lebih senang mendengarnya dari orang lain.\" lalu kubaca surat an Nisa`, ketika sampai pada ayat Dan Kami mendatangkan kamu (Muhammad) sebagai saksi atas mereka itu (sebagai umatmu). QS An-Nisa`: 41, kulihat kedua matanya berlinang air mata.\" Abu Isa berkata; Hadits ini lebih shahih dari hadits Al Ahwash. Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengabarkan kepada kami [Ibnu Al Mubarak] dari [Sufyan] dari [Al A'masy] seperti hadits Mu'awiyah bin Hisyam."}],"4:43":[{"p":"Darimi","n":794,"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي مِجْلَزٍ عَنْ ابْنِ عَبَّاسٍ فِي قَوْلِهِ { وَلَا جُنُبًا إِلَّا عَابِرِي سَبِيلٍ } قَالَ هُوَ الْمُسَافِرُ","trj":"Telah mengabarkan kepada kami [Muslim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Abu Mijlaz] dari [Ibnu Abbas] tentang firman-Nya: '((jangan pula hampiri masjid) sedang ia dalam keadaan junub, kecuali sekedar berlalu saja) ' (Qs. An Nisa: 43), ia berkata: \"Yaitu musafir.\" "},{"p":"Darimi","n":796,"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ وَأَبُو نُعَيْمٍ عَنْ شَرِيكٍ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ أَبِي عُبَيْدَةَ قَالَ الْجُنُبُ يَمُرُّ فِي الْمَسْجِدِ وَلَا يَقْعُدُ فِيهِ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ { وَلَا جُنُبًا إِلَّا عَابِرِي سَبِيلٍ }","trj":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] dan [Abu Nu'aim] dari [Syarik] dari [Abdul Karim Al Jazari] dari [Abu 'Ubaidah] ia berkata, \"Orang yang sedang junub boleh melewati masjid, tetapi ia tidak boleh duduk di dalamnya.\" Kemudian ia membaca ayat ini: '(jangan pula hampiri masjid) sedang ia dalam keadaan junub, kecuali sekedar berlalu saja) ' (Qs. An Nisaa: 43)."},{"p":"Tirmidzi","n":2838,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدٍ عَنْ أَبِي جَعْفَرٍ الرَّازِيِّ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَصَنَعَ لَنَا عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ طَعَامًا فَدَعَانَا وَسَقَانَا مِنْ الْخَمْرِ فَأَخَذَتْ الْخَمْرُ مِنَّا وَحَضَرَتْ الصَّلَاةُ فَقَدَّمُونِي فَقَرَأْتُ قُلْ يَا أَيُّهَا الْكَافِرُونَ لَا أَعْبُدُ مَا تَعْبُدُونَ وَنَحْنُ نَعْبُدُ مَا تَعْبُدُونَ قَالَ فَأَنْزَلَ اللَّهُ تَعَالَى{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى حَتَّى تَعْلَمُوا مَا تَقُولُونَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Abdurahman bin Sa'd] dari [Abu Ja'far Ar Razi] dari [Atha` bin As Sa`ib] dari [Abu Abdurrahman As Sulami] dari [Ali bin Abu Thalib] ia berkata; \"Abdurrahman bin 'Auf pernah membuatkan makanan dan menyajikan khamr untuk kami, sampai kami (mabuk) karenanya. Ketika waktu shalat telah tiba, mereka mendorongku (menjadi imam), kemudian aku membaca; Katakanlah (Muhammad): Hai orang-orang kafir, aku tidak akan menyembah apa yang kalian sembah, dan kami akan menyembah apa yang kalian sembah.\" lalu Allah menurunkan (ayat): \"Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk, sehingga kamu mengerti apa yang kamu ucapkan.\" QS An-Nisa`: 43. Abu Isa mengatakan bahwa hadits ini hasan shahih gharib."},{"p":"Tirmidzi","n":2845,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ أَبِي مَيْسَرَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَاللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ }الْآيَةَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ ثُمَّ قَالَ اللَّهُمَّ بَيِّنَ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا يُرِيدُ الشَّيْطَانُ أَنْ يُوقِعَ بَيْنَكُمْ الْعَدَاوَةَ وَالْبَغْضَاءَ فِي الْخَمْرِ وَالْمَيْسِرِ إِلَى قَوْلِهِ فَهَلْ أَنْتُمْ مُنْتَهُونَ }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ انْتَهَيْنَا انْتَهَيْنَاقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ إِسْرَائِيلَ هَذَا الْحَدِيثُ مُرْسَلٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَمْرِو بْنِ شُرَحْبِيلَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَذَكَرَ نَحْوَهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ يُوسُفَ","trj":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Syurahbil Abu Maisarah] dari [Umar bin Al Khaththab] ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Baqarah; Mereka bertanya kepadamu tentang khamer dan judi. QS Al Baqarah: 219, lalu Umar dipanggil dan dibacakan kepadanya. Setelah itu ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat An Nisa` Hai orang-orang yang beriman, janganlah kamu mendekati shalat sedang kamu mabuk QS An Nisa`: 43. Selanjutnya ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Mai`idah Sesungguhnya syaitan itu bermaksud hendak menimbulkan permusuhan dan kebencian di antara kamu lantaran (meminum) khamar dan berjudi itu, -sampai firmanNya- maka berhentilah kamu (dari mengerjakan pekerjaan itu) QS Al Ma`idah: 91. Umar lalu berkata; \"Kami berhenti, kami berhenti.\" Abu Isa berkata; Hadits ini juga diriwayatkan dari Isra`il secara mursal. Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Abu Maisarah 'Amru bin Syurahbil] bahwa [Umar bin Al Khaththab] berkata; \"Ya Allah, Ya Allah, berilah kami penjelasan tentang khamar dengan penjelasan yang memadai.\" Lalu ia menyebutkan seperti di atas, namun hadits ini lebih shahih dari hadits Muhammad bin Yusuf."}],"4:48":[{"p":"Abu Dawud","n":3950,"ar":"حَدَّثَنَا عَلِيُّ بْنُ نَصْرٍ وَمُحَمَّدُ بْنُ يُونُسَ النَّسَائِيُّ الْمَعْنَى قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا حَرْمَلَةُ يَعْنِي ابْنَ عِمْرَانَ حَدَّثَنِي أَبُو يُونُسَ سُلَيْمُ بْنُ جُبَيْرٍ مَوْلَى أَبِي هُرَيْرَةَ قَالَسَمِعْتُ أَبَا هُرَيْرَةَ يَقْرَأُ هَذِهِ الْآيَةَ{ إِنَّ اللَّهَ يَأْمُرُكُمْ أَنْ تُؤَدُّوا الْأَمَانَاتِ إِلَى أَهْلِهَا إِلَى قَوْلِهِ تَعَالَى سَمِيعًا بَصِيرًا }قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ إِبْهَامَهُ عَلَى أُذُنِهِ وَالَّتِي تَلِيهَا عَلَى عَيْنِهِ قَالَ أَبُو هُرَيْرَةَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَؤُهَا وَيَضَعُ إِصْبَعَيْهِ قَالَ ابْنُ يُونُسَ قَالَ الْمُقْرِئُ يَعْنِي إِنَّ اللَّهَ سَمِيعٌ بَصِيرٌ يَعْنِي أَنَّ لِلَّهِ سَمْعًا وَبَصَرًاقَالَ أَبُو دَاوُد وَهَذَا رَدٌّ عَلَى الْجَهْمِيَّةِ","trj":"Telah menceritakan kepada kami [Ali bin Nashr] dan [Muhammad bin Yunus An Nasai] secara makna, keduanya berkata; telah menceritakan kepada kami [Abdullah bin Yazid Al Muqri] berkata, telah menceritakan kepada kami [Harmalah] -maksudnya Harmalah bin Imran- berkata, telah menceritakan kepadaku [Abu Yunus Sulaim bin Jubair] -mantan budak (yang telah dimerdekakan oleh) Abu Hurairah- ia berkata; Aku mendengar [Abu Hurairah] membaca ayat ini: (Sesungguhnya Allah menyuruh kamu menyampaikan amanat kepada yang berhak menerimanya) -Qs. An Nisa: 48- sampai pada firman-Nya (Sesungguhnya Allah adalah Maha Mendengar lagi Maha Melihat). Abu Hurairah berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam meletakkan ibu jarinya ke telinga, sementara jari setelahnya pada mata.\" Abu Hurairah melanjutkan, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam membaca ayat tersebut seraya meletakkan kedua jarinya tersebut.\" Ibnu Yunus berkata, \"Al Muqri menyebutkan bahwa makna ayat: (Sesungguhnya Allah Maha Mendengar dan Maha Melihat) adalah, bahwa Allah memiliki penglihatan dan pendengaran.\" Abu Dawud berkata, \"Ini adalah bantahan untuk orang-orang Jahmiyah.\""}],"4:53":[{"p":"Abu Dawud","n":3610,"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَوْ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَلَمَّا نَزَلَتْ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ مُشْرِكُو أَهْلِ مَكَّةَ قَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَأَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ وَعَمِلَ عَمَلًا صَالِحًا فَأُولَئِكَ يُبَدِّلُ اللَّهُ سَيِّئَاتِهِمْ حَسَنَاتٍ }فَهَذِهِ لِأُولَئِكَ قَالَ وَأَمَّا الَّتِي فِي النِّسَاءِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }الْآيَةَ قَالَ الرَّجُلُ إِذَا عَرَفَ شَرَائِعَ الْإِسْلَامِ ثُمَّ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ لَا تَوْبَةَ لَهُفَذَكَرْتُ هَذَا لِمُجَاهِدٍ فَقَالَ إِلَّا مَنْ نَدِمَ حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي يَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذِهِ الْقِصَّةِ فِي{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }أَهْلِ الشِّرْكِ قَالَ وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Yusuf bin Musa] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Sa'id bin Jubair] atau ia mengatakan; telah menceritakan kepadaku [Al hakam] dari [Sa'id bin Jubair] ia berkata; Aku bertanya [Ibnu Abbas] berkata, \"Ketika ayat dalam surat Al furqan ini turun: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68-, orang-orang musyrik Makkah berkata, \"Kami telah membunuh jiwa yang telah diharamkan oleh Allah dan berbuat syirik kepada-Nya serta melakukan perbuatan keji!\" Allah pun menurunkan ayat: (Kecuali orang-orang yang bertaubat dan, beriman dan beramal shalih; maka kejahatan mereka akan diganti Allah dengan kebajikan..) -Qs. Al Furqan: 70-, maka ayat ini untuk orang-orang musyrik Quraisy tersebut. Ibnu Abbas melanjutkan, \"Sedangkan ayat yang ada dalam surat An Nisa: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam…) -An Nisa: 93- ia mengatakan, \"Seorang laki-laki yang mengetahui hukum-hukum Islam, kemudian ia membunuh seorang mukmin dengan sengaja, maka balasannya adalah neraka jahannam dan tidak ada lagi taubat untuknya.\" Perkataan ini lalu aku sebutkan kepada Mujahid, ia berkomentar, \"Kecuali jika ia (pembunuh) merasa menyesal.\" Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ya'la] dari [Sa'id bin Jubair] dari [Ibnu Abbas] -sebagaimana kisah dalam hadits tersebut- tentang firman Allah: (dan orang-orang yang tidak menyembah tuhan yang lain berserta Allah..) -Qs. Al Furqan: 53- yakni orang-orang musyrik. Ibnu Abbas berkata, \"Lalu turun ayat: (Katakanlah, 'Hai hamba-hamba-Ku yang melampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah') -Qs. Az Zumar: 53-. "}],"4:59":[{"p":"Muslim","n":3183,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَهَارُونُ بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا حَجَّاحُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍنَزَلَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنْكُمْ }فِي عَبْدِ اللَّهِ بْنِ حُذَافَةَ بْنِ قَيْسِ بْنِ عَدِيٍّ السَّهْمِيِّ بَعَثَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍأَخْبَرَنِيهِ يَعْلَى بْنُ مُسْلِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ","trj":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Harun bin Abdullah] keduanya berkata; telah menceritakan kepada kami [Hajjaj bin Muhahammad] dia berkata; [Ibnu Juraij] berkata (Ayat): '(Hai orang-orang yang beriman, ta'atilah Allah dan ta'atilah Rasul (Nya), dan ulil amri di antara kamu …) ' (Qs. An Nisaa': 59), turun berkenaan dengan Abdullah bin Hudzafah bin Qais bin 'Adiy As Sahmiy, ketika Nabi shallallahu 'alaihi wasallam mengutusnya dalam sebuah ekspedisi militer.\" [Ya'la bin Muslim] memberitahukan hadits ini kepadaku, dari [Sa'id bin Jubair] dari [Ibnu Abbas].\""},{"p":"Tirmidzi","n":1595,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ حَدَّثَنَا الْحَجَّاجُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ جُرَيْجٍفِي قَوْلِهِ{ أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنْكُمْ }قَالَ عَبْدُ اللَّهِ بْنُ حُذَافَةَ بْنِ قَيْسِ بْنِ عَدِيٍّ السَّهْمِيُّ بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى سَرِيَّةٍأَخْبَرَنِيهِ يَعْلَى بْنُ مُسْلِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ ابْنِ جُرَيْجٍ","trj":"Telah menceritakan kepada kami [Muhammad bin Yahya An Naisaburi] berkata, telah menceritakan kepada kami [Al Hajjaj bin Muhammad] berkata, telah menceritakan kepada kami [Ibnu Juraij] berkata, \"Firman Allah: '(ta'atilah Allah dan ta'atilah Rasul (Nya), dan ulil amri (pemimpin) di antara kamu) ' -Qs. An Nisa: 59- Abdullah bin Hudzafah bin Qais bin Adi As Sahmi diutus oleh Rasulullah shallallahu 'alaihi wasallam dalam sebuah ekspedisi, [Ya'la bin Muslim] mengabarkannya kepadaku dari [Sa'id bin Jubair], dari [Ibnu Abbas].\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih gharib, dan kami tidak mengetahuinya kecuali dari hadits Ibnu Juraij.\""}],"4:65":[{"p":"Abu Dawud","n":3075,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا اللَّيْثِ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُأَنَّ رَجُلًا خَاصَمَ الزُّبَيْرَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ فَأَبَى عَلَيْهِ الزُّبَيْرُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ اسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ إِلَى جَارِكَ قَالَ فَغَضِبَ الْأَنْصَارِيُّ فَقَالَ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اسْقِ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِفَقَالَ الزُّبَيْرُ فَوَاللَّهِ إِنِّي لَأَحْسَبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Al Laits] dari [Az Zuhri] dari ['Urwah] bahwa [Abdullah bin Az Zubair] menceritakan kepadanya, bahwa ada seorang laki-laki bermusuhan dengan Az Zubair mengenai saluran-saluran air pada tanah keras yang berbatu hitam yang mereka gunakan untuk mengairi tanaman. Kemudian orang anshar tersebut berkata, \"Biarkanlah air lewat!\" Namun Az Zubair menolak. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepada Az Zubair: \"Siramilah tanamanmu wahai Az Zubair, kemudian alirkan kepada tetanggamu!\" Maka marahklah orang anshar tersebut, lalu ia berkata, \"Wahai Rasulullah, apakah karena ia itu anak bibimu!\" Maka rona muka Rasulullah shallallahu 'alaihi wasallam berubah, beliau bersabda: \"Siramlah tanamanmu, lalu tahanlah iar tersebut hingga ia kembali ke tempatnya semula.\" Az Zubair berkata, \"Demi Allah, sungguh aku mengira ayat ini turun mengenai hal tersebut; '(Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim…) ' (Qs. An Nisa: 65). "},{"p":"Bukhari","n":2187,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ حَدَّثَهُأَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا النَّخْلَ فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ فَأَبَى عَلَيْهِ فَاخْتَصَمَا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ أَسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ فَقَالَ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اسْقِ يَا زُبَيْرُ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِ فَقَالَ الزُّبَيْرُ وَاللَّهِ إِنِّي لَأَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }","trj":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] berkata, telah menceritakan kepadaku [Ibnu Syihab] dari ['Urwah] dari ['Abdullah bin Az Zubair radliallahu 'anhuma] bahwasanya dia menceritakan bahwa ada seorang dari kalangan Anshar bersengketa dengan Az Zubair di hadapan Nabi shallallahu 'alaihi wasallam tentang aliran air di daerah Al Harrah yang mereka gunakan untuk menyirami pepohonan kurma. Berkata, orang Anshar tersebut: \"Bukalah air agar bisa mengalir?\" Az Zubair menolaknya lalu keduanya bertengkar di hadapan Nabi shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam berkata, kepada Az Zubair: \"Wahai Zubair, berilah air dan kirimlah buat tetanggamu\". Maka orang Anshar itu marah seraya berkata; \"Tentu saja kamu bela dia karena dia putra bibimu\". Maka wajah Rasulullah shallallahu 'alaihi wasallam memerah kemudian berkata: \"Wahai Zubair, berilah air kemudian bendunglah hingga air itu kembali ke dasar ladang\". Maka Az Zubair berkata: \"Demi Allah, sungguh aku menganggap bahwa ayat ini turun tentang kasus ini, yaitu firman Allah dalam surah An-Nisa ayat 65 yang artinya: (\"Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan…)."},{"p":"Bukhari","n":2188,"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ قَالَخَاصَمَ الزُّبَيْرَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا زُبَيْرُ اسْقِ ثُمَّ أَرْسِلْ فَقَالَ الْأَنْصَارِيُّ إِنَّهُ ابْنُ عَمَّتِكَ فَقَالَ عَلَيْهِ السَّلَام اسْقِ يَا زُبَيْرُ ثُمَّ يَبْلُغُ الْمَاءُ الْجَدْرَ ثُمَّ أَمْسِكْ فَقَالَ الزُّبَيْرُ فَأَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }","trj":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhriy] dari ['Urwah] berkata: Ada seorang dari Kaum Anshar bersengketa dengan Az Zubair lalu Nabi shallallahu 'alaihi wasallam berkata: \" Wahai Zubair, berilah air dan kirimlah buat tetanggamu\". Lalu orang Anshar itu berkata; \"Tentu saja kamu bela dia karena dia putra bibimu\". Maka Beliau shallallahu 'alaihi wasallam berkata: \"Wahai Zubair, berilah air kemudian biarkanlah air memenuhi dasar ladang lalu bendunglah\". Kemudian Az Zubair berkata: \"Aku menganggap bahwa ayat ini turun tentang kasus ini, yaitu firman Allah dalam surah An-Nisa ayat 65 yang artinya: (\"Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan…)."},{"p":"Bukhari","n":2189,"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ سَلَامٍ أَخْبَرَنَا مَخْلَدُ بْنُ يَزِيدَ الْحَرَّانِيُّ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّهُ حَدَّثَهُأَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ فِي شِرَاجٍ مِنْ الْحَرَّةِ يَسْقِي بِهَا النَّخْلَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ يَا زُبَيْرُ فَأَمَرَهُ بِالْمَعْرُوفِ ثُمَّ أَرْسِلْ إِلَى جَارِكَ فَقَالَ الْأَنْصَارِيُّ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اسْقِ ثُمَّ احْبِسْ يَرْجِعَ الْمَاءُ إِلَى الْجَدْرِ وَاسْتَوْعَى لَهُ حَقَّهُ فَقَالَ الزُّبَيْرُ وَاللَّهِ إِنَّ هَذِهِ الْآيَةَ أُنْزِلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }قَالَ لِي ابْنُ شِهَابٍ فَقَدَّرَتْ الْأَنْصَارُ وَالنَّاسُ قَوْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ ثُمَّ احْبِسْ حَتَّى يَرْجِعَ إِلَى الْجَدْرِ وَكَانَ ذَلِكَ إِلَى الْكَعْبَيْنِ","trj":"Telah menceritakan kepada kami [Muhammad, dia adalah anak dari Salam] telah mengabarkan kepada kami [Makhlad bin Yazid Al Harraniy] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ibnu Syihab] dari ['Urwah bin Az Zubair] bahwasanya dia menceritakan ada seorang dari kalangan Anshar bersengketa dengan Az Zubair di hadapan Nabi shallallahu 'alaihi wasallam tentang aliran air di daerah Al Harrah yang mereka gunakan untuk menyirami pepohonan kurma. Maka Rasulullah shallallahu 'alaihi wasallam berkata kepada Az Zubair: \"Wahai Zubair. Beliau memerintahkannya berbuat ma'ruf.\"Kemudian kirimlah buat tetanggamu\". Orang Anshar itu berkata; \"Tentu saja kamu bela dia karena dia putra bibimu\". Maka wajah Rasulullah shallallahu 'alaihi wasallam memerah kemudian berkata: \"Berilah air kemudian bendunglah hingga air itu kembali ke dasar ladang dan tunaikanlah haknya\". Maka Az Zubair berkata: \"Demi Allah, sungguh ayat ini turun tentang kasus ini, yaitu firman Allah dalam surah An-Nisa ayat 65 yang artinya: (\"Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan…). Ibnu Sihab berkata, kepadaku: \"Maka orang Anshar dan yang lainnya mengukur apa yang Nabi shallallahu 'alaihi wasallam sabdakan tadi: \"Berilah air kemudian bendunglah hingga air itu kembali ke dasar ladang\", dan saat itu mencapai setinggi mata kaki."},{"p":"Bukhari","n":2509,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ الزُّبَيْرَ كَانَ يُحَدِّثُأَنَّهُ خَاصَمَ رَجُلًا مِنْ الْأَنْصَارِ قَدْ شَهِدَ بَدْرًا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِرَاجٍ مِنْ الْحَرَّةِ كَانَا يَسْقِيَانِ بِهِ كِلَاهُمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْزُّبَيْرِ اسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ فَقَالَ يَا رَسُولَ اللَّهِ آنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اسْقِ ثُمَّ احْبِسْ حَتَّى يَبْلُغَ الْجَدْرَ فَاسْتَوْعَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَئِذٍ حَقَّهُ لِلْزُّبَيْرِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ ذَلِكَ أَشَارَ عَلَى الزُّبَيْرِ بِرَأْيٍ سَعَةٍ لَهُ وَلِلْأَنْصَارِيِّ فَلَمَّا أَحْفَظَ الْأَنْصَارِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَوْعَى لِلْزُّبَيْرِ حَقَّهُ فِي صَرِيحِ الْحُكْمِ قَالَ عُرْوَةُ قَالَ الزُّبَيْرُ وَاللَّهِ مَا أَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ إِلَّا فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }الْآيَةَ","trj":"Telah bercerita kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata telah bercerita kepadaku ['Urwah bin Az Zubair] bahwa [Az Zubair] pernah bercerita bahwa dia pernah bersengketa dengan seseorang dari kaum Anshor yang pernah ikut dalam perang Badar kepada Rasulullah shallallahu 'alaihi wasallam tentang masalah saluran air di Al Harrah dimana keduanya sama-sama saling menyiram (kebun mereka darinya) Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepada Az Zubair: \"Siramlah (kebunmu darinya) wahai Zubair lalu alirkanlah ke tetanggamu\". Maka orang Anshor itu marah seraya berkata: \"Wahai Rasulullah, Tuan bela dia karena dia anak dari bibi Tuan\". Maka wajah Rasulullah shallallahu 'alaihi wasallam berubah kemudian Beliau berkata: \"Siramlah (kebunmu) darinya kemudian tahanlah air itu hingga memenuhi kebun\". Maka Rasulullah shallallahu 'alaihi wasallam saat itu memutuskan untuk mememnuhi hak Zubair padahal sebelumnya Rasulullah shallallahu 'alaihi wasallam memberi isyarat kepada Zubair agar memberi kelapangan bagi orang Anshor itu. Ketika orang Anshor itu tidak menerima maka Rasulullah shallallahu 'alaihi wasallam mengembalikan hak Zubair sepenuhnya sesuai hukum yang semestiya. 'Urwah berkata; Az Zubair berkata: \"Demi Allah, tidaklah aku menduga ayat ini turun melainkan dalam perkara ini: (\"Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan….) Ayat 65 dari surah an-Nisaa'"},{"p":"Tirmidzi","n":2839,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّهُ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُأَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا النَّخْلَ فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ فَأَبَى عَلَيْهِ فَاخْتَصَمُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ اسْقِ يَا زُبَيْرُ وَأَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ وَقَالَ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَغَيَّرَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا زُبَيْرُ اسْقِ وَاحْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجُدُرِ فَقَالَ الزُّبَيْرُ وَاللَّهِ إِنِّي لَأَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }الْآيَةَقَالَ أَبُو عِيسَى سَمِعْت مُحَمَّدًا يَقُولُ قَدْ رَوَى ابْنُ وَهْبٍ هَذَا الْحَدِيثَ عَنْ اللَّيْثِ بْنِ سَعْدٍ وَيُونُسُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ نَحْوَ هَذَا الْحَدِيثِ وَرَوَى شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ الزُّبَيْرِ وَلَمْ يَذْكُرْ فِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ","trj":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari ['Urwah bin Zubair] menceritakan bahwa [Abdullah bin Zubair] bercerita kepadanya, bahwa seorang Anshar bersengketa dengan Zubair tentang aliran air untuk dipakai menyirami pohon kurma, orang Anshar itu berkata; \"Biarkan air itu mengalir.\" Namun Zubair enggan (tidak menghiraukannya). Kemudian mereka mengadu kepada Rasulullah Shallallahu 'alahi wasallam, beliau bersabda kepada Zubair: \"Wahai Zubair siramlah, dan alirkanlah air kepada tetanggamu.\" Orang Anshar itu marah dan berkata; \"Wahai Rasulullah, apa dia sepupu anda?\" (mendengar hal itu) berubahlah wajah beliau sambil bersabda: \"Wahai Zubair, siramlah dan tahanlah air itu kembali ke kebun.\" Demi Allah aku menganggap ayat ini turun berkaitan dengan peristiwa itu, Maka demi Rabbmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan. QS An-Nisa`: 65. Abu Isa berkata; \"Aku mendengar Muhammad berkata; [Ibnu Wahab] meriwayatkan hadits ini dari [Al Laits bin Sa'd] dan [Yunus] dari [Az Zuhri] dari ['Urwah] dari [Abdullah bin Az Zubair] seperti hadits ini. [Syu'aib bin Abu Hamzah] meriwayatkan dari [Az Zuhri] dari ['Urwah] dari [Az Zubair] tanpa menyebut: \"Dari Abdullah bin Az Zubair.\""}],"4:68":[{"p":"Abu Dawud","n":3610,"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَوْ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَلَمَّا نَزَلَتْ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ مُشْرِكُو أَهْلِ مَكَّةَ قَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَأَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ وَعَمِلَ عَمَلًا صَالِحًا فَأُولَئِكَ يُبَدِّلُ اللَّهُ سَيِّئَاتِهِمْ حَسَنَاتٍ }فَهَذِهِ لِأُولَئِكَ قَالَ وَأَمَّا الَّتِي فِي النِّسَاءِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }الْآيَةَ قَالَ الرَّجُلُ إِذَا عَرَفَ شَرَائِعَ الْإِسْلَامِ ثُمَّ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ لَا تَوْبَةَ لَهُفَذَكَرْتُ هَذَا لِمُجَاهِدٍ فَقَالَ إِلَّا مَنْ نَدِمَ حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي يَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذِهِ الْقِصَّةِ فِي{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }أَهْلِ الشِّرْكِ قَالَ وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Yusuf bin Musa] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Sa'id bin Jubair] atau ia mengatakan; telah menceritakan kepadaku [Al hakam] dari [Sa'id bin Jubair] ia berkata; Aku bertanya [Ibnu Abbas] berkata, \"Ketika ayat dalam surat Al furqan ini turun: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68-, orang-orang musyrik Makkah berkata, \"Kami telah membunuh jiwa yang telah diharamkan oleh Allah dan berbuat syirik kepada-Nya serta melakukan perbuatan keji!\" Allah pun menurunkan ayat: (Kecuali orang-orang yang bertaubat dan, beriman dan beramal shalih; maka kejahatan mereka akan diganti Allah dengan kebajikan..) -Qs. Al Furqan: 70-, maka ayat ini untuk orang-orang musyrik Quraisy tersebut. Ibnu Abbas melanjutkan, \"Sedangkan ayat yang ada dalam surat An Nisa: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam…) -An Nisa: 93- ia mengatakan, \"Seorang laki-laki yang mengetahui hukum-hukum Islam, kemudian ia membunuh seorang mukmin dengan sengaja, maka balasannya adalah neraka jahannam dan tidak ada lagi taubat untuknya.\" Perkataan ini lalu aku sebutkan kepada Mujahid, ia berkomentar, \"Kecuali jika ia (pembunuh) merasa menyesal.\" Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ya'la] dari [Sa'id bin Jubair] dari [Ibnu Abbas] -sebagaimana kisah dalam hadits tersebut- tentang firman Allah: (dan orang-orang yang tidak menyembah tuhan yang lain berserta Allah..) -Qs. Al Furqan: 53- yakni orang-orang musyrik. Ibnu Abbas berkata, \"Lalu turun ayat: (Katakanlah, 'Hai hamba-hamba-Ku yang melampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah') -Qs. Az Zumar: 53-. "},{"p":"Bukhari","n":4085,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي الْقَاسِمُ بْنُ أَبِي بَزَّةَ أَنَّهُ سَأَلَ سَعِيدَ بْنَ جُبَيْرٍهَلْ لِمَنْ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا مِنْ تَوْبَةٍ فَقَرَأْتُ عَلَيْهِ{ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }فَقَالَ سَعِيدٌ قَرَأْتُهَا عَلَى ابْنِ عَبَّاسٍ كَمَا قَرَأْتَهَا عَلَيَّ فَقَالَ هَذِهِ مَكِّيَّةٌ نَسَخَتْهَا آيَةٌ مَدَنِيَّةٌ الَّتِي فِي سُورَةِ النِّسَاءِ","trj":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] Telah mengabarkan kepada mereka dia berkata; Telah mengabarkan kepadaku [Qasim bin Abu Bazzah] bahwsanya dia bertanya [Sa'id bin Jubair] apakah ada taubat bagi orang yang telah membunuh seorang mukmin? Lalu aku membacakan ayat; dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar... (Al Furqan: 68). Maka Sa'id berkata; Aku telah membacakannya kepada [Ibnu Abbas] sebagaimana kamu membacakannya kepadaku. Dia berkata; Ayat ini turun di Makkah, telah dinasakh (dihapus) oleh ayat yang turun di Madinah yang ada di didalam surat An Nisa."}],"4:70":[{"p":"Abu Dawud","n":3610,"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَوْ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَلَمَّا نَزَلَتْ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ مُشْرِكُو أَهْلِ مَكَّةَ قَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَأَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ وَعَمِلَ عَمَلًا صَالِحًا فَأُولَئِكَ يُبَدِّلُ اللَّهُ سَيِّئَاتِهِمْ حَسَنَاتٍ }فَهَذِهِ لِأُولَئِكَ قَالَ وَأَمَّا الَّتِي فِي النِّسَاءِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }الْآيَةَ قَالَ الرَّجُلُ إِذَا عَرَفَ شَرَائِعَ الْإِسْلَامِ ثُمَّ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ لَا تَوْبَةَ لَهُفَذَكَرْتُ هَذَا لِمُجَاهِدٍ فَقَالَ إِلَّا مَنْ نَدِمَ حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي يَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذِهِ الْقِصَّةِ فِي{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }أَهْلِ الشِّرْكِ قَالَ وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Yusuf bin Musa] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Sa'id bin Jubair] atau ia mengatakan; telah menceritakan kepadaku [Al hakam] dari [Sa'id bin Jubair] ia berkata; Aku bertanya [Ibnu Abbas] berkata, \"Ketika ayat dalam surat Al furqan ini turun: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68-, orang-orang musyrik Makkah berkata, \"Kami telah membunuh jiwa yang telah diharamkan oleh Allah dan berbuat syirik kepada-Nya serta melakukan perbuatan keji!\" Allah pun menurunkan ayat: (Kecuali orang-orang yang bertaubat dan, beriman dan beramal shalih; maka kejahatan mereka akan diganti Allah dengan kebajikan..) -Qs. Al Furqan: 70-, maka ayat ini untuk orang-orang musyrik Quraisy tersebut. Ibnu Abbas melanjutkan, \"Sedangkan ayat yang ada dalam surat An Nisa: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam…) -An Nisa: 93- ia mengatakan, \"Seorang laki-laki yang mengetahui hukum-hukum Islam, kemudian ia membunuh seorang mukmin dengan sengaja, maka balasannya adalah neraka jahannam dan tidak ada lagi taubat untuknya.\" Perkataan ini lalu aku sebutkan kepada Mujahid, ia berkomentar, \"Kecuali jika ia (pembunuh) merasa menyesal.\" Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ya'la] dari [Sa'id bin Jubair] dari [Ibnu Abbas] -sebagaimana kisah dalam hadits tersebut- tentang firman Allah: (dan orang-orang yang tidak menyembah tuhan yang lain berserta Allah..) -Qs. Al Furqan: 53- yakni orang-orang musyrik. Ibnu Abbas berkata, \"Lalu turun ayat: (Katakanlah, 'Hai hamba-hamba-Ku yang melampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah') -Qs. Az Zumar: 53-. "},{"p":"Bukhari","n":3409,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ أَوْ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى قَالَ سَلْ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ مَا أَمْرُهُمَا{ وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ لَمَّا أُنْزِلَتْ الَّتِي فِي الْفُرْقَانِ قَالَ مُشْرِكُو أَهْلِ مَكَّةَ فَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَقَدْ أَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ }الْآيَةَ فَهَذِهِ لِأُولَئِكَ وَأَمَّا الَّتِي فِي النِّسَاءِ الرَّجُلُ إِذَا عَرَفَ الْإِسْلَامَ وَشَرَائِعَهُ ثُمَّ قَتَلَ فَجَزَاؤُهُ جَهَنَّمُفَذَكَرْتُهُ لِمُجَاهِدٍ فَقَالَإِلَّا مَنْ نَدِمَ","trj":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] telah menceritakan kepadaku [Sa'id bin Jubair] -atau dia berkata, telah menceritakan kepadaku [Al Hakam] dari [Sa'id bin Jubair] berkata, - 'Abdurrahman bin Abza menyuruhku, katanya; \"Tanyalah kepada Ibnu 'Abbas tentang dua ayat ini dan apa maksudnya, yaitu yang pertama firman Allah dalam QS al Isra` ayat 33; (\"Dan janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan haq (alasan yang benar) \" dan yang kedua firman Allah dalam QS an Nisaa' ayat 93: (\"Dan barangsiapa yang membunuh orang beriman dengan sengaja...\"). Maka aku bertanya kepada [Ibnu 'Abbas], maka dia menjelaskan; Ketika turun firman Allah yang serupa ini pada surah al Furqan, orang-orang musyrik penduduk Makkah berkata; \"Sungguh kita telah membunuh jiwa yang diharamkan Allah dan kita juga menyembah selain Allah dan kita telah banyak berbuat maksiat, maka Allah menurunkan firman-Nya yang artinya: \"...kecuali siapa yang bertaubat dan beriman...\" (QS al Furqan ayat 70). Nah, ayat-ayat ini turun untuk mereka. Adapun ayat yang ada dalam surah an Nisaa' adalah bila seseorang telah mengenal Islam dan syari'atnya, kemudian dia membunuh seseorang dengan sengaja maka balasan baginya adalah neraka jahannam\". Kemudian keterangan ini aku sampaikan kepada Mujahidmaka dia berkata; \"Kecuali siapa yang menyesali perbuartannya\"."},{"p":"Nasa'i","n":1378,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ يُحَدِّثُ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَّمَنَا خُطْبَةَ الْحَاجَةِ الْحَمْدُ لِلَّهِ نَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا وَسَيِّئَاتِ أَعْمَالِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَقْرَأُ ثَلَاثَ آيَاتٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَثَّ مِنْهُمَا رِجَالًا كَثِيرًا وَنِسَاءً وَاتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ وَالْأَرْحَامَ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا }قَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو عُبَيْدَةَ لَمْ يَسْمَعْ مِنْ أَبِيهِ شَيْئًا وَلَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَلَا عَبْدُ الْجَبَّارِ بْنُ وَائِلِ بْنِ حُجْرٍ","trj":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Abu Ishaq] menceritakan dari [Abu 'Ubaidah] dari ['Abdullah] dari Nabi Shalallahu 'Alaihi Wa Sallam. Abdullah berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam telah mengajarkan Khutbah Hajah kepada kami, yaitu, 'Segala puji bagi Allah, kita memohon pertolongan dan ampunan kepadanya, berlindung kepadanya dari kejahatan jiwa kami dan kejelekan perbuatan-perbuatan kami. Barang siapa yang diberikan petunjuk oleh Allah, maka tidak akan ada yang bisa menyesatkannya. Barangsiapa yang telah Allah sesatkan, maka tidak akan ada yang bisa memberinya petunjuk. Aku bersaksi tiada tuhan (yang berhak disembah) kecuali Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusannya'. Kemudian beliau membaca tiga ayat berikut ini: 'Wahai orang-orang yang beriman, bertakwalah kepada Allah dengan sebenar-benar takwa kepadanya, dan janganlah kamu mati melainkan dalam keadaan beragama Islam'. (Qs. Ali 'Imran (3): 102). 'Hai kalian manusia, bertakwalah kepada tuhanmu yang telah menciptakanmu dari diri yang satu, dan daripadanya Allah menciptakan istrinya, dan daripada keduanya Allah memperkembangbiakan laki-laki dan perempuan yang banyak, dan bertakwalah kepada Allah dengan (mempergunakan) nama-Nya kamu saling meminta satu dengan yang lain, dan (periharalah) hubungan Silaturrahim. Sesungguhnya Allah selalu menjaga dan mengawasimu'.\"(Qs. An-Nisaa'(4): 1). 'Hai orang-orang yang beriman, bertakwalah kepada Allah dan katakanlah perkataan yang benar'.\"(Qs. Al Ahzaab (33): 70). Abu Abdurrahman berkata; Abu Ubaidah tidak pernah mendengar dari Bapaknya sedikitpun, demikian juga Abdurrahman bin Abdullah bin Mas'ud dan Abdul Jabbar bin Wa'il bin Hujr. "}],"4:79":[{"p":"Bukhari","n":6533,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقُلْنَا يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ قَالَ هَلْ تُضَارُونَ فِي رُؤْيَةِ الشَّمْسِ وَالْقَمَرِ إِذَا كَانَتْ صَحْوًا قُلْنَا لَا قَالَ فَإِنَّكُمْ لَا تُضَارُونَ فِي رُؤْيَةِ رَبِّكُمْ يَوْمَئِذٍ إِلَّا كَمَا تُضَارُونَ فِي رُؤْيَتِهِمَا ثُمَّ قَالَ يُنَادِي مُنَادٍ لِيَذْهَبْ كُلُّ قَوْمٍ إِلَى مَا كَانُوا يَعْبُدُونَ فَيَذْهَبُ أَصْحَابُ الصَّلِيبِ مَعَ صَلِيبِهِمْ وَأَصْحَابُ الْأَوْثَانِ مَعَ أَوْثَانِهِمْ وَأَصْحَابُ كُلِّ آلِهَةٍ مَعَ آلِهَتِهِمْ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ وَغُبَّرَاتٌ مِنْ أَهْلِ الْكِتَابِ ثُمَّ يُؤْتَى بِجَهَنَّمَ تُعْرَضُ كَأَنَّهَا سَرَابٌ فَيُقَالُ لِلْيَهُودِ مَا كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ عُزَيْرَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ قَالُوا نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ ثُمَّ يُقَالُ لِلنَّصَارَى مَا كُنْتُمْ تَعْبُدُونَ فَيَقُولُونَ كُنَّا نَعْبُدُ الْمَسِيحَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ فَيَقُولُونَ نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ فَيُقَالُ لَهُمْ مَا يَحْبِسُكُمْ وَقَدْ ذَهَبَ النَّاسُ فَيَقُولُونَ فَارَقْنَاهُمْ وَنَحْنُ أَحْوَجُ مِنَّا إِلَيْهِ الْيَوْمَ وَإِنَّا سَمِعْنَا مُنَادِيًا يُنَادِي لِيَلْحَقْ كُلُّ قَوْمٍ بِمَا كَانُوا يَعْبُدُونَ وَإِنَّمَا نَنْتَظِرُ رَبَّنَا قَالَ فَيَأْتِيهِمْ الْجَبَّارُ فِي صُورَةٍ غَيْرِ صُورَتِهِ الَّتِي رَأَوْهُ فِيهَا أَوَّلَ مَرَّةٍ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ أَنْتَ رَبُّنَا فَلَا يُكَلِّمُهُ إِلَّا الْأَنْبِيَاءُ فَيَقُولُ هَلْ بَيْنَكُمْ وَبَيْنَهُ آيَةٌ تَعْرِفُونَهُ فَيَقُولُونَ السَّاقُ فَيَكْشِفُ عَنْ سَاقِهِ فَيَسْجُدُ لَهُ كُلُّ مُؤْمِنٍ وَيَبْقَى مَنْ كَانَ يَسْجُدُ لِلَّهِ رِيَاءً وَسُمْعَةً فَيَذْهَبُ كَيْمَا يَسْجُدَ فَيَعُودُ ظَهْرُهُ طَبَقًا وَاحِدًا ثُمَّ يُؤْتَى بِالْجَسْرِ فَيُجْعَلُ بَيْنَ ظَهْرَيْ جَهَنَّمَ قُلْنَا يَا رَسُولَ اللَّهِ وَمَا الْجَسْرُ قَالَ مَدْحَضَةٌ مَزِلَّةٌ عَلَيْهِ خَطَاطِيفُ وَكَلَالِيبُ وَحَسَكَةٌ مُفَلْطَحَةٌ لَهَا شَوْكَةٌ عُقَيْفَاءُ تَكُونُ بِنَجْدٍ يُقَالُ لَهَا السَّعْدَانُ الْمُؤْمِنُ عَلَيْهَا كَالطَّرْفِ وَكَالْبَرْقِ وَكَالرِّيحِ وَكَأَجَاوِيدِ الْخَيْلِ وَالرِّكَابِ فَنَاجٍ مُسَلَّمٌ وَنَاجٍ مَخْدُوشٌ وَمَكْدُوسٌ فِي نَارِ جَهَنَّمَ حَتَّى يَمُرَّ آخِرُهُمْ يُسْحَبُ سَحْبًا فَمَا أَنْتُمْ بِأَشَدَّ لِي مُنَاشَدَةً فِي الْحَقِّ قَدْ تَبَيَّنَ لَكُمْ مِنْ الْمُؤْمِنِ يَوْمَئِذٍ لِلْجَبَّارِ وَإِذَا رَأَوْا أَنَّهُمْ قَدْ نَجَوْا فِي إِخْوَانِهِمْ يَقُولُونَ رَبَّنَا إِخْوَانُنَا كَانُوا يُصَلُّونَ مَعَنَا وَيَصُومُونَ مَعَنَا وَيَعْمَلُونَ مَعَنَا فَيَقُولُ اللَّهُ تَعَالَى اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ دِينَارٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ وَيُحَرِّمُ اللَّهُ صُوَرَهُمْ عَلَى النَّارِ فَيَأْتُونَهُمْ وَبَعْضُهُمْ قَدْ غَابَ فِي النَّارِ إِلَى قَدَمِهِ وَإِلَى أَنْصَافِ سَاقَيْهِ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ نِصْفِ دِينَارٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ ذَرَّةٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا قَالَ أَبُو سَعِيدٍ فَإِنْ لَمْ تُصَدِّقُونِي فَاقْرَءُوا{ إِنَّ اللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍ وَإِنْ تَكُ حَسَنَةً يُضَاعِفْهَا }فَيَشْفَعُ النَّبِيُّونَ وَالْمَلَائِكَةُ وَالْمُؤْمِنُونَ فَيَقُولُ الْجَبَّارُ بَقِيَتْ شَفَاعَتِي فَيَقْبِضُ قَبْضَةً مِنْ النَّارِ فَيُخْرِجُ أَقْوَامًا قَدْ امْتُحِشُوا فَيُلْقَوْنَ فِي نَهَرٍ بِأَفْوَاهِ الْجَنَّةِ يُقَالُ لَهُ مَاءُ الْحَيَاةِ فَيَنْبُتُونَ فِي حَافَتَيْهِ كَمَا تَنْبُتُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ قَدْ رَأَيْتُمُوهَا إِلَى جَانِبِ الصَّخْرَةِ وَإِلَى جَانِبِ الشَّجَرَةِ فَمَا كَانَ إِلَى الشَّمْسِ مِنْهَا كَانَ أَخْضَرَ وَمَا كَانَ مِنْهَا إِلَى الظِّلِّ كَانَ أَبْيَضَ فَيَخْرُجُونَ كَأَنَّهُمْ اللُّؤْلُؤُ فَيُجْعَلُ فِي رِقَابِهِمْ الْخَوَاتِيمُ فَيَدْخُلُونَ الْجَنَّةَ فَيَقُولُ أَهْلُ الْجَنَّةِ هَؤُلَاءِ عُتَقَاءُ الرَّحْمَنِ أَدْخَلَهُمْ الْجَنَّةَ بِغَيْرِ عَمَلٍ عَمِلُوهُ وَلَا خَيْرٍ قَدَّمُوهُ فَيُقَالُ لَهُمْ لَكُمْ مَا رَأَيْتُمْ وَمِثْلَهُ مَعَهُوَقَالَ حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُحْبَسُ الْمُؤْمِنُونَ يَوْمَ الْقِيَامَةِ حَتَّى يُهِمُّوا بِذَلِكَ فَيَقُولُونَ لَوْ اسْتَشْفَعْنَا إِلَى رَبِّنَا فَيُرِيحُنَا مِنْ مَكَانِنَا فَيَأْتُونَ آدَمَ فَيَقُولُونَ أَنْتَ آدَمُ أَبُو النَّاسِ خَلَقَكَ اللَّهُ بِيَدِهِ وَأَسْكَنَكَ جَنَّتَهُ وَأَسْجَدَ لَكَ مَلَائِكَتَهُ وَعَلَّمَكَ أَسْمَاءَ كُلِّ شَيْءٍ لِتَشْفَعْ لَنَا عِنْدَ رَبِّكَ حَتَّى يُرِيحَنَا مِنْ مَكَانِنَا هَذَا قَالَ فَيَقُولُ لَسْتُ هُنَاكُمْ قَالَ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ أَكْلَهُ مِنْ الشَّجَرَةِ وَقَدْ نُهِيَ عَنْهَا وَلَكِنْ ائْتُوا نُوحًا أَوَّلَ نَبِيٍّ بَعَثَهُ اللَّهُ إِلَى أَهْلِ الْأَرْضِ فَيَأْتُونَ نُوحًا فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ سُؤَالَهُ رَبَّهُ بِغَيْرِ عِلْمٍ وَلَكِنْ ائْتُوا إِبْرَاهِيمَ خَلِيلَ الرَّحْمَنِ قَالَ فَيَأْتُونَ إِبْرَاهِيمَ فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ ثَلَاث�� كَلِمَاتٍ كَذَبَهُنَّ وَلَكِنْ ائْتُوا مُوسَى عَبْدًا آتَاهُ اللَّهُ التَّوْرَاةَ وَكَلَّمَهُ وَقَرَّبَهُ نَجِيًّا قَالَ فَيَأْتُونَ مُوسَى فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ قَتْلَهُ النَّفْسَ وَلَكِنْ ائْتُوا عِيسَى عَبْدَ اللَّهِ وَرَسُولَهُ وَرُوحَ اللَّهِ وَكَلِمَتَهُ قَالَ فَيَأْتُونَ عِيسَى فَيَقُولُ لَسْتُ هُنَاكُمْ وَلَكِنْ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدًا غَفَرَ اللَّهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ فَيَأْتُونِي فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي فَيَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ أَيْضًا يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّانِيَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّالِثَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَهْ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَقَدْ سَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ حَتَّى مَا يَبْقَى فِي النَّارِ إِلَّا مَنْ حَبَسَهُ الْقُرْآنُ أَيْ وَجَبَ عَلَيْهِ الْخُلُودُ قَالَ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ عَسَى أَنْ يَبْعَثَكَ رَبُّكَ مَقَامًا مَحْمُودًا }قَالَ وَهَذَا الْمَقَامُ الْمَحْمُودُ الَّذِي وُعِدَهُ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Allaits bin Sa'd] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Zaid] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudzri] berkata, \"Kami bertanya, \"Ya Rasulullah, apakah kita akan melihat Tuhan kita pada hari kiamat?\" Nabi balik bertanya: \"Apakah kalian merasa kesulitan melihat matahari dan bulan ketika terang benderang?\" kami menjawab, \"Tidak.\" Nabi meneruskan: \"Begitulah kalian tidak kesulitan melihat melihat Tuhan kalian ketika itu, selain sebagaimana kesulitan kalian melihat keduanya.\" Kemudian beliau berkata: \"Lantas ada seorang penyeru memanggil-manggil, \"Hendaklah setiap kaum pergi menemui yang disembahnya!\" Maka pemuja salib pergi bersama salib mereka, dan pemuja patung menemui patung-patung mereka, dan setiap pemuja Tuhan bersama tuhan-tuhan mereka hingga tinggal orang-orang yang menyembah Allah, entah baik atau durhaka dan ahli kitab terdahulu. Kemudian jahannam didatangkan dan dipasang, ia seolah-olah fatamorgana, lantas orang-orang yahudi ditanya, \"Apa yang dahulu kalian sembah?\" Mereka menjawab, \"Kami dahulu menyembah Uzair anak Allah.\" Lalu ada suara, \"Kalian dusta! Allah sama sekali tidak mempunyai isteri dan tidak pula anak.\" Lalu apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin jika Engkau memberi kami minuman!\" Lantas ada suara, \"Minumlah kalian!\" Lalu mereka berjatuhan di neraka jahannam. Lantas orang-orang Nashara diseru, \"Apa yang kalian dahulu sembah?\" Mereka menjawab, \"Kami dahulu menyembah Isa al Masih, anak Anak Allah.\" Mereka dijawab, \"Kamu semua bohong! Allah sama sekali tidak mempunyai isteri atau bahkan anak, dan apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin agar Engkau memberi kami minuman!\" Lalu dijawab, \"Minumlah kalian!\" Dan langsung mereka berjatuhan di neraka jahannam hingga tersisa manusia yang menyembah Allah, entah yang baik atau berbuat durhaka. Mereka ditanya, \"Apa yang menyebabkan kalian tertahan padahal manusia lainnya sudah pergi?\" Mereka menjawab, \"Kami memisahkan diri dari mereka dan kami adalah manusia yang paling membutuhkan-Nya, kami dengar ada seorang juru seru menyerukan diri, \"Hendaklah setiap kaum menemui yang mereka sembah! Hanyasanya kami menunggu-nunggu Tuhan kami.\" Beliau melanjutkan, \"Lantas Allah (Al jabbar) mendatangi mereka dengan bentuk yang belum pernah mereka lihat pertama kali, lalu Allah firmankan: 'Akulah Tuhan kalian.' Mereka menjawab, 'Engkau adalah rabb kami, dan tidak ada yang berani mengajak-Nya bicara selain para nabi shallallahu 'alaihi wasallam, lantas para nabi berkata, 'Bukankah di antara kalian dan Allah ada tanda yang kalian mengenalnya? ' Mereka menjawab, 'Ya, yaitu betis, ' maka Allah pun menyingkap betis-Nya sehingga setiap mukmin bersujud kepada-Nya. Lalu tersisalah orang-orang yang sujud kepada Allah karena riya dan sum'ah sehingga ia pergi sujud dan punggungnya kembali menjadi satu bagian, kemudian titian (jembatan) jahannam didatangkan dan dipasang antara dua tepi jahannam, kami bertanya, 'Wahai Rasulullah, memang jembatan jahannam tersebut misterinya apa? ' Nabi menjawab: 'Jembatan itu bisa menggelincirkan, menjatuhkan, ada pengait-pengait besi, ada duri-duri yang lebar dan tajam, durinya besok yang terbuat dari kayu berduri namanya Sa'dan (kayu berduri tajam). Orang mukmin yang melewatinya sedemikian cepat, ada yang bagaikan kedipan mata, ada yang bagaikan kilat, ada yang bagaikan angin, dan ada yang bagaikan kuda pilihan. Ada yang bagaikan kuda tunggangan, ada yang selamat dengan betul-betul terselamatkan, namun ada juga yang selamat setelah tercabik-cabik oleh besi-besi pengait itu, atau terlempar karenanya di neraka jahannam, hingga manusia terakhir kali melewati dengan diseret seret, dan kalian tidak bisa sedemikian gigihnya menyumpahiku terhadap kebenaran yang jelas bagi kalian daripada terhadap seorang mukmin ketika itu kepada Allah Al Jabbar. Jika mereka melihat bahwasanya mereka telah selamat di kalangan teman-teman mereka, mereka berkata, 'Ya Tuhan kami, sesungguhnya kawan-kawan kami mendirikn shalat bersama kami dan berpuasa bersama kami, dan beramal bersama kami! ' Allah Ta'ala berfirman, 'Pergilah kalian, siapa diantara kalian dapatkan dalam hatinya masih ada seberat dinar keimanan, maka keluarkanlah dia', dan Allah mengharamkan bentuk mereka dalam neraka. Maka mereka datangi kawan-kawan mereka sedang sebagian mereka telah terendam dalam neraka ada yang sampai telapak kakinya, setengah betisnya, sehingga mereka keluarkan siapa saja yang mereka, kemudian mereka kembali dan Allah berkata, 'Pergilah kalian sekali lagi, dan siapa yang kalian temukan dalam hatinya seberat atom keimanan, maka keluarkanlah dia.' Maka mereka keluarkan siapa saja yang mereka kenal.\" Rasulullah berkata: 'Jika kalian tidak mempercayaiku, maka bacalah: '(Allah tidak menzhalimi seberat biji sawi pun, jika ada kebaikan, maka Allah melipatgandakan balasannya) ' (Qs. An nisaa': 40), maka para nabi shallallahu 'alaihi wasallam, malaikat dan orang-orang yang beriman, kesemuanya memberi syafaat. Kemudian Allah Al Jabbar berkata, syafaat-Ku masih ada. Lantas Allah menggenggam segenggam dari neraka dan mengentaskan beberapa kaum yang mereka telah terbakar, lantas mereka dilempar ke sebuah sungai di pintu surga yang namanya 'Sungai kehidupan' sehingga mereka tumbuh dalam kedua tepinya sebagaimana biji-bijian tumbuh dalam genangan sungai yang kalian sering melihatnya di samping batu karang dan samping pohon, apa yang diantaranya condong kepada matahari, maka berwarna hijau, dan apa yang diantaranya condong kepada bayangan, maka berwarna putih, lantas mereka muncul seolah-olah mutiara dan dalam tengkuk mereka terdapat cincin-cincin. Mereka kemudian masuk surga hingga penghuni surga berkata, 'Mereka adalah 'utaqa' Ar Rahman (orang-orang yang dibebaskan Arrahman), Allah memasukkan mereka bukan karena amal yang mereka lakukan, dan bukan pula karena kebaikan yang mereka persembahkan sehingga mereka memperoleh jawaban 'Bagimu yang kau lihat dan semisalnya'.\" [Hajjaj bin Minhal] berkata; telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dari [Anas] radliyallahu'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: 'Pada hari kiamat nanti orang-orang mukmin ditahan hingga yang demikian menjadikan mereka sedih. Mereka katakan, 'Duh, sekiranya kita meminta syafaat kepada Tuhan kami sehingga Dia menjadikan kita merasa nyaman dari tempat kita ini.' Mereka pun mendatangi Adam dan berkata, 'Engkau hai Adam, Engkau adalah nenek moyang seluruh manusia, Allah menciptamu dengan tangan-Nya, menjadikan surga sebagai tempat hunianmu dan menjadikan malaikat bertunduk sujud kepadamu, Allah juga mengajarimu nama-nama segala sesuatu agar engkau bisa memberi syafaat kepada kami disisi Tuhanmu sehingga engkau bisa memberi kenyamanan di tempat kami ini. Namun Adam hanya menjawab, 'Disini saya tak berhak memberi syafaat untuk kalian'.\" Rasulullah melanjutkan: \"Lantas Adam mengingatkan kesalahan yang pernah dilakukannya, yaitu memakan pohon larangan padahal telah dilarang, dan ia katakan 'Coba kalian datangi Nuh, sebab ia adalah nabi shallallahu 'alaihi wasallam pertama-tama yang Allah utus kepada penduduk bumi.' Mereka pun mendatangi Nuh, namun Nuh juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', dan Nuh menyebutkan kesalahan yang pernah dilakukannya, yaitu bertanya kepada Rabbnya dengan tanpa ilmu sambil ia katakan, 'Cobalah kalian datangi Ibrahim, sebab ia adalah Khalilurrahman (kekasih Arrahman).\" Rasulullah melanjutkan lagi kisahnya: \"Mereka pun mendatangi Ibrahim, hanya Ibrahim juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', Ibrahim lantas menyebutkan kesalahannya, yaitu tiga kebohongan yang pernah dilakukannya sambil berkata, 'Cobalah kalian datangi Musa, seorang hamba yang Allah memberinya taurat, mengajaknya bicara dan mendekatkannya kepada-Nya sedekat-dekatnya'.\" Rasulullah lanjutkan: \"Mereka pun mendatangi Musa, hanya Musa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil Musa mengingatkan kesalahan yang pernah dilakukannya, yaitu membunuh jiwa tanpa alasan yang dibenarkan, sambil ia katakan, 'Coba kalian datangi Isa, seorang hamba Allah dan rasul-Nya, ruh Allah dan kalimah-Nya. Merekapun mendatangi Isa, namun 'Isa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil ia katakan 'Cobalah kalian datangi Muhammad Shallallahu'alaihiwasallam, seorang hamba yang Allah telah mengampuni dosanya yang terdahulu dan yang akan datang.' Lantas mereka mendatangi aku (Muhammad) dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud, Allah lalu membiarkan aku sekehendak Dia membiarkaku. Allah lantas berkata, 'Angkat kepalamu hai Muhammad, katakanlah, engkau didengar, mintailah syafaat, engkau diberi syafaat, mintalah, engkau diberi.' Aku lalu angkat kepalaku dan aku memuji Tuhanku dengan pujian yang Ia ajarkannya kepadaku, kemudian aku memberi syafaat dan Dia memberiku batasan. Kemudian aku keluar dan memasukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku juga mendengarnya menyebutkan, \"Aku lalu keluar, kemudian aku keluarkan mereka dari neraka dan kumasukkan ke dalam surga. Setelah itu aku kembali untuk kali kedua dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan untuk menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud. Allah lantas membiarkanku sekehendak Allah membiarkan, kemudian Allah berkata, 'Angkatlah kepalamu hai Muhammad dan katakanlah engkau akan didengar, dan berilah syafaat engkau akan diberi syafaat, dan mintalah engkau akan diberi.' Aku lalu angkat kepalaku dan memanjatkan pujian dan pujaan terhadap tuhanku sebagaimana yang diajakrkan-Nya kepadaku. Kemudian aku memberi syafaat, dan Ia memberiku batasan sehingga aku keluar dan aku masukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, \"Dan aku berangkat sehingga aku keluarkan mereka dari neraka, lalu mereka aku masukkan ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, 'Maka aku berangkat dan aku keluarkan mereka dari neraka, untuk kemudian aku masukkan mereka ke dalam surga, hingga tidak tersisa dalam neraka selain yang digi ditahan oleh alquran, atau maksudnya ia wajib abadi, kemudian beliau membaca ayat ini '(semoga Tuhanmu membangkitkankmu di tempat yang terpuji) ' (Qs. Al Isra': 79). Nabi mengatakan, \"Inilah maqam terpuji yang dijanjikan untuk nabi shallallahu 'alaihi wasallam kalian.\""}],"4:88":[{"p":"Bukhari","n":3545,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ يُحَدِّثُ عَنْ زَيْدِ بْنِ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أُحُدٍ رَجَعَ نَاسٌ مِمَّنْ خَرَجَ مَعَهُ وَكَانَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِرْقَتَيْنِ فِرْقَةً تَقُولُ نُقَاتِلُهُمْ وَفِرْقَةً تَقُولُ لَا نُقَاتِلُهُمْ فَنَزَلَتْ{ فَمَا لَكُمْ فِي الْمُنَافِقِينَ فِئَتَيْنِ وَاللَّهُ أَرْكَسَهُمْ بِمَا كَسَبُوا }وَقَالَ إِنَّهَا طَيْبَةُ تَنْفِي الذُّنُوبَ كَمَا تَنْفِي النَّارُ خَبَثَ الْفِضَّةِ","trj":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] aku mendengar [Abdullah bin Yazid] bercerita dari [Zaid bin Tsabit] radliallahu 'anhu, dia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam berangkat ke medan Uhud, di tengah perjalanan beberapa orang yang ikut bersama beliau kembali pulang, dan sebab itu sahabat Nabi shallallahu 'alaihi wasallam terpecah menjadi dua kelompok; kelompok yang mengatakan, \"Kami akan memerangi mereka, \" dan kelompok yang mengatakan, \"Kami tidak akan memerangi mereka.\" Maka turunlah ayat: '(Maka Mengapa kamu (terpecah) menjadi dua golongan dalam (menghadapi) orang-orang munafik, padahal Allah Telah membalikkan mereka kepada kekafiran, disebabkan usaha mereka sendiri?) ' (Qs. An Nisaa: 88), beliau bersabda: \"Sesungguhnya hal itu terdapat suatu kebaikan, yang dapat menghapuskan dosa sebagaimana api menghilangkan karat pada perak.\""},{"p":"Muslim","n":4626,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَدِيٍّ وَهُوَ ابْنُ ثَابِتٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ يُحَدِّثُ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى أُحُدٍ فَرَجَعَ نَاسٌ مِمَّنْ كَانَ مَعَهُ فَكَانَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمْ فِرْقَتَيْنِ قَالَ بَعْضُهُمْ نَقْتُلُهُمْ وَقَالَ بَعْضُهُمْ لَا فَنَزَلَتْ{ فَمَا لَكُمْ فِي الْمُنَافِقِينَ فِئَتَيْنِ }و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ ح و حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ حَدَّثَنَا غُنْدَرٌ كِلَاهُمَا عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ نَحْوَهُ","trj":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] dia berkata; aku mendengar ['Abdullah bin Yazid] bercerita dari [Zaid bin Tsabit] bahwa ketika Nabi shallallahu 'alaihi wasallam berangkat ke medan perang Uhud, beberapa orang yang ikut berangkat bersama-sama beliau pulang kembali di tengah perjalanan. Karena itu, para sahabat Nabi shallallahu 'alaihi wasallam berbeda pendapat mengenai mereka menjadi dua golongan: Sebagian mengatakan mereka harus diperangi dan sebagian lagi mengatakan jangan diperangi. Karena itu, turunlah ayat: 'Mengapa kamu menjadi dua golongan dalam (menghadapi) orang-orang munafik…' (QS. An Nisaa (4): 88). Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Yahya bin Sa'id] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepadaku [Abu Bakr bin Nafi'] telah menceritakan kepada kami [Ghundar] keduanya dari [Syu'bah] melalui sanad ini dengan Hadits yang serupa."}],"4:91":[{"p":"Abu Dawud","n":3107,"ar":"حَدَّثَنَا عَبَّادُ بْنُ مُوسَى الْخُتَّلِيُّ أَخْبَرَنَا إِسْمَعِيلُ يَعْنِي ابْنَ جَعْفَرٍ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرٍو عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَلَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ قَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ }الْآيَةَ قَالَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ الْآيَةُ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَكَانَ مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ يُنَادِي أَلَا لَا يَقْرَبَنَّ الصَّلَاةَ سَكْرَانُ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَهَلْ أَنْتُمْ مُنْتَهُونَ }قَالَ عُمَرُ انْتَهَيْنَا","trj":"Telah menceritakan kepada kami ['Abbad bin Musa Al Khuttali] telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Israil] dari [Abu Ishaq] dari ['Amru] dari [Umar bin Al Khathab] ia berkata, \"Tatkala telah turun pengharaman arak Umar berkata, \"Ya Allah, jelaskan kepada kami mengenai arak dengan penjelasan yang memuaskan.\" Kemudian turunlah ayat yang terdapat dalam Surat Al Baqarah (219): '(Mereka bertanya kepadamu tentang khamer dan judi…) '. 'Ammar berkata, \"Kemudian Umar dipanggil dan dibacakan kepadanya ayat tersebut, ia berkata lagi, \"Ya Allah, jelaskan kepada kami mengenai khamer dengan penjelasan yang memuaskan.\" Kemudian turunlah ayat yang terdapat pada Surat An Nisaa` (41): '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…..) ' Penyeru Rasulullah shallallahu 'alaihi wasallam apabila shalat telah ditegakkan maka ia berseru, 'ketahuilah bahwa tidak boleh orang yang mabuk mendekati shalat! ' Kemudian Umar dipanggil dan dibacakanlah ayat tersebut kepadanya, lalu ia berkata, \"Ya Allah jelaskanlah kepada kami mengenai khamer dengan penjelasan yang memuaskan!\" Maka turunlah ayat ini: '(….. apakah kalian akan berhenti?) ' (Qs. Al Maa`idah: 91) Umar berkata, \"Kami telah berhenti.\""},{"p":"Abu Dawud","n":3109,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيِّ حَدَّثَنَا عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }وَ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ وَمَنَافِعُ لِلنَّاسِ }نَسَخَتْهُمَا الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا الْخَمْرُ وَالْمَيْسِرُ وَالْأَنْصَابُ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepada kami [Ali bin Husain] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia membaca: '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…) ' (Qs. An Nisaa`: 41). Dan ayat: '(Mereka bertanya kepadamu tentang khamer dan judi. Katakanlah: \"Pada keduanya terdapat dosa yang besar dan beberapa manfaat bagi manusia.....) ' (Qs. Al Baqarah: 219), ia berkata, \"Kedua ayat tersebut dihapus dan digantikan oleh ayat yang terdapat dalam Surat Al Maaidah: 91: '(Sesungguhnya (meminum) khamar, berjudi, (berkorban untuk) berhala…) '. "},{"p":"Tirmidzi","n":2845,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ أَبِي مَيْسَرَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَاللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ }الْآيَةَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ ثُمَّ قَالَ اللَّهُمَّ بَيِّنَ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا يُرِيدُ الشَّيْطَانُ أَنْ يُوقِعَ بَيْنَكُمْ الْعَدَاوَةَ وَالْبَغْضَاءَ فِي الْخَمْرِ وَالْمَيْسِرِ إِلَى قَوْلِهِ فَهَلْ أَنْتُمْ مُنْتَهُونَ }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ انْتَهَيْنَا انْتَهَيْنَاقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ إِسْرَائِيلَ هَذَا الْحَدِيثُ مُرْسَلٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَمْرِو بْنِ شُرَحْبِيلَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَذَكَرَ نَحْوَهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ يُوسُفَ","trj":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Syurahbil Abu Maisarah] dari [Umar bin Al Khaththab] ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Baqarah; Mereka bertanya kepadamu tentang khamer dan judi. QS Al Baqarah: 219, lalu Umar dipanggil dan dibacakan kepadanya. Setelah itu ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat An Nisa` Hai orang-orang yang beriman, janganlah kamu mendekati shalat sedang kamu mabuk QS An Nisa`: 43. Selanjutnya ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Mai`idah Sesungguhnya syaitan itu bermaksud hendak menimbulkan permusuhan dan kebencian di antara kamu lantaran (meminum) khamar dan berjudi itu, -sampai firmanNya- maka berhentilah kamu (dari mengerjakan pekerjaan itu) QS Al Ma`idah: 91. Umar lalu berkata; \"Kami berhenti, kami berhenti.\" Abu Isa berkata; Hadits ini juga diriwayatkan dari Isra`il secara mursal. Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Abu Maisarah 'Amru bin Syurahbil] bahwa [Umar bin Al Khaththab] berkata; \"Ya Allah, Ya Allah, berilah kami penjelasan tentang khamar dengan penjelasan yang memadai.\" Lalu ia menyebutkan seperti di atas, namun hadits ini lebih shahih dari hadits Muhammad bin Yusuf."}],"4:93":[{"p":"Abu Dawud","n":3610,"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَوْ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَلَمَّا نَزَلَتْ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ مُشْرِكُو أَهْلِ مَكَّةَ قَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَأَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ وَعَمِلَ عَمَلًا صَالِحًا فَأُولَئِكَ يُبَدِّلُ اللَّهُ سَيِّئَاتِهِمْ حَسَنَاتٍ }فَهَذِهِ لِأُولَئِكَ قَالَ وَأَمَّا الَّتِي فِي النِّسَاءِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }الْآيَةَ قَالَ الرَّجُلُ إِذَا عَرَفَ شَرَائِعَ الْإِسْلَامِ ثُمَّ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ لَا تَوْبَةَ لَهُفَذَكَرْتُ هَذَا لِمُجَاهِدٍ فَقَالَ إِلَّا مَنْ نَدِمَ حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي يَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذِهِ الْقِصَّةِ فِي{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }أَهْلِ الشِّرْكِ قَالَ وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Yusuf bin Musa] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Sa'id bin Jubair] atau ia mengatakan; telah menceritakan kepadaku [Al hakam] dari [Sa'id bin Jubair] ia berkata; Aku bertanya [Ibnu Abbas] berkata, \"Ketika ayat dalam surat Al furqan ini turun: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68-, orang-orang musyrik Makkah berkata, \"Kami telah membunuh jiwa yang telah diharamkan oleh Allah dan berbuat syirik kepada-Nya serta melakukan perbuatan keji!\" Allah pun menurunkan ayat: (Kecuali orang-orang yang bertaubat dan, beriman dan beramal shalih; maka kejahatan mereka akan diganti Allah dengan kebajikan..) -Qs. Al Furqan: 70-, maka ayat ini untuk orang-orang musyrik Quraisy tersebut. Ibnu Abbas melanjutkan, \"Sedangkan ayat yang ada dalam surat An Nisa: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam…) -An Nisa: 93- ia mengatakan, \"Seorang laki-laki yang mengetahui hukum-hukum Islam, kemudian ia membunuh seorang mukmin dengan sengaja, maka balasannya adalah neraka jahannam dan tidak ada lagi taubat untuknya.\" Perkataan ini lalu aku sebutkan kepada Mujahid, ia berkomentar, \"Kecuali jika ia (pembunuh) merasa menyesal.\" Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ya'la] dari [Sa'id bin Jubair] dari [Ibnu Abbas] -sebagaimana kisah dalam hadits tersebut- tentang firman Allah: (dan orang-orang yang tidak menyembah tuhan yang lain berserta Allah..) -Qs. Al Furqan: 53- yakni orang-orang musyrik. Ibnu Abbas berkata, \"Lalu turun ayat: (Katakanlah, 'Hai hamba-hamba-Ku yang melampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah') -Qs. Az Zumar: 53-. "},{"p":"Abu Dawud","n":3612,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي مِجْلَزٍفِي قَوْلِهِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }قَالَ هِيَ جَزَاؤُهُ فَإِنْ شَاءَ اللَّهُ أَنْ يَتَجَاوَزَ عَنْهُ فَعَلَ","trj":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Abu Syihab] dari [Sulaiman At Taimi] dari [Abu Mijlaz] tentang firman Allah: (Dan barangsiapa membunuh seorang mukmin dengan sengaja, maka balasannya ialah Jahannam..) -Qs. An Nisa: 93- ia berkata, \"Itu adalah ganjaran baginya, jika Allah akan mengampuninya, maka Allah akan melakukannya.\""},{"p":"Bukhari","n":3409,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ أَوْ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى قَالَ سَلْ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ مَا أَمْرُهُمَا{ وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ لَمَّا أُنْزِلَتْ الَّتِي فِي الْفُرْقَانِ قَالَ مُشْرِكُو أَهْلِ مَكَّةَ فَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَقَدْ أَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ }الْآيَةَ فَهَذِهِ لِأُولَئِكَ وَأَمَّا الَّتِي فِي النِّسَاءِ الرَّجُلُ إِذَا عَرَفَ الْإِسْلَامَ وَشَرَائِعَهُ ثُمَّ قَتَلَ فَجَزَاؤُهُ جَهَنَّمُفَذَكَرْتُهُ لِمُجَاهِدٍ فَقَالَإِلَّا مَنْ نَدِمَ","trj":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] telah menceritakan kepadaku [Sa'id bin Jubair] -atau dia berkata, telah menceritakan kepadaku [Al Hakam] dari [Sa'id bin Jubair] berkata, - 'Abdurrahman bin Abza menyuruhku, katanya; \"Tanyalah kepada Ibnu 'Abbas tentang dua ayat ini dan apa maksudnya, yaitu yang pertama firman Allah dalam QS al Isra` ayat 33; (\"Dan janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan haq (alasan yang benar) \" dan yang kedua firman Allah dalam QS an Nisaa' ayat 93: (\"Dan barangsiapa yang membunuh orang beriman dengan sengaja...\"). Maka aku bertanya kepada [Ibnu 'Abbas], maka dia menjelaskan; Ketika turun firman Allah yang serupa ini pada surah al Furqan, orang-orang musyrik penduduk Makkah berkata; \"Sungguh kita telah membunuh jiwa yang diharamkan Allah dan kita juga menyembah selain Allah dan kita telah banyak berbuat maksiat, maka Allah menurunkan firman-Nya yang artinya: \"...kecuali siapa yang bertaubat dan beriman...\" (QS al Furqan ayat 70). Nah, ayat-ayat ini turun untuk mereka. Adapun ayat yang ada dalam surah an Nisaa' adalah bila seseorang telah mengenal Islam dan syari'atnya, kemudian dia membunuh seseorang dengan sengaja maka balasan baginya adalah neraka jahannam\". Kemudian keterangan ini aku sampaikan kepada Mujahidmaka dia berkata; \"Kecuali siapa yang menyesali perbuartannya\"."},{"p":"Bukhari","n":3919,"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُغِيرَةُ بْنُ النُّعْمَانِ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ قَالَآيَةٌ اخْتَلَفَ فِيهَا أَهْلُ الْكُوفَةِ فَرَحَلْتُ فِيهَا إِلَى ابْنِ عَبَّاسٍ فَسَأَلْتُهُ عَنْهَا فَقَالَ نَزَلَتْ هَذِهِ الْآيَةُ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }هِيَ آخِرُ مَا نَزَلَ وَمَا نَسَخَهَا شَيْءٌ","trj":"Telah menceritakan kepada kami [Adam bin Abu Iyas] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Mughirah bin An Nu'man] ia berkata; Aku mendengar [Sa'id bin Jubair] berkata; ada sebuah ayat yang menyebabkan penduduk Kufah berselisih tentangnya, maka aku berangkat menemui Ibnu Abbas untuk menanyakan ayat itu. Lalu [Ibnu Abbas] berkata; Yaitu ayat: \"Dan barangsiapa yang membunuh seorang mukmin dengan sengaja maka balasannya ialah Jahannam, kekal ia di dalamnya dan Allah murka kepadanya.\" (An Nisa: 93). Ayat ini adalah ayat yang terakhir turun dari surat An Nisa, tidak ada yang menghapusnya sedikitpun."}],"4:94":[{"p":"Abu Dawud","n":3373,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَحِقَ الْمُسْلِمُونَ رَجُلًا فِي غُنَيْمَةٍ لَهُ فَقَالَ السَّلَامُ عَلَيْكُمْ فَقَتَلُوهُ وَأَخَذُوا تِلْكَ الْغُنَيْمَةَ فَنَزَلَتْ{ وَلَا تَقُولُوا لِمَنْ أَلْقَى إِلَيْكُمْ السَّلَامَ لَسْتَ مُؤْمِنًا تَبْتَغُونَ عَرَضَ الْحَيَاةِ الدُّنْيَا }تِلْكَ الْغُنَيْمَةَ","trj":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru bin Dinar] dari ['Atha] dari [Ibnu Abbas] ia berkata, \"Orang-orang muslim bertemu dengan seorang laki-laki yang membawa kambingnya, kemudian ia mengucapkan, 'Assalaamu 'alaikum! ' Lalu mereka membunuhnya dan mengambil kambing tersebut. Maka turunlah ayat: '(Dan janganlah kamu mengatakan kepada orang yang mengucapkan 'salam' kepadamu: 'Kamu bukan seorang mukmin' (lalu kamu membunuhnya), dengan maksud mencari harta benda kehidupan di dunia) ' (Qs. An Nisaa: 94), yaitu kambing tersebut.\""},{"p":"Abu Dawud","n":3611,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }قَالَ مَا نَسَخَهَا شَيْءٌ","trj":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami ['Abdurrahman] berkata, telah menceritakan kepada kami [Sufyan] dari [Al Mughirah bin Nu'man] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Firman Allah: (Dan barangsiapa membunuh seorang mukmin dengan sengaja…) -Qs. An Nisa: 94-, tidak pernah dihapus oleh ayat manapun.\""}],"4:95":[{"p":"Muslim","n":3276,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ أَنَّهُ سَمِعَ الْبَرَاءَ يَقُولُا فِي هَذِهِ الْآيَةِ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا فَجَاءَ بِكَتِفٍ يَكْتُبُهَا فَشَكَا إِلَيْهِ ابْنُ أُمِّ مَكْتُومٍ ضَرَارَتَهُ فَنَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ غَيْرُ أُولِي الضَّرَرِ }قَالَ شُعْبَةُ وَأَخْبَرَنِي سَعْدُ بْنُ إِبْرَاهِيمَ عَنْ رَجُلٍ عَنْ زَيْدِ بْنِ ثَابِتٍ فِي هَذِهِ الْآيَةِ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }بِمِثْلِ حَدِيثِ الْبَرَاءِ و قَالَ ابْنُ بَشَّارٍ فِي رِوَايَتِهِ سَعْدُ بْنُ إِبْرَاهِيمَ عَنْ أَبِيهِ عَنْ رَجُلٍ عَنْ زَيْدِ بْنِ ثَابِتٍ","trj":"Telah menceritakan kepada kami [Muhammad bin Mutsanna] dan [Muhammad bin Basysyar] dan ini adalah lafadz Ibnu Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] bahwa dia pernah mendengar [Al Barra] berkomentar sehubungan dengan ayat ini: '(Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) dengan orang-orang yang berjihad di jalan Allah …) ' (Qs. An Nisaa: 95), dan orang-orang yang berjihad di jalan Allah, kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan Zaid bin Tsabit untuk menulis ayat tersebut. Lalu Zaid datang dengan membawa tulang (pundak) kambing untuk menulis ayat tersebut. Tiba-tiba datanglah Ibnu Ummi Maktum mengadukan kesulitannya, tidak dapat turut berperang karena buta. Kemudian turunlah ayat: '(Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) yang tidak mempunyai 'uzur dengan orang-orang yang berjihad di jalan Allah…) ' [Syu'bah] berkata; dan telah mengabarkan kepadaku [Sa'd bin Ibrahim] dari [seorang laki-laki] dari [Zaid bin Tsabit] berhubungan dengan ayat ini: '(Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) …) ' seperti hadits Al Barra.\" Dan [Ibnu Basysyar] menyebutkan dalam riwayatnya; [Sa'd bin Ibrahim] dari [ayahnya] dari [seorang laki-laki] dari [Zaid bin Tsabit].\""},{"p":"Muslim","n":3277,"ar":"و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ بِشْرٍ عَنْ مِسْعَرٍ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ الْبَرَاءِ قَالَلَمَّا نَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }كَلَّمَهُ ابْنُ أُمِّ مَكْتُومٍ فَنَزَلَتْ{ غَيْرُ أُولِي الضَّرَرِ }","trj":"Dan telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Ibnu Bisyr] dari [Mis'ar] telah menceritakan kepadaku [Abu Ishaq] dari [Al Barra] dia berkata, \"Tatkala turunnya ayat: '(Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) …' (Qs. An Nisaa: 95), lalu Ibnu Ummi Maktum protes, maka setelah itu turunlah: '(yang tidak mempunyai 'uzur).\""},{"p":"Tirmidzi","n":1593,"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ائْتُونِي بِالْكَتِفِ أَوْ اللَّوْحِ فَكَتَبَ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }وَعَمْرُو بْنُ أُمِّ مَكْتُومٍ خَلْفَ ظَهْرِهِ فَقَالَ هَلْ لِي مِنْ رُخْصَةٍ فَنَزَلَتْ{ غَيْرُ أُولِي الضَّرَرِ }وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَجَابِرٍ وَزَيْدِ بْنِ ثَابِتٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي إِسْحَقَ وَقَدْ رَوَى شُعْبَةُ وَالثَّوْرِيُّ عَنْ أَبِي إِسْحَقَ هَذَا الْحَدِيثَ","trj":"Telah menceritakan kepada kami [Nashr bin Ali Al jahdhami] berkata, telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Bapaknya] dari [Abu Ishaq] dari [Al Barra` bin Azib] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berikan aku lembaran itu.\" Beliau kemudian menulis '(Tidaklah sama antara mu'min yang duduk (yang tidak ikut berperang)) ' -Qs. An Nisa: 95-, sementara Amru bin Ummi Maktum berada di belakang beliau. Amru berkata, \"Apakah ada keringanan untukku?\" lalu turunlah ayat: '(selain orang yang mempunyai 'uzur) ' -Qs. An Nisa: 95-Dalam bab ini juga ada hadits dari Ibnu Abbas, Jabir dan Zaid bin Tsabit. Hadits ini derajatnya hasan shahih, tetapi hadits ini termasuk hadits gharib riwayat Sulaiman At Taimi dari Abu Ishaq. [Syu'bah] dan [Ats Tsauri] juga meriwayatkan hadits ini dari [Abu Ishaq].\""}],"4:97":[{"p":"Bukhari","n":2619,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُ يَقُولُلَمَّا نَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }دَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا فَجَاءَ بِكَتِفٍ فَكَتَبَهَا وَشَكَا ابْنُ أُمِّ مَكْتُومٍ ضَرَارَتَهُ فَنَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ غَيْرُ أُولِي الضَّرَرِ }","trj":"Telah bercerita kepada kami [Abu Al Walid] telah bercerita kepada kami [Syu'bah] dari [Abu Ishaq] berkata aku mendengar [Al Bara' radliallahu 'anhu] berkata; Ketika turun ayat 97 Surah an-Nisaa' yang artinya (\"Tidaklah sama orang-orang yang duduk-duduk saja (tidak ikut berperang) dari kalangan Kaum Mu'minin…\"), Rasulullah shallallahu 'alaihi wasallam memanggil Zaid, maka dia datang dengan membawa papan tulis lalu dia menulis ayat itu. Kemudian Ummu Maktum datang mengadukan alasannya, maka turunlah ayat ini (\"Tidaklah sama orang-orang yang duduk-duduk saja (tidak ikut berperang) dari kalangan Kaum Mu'minin tanpa memiliki alasan…\"), "},{"p":"Bukhari","n":2620,"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ الزُّهْرِيُّ قَالَ حَدَّثَنِي صَالِحُ بْنُ كَيْسَانَ عَنْ ابْنِ شِهَابٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ أَنَّهُ قَالَ رَأَيْتُ مَرْوَانَ بْنَ الْحَكَمِ جَالِسًا فِي الْمَسْجِدِ فَأَقْبَلْتُ حَتَّى جَلَسْتُ إِلَى جَنْبِهِ فَأَخْبَرَنَا أَنَّ زَيْدَ بْنَ ثَابِتٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْلَى عَلَيْهِ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }{ وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ }قَالَ فَجَاءَهُ ابْنُ أُمِّ مَكْتُومٍ وَهُوَ يُمِلُّهَا عَلَيَّ فَقَالَ يَا رَسُولَ اللَّهِ لَوْ أَسْتَطِيعُ الْجِهَادَ لَجَاهَدْتُ وَكَانَ رَجُلًا أَعْمَى فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفَخِذُهُ عَلَى فَخِذِي فَثَقُلَتْ عَلَيَّ حَتَّى خِفْتُ أَنَّ تَرُضَّ فَخِذِي ثُمَّ سُرِّيَ عَنْهُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ غَيْرُ أُولِي الضَّرَرِ }","trj":"Telah bercerita kepada kami ['Abdul 'Aziz bin 'Abdullah] telah bercerita kepada kami [Ibrahim bin Sa'ad Az Zuhriy] berkata telah bercerita kepadaku [Shalih bin Kaisan] dari [Ibnu Syihab] dari [Sahal bin Sa'ad As-Sa'idiy] bahwa dia berkata: \"Aku melihat [Marwan bin Al Hakam] sedang duduk di masjid lalu aku menemuinya hingga aku duduk di sampingnya lalu dia mengabarkan kepada kami bahwa [Zaid bin Tsabit] mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam membacakan ayat 97 Surah an-Nisaa' kepadanya yang artinya (\"Tidaklah sama orang-orang yang duduk-duduk saja (tidak ikut berperang) dari kalangan Kaum Mu'minin dengan orang-orang yang berjihad fii sabilillah…\"), maka datang Ibnu Ummu Maktum kepada Beliau padahal Beliau sedang membacakan ayat itu kepadaku dengan berkata: \"Wahai Rasulullah, seandainya aku mampu berjihad pasti aku akan berjihad\". Dia adalah seorang yang buta. Maka Allah Tabaaraka Wa Ta'ala menurunkan ayat kepada Rosul-Nya pada saat paha Beliau sedang berada diatas pahaku dan aku merasa berat dengan paha Beliau tersebut (karena beratnya wahyu yang Beliau terima) hingga aku khawatir pahaku retak. Kemudian Beliau tenang kembali. Maka Allah 'AZZA WAJALLA menurunkan firman-Nya (kelanjutan ayat tersebut) yang artinya: (\"Yang tanpa memiliki alasan…\")."},{"p":"Bukhari","n":3490,"ar":"بَاب حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي عَبْدُ الْكَرِيمِ أَنَّهُ سَمِعَ مِقْسَمًا مَوْلَى عَبْدِ اللَّهِ بْنِ الْحَارِثِ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ سَمِعَهُ يَقُولُ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }عَنْ بَدْرٍ وَالْخَارِجُونَ إِلَى بَدْرٍ","trj":"Bab. Telah menceritakan kepadaku [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] bahwa [Ibnu Juraij] telah mengabarkan kepada mereka, katanya telah mengabarkan kepadaku ['Abdul Karim] bahwa dia mendengar [Miqsam, maula 'Abdullah bin Al Harits] menceritakan dari [Ibnu 'Abbas] bahwanya dia mendengarnya menjelaskan firman Allah dalam QS an-Nisaa' ayat 97 yang artinya (\"Tidak sama orang-orang yang duduk dari orang beriman....\".) maksudnya adalah tentang perang Badar dan orang-orang yang keluar ikut perang Badar\"."}],"4:101":[{"p":"Darimi","n":1113,"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَ قُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ قَالَ اللَّهُ تَعَالَى { أَنْ تَقْصُرُوا مِنْ الصَّلَاةِ إِنْ خِفْتُمْ } فَقَدْ أَمِنَ النَّاسُ قَالَ عَجِبْتُ مِمَّا عَجِبْتَ مِنْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَةٌ تَصَدَّقَ اللَّهُ بِهَا عَلَيْكُمْ فَاقْبَلُوهَا","trj":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Abu 'Ammar] dari [Abdullah bin Babaih] dari [Ya'la bin Umayyah] ia berkata, \"Aku katakan kepada [Umar bin Al Khathab, \"Allah Ta'ala berfirman: '(Kamu men-qashar sembahyang(mu), jika kamu takut) ' (Qs. An Nisa: 101). Sementara orang-orang sekarang telah merasa aman?\" Umar menjawab, \"Aku juga pernah heran sebagaimana engkau heran. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah sedekah yang telah Allah berikan kepada kalian, maka terimalah sedekah-Nya.\""},{"p":"Nasa'i","n":1407,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ ابْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَقُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَقْصُرُوا مِنْ الصَّلَاةِ إِنْ خِفْتُمْ أَنْ يَفْتِنَكُمْ الَّذِينَ كَفَرُوا }فَقَدْ أَمِنَ النَّاسُ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ عَجِبْتُ مِمَّا عَجِبْتَ مِنْهُ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ صَدَقَةٌ تَصَدَّقَ اللَّهُ بِهَا عَلَيْكُمْ فَاقْبَلُوا صَدَقَتَهُ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdullah bin Idris] dia berkata; telah memberitakan kepada kami [Ibnu Juraij] dari [Ibnu Abu 'Ammar] dari ['Abdullah bin Babaih] dari [Ya'la bin Umayyah] dia berkata;? ku pernah bertanya kepada ['Umar bin Al Khaththab] tentang ayat, 'Tidaklah apa-apa bagi kalian untuk mengqashar/meringkas shalat jika kalian takut (khawatir) diserang orang-orang kafir'. (Qs. An-Nisaa' (4): 101), bukankah sekarang manusia sudah merasa aman?!\" Lalu Umar menjawab, \"Aku juga heran seperti kamu, dan aku juga pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam seperti itu? Beliau menjawab: 'Itu sedekah yang Allah sedekahkan kepada kalian, maka terimalah sedekah-Nya'.\""}],"4:102":[{"p":"Nasa'i","n":1378,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ يُحَدِّثُ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَّمَنَا خُطْبَةَ الْحَاجَةِ الْحَمْدُ لِلَّهِ نَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا وَسَيِّئَاتِ أَعْمَالِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَقْرَأُ ثَلَاثَ آيَاتٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَثَّ مِنْهُمَا رِجَالًا كَثِيرًا وَنِسَاءً وَاتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ وَالْأَرْحَامَ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا }قَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو عُبَيْدَةَ لَمْ يَسْمَعْ مِنْ أَبِيهِ شَيْئًا وَلَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَلَا عَبْدُ الْجَبَّارِ بْنُ وَائِلِ بْنِ حُجْرٍ","trj":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Abu Ishaq] menceritakan dari [Abu 'Ubaidah] dari ['Abdullah] dari Nabi Shalallahu 'Alaihi Wa Sallam. Abdullah berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam telah mengajarkan Khutbah Hajah kepada kami, yaitu, 'Segala puji bagi Allah, kita memohon pertolongan dan ampunan kepadanya, berlindung kepadanya dari kejahatan jiwa kami dan kejelekan perbuatan-perbuatan kami. Barang siapa yang diberikan petunjuk oleh Allah, maka tidak akan ada yang bisa menyesatkannya. Barangsiapa yang telah Allah sesatkan, maka tidak akan ada yang bisa memberinya petunjuk. Aku bersaksi tiada tuhan (yang berhak disembah) kecuali Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusannya'. Kemudian beliau membaca tiga ayat berikut ini: 'Wahai orang-orang yang beriman, bertakwalah kepada Allah dengan sebenar-benar takwa kepadanya, dan janganlah kamu mati melainkan dalam keadaan beragama Islam'. (Qs. Ali 'Imran (3): 102). 'Hai kalian manusia, bertakwalah kepada tuhanmu yang telah menciptakanmu dari diri yang satu, dan daripadanya Allah menciptakan istrinya, dan daripada keduanya Allah memperkembangbiakan laki-laki dan perempuan yang banyak, dan bertakwalah kepada Allah dengan (mempergunakan) nama-Nya kamu saling meminta satu dengan yang lain, dan (periharalah) hubungan Silaturrahim. Sesungguhnya Allah selalu menjaga dan mengawasimu'.\"(Qs. An-Nisaa'(4): 1). 'Hai orang-orang yang beriman, bertakwalah kepada Allah dan katakanlah perkataan yang benar'.\"(Qs. Al Ahzaab (33): 70). Abu Abdurrahman berkata; Abu Ubaidah tidak pernah mendengar dari Bapaknya sedikitpun, demikian juga Abdurrahman bin Abdullah bin Mas'ud dan Abdul Jabbar bin Wa'il bin Hujr. "}],"4:123":[{"p":"Muslim","n":4329,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبْي شَيْبَةَ كِلَاهُمَا عَنْ ابْنِ عُيَيْنَةَ وَاللَّفْظُ لِقُتَيْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ مُحَيْصِنٍ شَيْخٍ مِنْ قُرَيْشٍ سَمِعَ مُحَمَّدَ بْنَ قَيْسِ بْنِ مَخْرَمَةَ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا نَزَلَتْ{ مَنْ يَعْمَلْ سُوءًا يُجْزَ بِهِ }بَلَغَتْ مِنْ الْمُسْلِمِينَ مَبْلَغًا شَدِيدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَارِبُوا وَسَدِّدُوا فَفِي كُلِّ مَا يُصَابُ بِهِ الْمُسْلِمُ كَفَّارَةٌ حَتَّى النَّكْبَةِ يُنْكَبُهَا أَوْ الشَّوْكَةِ يُشَاكُهَاقَالَ مُسْلِم هُوَ عُمَرُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ مُحَيْصِنٍ مِنْ أَهْلِ مَكَّةَ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Abu Bakr bin Abu Syaibah] keduanya dari [Ibnu 'Uyainah] dan lafazh ini milik Qutaibah; Telah menceritakan kepada kami [Sufyan] dari [Ibnu Muhaishin] seorang syaikh dari bangsa Quraisy, dia mendengar [Muhammad bin Qais bin Makhramah] bercerita dari [Abu Hurairah] dia berkata; \"Tatkala telah turun ayat yang mengatakan: \"Ketika turun ayat Al Qur'an yang berbunyi Barang siapa berbuat kejelekan, niscaya ia akan dibalas dengan kejelekan (siksa) (Qs. An-Nisaa'(4): 123), maka kaum muslimin pun merasa prihatin. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: 'Janganlah kalian berlebihan, tempuhlah kejujuran dan perbaikilah dirimu. Sesungguhnya setiap musibah yang menimpa seorang muslim itu adalah sebagai penghapus dosa, termasuk pula jika ia terantuk batu ataupun tertusuk duri.' Muslim berkata; 'Dia adalah Umar bin Abdurrahman bin Muhshin dari penduduk Makkah."}],"4:126":[{"p":"Bukhari","n":2557,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ كَانَ عُرْوَةُ بْنُ الزُّبَيْرِ يُحَدِّثُ أَنَّهُ سَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ هِيَ الْيَتِيمَةُ فِي حَجْرِ وَلِيِّهَا فَيَرْغَبُ فِي جَمَالِهَا وَمَالِهَا وَيُرِيدُ أَنْ يَتَزَوَّجَهَا بِأَدْنَى مِنْ سُنَّةِ نِسَائِهَا فَنُهُوا عَنْ نِكَاحِهِنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ فِي إِكْمَالِ الصَّدَاقِ وَأُمِرُوا بِنِكَاحِ مَنْ سِوَاهُنَّ مِنْ النِّسَاءِ قَالَتْ عَائِشَةُ ثُمَّ اسْتَفْتَى النَّاسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ قُلْ اللَّهُ يُفْتِيكُمْ فِيهِنَّ }قَالَتْ فَبَيَّنَ اللَّهُ فِي هَذِهِ الْآيَةِ أَنَّ الْيَتِيمَةَ إِذَا كَانَتْ ذَاتَ جَمَالٍ وَمَالٍ رَغِبُوا فِي نِكَاحِهَا وَلَمْ يُلْحِقُوهَا بِسُنَّتِهَا بِإِكْمَالِ الصَّدَاقِ فَإِذَا كَانَتْ مَرْغُوبَةً عَنْهَا فِي قِلَّةِ الْمَالِ وَالْجَمَالِ تَرَكُوهَا وَالْتَمَسُوا غَيْرَهَا مِنْ النِّسَاءِ قَالَ فَكَمَا يَتْرُكُونَهَا حِينَ يَرْغَبُونَ عَنْهَا فَلَيْسَ لَهُمْ أَنْ يَنْكِحُوهَا إِذَا رَغِبُوا فِيهَا إِلَّا أَنْ يُقْسِطُوا لَهَا الْأَوْفَى مِنْ الصَّدَاقِ وَيُعْطُوهَا حَقَّهَا","trj":"Telah bercerita kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata ['Urwah bin Az Zubair] bercerita bahwa dia pernah bertanya kepada ['Aisyah radliallahu 'anha] tentaang firman Allah QS an-Nisaa' ayat 3 yang artinya: (Dan jika kamu takut tidak akan dapat berlaku adil terhadap (hak-hak) perempuan yang yatim (bilamana kamu mengawininya), maka kawinilah wanita-wanita (lain) yang kamu senangi …). 'Aisyah menjawab: \"Yang dimaksud ayat itu adalah seorang anak perempuan yatim yang berada pada asuhan walinya, lalu walinya itu tertarik dengan kecantikan dan hartanya dan berhasrat untuk mengawininya namun memberikan haknya lebih rendah dari yang biasa diberikan kepada istri-istrinya sebelumnya maka mereka dilarang menikahinya kecuali bila mereka dapat berlaku adil kepada mereka, dan mereka diperintahkan untuk menikahi wanita-wanita lain selain mereka\". 'Aisyah berkata: \"Kemudian orang-orang meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam setelah itu, maka Allah 'azza wajalla menurunkan firman-Nya QS an-Nisaa' ayat 126 yang artinya (dan mereka meminta fatwa kepadamu tentang para wanita. Katakanlah; Allah akan memberikan fatwa kepada kalian tentang mereka..) 'Aisyah berkata: \"Maka Allah menjelaskan dalam ayat ini bahwa seorang anak yatim perempuan jika memiliki kecantikan dan harta lalu walinya berhasrat menikahinya namun tidak memberikan haknya dengan melengkapi mahar sebagaimana semestinya. Namun bila anak yatim perempuan itu tidak memiliki harta dan kecantikan mereka meninggalkannya dan mencari wanita selain mereka\". Beliau bersabda: \"Sebagaimana mereka tidak menyukainya disebabkan sedikit hartanya dan tidak cantik lalu meninggalkannya maka mereka juga tidak boleh menikahinya saat tertarik kecuali bila mereka dapat berlaku adil kepadanya dengan menunaikan maharnya secara wajar serta memberikan hak-haknya\"."}],"4:127":[{"p":"Bukhari","n":6116,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ كَانَ عُرْوَةُ يُحَدِّثُ أَنَّهُ سَأَلَ عَائِشَةَ{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ هِيَ الْيَتِيمَةُ فِي حَجْرِ وَلِيِّهَا فَيَرْغَبُ فِي مَالِهَا وَجَمَالِهَا فَيُرِيدُ أَنْ يَتَزَوَّجَهَا بِأَدْنَى مِنْ سُنَّةِ نِسَائِهَا فَنُهُوا عَنْ نِكَاحِهِنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ فِي إِكْمَالِ الصَّدَاقِ ثُمَّ اسْتَفْتَى النَّاسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ فَأَنْزَلَ اللَّهُ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ }فَذَكَرَ الْحَدِيثَ","trj":"Telah menceritakan kepada kami [Abul Yaman] telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] mengatakan, [Urwah] menceritakan; ia bertanya [Aisyah] tentang ayat; 'Jika kalian khawatir tidak bisa berbuat adil terhadap yatimmu, maka nikahilah wanita yang baik-baik bagimu, dua, tiga, atau empat (QS. Annisa'; 3) dia mengatakan; 'yaitu yatim dalam asuhan walinya, dan si wali tersebut kurang menyukai kecantikan dan hartanya, namun tetap akan ia nikahi dengan syarat membayar mahar serendah-rendahnya yang menyalahi adat normal. Maka mereka dilarang menikahi anak-anak yatim tersebut kecuali jika berbuat adil dengan membayar mahar secara sempurna, lantas para sahabat bertanya kepada Rasulullah shallallahu 'alaihi wasallam di kemudian hari, maka Allah menurunkan ayat; 'Mereka meminta fatwa kepadamu,,, dan seterusnya (QS. Annisa' 127), kemudian dia menyebutkan hadits."}],"4:128":[{"p":"Bukhari","n":2270,"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَافِي هَذِهِ الْآيَةِ{ وَإِنْ امْرَأَةٌ خَافَتْ مِنْ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا }قَالَتْ الرَّجُلُ تَكُونُ عِنْدَهُ الْمَرْأَةُ لَيْسَ بِمُسْتَكْثِرٍ مِنْهَا يُرِيدُ أَنْ يُفَارِقَهَا فَتَقُولُ أَجْعَلُكَ مِنْ شَأْنِي فِي حِلٍّ فَنَزَلَتْ هَذِهِ الْآيَةُ فِي ذَلِكَ","trj":"Telah menceritakan kepada kami [Muhamamad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] tentang ayat ini QS An-Nisaa: 128): (\"Apabila seorang isteri takut suaminya akan berbuat nusyuz (tidak mau menggaulinya) atau berlaku kasar terhadapnya\"), dia ('Aisyah radliallahu 'anha) berkata: \"Yaitu jika seorang suami yang memiliki isteri namun dia tidak lagi mencintai dan menggaulinya serta berkehendak untuk menceraikanya lalu isterinya berkata, \"aku persilakan kamu meninggalkan aku namun jangan ceraikan aku\", maka turunlah ayat ini\". "},{"p":"Bukhari","n":2497,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ وَإِنْ امْرَأَةٌ خَافَتْ مِنْ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا }قَالَتْ هُوَ الرَّجُلُ يَرَى مِنْ امْرَأَتِهِ مَا لَا يُعْجِبُهُ كِبَرًا أَوْ غَيْرَهُ فَيُرِيدُ فِرَاقَهَا فَتَقُولُ أَمْسِكْنِي وَاقْسِمْ لِي مَا شِئْتَ قَالَتْ فَلَا بَأْسَ إِذَا تَرَاضَيَا","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'ad] telah menceritakan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa ayat yang berbunyi: QS An-Nisaa: 128): (\"Apabila seorang isteri takut suaminya akan berbuat nusyuz (tidak mau menggaulinya) atau berlaku kasar terhadapnya\"), dia ('Aisyah radliallahu 'anha) berkata: \"Itu adalah seorang suami yang melihat pada isterinya apa-apa yang tidak menyenangkannya berupa pelanggaran dosa besar atau lainnya lalu dia berniat menceraikan isterinya lalu isterinya itu berkata: \"Pertahankanlah aku dan bersumpahlah kepadaku terserah apa saja yang kamu kehendaki\". 'Aisyah radliallahu 'anha berkata: \"Maka tidak berdosa bila keduanya saling ridho\"."}],"4:159":[{"p":"Bukhari","n":3134,"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ سَعِيدَ بْنَ الْمُسَيَّبِ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَيُوشِكَنَّ أَنْ يَنْزِلَ فِيكُمْ ابْنُ مَرْيَمَ حَكَمًا عَدْلًا فَيَكْسِرَ الصَّلِيبَ وَيَقْتُلَ الْخِنْزِيرَ وَيَضَعَ الْجِزْيَةَ وَيَفِيضَ الْمَالُ حَتَّى لَا يَقْبَلَهُ أَحَدٌ حَتَّى تَكُونَ السَّجْدَةُ الْوَاحِدَةُ خَيْرًا مِنْ الدُّنْيَا وَمَا فِيهَا ثُمَّ يَقُولُ أَبُو هُرَيْرَةَ وَاقْرَءُوا إِنْ شِئْتُمْ{ وَإِنْ مِنْ أَهْلِ الْكِتَابِ إِلَّا لَيُؤْمِنَنَّ بِهِ قَبْلَ مَوْتِهِ وَيَوْمَ الْقِيَامَةِ يَكُونُ عَلَيْهِمْ شَهِيدًا }","trj":"Telah bercerita kepada kami [Ishaq] telah mengabarkan kepada kami [Ya'qub binIbrahim] telah bercerita kepada kami [bapakku] dari [Shalih] dari [Ibnu Syihab] bahwa [Sa'id bin Al Musayyab] mendengar [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam besabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, diprediksikan segera turun kepada kalian 'Isa bin Maryam sebagai hakim yang adil, dia akan menghancurkan salib, membunuh babi, membebaskan jizyah dan harta benda akan banyak tersebar sehingga tidak ada seorangpun yag mau menerima (shadaqah) hingga pada masa itu satu kali sujud lebih baik daripada dunia dan isinya\". Kemudian Abu Hurairah radliallahu 'anhu berkata; \"Bacalah firman Allah jika kamu mau; (\"Dan tidak ada satu pun dari Ahli Kitab kecuali pasti akan beriman kepadanya ('Isa 'alahis salam) sebelum kematiannya dan pada hari qiyamat nanti 'Isa akan menjadi saksi bagi mereka\"). (QS an-Nisaa ayat 159)."},{"p":"Muslim","n":219,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَيُوشِكَنَّ أَنْ يَنْزِلَ فِيكُمْ ابْنُ مَرْيَمَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَكَمًا مُقْسِطًا فَيَكْسِرَ الصَّلِيبَ وَيَقْتُلَ الْخِنْزِيرَ وَيَضَعَ الْجِزْيَةَ وَيَفِيضُ الْمَالُ حَتَّى لَا يَقْبَلَهُ أَحَدٌو حَدَّثَنَاه عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ ح و حَدَّثَنِيهِ حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنِي يُونُسُ ح و حَدَّثَنَا حَسَنٌ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ عَنْ يَعْقُوبَ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ كُلُّهُمْ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ وَفِي رِوَايَةِ ابْنِ عُيَيْنَةَ إِمَامًا مُقْسِطًا وَحَكَمًا عَدْلًا وَفِي رِوَايَةِ يُونُسَ حَكَمًا عَادِلًا وَلَمْ يَذْكُرْ إِمَامًا مُقْسِطًا وَفِي حَدِيثِ صَالِحٍ حَكَمًا مُقْسِطًا كَمَا قَالَ اللَّيْثُ وَفِي حَدِيثِهِ مِنْ الزِّيَادَةِ وَحَتَّى تَكُونَ السَّجْدَةُ الْوَاحِدَةُ خَيْرًا مِنْ الدُّنْيَا وَمَا فِيهَا ثُمَّ يَقُولُا أَبُو هُرَيْرَةَ اقْرَءُوا إِنْ شِئْتُمْ{ وَإِنْ مِنْ أَهْلِ الْكِتَابِ إِلَّا لَيُؤْمِنَنَّ بِهِ قَبْلَ مَوْتِهِ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits]. (dalam jalur lain disebutkan) Dan telah menceritakan kepada kami [Muhammad bin Rumh] telah mengabarkan kepada kami [al-Laits] dari [Ibnu Syihab] dari [Ibnu al-Musayyab] bahwa dia mendengar [Abu Hurairah] mengatakan, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya! Sungguh, kedatangan Isa bin Mariam kepada kalian untuk menjadi hakim secara adil akan segera tiba. Dia akan mematahkan salib, membunuh babi serta menghapuskan jizyah (dari orang kafir). Harta akan melimpah ruah, sehingga tidak ada seorang pun yang ingin menerimanya.\" Dan telah menceritakannya kepada kami [Abdul A'la bin Hammad] dan [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] mereka berkata; telah menceritakan kepada kami [Sufyan bin Uyainah]. (dalam riwayat lain disebutkan) Dan telah menceritakannya kepadaku tentangnya [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahab] dia berkata, telah menceritakan kepadaku [Yunus]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Hasan al-Hulwani] dan ['Abd bin Humaid] dari [Ya'qub bin Ibrahim bin Sa'id] telah menceritakan kepada kami [ayahku] dari [Shalih] seluruhnya dari [Az-Zuhri] dengan isnad ini. Dan dalam riwayat Ibnu Uyainah disebutkan, \"Sebagai imam yang adil dan hakim yang adil.\" Sedangkan dalam riwayat Yunus, \"Sebagai hakim yang adil, \" dan tidak menyebutkan, \"imam yang adil.\" Sedangkan dalam riwayat Shalih, \"Hakim yang adil.\" Sebagaimana dikatakan al-Laits, dan dalam haditsnya terdapat tambahan, \"hingga satu sujud lebih baik daripada dunia dan seisinya.\" Kemudian Abu Hurairah berkata, \"Bacalah jika kalian berkehendak: '(Tidak ada seorang pun dari Ahli Kitab, kecuali akan beriman kepadanya (Isa) sebelum kematiannya) ' (Qs. an-Nisaa': 159)."}],"4:164":[{"p":"Darimi","n":46,"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا زَمْعَةُ عَنْ سَلَمَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ جَلَسَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْتَظِرُونَهُ فَخَرَجَ حَتَّى إِذَا دَنَا مِنْهُمْ سَمِعَهُمْ يَتَذَاكَرُونَ فَتَسَمَّعَ حَدِيثَهُمْ فَإِذَا بَعْضُهُمْ يَقُولُ عَجَبًا إِنَّ اللَّهَ اتَّخَذَ مِنْ خَلْقِهِ خَلِيلًا فَإِبْرَاهِيمُ خَلِيلُهُ وَقَالَ آخَرُ مَاذَا بِأَعْجَبَ مِنْ { وَكَلَّمَ اللَّهُ مُوسَى تَكْلِيمًا } وَقَالَ آخَرُ فَعِيسَى كَلِمَةُ اللَّهِ وَرُوحُهُ وَقَالَ آخَرُ وَآدَمُ اصْطَفَاهُ اللَّهُ فَخَرَجَ عَلَيْهِمْ فَسَلَّمَ وَقَالَ قَدْ سَمِعْتُ كَلَامَكُمْ وَعَجَبَكُمْ أَنَّ إِبْرَاهِيمَ خَلِيلُ اللَّهِ وَهُوَ كَذَلِكَ وَمُوسَى نَجِيُّهُ وَهُوَ كَذَلِكَ وَعِيسَى رُوحُهُ وَكَلِمَتُهُ وَهُوَ كَذَلِكَ وَآدَمُ اصْطَفَاهُ اللَّهُ تَعَالَى وَهُوَ كَذَلِكَ أَلَا وَأَنَا حَبِيبُ اللَّهِ وَلَا فَخْرَ وَأَنَا حَامِلُ لِوَاءِ الْحَمْدِ يَوْمَ الْقِيَامَةِ تَحْتَهُ آدَمُ فَمَنْ دُونَهُ وَلَا فَخْرَ وَأَنَا أَوَّلُ شَافِعٍ وَأَوَّلُ مُشَفَّعٍ يَوْمَ الْقِيَامَةِ وَلَا فَخْرَ وَأَنَا أَوَّلُ مَنْ يُحَرِّكُ بِحَلَقِ الْجَنَّةِ وَلَا فَخْرَ فَيَفْتَحُ اللَّهُ فَيُدْخِلُنِيهَا وَمَعِي فُقَرَاءُ الْمُؤْمِنِينَ وَلَا فَخْرَ وَأَنَا أَكْرَمُ الْأَوَّلِينَ وَالْآخِرِينَ عَلَى اللَّهِ وَلَا فَخْرَ","trj":"Telah mengabarkan kepada kami [Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Zam'ah] dari [Salamah] dari ['Ikrimah] dari [Ibnu Abbas] Radliyallahu'anhu ia berkata; Orang-orang dari sahabat Nabi shallallahu 'alaihi wasallam duduk menunggu beliau. Kemudian beliau keluar dan tatkala dekat dengan mereka beliau mendengar mereka sedang menyebut-nyebut nama beliau shallallahu 'alaihi wasallam. Lalu beliau mendengarkan percakapan mereka dengan baik, maka diantara mereka ada yang berkata; \"Sungguh sangat mengherankan bahwasannya Allah Subhanahu wa Ta'ala menjadikan dari makhluk-Nya Sebagai sahabat karib-Nya, dan Ibrahim adalah sahabat karib Allah Subhanahu wa Ta'ala yang lain berkata; Mana yang lebih mengherankan dari ayat, WA KALLAMA ALLAHU MUSA TAKLIIMAA Dan Allah telah berbicara kepada Nabi Musa dengan langsung (Qs. An Nisaa`/4: 164) sementara yang lainnya lagi berkata; Sedangkan Isa adalah Kalimat Allah Subhanahu wa Ta'ala dan Ruh Nya, yang lainnya pun ikut berkata; Sementara Adam telah disucikan Allah Subhanahu wa Ta'ala. Lalu beliau keluar menemui mereka dan mengucapkan salam, lalu bersabda: \"Saya telah mendengarkan percakapan kalian dan keheranan bahwa Ibrahim adalah sahabat karib Allah Subhanahu wa Ta'ala, dan memang demikian, Musa orang yang diajak langsung berbicara dengan-Nya dan memang demikian, dan Isa adalah Ruh dan Kalimat-Nya dan memang demikian, dan Adam Allah Subhanahu wa Ta'ala telah memilihnya dan memang demikian, ketahuilah bahwa saya adalah habibullah (manusia kecintaan Allah) dan tiada kesombongan, aku adalah pembawa panji pujian di hari kiamat yang membawai Adam dan para nabi sesudahnya dan tiada kesombongan, dan aku adalah orang pertama yang memberi dan yang diberi syafa`at pada hari kiamat dan tidak ada kesombongan, dan saya adalah orang pertama yang menggerakkan tali pintu surga dan tidak ada kesombongan, kemudian Allah Subhanahu wa Ta'ala membukakan pintunya dan memasukkan saya ke dalamnya, saya masuk bersama orang-orang miskin dari kaum muslimin dan tidak ada kesombongan, serta saya adalah orang yang paling mulia dari orang-orang terdahulu dan orang-orang yang datang belakangan di sisi Allah Subhanahu wa Ta'ala dan tidak ada kesombongan\". "}],"4:176":[{"p":"Bukhari","n":5914,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَآخِرُ آيَةٍ نَزَلَتْ خَاتِمَةُ سُورَةِ النِّسَاءِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","trj":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Al Barra`] radliallahu 'anhu mengatakan; 'akhir ayat yang diturunkan adalah penutupan surat An Naisa`; 'Mereka memintamu fatwa tentang kalalah, katakanlah bahwa Allah memfatwakan kepada kalian….(QS. Annisa' 176)."},{"p":"Muslim","n":2802,"ar":"حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدِ بْنِ بُكَيْرٍ النَّاقِدُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَمَرِضْتُ فَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ يَعُودَانِي مَاشِيَيْنِ فَأُغْمِيَ عَلَيَّ فَتَوَضَّأَ ثُمَّ صَبَّ عَلَيَّ مِنْ وَضُوئِهِ فَأَفَقْتُ قُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ أَقْضِي فِي مَالِي فَلَمْ يَرُدَّ عَلَيَّ شَيْئًا حَتَّى نَزَلَتْ آيَةُ الْمِيرَاثِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","trj":"Telah menceritakan kepada kami [Amru bin Muhammad bin Bukair An Naqid] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Muhammad bin Al Munkadir] dia mendengar [Jabir bin Abdullah] berkata, \"Saat aku sakit Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar menjengukku dengan berjalan kaki, dan saat itu aku sedang pingsan. Lalu beliau berwudlu dan memercikkan air wudlunya kepadaku sehingga aku pun sadar. Kemudian aku berkata, \"Wahai Rasulullah, bagaimana seharusnya saya mengatur hartaku?\" Sedikitpun beliau tidak menjawabnya, hingga turunlah ayat tentang waris: '(Mereka meminta fatwa kepadamu (wahai Muhammad) tentang kalalah (yaitu seseorang yang meninggal dunia tanpa meninggalkan ayah dan anak), katakanlah, Allah lah yang memberi fatwa kepadamu tentang kalalah…) ' (Qs. An Nisaa: 176)."},{"p":"Muslim","n":2805,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُادَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَرِيضٌ لَا أَعْقِلُ فَتَوَضَّأَ فَصَبُّوا عَلَيَّ مِنْ وَضُوئِهِ فَعَقَلْتُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا يَرِثُنِي كَلَالَةٌ فَنَزَلَتْ آيَةُ الْمِيرَاثِفَقُلْتُ لِمُحَمَّدِ بْنِ الْمُنْكَدِرِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }قَالَ هَكَذَا أُنْزِلَتْ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ وَأَبُو عَامِرٍ الْعَقَدِيُّ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ كُلُّهُمْ عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ فِي حَدِيثِ وَهْبِ بْنِ جَرِيرٍ فَنَزَلَتْ آيَةُ الْفَرَائِضِ وَفِي حَدِيثِ النَّضْرِ وَالْعَقَدِيِّ فَنَزَلَتْ آيَةُ الْفَرْضِ وَلَيْسَ فِي رِوَايَةِ أَحَدٍ مِنْهُمْ قَوْلُ شُعْبَةَ لِابْنِ الْمُنْكَدِرِ","trj":"Telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Muhammad bin Al Munkadir] dia berkata, aku mendengar [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam menjengukku ketika aku sakit tak sadarkan diri, lalu beliau berwudlu dan memercikkan air wudlunya kepadaku, sehingga aku pun sadar. Kemudian aku berkata, \"Wahai Rasulullah, bagaimana aku mewariskan harta peninggalan? Maka turunlah ayat tentang warisan.\" Aku (Syu'bah) bertanya kepada [Muhammad bin Munkadir], \"Apakah (yang turun) YASTAFTUUNAKA QULILLAH YUFTIIKUM FIL KALAALAH (Mereka meminta fatwa kepadamu (tentang kalalah). Katakanlah: \"Allah memberi fatwa kepadamu tentang kalalah) '? (Qs. An Nisaa: 176). Dia menjawab, \"Seperti inilah ayat ini diturunkan.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [An Nadlr bin Syumail] dan [Abu Amir Al 'Aqadi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Mutsanna] telah menceritakan kepada kami [Wahb bin Jarir] semuanya dari [Syu'bah] dengan isnad ini dalam haditsnya Wahb bin Jarir, disebutkan, 'lalu turunkah ayat faraidl (pembagian harta warisan).' Sedangkan dalam hadits An Nadlr dan Al 'Aqadi, disebutkan, 'Lalu turunlah ayat fardl.' Dan dalam riwayat mereka berdua (tidak disebutkan) perkataan Syu'bah kepada Ibnu Munkadir.\""},{"p":"Muslim","n":2807,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا وَكِيعٌ عَنْ ابْنِ أَبِي خَالِدٍ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَآخِرُ آيَةٍ أُنْزِلَتْ مِنْ الْقُرْآنِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","trj":"Telah menceritakan kepada kami [Ali bin Khasyram] telah mengabarkan kepada kami [Waki'] dari [Ibnu Abu Khalid] dari [Abu Ishaq] dari [Al Barra'] dia berkata, \"Ayat Al Qur'an yang terakhir diturunkan adalah 'YASTAFTUUNAKA QULILLAHU YUFTIIKUM FIL KALAALAH (Mereka meminta fatwa kepadamu (tentang kalalah). Katakanlah: \"Allah memberi fatwa kepadamu tentang kalalah…) ' (Qs. An Nisaa: 176)."}]},"mapping_surah":[{"p":"Abu Dawud","n":272,"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ أَخْبَرَنَا أَبِي قَالَ سَمِعْتُ يَحْيَى بْنَ أَيُّوبَ يُحَدِّثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ الْمِصْرِيِّ عَنْ عَمْرِو بْنِ الْعَاصِ قَالَاحْتَلَمْتُ فِي لَيْلَةٍ بَارِدَةٍ فِي غَزْوَةِ ذَاتِ السُّلَاسِلِ فَأَشْفَقْتُ إِنْ اغْتَسَلْتُ أَنْ أَهْلِكَ فَتَيَمَّمْتُ ثُمَّ صَلَّيْتُ بِأَصْحَابِي الصُّبْحَ فَذَكَرُوا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا عَمْرُو صَلَّيْتَ بِأَصْحَابِكَ وَأَنْتَ جُنُبٌ فَأَخْبَرْتُهُ بِالَّذِي مَنَعَنِي مِنْ الِاغْتِسَالِ وَقُلْتُ إِنِّي سَمِعْتُ اللَّهَ يَقُولُ{ وَلَا تَقْتُلُوا أَنْفُسَكُمْ إِنَّ اللَّهَ كَانَ بِكُمْ رَحِيمًا }فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَقُلْ شَيْئًاقَالَ أَبُو دَاوُد عَبْدُ الرَّحْمَنِ بْنُ جُبَيْرٍ مِصْرِيٌّ مَوْلَى خَارِجَةَ بْنِ حُذَافَةَ وَلَيْسَ هُوَ ابْنُ جُبَيْرِ بْنِ نُفَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ ابْنِ لَهِيعَةَ وَعَمْرِو بْنِ الْحَارِثِ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ أَبِي قَيْسٍ مَوْلَى عَمْرِو بْنِ الْعَاصِ أَنَّ عَمْرَو بْنَ الْعَاصِ كَانَ عَلَى سَرِيَّةٍ وَذَكَرَ الْحَدِيثَ نَحْوَهُ قَالَ فَغَسَلَ مَغَابِنَهُ وَتَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ صَلَّى بِهِمْ فَذَكَرَ نَحْوَهُ وَلَمْ يَذْكُرْ التَّيَمُّمَ قَالَ أَبُو دَاوُد وَرَوَى هَذِهِ الْقِصَّةَ عَنْ الْأَوْزَاعِيِّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ قَالَ فِيهِ فَتَيَمَّمَ","trj":"Telah menceritakan kepada kami [Ibnu Al-Mutsanna] telah mengabarkan kepada kami [Wahb bin Jarir] telah mengabarkan kepada kami [Ayahku] dia berkata; Saya telah mendengar [Yahya bin Ayyub] menceritakan hadits dari [Yazid bin Abi Habib] dari [Imran bin Abi Anas] dari [Abdurrahman bin Jubair Al-Mishri] dari [Amru bin Al-'Ash] dia berkata; Saya pernah bermimpi basah pada suatu malam yang sangat dingin sekali ketika perang Dzatus Salasil, sehingga saya takut akan binasa jika saya mandi. Lalu saya pun bertayammum kemudian shalat Shubuh dengan para sahabatku. Lalu hal itu mereka laporkan kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Wahai Amru, engkau shalat bersama para sahabatmu dalam keadaan junub?\" Maka saya katakan kapada beliau tentang apa yang menghalangiku untuk mandi dan saya katakan; Sesungguhnya saya pernah mendengar Allah berfirman: 'Dan janganlah kalian membunuh diri-diri kalian, sesungguhnya Allah Maha Penyayang kepada kalian. ' (QS. ANnisa'; 29), Maka Rasulullah shallallahu 'alaihi wasallam tertawa dan tidak mengatakan apa-apa. Abu Dawud berkata; Abdurrahman bin Jubair Al-Mishri adalah mantan sahaya Kharijah bin Hudzafah, dan dia bukanlah Jubair bin Nufair. Telah menceritakan kepada kami [Muhammad bin Salamah Al-Muradi] telah mengabarkan kepada kami [Ibnu Wahb] dari [Ibnu Lahi'ah] dan [Amru bin Al-Harits] dari [Yazid bin Abi Habib] dari [Imran bin Abi Anas] dari [Abdurrahman bin Jubair] dari [Abu Qais, mantan sahaya Amru bin Al-'Ash] bahwasanya [Amru bin Al-'Ash] pernah diutus pada suatu peperangan yang tidak diikuti Rasulullah shallallahu 'alaihi wasallam. Kemudian dia meyebutkan hadits semisal di atas. dia menyebutkan; dia membasuh bagian-bagian lipatan tubuhnya dan berwudlu kemudian shalat dengan mereka, lalu dia menyebutkan semisalnya tanpa menyebutkan perihal tayammum. Abu Dawud berkata; Dan kisah ini telah diriwayatkan dari [Al-Auza'i] dari [Hasan bin 'Athiyyah] dia menyebutkan padanya; Lalu dia bertayammum."},{"p":"Abu Dawud","n":1001,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ ح و حَدَّثَنَا خُشَيْشٌ يَعْنِي ابْنَ أَصْرَمَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَقُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ أَرَأَيْتَ إِقْصَارَ النَّاسِ الصَّلَاةَ وَإِنَّمَا قَالَ تَعَالَى{ إِنْ خِفْتُمْ أَنْ يَفْتِنَكُمْ الَّذِينَ كَفَرُوا }فَقَدْ ذَهَبَ ذَلِكَ الْيَوْمَ فَقَالَ عَجِبْتُ مِمَّا عَجِبْتَ مِنْهُ فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَدَقَةٌ تَصَدَّقَ اللَّهُ بِهَا عَلَيْكُمْ فَاقْبَلُوا صَدَقَتَهُحَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَمُحَمَّدُ بْنُ بَكْرٍ قَالَا أَخْبَرَنَا ابْنُ جُرَيْجٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي عَمَّارٍ يُحَدِّثُ فَذَكَرَهُ نَحْوَهُ قَالَ أَبُو دَاوُد رَوَاهُ أَبُو عَاصِمٍ وَحَمَّادُ بْنُ مَسْعَدَةَ كَمَا رَوَاهُ ابْنُ بَكْرٍ","trj":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Musaddad] keduanya berkata; telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Khusyaisy yaitu Ibnu Ashram] telah menceritakan kepada kami [Abdurrazaq] dari [Ibnu Juraij] dia berkata; telah menceritakan kepadaku [Abdurrahman bin Abdullah bin Abu 'Ammar] dari [Abdullah bin Babaih] dari [Ya'la bin Umayyah] dia berkata; aku bertanya kepada Umar bin Khattab; \"Bagaimana pendapat anda mengenai orang-orang yang meng-qashar shalatnya karena firman Allah; \"…Jika kamu takut di serang oleh orang-orang kafir…\" QS An Nisaa'; 101, padahal rasa takut itu telah hilang saat sekarang ini.\" [Umar] berkata; \"Sebenarnya aku juga heran seperti yang kamu herankan itu, oleh karena itu, aku sampaikan masalah tersebut kepada Rasulullah shallallahu 'alaihi wasallam, justru beliau menjawab: \"Itu merupakan sedekah Allah terhadap kalian, oleh karena itu, terimalah sedekah-Nya.\" Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdurrazaq] dan [Muhammad bin Bakr] keduanya berkata; telah mengabarkan kepada kami [Ibnu Juraij] saya mendengar [Abdullah bin Abu 'Ammar] bercerita …\" kemudian ia menyebutkan hadits yang semisalnya, Abu Daud mengatakan; \"Di riwayatkan pula oleh [Abu 'Ashim] dan [Hammad bin Mas'adah] sebagaimana yang di riwayatkan oleh Ibnu Bakr.\""},{"p":"Abu Dawud","n":1898,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْعَلَاءِ قَالَ عُثْمَانُ حَدَّثَنَا وَقَالَ ابْنُ الْعَلَاءِ أَخْبَرَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَمَنْ شَاءَ لَاعَنْتُهُ لَأُنْزِلَتْ سُورَةُ النِّسَاءِ الْقُصْرَى بَعْدَ الْأَرْبَعَةِ الْأَشْهُرِ وَعَشْرًا","trj":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], dan [Muhammad bin Al 'Ala`], Utsman ia berkata; telah menceritakan kepada kami, dan Ibnu Al 'Ala` berkata; telah mengabarkan kepada kami [Abu Mu'awiyah], telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Masruq] dari [Abdullah], ia berkata; barang siapa yang menghendaki maka akan aku ajak ia untuk saling melaknat. Sungguh surat An Nisa` tentang talak telah turun setelah ayat mengenai 'iddah empat bulan dan sepuluh hari. "},{"p":"Abu Dawud","n":2439,"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى جِئْنَا امْرَأَةً مِنْ الْأَنْصَارِ فِي الْأَسْوَاقِ فَجَاءَتْ الْمَرْأَةُ بِابْنَتَيْنِ لَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ هَاتَانِ بِنْتَا ثَابِتِ بْنِ قَيْسٍ قُتِلَ مَعَكَ يَوْمَ أُحُدٍ وَقَدْ اسْتَفَاءَ عَمُّهُمَا مَالَهُمَا وَمِيرَاثَهُمَا كُلَّهُ فَلَمْ يَدَعْ لَهُمَا مَالًا إِلَّا أَخَذَهُ فَمَا تَرَى يَا رَسُولَ اللَّهِ فَوَاللَّهِ لَا تُنْكَحَانِ أَبَدًا إِلَّا وَلَهُمَا مَالٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْضِي اللَّهُ فِي ذَلِكَ قَالَ وَنَزَلَتْ سُورَةُ النِّسَاءِ{ يُوصِيكُمُ اللَّهُ فِي أَوْلَادِكُمْ }الْآيَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْعُوا لِي الْمَرْأَةَ وَصَاحِبَهَا فَقَالَ لِعَمِّهِمَا أَعْطِهِمَا الثُّلُثَيْنِ وَأَعْطِ أُمَّهُمَا الثُّمُنَ وَمَا بَقِيَ فَلَكَقَالَ أَبُو دَاوُد أَخْطَأَ بِشْرٌ فِيهِ إِنَّمَا هُمَا ابْنَتَا سَعْدِ بْنِ الرَّبِيعِ وَثَابِتُ بْنُ قَيْسٍ قُتِلَ يَوْمَ الْيَمَامَةِ حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي دَاوُدُ بْنُ قَيْسٍ وَغَيْرُهُ مِنْ أَهْلِ الْعِلْمِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ امْرَأَةَ سَعْدِ بْنِ الرَّبِيعِ قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ سَعْدًا هَلَكَ وَتَرَكَ ابْنَتَيْنِ وَسَاقَ نَحْوَهُ قَالَ أَبُو دَاوُد وَهَذَا هُوَ أَصَحُّ","trj":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal], telah menceritakan kepada kami [Abdullah bin Muhammad bin 'Aqil], dari [Jabir bin Abdullah], ia berkata; kami keluar bersama Rasulullah shallallahu 'alaihi wasallam hingga kami sampai pada seorang wanita anshar di beberapa pasar kemudian wanita tersebut datang dengan membawa dua orang anak wanitanya dan berkata; wahai Rasulullah, ini adalah dua anak wanita Tsabit bin Qais, ia terbunuh bersama engkau pada saat perang Uhud. Dan pamannya telah mengambil seluruh harta dan warisan mereka berdua, dan tidaklah Tsabit meninggalkan harta untuk mereka berdua melainkan ia telah mengambilnya. Bagaimana pendapat engkau wahai Rasulullah? Demi Allah, mereka berdua tidaklah dinikahkan selamanya kecuali mereka memiliki harta. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah akan memutuskan dalam perkara tersebut.\" Jabir berkata; dan turunlah Surat An Nisa`: \"Allah mensyari'atkan bagimu tentang (pembagian pusaka untuk) anak-anakmu.\" Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Panggilkan wanita tersebut sahabatnya (paman kedua anak tersebut)!\" kemudian beliau berkata kepada paman kedua anak tersebut: \"Berikan kepada keduanya dua pertiga, dan berikan seperdelapan kepada ibu mereka, dan sisanya adalah untukmu.\" Abu Daud berkata; Bisyr telah salah dalam hal tersebut. Sesungguhnya mereka berdua adalah anak wanita Sa'd bin Ar Rabi', sedangkan Tsabit bin Qais terbunuh pada perang Yamamah. Telah menceritakan kepada kami [Ibnu As Sarh], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Daud bin Qais], dan yang lainnya dari kalangan ahli ilmu, dari [Abdullah bin Muhammad bin 'Aqil], dari [Jabir bin Abdullah], bahwa isteri Sa'd bin Ar Rabi' berkata; wahai Rasulullah, sesungguhnya Sa'd telah mati dan meninggalkan dua anak wanita, kemudian Ibnu As Sarh menyebutkan hadits seperti hadits tersebut. Abu Daud berkata; dan hadits ini lebih shahih. "},{"p":"Abu Dawud","n":3075,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا اللَّيْثِ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُأَنَّ رَجُلًا خَاصَمَ الزُّبَيْرَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ فَأَبَى عَلَيْهِ الزُّبَيْرُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ اسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ إِلَى جَارِكَ قَالَ فَغَضِبَ الْأَنْصَارِيُّ فَقَالَ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اسْقِ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِفَقَالَ الزُّبَيْرُ فَوَاللَّهِ إِنِّي لَأَحْسَبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Al Laits] dari [Az Zuhri] dari ['Urwah] bahwa [Abdullah bin Az Zubair] menceritakan kepadanya, bahwa ada seorang laki-laki bermusuhan dengan Az Zubair mengenai saluran-saluran air pada tanah keras yang berbatu hitam yang mereka gunakan untuk mengairi tanaman. Kemudian orang anshar tersebut berkata, \"Biarkanlah air lewat!\" Namun Az Zubair menolak. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepada Az Zubair: \"Siramilah tanamanmu wahai Az Zubair, kemudian alirkan kepada tetanggamu!\" Maka marahklah orang anshar tersebut, lalu ia berkata, \"Wahai Rasulullah, apakah karena ia itu anak bibimu!\" Maka rona muka Rasulullah shallallahu 'alaihi wasallam berubah, beliau bersabda: \"Siramlah tanamanmu, lalu tahanlah iar tersebut hingga ia kembali ke tempatnya semula.\" Az Zubair berkata, \"Demi Allah, sungguh aku mengira ayat ini turun mengenai hal tersebut; '(Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim…) ' (Qs. An Nisa: 65). "},{"p":"Abu Dawud","n":3105,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ سُورَةَ النِّسَاءِ قَالَ قُلْتُ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أُحِبُّ أَنْ أَسْمَعَهُ مِنْ غَيْرِي قَالَ فَقَرَأْتُ عَلَيْهِ حَتَّى إِذَا انْتَهَيْتُ إِلَى قَوْلِهِ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ }الْآيَةَ فَرَفَعْتُ رَأْسِي فَإِذَا عَيْنَاهُ تَهْمِلَانِ","trj":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al A'masy] dari [Ibrahim] dari ['Abidah] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Bacakan kepadaku Surat An Nisa!\" Aku katakan, \"Apakah aku akan membacakan kepadamu sementara Al Qur'an turun kepadamu?\" Beliau bersabda: \"Aku senang untuk mendengarnya dari selainku.\" Abdullah berkata, \"Kemudian aku membacakan Al Qur'an kepadanya hingga sampai pada firman-Nya: '(Maka bagaimanakah (halnya orang kafir nanti), apabila Kami mendatangkan seseorang saksi (rasul) …) ' (Qs. An Nisa: 41) Kemudian aku angkat kepalaku dan ternyata kedua mata beliau telah berurai dengan air mata.\""},{"p":"Abu Dawud","n":3107,"ar":"حَدَّثَنَا عَبَّادُ بْنُ مُوسَى الْخُتَّلِيُّ أَخْبَرَنَا إِسْمَعِيلُ يَعْنِي ابْنَ جَعْفَرٍ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرٍو عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَلَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ قَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ }الْآيَةَ قَالَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ الْآيَةُ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَكَانَ مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ يُنَادِي أَلَا لَا يَقْرَبَنَّ الصَّلَاةَ سَكْرَانُ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَهَلْ أَنْتُمْ مُنْتَهُونَ }قَالَ عُمَرُ انْتَهَيْنَا","trj":"Telah menceritakan kepada kami ['Abbad bin Musa Al Khuttali] telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Israil] dari [Abu Ishaq] dari ['Amru] dari [Umar bin Al Khathab] ia berkata, \"Tatkala telah turun pengharaman arak Umar berkata, \"Ya Allah, jelaskan kepada kami mengenai arak dengan penjelasan yang memuaskan.\" Kemudian turunlah ayat yang terdapat dalam Surat Al Baqarah (219): '(Mereka bertanya kepadamu tentang khamer dan judi…) '. 'Ammar berkata, \"Kemudian Umar dipanggil dan dibacakan kepadanya ayat tersebut, ia berkata lagi, \"Ya Allah, jelaskan kepada kami mengenai khamer dengan penjelasan yang memuaskan.\" Kemudian turunlah ayat yang terdapat pada Surat An Nisaa` (41): '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…..) ' Penyeru Rasulullah shallallahu 'alaihi wasallam apabila shalat telah ditegakkan maka ia berseru, 'ketahuilah bahwa tidak boleh orang yang mabuk mendekati shalat! ' Kemudian Umar dipanggil dan dibacakanlah ayat tersebut kepadanya, lalu ia berkata, \"Ya Allah jelaskanlah kepada kami mengenai khamer dengan penjelasan yang memuaskan!\" Maka turunlah ayat ini: '(….. apakah kalian akan berhenti?) ' (Qs. Al Maa`idah: 91) Umar berkata, \"Kami telah berhenti.\""},{"p":"Abu Dawud","n":3108,"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ عَلَيْهِ السَّلَامأَنَّ رَجُلًا مِنْ الْأَنْصَارِ دَعَاهُ وَعَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ فَسَقَاهُمَا قَبْلَ أَنْ تُحَرَّمَ الْخَمْرُ فَأَمَّهُمْ عَلِيٌّ فِي الْمَغْرِبِ فَقَرَأَ قُلْ يَا أَيُّهَا الْكَافِرُونَ فَخَلَطَ فِيهَا فَنَزَلَتْ{ لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى حَتَّى تَعْلَمُوا مَا تَقُولُونَ }","trj":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepada kami ['Atha bin As Saib] dari [Abu Abdurrahman As Sulami] dari [Ali bin Abu Thalib] bahwa seorang laki-laki Anshar memanggil dirinya dan Abdurrahman bin 'Auf, lalu ia memberi mereka minum khamer sebelum khamer diharamkan. Setelah itu Ali mengimami mereka dalam Shalat Maghrib. Ketika ia membaca Surat Al Ikhlash dan terbolak-balik dalam membacanya, maka turunlah ayat: '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk, sehingga kamu mengerti apa yang kamu ucapkan…) ' (Qs. An Nisaa`: 41). "},{"p":"Abu Dawud","n":3109,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيِّ حَدَّثَنَا عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }وَ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ وَمَنَافِعُ لِلنَّاسِ }نَسَخَتْهُمَا الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا الْخَمْرُ وَالْمَيْسِرُ وَالْأَنْصَابُ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepada kami [Ali bin Husain] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia membaca: '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…) ' (Qs. An Nisaa`: 41). Dan ayat: '(Mereka bertanya kepadamu tentang khamer dan judi. Katakanlah: \"Pada keduanya terdapat dosa yang besar dan beberapa manfaat bagi manusia.....) ' (Qs. Al Baqarah: 219), ia berkata, \"Kedua ayat tersebut dihapus dan digantikan oleh ayat yang terdapat dalam Surat Al Maaidah: 91: '(Sesungguhnya (meminum) khamar, berjudi, (berkorban untuk) berhala…) '. "},{"p":"Abu Dawud","n":3182,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ لَا تَأْكُلُوا أَمْوَالَكُمْ بَيْنَكُمْ بِالْبَاطِلِ إِلَّا أَنْ تَكُونَ تِجَارَةً عَنْ تَرَاضٍ مِنْكُمْ }فَكَانَ الرَّجُلُ يَحْرَجُ أَنْ يَأْكُلَ عِنْدَ أَحَدٍ مِنْ النَّاسِ بَعْدَ مَا نَزَلَتْ هَذِهِ الْآيَةُ فَنَسَخَ ذَلِكَ الْآيَةُ الَّتِي فِي النُّورِ قَالَ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَأْكُلُوا مِنْ بُيُوتِكُمْ إِلَى قَوْلِهِ أَشْتَاتًا كَانَ الرَّجُلُ الْغَنِيُّ يَدْعُو الرَّجُلَ مِنْ أَهْلِهِ إِلَى الطَّعَامِ قَالَ إِنِّي لَأَجَّنَّحُ أَنْ آكُلَ مِنْهُ وَالتَّجَنُّحُ الْحَرَجُ وَيَقُولُ الْمِسْكِينُ أَحَقُّ بِهِ مِنِّي فَأُحِلَّ فِي ذَلِكَ أَنْ يَأْكُلُوا مِمَّا ذُكِرَ اسْمُ اللَّهِ عَلَيْهِ وَأُحِلَّ طَعَامُ أَهْلِ الْكِتَابِ","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepadaku [Ali bin Al Husain bin Waqid] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Firman Allah: '(Janganlah kamu saling memakan harta sesamamu dengan jalan yang batil, kecuali dengan jalan perniagaan yang berlaku dengan suka sama-suka di antara kamu) ' (Qs. An Nisaa: 29), maka setelah ayat tersebut turun, seseorang merasa tidak enak untuk makan di rumah orang lain, kemudian hal tersebut dihapuskan oleh ayat yang ada dalam Surat An Nuur: '(dan tidak (pula) ada halangan bagi dirimu sendiri untuk makan (bersama-sama mereka) di rumah kamu sendiri atau di rumah bapak-bapakmu, di rumah ibu-ibumu, di rumah saudara- saudaramu yang laki-laki, di rumah saudaramu yang perempuan, di rumah saudara bapakmu yang laki-laki, di rumah saudara bapakmu yang perempuan, di rumah saudara ibumu yang laki-laki, di rumah saudara ibumu yang perempuan, di rumah yang kamu miliki kuncinya atau di rumah kawan-kawanmu. Tidak ada halangan bagi kamu makan bersama-sama mereka atau sendirian) '. Maka orang yang kaya mengundang seseorang dari keluarganya untuk makan. Ia berkata, \"Sungguh aku merasa ada ganjalan untuk makan darinya.\" Tajannuh adalah perasaan mengganjal dalam hati. Ia berkata; orang miskin lebih berhak daripada diriku. Kemudian dihalalkan dalam hal tersebut untuk maka apa yang disebutkan padanya nama Allah, dan telah dihalalkan makanan ahli kitab.\""},{"p":"Abu Dawud","n":3373,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَحِقَ الْمُسْلِمُونَ رَجُلًا فِي غُنَيْمَةٍ لَهُ فَقَالَ السَّلَامُ عَلَيْكُمْ فَقَتَلُوهُ وَأَخَذُوا تِلْكَ الْغُنَيْمَةَ فَنَزَلَتْ{ وَلَا تَقُولُوا لِمَنْ أَلْقَى إِلَيْكُمْ السَّلَامَ لَسْتَ مُؤْمِنًا تَبْتَغُونَ عَرَضَ الْحَيَاةِ الدُّنْيَا }تِلْكَ الْغُنَيْمَةَ","trj":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru bin Dinar] dari ['Atha] dari [Ibnu Abbas] ia berkata, \"Orang-orang muslim bertemu dengan seorang laki-laki yang membawa kambingnya, kemudian ia mengucapkan, 'Assalaamu 'alaikum! ' Lalu mereka membunuhnya dan mengambil kambing tersebut. Maka turunlah ayat: '(Dan janganlah kamu mengatakan kepada orang yang mengucapkan 'salam' kepadamu: 'Kamu bukan seorang mukmin' (lalu kamu membunuhnya), dengan maksud mencari harta benda kehidupan di dunia) ' (Qs. An Nisaa: 94), yaitu kambing tersebut.\""},{"p":"Abu Dawud","n":3374,"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ أَبِي الزِّنَادِ وَهُوَ أَشْبَعُ عَنْ أَبِيهِ عَنْ خَارِجَةَ بْنِ زَيْدِ بْنِ ثَابِتٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ{ غَيْرُ أُولِي الضَّرَرِ }وَلَمْ يَقُلْ سَعِيدٌ كَانَ يَقْرَأُ","trj":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Ibnu Abu Az Zinad]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Abu Az Zinad Asyba'] dari [Ayahnya] dari [Kharijah bin Zaid bin Tsabit] dari [Ayahnya], bahwa Nabi shallallahu 'alaihi wasallam membaca ayat: (yang tidak mempunyai 'uzur…) ' (Qs. An Nisaa; 95). Sa'id tidak menyebutkan kata, 'membaca'.\""},{"p":"Abu Dawud","n":3610,"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَوْ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَلَمَّا نَزَلَتْ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ مُشْرِكُو أَهْلِ مَكَّةَ قَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَأَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ وَعَمِلَ عَمَلًا صَالِحًا فَأُولَئِكَ يُبَدِّلُ اللَّهُ سَيِّئَاتِهِمْ حَسَنَاتٍ }فَهَذِهِ لِأُولَئِكَ قَالَ وَأَمَّا الَّتِي فِي النِّسَاءِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }الْآيَةَ قَالَ الرَّجُلُ إِذَا عَرَفَ شَرَائِعَ الْإِسْلَامِ ثُمَّ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ لَا تَوْبَةَ لَهُفَذَكَرْتُ هَذَا لِمُجَاهِدٍ فَقَالَ إِلَّا مَنْ نَدِمَ حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي يَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذِهِ الْقِصَّةِ فِي{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }أَهْلِ الشِّرْكِ قَالَ وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Yusuf bin Musa] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Sa'id bin Jubair] atau ia mengatakan; telah menceritakan kepadaku [Al hakam] dari [Sa'id bin Jubair] ia berkata; Aku bertanya [Ibnu Abbas] berkata, \"Ketika ayat dalam surat Al furqan ini turun: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68-, orang-orang musyrik Makkah berkata, \"Kami telah membunuh jiwa yang telah diharamkan oleh Allah dan berbuat syirik kepada-Nya serta melakukan perbuatan keji!\" Allah pun menurunkan ayat: (Kecuali orang-orang yang bertaubat dan, beriman dan beramal shalih; maka kejahatan mereka akan diganti Allah dengan kebajikan..) -Qs. Al Furqan: 70-, maka ayat ini untuk orang-orang musyrik Quraisy tersebut. Ibnu Abbas melanjutkan, \"Sedangkan ayat yang ada dalam surat An Nisa: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam…) -An Nisa: 93- ia mengatakan, \"Seorang laki-laki yang mengetahui hukum-hukum Islam, kemudian ia membunuh seorang mukmin dengan sengaja, maka balasannya adalah neraka jahannam dan tidak ada lagi taubat untuknya.\" Perkataan ini lalu aku sebutkan kepada Mujahid, ia berkomentar, \"Kecuali jika ia (pembunuh) merasa menyesal.\" Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ya'la] dari [Sa'id bin Jubair] dari [Ibnu Abbas] -sebagaimana kisah dalam hadits tersebut- tentang firman Allah: (dan orang-orang yang tidak menyembah tuhan yang lain berserta Allah..) -Qs. Al Furqan: 53- yakni orang-orang musyrik. Ibnu Abbas berkata, \"Lalu turun ayat: (Katakanlah, 'Hai hamba-hamba-Ku yang melampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah') -Qs. Az Zumar: 53-. "},{"p":"Abu Dawud","n":3611,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }قَالَ مَا نَسَخَهَا شَيْءٌ","trj":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami ['Abdurrahman] berkata, telah menceritakan kepada kami [Sufyan] dari [Al Mughirah bin Nu'man] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Firman Allah: (Dan barangsiapa membunuh seorang mukmin dengan sengaja…) -Qs. An Nisa: 94-, tidak pernah dihapus oleh ayat manapun.\""},{"p":"Abu Dawud","n":3612,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي مِجْلَزٍفِي قَوْلِهِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }قَالَ هِيَ جَزَاؤُهُ فَإِنْ شَاءَ اللَّهُ أَنْ يَتَجَاوَزَ عَنْهُ فَعَلَ","trj":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Abu Syihab] dari [Sulaiman At Taimi] dari [Abu Mijlaz] tentang firman Allah: (Dan barangsiapa membunuh seorang mukmin dengan sengaja, maka balasannya ialah Jahannam..) -Qs. An Nisa: 93- ia berkata, \"Itu adalah ganjaran baginya, jika Allah akan mengampuninya, maka Allah akan melakukannya.\""},{"p":"Abu Dawud","n":3717,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ الْحُسَيْنِ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَاللَّاتِي يَأْتِينَ الْفَاحِشَةَ مِنْ نِسَائِكُمْ فَاسْتَشْهِدُوا عَلَيْهِنَّ أَرْبَعَةً مِنْكُمْ فَإِنْ شَهِدُوا فَأَمْسِكُوهُنَّ فِي الْبُيُوتِ حَتَّى يَتَوَفَّاهُنَّ الْمَوْتُ أَوْ يَجْعَلَ اللَّهُ لَهُنَّ سَبِيلًا }وَذَكَرَ الرَّجُلَ بَعْدَ الْمَرْأَةِ ثُمَّ جَمَعَهُمَا فَقَالَ{ وَاللَّذَانِ يَأْتِيَانِهَا مِنْكُمْ فَآذُوهُمَا فَإِنْ تَابَا وَأَصْلَحَا فَأَعْرِضُوا عَنْهُمَا }فَنَسَحَ ذَلِكَ بِآيَةِ الْجَلْدِ فَقَالَ{ الزَّانِيَةُ وَالزَّانِي فَاجْلِدُوا كُلَّ وَاحِدٍ مِنْهُمَا مِائَةَ جَلْدَةٍ }حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ حَدَّثَنَا مُوسَى يَعْنِي ابْنَ مَسْعُودٍ عَنْ شِبْلٍ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجِاهِدٍ قَالَ السَّبِيلُ الْحَدُّ قَالَ سُفْيَانُ{ فَآذُوهُمَا }الْبِكْرَانِ{ فَأَمْسِكُوهُنَّ فِي الْبُيُوتِ }الثَّيِّبَاتُ","trj":"Telah menceritakan kepada kami [Amad bin Muhammad bin Tsabit Al Marwazi] berkata, telah menceritakan kepadaku [Ali bin Al Husain] dari [Bapaknya] dari [Yazid bin An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata tentang firman Allah: '(Dan (terhadap) para wanita yang mengerjakan perbuatan keji, hendaklah ada empat orang saksi diantara kamu (yang menyaksikannya). Kemudian apabila mereka telah memberi persaksian, maka kurunglah mereka (wanita-wanita itu) dalam rumah sampai mereka menemui ajalnya, atau sampai Allah memberi jalan lain kepadanya) ' -Qs. An Nisa: 15-. Allah menyebutkan laki-laki setelah perempuan, kemudian Dia menggabungkan keduanya. Allah berfirman: '(Dan terhadap dua orang yang melakukan perbuatan keji di antara kamu, maka berilah hukuman kepada keduanya, kemudian jika keduanya bertaubat dan memperbaiki diri, maka biarkanlah mereka..) ' -Qs. An Nisa: 16-. Ayat ini kemudian dihapus dengan ayat cambuk, Allah berfirman: '(perempuan yang berzina dan laki-laki yang berzina, maka deralah tiap-tiap seorang dari keduanya seratus kali dera…) ' -Qs. An Nuur: 2-. Telah menceritakan kepada kami Ahmad bin Muhammad bin Tsabit berkata, telah menceritakan kepada kami Musa -maksudnya Musa bin Mas'ud- dari Syibl dari Ibnu Abu Najih dari Mujahid ia berkata, \"Kata 'as sabil' maksudnya adalah hukuman had.\" Mujahid berkata, \"Firman Allah 'maka berilah hukuman kepada keduanya', maksudnya adalah pezina yang masih lajang. Sementara firman Allah 'maka kurunglah mereka (wanita-wanita itu) dalam rumah', maksudnya adalah para janda.\""},{"p":"Abu Dawud","n":3950,"ar":"حَدَّثَنَا عَلِيُّ بْنُ نَصْرٍ وَمُحَمَّدُ بْنُ يُونُسَ النَّسَائِيُّ الْمَعْنَى قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا حَرْمَلَةُ يَعْنِي ابْنَ عِمْرَانَ حَدَّثَنِي أَبُو يُونُسَ سُلَيْمُ بْنُ جُبَيْرٍ مَوْلَى أَبِي هُرَيْرَةَ قَالَسَمِعْتُ أَبَا هُرَيْرَةَ يَقْرَأُ هَذِهِ الْآيَةَ{ إِنَّ اللَّهَ يَأْمُرُكُمْ أَنْ تُؤَدُّوا الْأَمَانَاتِ إِلَى أَهْلِهَا إِلَى قَوْلِهِ تَعَالَى سَمِيعًا بَصِيرًا }قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ إِبْهَامَهُ عَلَى أُذُنِهِ وَالَّتِي تَلِيهَا عَلَى عَيْنِهِ قَالَ أَبُو هُرَيْرَةَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَؤُهَا وَيَضَعُ إِصْبَعَيْهِ قَالَ ابْنُ يُونُسَ قَالَ الْمُقْرِئُ يَعْنِي إِنَّ اللَّهَ سَمِيعٌ بَصِيرٌ يَعْنِي أَنَّ لِلَّهِ سَمْعًا وَبَصَرًاقَالَ أَبُو دَاوُد وَهَذَا رَدٌّ عَلَى الْجَهْمِيَّةِ","trj":"Telah menceritakan kepada kami [Ali bin Nashr] dan [Muhammad bin Yunus An Nasai] secara makna, keduanya berkata; telah menceritakan kepada kami [Abdullah bin Yazid Al Muqri] berkata, telah menceritakan kepada kami [Harmalah] -maksudnya Harmalah bin Imran- berkata, telah menceritakan kepadaku [Abu Yunus Sulaim bin Jubair] -mantan budak (yang telah dimerdekakan oleh) Abu Hurairah- ia berkata; Aku mendengar [Abu Hurairah] membaca ayat ini: (Sesungguhnya Allah menyuruh kamu menyampaikan amanat kepada yang berhak menerimanya) -Qs. An Nisa: 48- sampai pada firman-Nya (Sesungguhnya Allah adalah Maha Mendengar lagi Maha Melihat). Abu Hurairah berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam meletakkan ibu jarinya ke telinga, sementara jari setelahnya pada mata.\" Abu Hurairah melanjutkan, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam membaca ayat tersebut seraya meletakkan kedua jarinya tersebut.\" Ibnu Yunus berkata, \"Al Muqri menyebutkan bahwa makna ayat: (Sesungguhnya Allah Maha Mendengar dan Maha Melihat) adalah, bahwa Allah memiliki penglihatan dan pendengaran.\" Abu Dawud berkata, \"Ini adalah bantahan untuk orang-orang Jahmiyah.\""},{"p":"Ahmad","n":16,"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى قَالَ حَدَّثَنَا قَتَادَةُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ الْغَطَفَانِيِّ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ الْيَعْمَرِيِّأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَامَ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ ذَكَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرَ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ ثُمَّ قَالَ رَأَيْتُ رُؤْيَا لَا أُرَاهَا إِلَّا لِحُضُورِ أَجَلِي رَأَيْتُ كَأَنَّ دِيكًا نَقَرَنِي نَقْرَتَيْنِ قَالَ وَذَكَرَ لِي أَنَّهُ دِيكٌ أَحْمَرُ فَقَصَصْتُهَا عَلَى أَسْمَاءَ بِنْتِ عُمَيْسٍ امْرَأَةِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَتْ يَقْتُلُكَ رَجُلٌ مِنْ الْعَجَ��ِ قَالَ وَإِنَّ النَّاسَ يَأْمُرُونَنِي أَنْ أَسْتَخْلِفَ وَإِنَّ اللَّهَ لَمْ يَكُنْ لِيُضَيِّعَ دِينَهُ وَخِلَافَتَهُ الَّتِي بَعَثَ بِهَا نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنْ يَعْجَلْ بِي أَمْرٌ فَإِنَّ الشُّورَى فِي هَؤُلَاءِ السِّتَّةِ الَّذِينَ مَاتَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَنْهُمْ رَاضٍ فَمَنْ بَايَعْتُمْ مِنْهُمْ فَاسْمَعُوا لَهُ وَأَطِيعُوا وَإِنِّي أَعْلَمُ أَنَّ أُنَاسًا سَيَطْعَنُونَ فِي هَذَا الْأَمْرِ أَنَا قَاتَلْتُهُمْ بِيَدِي هَذِهِ عَلَى الْإِسْلَامِ أُولَئِكَ أَعْدَاءُ اللَّهِ الْكُفَّارُ الضُّلَّالُ وَايْمُ اللَّهِ مَا أَتْرُكُ فِيمَا عَهِدَ إِلَيَّ رَبِّي فَاسْتَخْلَفَنِي شَيْئًا أَهَمَّ إِلَيَّ مِنْ الْكَلَالَةِ وَايْمُ اللَّهِ مَا أَغْلَظَ لِي نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَيْءٍ مُنْذُ صَحِبْتُهُ أَشَدَّ مَا أَغْلَظَ لِي فِي شَأْنِ الْكَلَالَةِ حَتَّى طَعَنَ بِإِصْبَعِهِ فِي صَدْرِي وَقَالَ تَكْفِيكَ آيَةُ الصَّيْفِ الَّتِي نَزَلَتْ فِي آخِرِ سُورَةِ النِّسَاءِ وَإِنِّي إِنْ أَعِشْ فَسَأَقْضِي فِيهَا بِقَضَاءٍ يَعْلَمُهُ مَنْ يَقْرَأُ وَمَنْ لَا يَقْرَأُ وَإِنِّي أُشْهِدُ اللَّهَ عَلَى أُمَرَاءِ الْأَمْصَارِ إِنِّي إِنَّمَا بَعَثْتُهُمْ لِيُعَلِّمُوا النَّاسَ دِينَهُمْ وَيُبَيِّنُوا لَهُمْ سُنَّةَ نَبِيِّهِمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَرْفَعُوا إِلَيَّ مَا عُمِّيَ عَلَيْهِمْ ثُمَّ إِنَّكُمْ أَيُّهَا النَّاسُ تَأْكُلُونَ مِنْ شَجَرَتَيْنِ لَا أُرَاهُمَا إِلَّا خَبِيثَتَيْنِ هَذَا الثُّومُ وَالْبَصَلُ وَايْمُ اللَّهِ لَقَدْ كُنْتُ أَرَى نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجِدُ رِيحَهُمَا مِنْ الرَّجُلِ فَيَأْمُرُ بِهِ فَيُؤْخَذُ بِيَدِهِ فَيُخْرَجُ بِهِ مِنْ الْمَسْجِدِ حَتَّى يُؤْتَى بِهِ الْبَقِيعَ فَمَنْ أَكَلَهُمَا لَا بُدَّ فَلْيُمِتْهُمَا طَبْخًا قَالَ فَخَطَبَ النَّاسَ يَوْمَ الْجُمُعَةِ وَأُصِيبَ يَوْمَ الْأَرْبِعَاءِ","trj":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammam Bin Yahya] dia berkata; Telah menceritakan kepada kami [Qatadah] dari [Salim Bin Abul Ja'd Al Ghatafani] dari [Ma'dan Bin Abu Thalhah Al Ya'mari] bahwa [Umar Bin Al Khaththab] berdiri di atas mimbar pada hari Jum'at, kemudian memuji dan mengagungkan Allah lalu menyebutkan Rasulullah shallallahu 'alaihi wasallam dan Abu bakar, kemudian berkata; \"Aku bermimpi dan aku menganggapnya itu adalah pertanda akan tibanya ajalku, aku bermimpi seakan akan seekor ayam jantan mematukku dua kali.\" Ma'dan berkata; dia (Umar) menyebutkan bahwa ayamnya berwarna merah, kemudian aku ceritakan kepada Asma' Binti Umais istri Abu Bakar, maka dia berkata; \"Seorang lelaki asing/selain arab akan membunuhmu.\" Umar berkata; \"Sesungguhnya orang-orang menyuruhku untuk mengangkat seorang pengganti, dan sesungguhnya Allah tidak akan menyia-nyiakan agama dan kekhilafahanNya, yang telah mengutus Nabi-Nya shallallahu 'alaihi wasallam dengan mengusungnya, dan jika ajal menjemputku maka urusan ini diserahkan didalam Syuraa (musyawarah) diantara enam orang yang ketika Nabiyullah shallallahu 'alaihi wasallam meninggal beliau ridla kepada mereka, maka siapa saja diantara mereka yang kalian bai'at hendaklah kalian dengar dan taati, dan sesungguhnya aku mengetahui akan ada orang-orang yang akan mengacaukan urusan ini, dan aku adalah yang akan memerangi mereka dengan tanganku atas dasar Islam, mereka itulah musuh musuh Allah, orang-orang kafir lagi sesat, demi Allah, aku tidak akan meninggalkan dari apa-apa yang telah Rabbku janjikan kepadaku kemudian menggantikanku dengan sesuatu yang lebih penting bagiku ketimbang Al Kalalah (seseorang yang meninggal dan tidak meninggalkan bapak serta anak), dan demi Allah, tidak pernah Nabiyullah shallallahu 'alaihi wasallam menegaskan sesuatu kepadaku tentang sesuatu sejak aku menemani beliau melebihi ketegasannya kepadaku dalam masalah kalalah sampai beliau menusukkan jarinya ke dadaku dan berkata: \"Cukup bagimu ayat tentang shaif yang ada di akhir surat An Nisa', sesungguhnya jika aku hidup maka aku akan putuskan masalah itu dengan keputusan yang dapat diketahui oleh orang yang membaca dan orang yang tidak membaca, dan aku bersaksi kepada Allah atas pemimpin pemimpin negri, bahwasannya aku mengutus mereka supaya mereka mengajarkan kepada manusia perihal urusan agama mereka dan agar supaya mereka menjelaskan tentang sunnah Nabi mereka shallallahu 'alaihi wasallam dan mengadukan kepadaku apa yang tidak mereka tidak ketahui, kemudian sesungguhnya kalian wahai manusia, kalian memakan dua pohon yang tidak aku anggap kecuali keduanya adalah menjijikan, yaitu bawang putih dan bawang merah ini, demi Allah aku telah melihat Nabiyullah shallallahu 'alaihi wasallam ketika mencium bau keduanya dari seorang lelaki, beliau menyuruhnya sambil memegang tangannya untuk keluar dari masjid sehingga diletakkan di Baqi', maka barangsiapa memakan keduanya hendaklah memasaknya hingga tidak ada baunya.\" Ma'dan berkata; \"Umar berkhutbah di hadapan manusia pada hari jum'at dan terbunuh pada hari Rabu.\""},{"p":"Ahmad","n":1773,"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ ثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَبِيبٍ عَن عِمْرَانَ بْنِ أَبِي أَنَسٍ عَن عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَن عَمْرِو بْنِ الْعَاصِ أَنَّهُ قَالَلَمَّا بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ ذَاتِ السَّلَاسِلِ قَالَ احْتَلَمْتُ فِي لَيْلَةٍ بَارِدَةٍ شَدِيدَةِ الْبَرْدِ فَأَشْفَقْتُ إِنْ اغْتَسَلْتُ أَنْ أَهْلَكَ فَتَيَمَّمْتُ ثُمَّ صَلَّيْتُ بِأَصْحَابِي صَلَاةَ الصُّبْحِ قَالَ فَلَمَّا قَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرْتُ ذَلِكَ لَهُ فَقَالَ يَا عَمْرُو صَلَّيْتَ بِأَصْحَابِكَ وَأَنْتَ جُنُبٌ قَالَ قُلْتُ نَعَمْ يَا رَسُولَ اللَّهِ إِنِّي احْتَلَمْتُ فِي لَيْلَةٍ بَارِدَةٍ شَدِيدَةِ الْبَرْدِ فَأَشْفَقْتُ إِنْ اغْتَسَلْتُ أَنْ أَهْلَكَ وَذَكَرْتُ قَوْلَ اللَّهِ عَزَّ وَجَلَّ{ وَلَا تَقْتُلُوا أَنْفُسَكُمْ إِنَّ اللَّهَ كَانَ بِكُمْ رَحِيمًا }فَتَيَمَّمْتُ ثُمَّ صَلَّيْتُ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَقُلْ شَيْئًا","trj":"Telah menceritakan kepada kami [Hasan bin Musa] ia berkata, Telah menceritakan kepada kami [Ibnu Lahi'ah] Telah menceritakan kepada kami [Yazid bin Abu Habib] dari [Imran bin Abu Anas] dari [Abdurrahman bin Jubair] dari [Amru bin Ash] berkata saat Rasulullah shallallahu 'alaihi wasallam mengutusnya pada tahun Dzatu Salasil, \"Pada suatu malam yang sangat dingin saya mimpi basah, jika mandi maka saya khawatir akan jatuh sakit. Maka saya pun bertayammum kemudian shalat Subuh berjama'ah bersama sahabat-sahabatku. Saat kami menemui Rasulullah shallallahu 'alaihi wasallam, maka saya pun menuturkan hal itu kepada beliau. Beliau bertanya: \"Wahai Amru, apakah kamu shalat bersama sahabat-sahabatmu sedangkan kamu dalam keadaan junub?\" saya menjawab, \"Benar. Wahai Rasulullah, saya mimpi basah pada malam yang sangat dingin sekali, jika mandi saya khawatir akan jatuh sakit. Lalu saya teringat firman Allah, '(Dan janganlah kamu membunuh dirimu. Sesungguhnya Allah adalah Maha Penyayang kepadamu) ' (Qs. An Nisa: 29) Maka saya pun bertayammum dan shalat.\" Rasulullah shallallahu 'alaihi wasallam tertawa dan beliau tidak berkata sesuatu pun."},{"p":"Bukhari","n":664,"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا مُحَارِبُ بْنُ دِثَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ الْأَنْصَارِيَّ قَالَأَقْبَلَ رَجُلٌ بِنَاضِحَيْنِ وَقَدْ جَنَحَ اللَّيْلُ فَوَافَقَ مُعَاذًا يُصَلِّي فَتَرَكَ نَاضِحَهُ وَأَقْبَلَ إِلَى مُعَاذٍ فَقَرَأَ بِسُورَةِ الْبَقَرَةِ أَوْ النِّسَاءِ فَانْطَلَقَ الرَّجُلُ وَبَلَغَهُ أَنَّ مُعَاذًا نَالَ مِنْهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَكَا إِلَيْهِ مُعَاذًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُعَاذُ أَفَتَّانٌ أَنْتَ أَوْ أَفَاتِنٌ ثَلَاثَ مِرَارٍ فَلَوْلَا صَلَّيْتَ بِسَبِّحِ اسْمَ رَبِّكَ وَالشَّمْسِ وَضُحَاهَا وَاللَّيْلِ إِذَا يَغْشَى فَإِنَّهُ يُصَلِّي وَرَاءَكَ الْكَبِيرُ وَالضَّعِيفُ وَذُو الْحَاجَةِأَحْسِبُ هَذَا فِي الْحَدِيثِ قَالَ أَبُو عَبْد اللَّهِ وَتَابَعَهُ سَعِيدُ بْنُ مَسْرُوقٍ وَمِسْعَرٌ وَالشَّيْبَانِيُّ قَالَ عَمْرٌو وَعُبَيْدُ اللَّهِ بْنُ مِقْسَمٍ وَأَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَرَأَ مُعَاذٌ فِي الْعِشَاءِ بِالْبَقَرَةِ وَتَابَعَهُ الْأَعْمَشُ عَنْ مُحَارِبٍ","trj":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Muharib bin Ditsar] berkata, Aku mendengar [Jabir bin 'Abdullah Al Anshari] berkata, \"Seoranglaki-laki datang dengan membawa dua unta yang baru saja diberinya minum saat malam sudah gelap gulita. Laki-laki itu kemudian tinggalkan untanya dan ikut shalat bersama Mu'adz. Dalam shalatnya Mu'adz membaca surah Al Baqarah atau surah An Nisaa' sehingga laki-laki tersebut meninggalkan Mu'adz. Maka sampailah kepadanya berita bahwa Mu'adz mengecam tindakannya. Akhirnya laki-laki tersebut mendatangi Nabi shallallahu 'alaihi wasallam dan mengadukan persoalannya kepada beliau. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Wahai Mu'adz, apakah kamu membuat fitnah?\" Atau kata Beliau: \"Apakah kamu menjadi pembuat fitnah? -Beliau ulangi perkataannya tersebut hingga tiga kali- \"Mengapa kamu tidak membaca saja surat 'Sabbihisma rabbika', atau dengan 'Wasysyamsi wa dluhaahaa' atau 'Wallaili idzaa yaghsyaa'? Karena yang ikut shalat di belakangmu mungkin ada orang yang lanjut usia, orang yang lemah atau orang yang punya keperluan.\" Perawi berkata, \"Menurutku sampai inilah kalimat hadits ini.\" Abu 'Abdullah berkata; hadits ini dikuatkan oleh [Sa'id bin Masruq] dan [Mis'ar] dan [Asy Syaibani]. [Amru] dan [Ubaidullah bin Miqsam] dan [Abu Az Zubair] dari [Jabir] bahwa dalam shalat Isya Mu'adz membaca surat Al Baqarah. Dan hadits ini dikuatkan oleh [Al A'masy] dari [Muharib].\""},{"p":"Bukhari","n":2060,"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا ابْنُ نُمَيْرٍ أَخْبَرَنَا هِشَامٌ ح و حَدَّثَنِي مُحَمَّدُ بْنُ سَلَّامٍ قَالَ سَمِعْتُ عُثْمَانَ بْنَ فَرْقَدٍ قَالَ سَمِعْتُ هِشَامَ بْنَ عُرْوَةَ يُحَدِّثُ عَنْ أَبِيهِ أَنَّهُ سَمِعَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاتَقُولُ{ وَمَنْ كَانَ غَنِيًّا فَلْيَسْتَعْفِفْ وَمَنْ كَانَ فَقِيرًا فَلْيَأْكُلْ بِالْمَعْرُوفِ }أُنْزِلَتْ فِي وَالِي الْيَتِيمِ الَّذِي يُقِيمُ عَلَيْهِ وَيُصْلِحُ فِي مَالِهِ إِنْ كَانَ فَقِيرًا أَكَلَ مِنْهُ بِالْمَعْرُوفِ","trj":"Telah menceritakan kepada saya [Ishaq] telah menceritakan kepada kami [Ibnu Numair] telah mengabarkan kepada kami [Hisyam] dan diriwayatkan pula telah menceritakan kepada saya [Muhammad bin Salam] berkata; Aku mendengar ['Utsman bin Farqad] berkata; Aku mendengar [Hisyam bin 'Urwah] menceritakan dari [Bapaknya] bahwa dia mendengar ['Aisyah radliallahu 'anha] berkata, (tentang ayat QS. An-Nisaa' ayat 6 yang artinya (barangsiapa diantara pemelihara itu yang mampu maka hendaknya ia menehan diri dari memakan harta anak yatim itu, dan barangsiapa yang miskin maka ia boleh makan harta itu menurut yang patut), ayat ini turun pada wali anak yatim yang memelihara dan menjaga hartanya, dan jika ia seorang miskin maka ia boleh memakannya dengan cara ma'ruf (yang patut)."},{"p":"Bukhari","n":2187,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ حَدَّثَهُأَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا النَّخْلَ فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ فَأَبَى عَلَيْهِ فَاخْتَصَمَا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ أَسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ فَقَالَ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اسْقِ يَا زُبَيْرُ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِ فَقَالَ الزُّبَيْرُ وَاللَّهِ إِنِّي لَأَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }","trj":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] berkata, telah menceritakan kepadaku [Ibnu Syihab] dari ['Urwah] dari ['Abdullah bin Az Zubair radliallahu 'anhuma] bahwasanya dia menceritakan bahwa ada seorang dari kalangan Anshar bersengketa dengan Az Zubair di hadapan Nabi shallallahu 'alaihi wasallam tentang aliran air di daerah Al Harrah yang mereka gunakan untuk menyirami pepohonan kurma. Berkata, orang Anshar tersebut: \"Bukalah air agar bisa mengalir?\" Az Zubair menolaknya lalu keduanya bertengkar di hadapan Nabi shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam berkata, kepada Az Zubair: \"Wahai Zubair, berilah air dan kirimlah buat tetanggamu\". Maka orang Anshar itu marah seraya berkata; \"Tentu saja kamu bela dia karena dia putra bibimu\". Maka wajah Rasulullah shallallahu 'alaihi wasallam memerah kemudian berkata: \"Wahai Zubair, berilah air kemudian bendunglah hingga air itu kembali ke dasar ladang\". Maka Az Zubair berkata: \"Demi Allah, sungguh aku menganggap bahwa ayat ini turun tentang kasus ini, yaitu firman Allah dalam surah An-Nisa ayat 65 yang artinya: (\"Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan…)."},{"p":"Bukhari","n":2188,"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ قَالَخَاصَمَ الزُّبَيْرَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا زُبَيْرُ اسْقِ ثُمَّ أَرْسِلْ فَقَالَ الْأَنْصَارِيُّ إِنَّهُ ابْنُ عَمَّتِكَ فَقَالَ عَلَيْهِ السَّلَام اسْقِ يَا زُبَيْرُ ثُمَّ يَبْلُغُ الْمَاءُ الْجَدْرَ ثُمَّ أَمْسِكْ فَقَالَ الزُّبَيْرُ فَأَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }","trj":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhriy] dari ['Urwah] berkata: Ada seorang dari Kaum Anshar bersengketa dengan Az Zubair lalu Nabi shallallahu 'alaihi wasallam berkata: \" Wahai Zubair, berilah air dan kirimlah buat tetanggamu\". Lalu orang Anshar itu berkata; \"Tentu saja kamu bela dia karena dia putra bibimu\". Maka Beliau shallallahu 'alaihi wasallam berkata: \"Wahai Zubair, berilah air kemudian biarkanlah air memenuhi dasar ladang lalu bendunglah\". Kemudian Az Zubair berkata: \"Aku menganggap bahwa ayat ini turun tentang kasus ini, yaitu firman Allah dalam surah An-Nisa ayat 65 yang artinya: (\"Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan…)."},{"p":"Bukhari","n":2189,"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ سَلَامٍ أَخْبَرَنَا مَخْلَدُ بْنُ يَزِيدَ الْحَرَّانِيُّ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّهُ حَدَّثَهُأَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ فِي شِرَاجٍ مِنْ الْحَرَّةِ يَسْقِي بِهَا النَّخْلَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ يَا زُبَيْرُ فَأَمَرَهُ بِالْمَعْرُوفِ ثُمَّ أَرْسِلْ إِلَى جَارِكَ فَقَالَ الْأَنْصَارِيُّ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اسْقِ ثُمَّ احْبِسْ يَرْجِعَ الْمَاءُ إِلَى الْجَدْرِ وَاسْتَوْعَى لَهُ حَقَّهُ فَقَالَ الزُّبَيْرُ وَاللَّهِ إِنَّ هَذِهِ الْآيَةَ أُنْزِلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }قَالَ لِي ابْنُ شِهَابٍ فَقَدَّرَتْ الْأَنْصَارُ وَالنَّاسُ قَوْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ ثُمَّ احْبِسْ حَتَّى يَرْجِعَ إِلَى الْجَدْرِ وَكَانَ ذَلِكَ إِلَى الْكَعْبَيْنِ","trj":"Telah menceritakan kepada kami [Muhammad, dia adalah anak dari Salam] telah mengabarkan kepada kami [Makhlad bin Yazid Al Harraniy] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ibnu Syihab] dari ['Urwah bin Az Zubair] bahwasanya dia menceritakan ada seorang dari kalangan Anshar bersengketa dengan Az Zubair di hadapan Nabi shallallahu 'alaihi wasallam tentang aliran air di daerah Al Harrah yang mereka gunakan untuk menyirami pepohonan kurma. Maka Rasulullah shallallahu 'alaihi wasallam berkata kepada Az Zubair: \"Wahai Zubair. Beliau memerintahkannya berbuat ma'ruf.\"Kemudian kirimlah buat tetanggamu\". Orang Anshar itu berkata; \"Tentu saja kamu bela dia karena dia putra bibimu\". Maka wajah Rasulullah shallallahu 'alaihi wasallam memerah kemudian berkata: \"Berilah air kemudian bendunglah hingga air itu kembali ke dasar ladang dan tunaikanlah haknya\". Maka Az Zubair berkata: \"Demi Allah, sungguh ayat ini turun tentang kasus ini, yaitu firman Allah dalam surah An-Nisa ayat 65 yang artinya: (\"Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan…). Ibnu Sihab berkata, kepadaku: \"Maka orang Anshar dan yang lainnya mengukur apa yang Nabi shallallahu 'alaihi wasallam sabdakan tadi: \"Berilah air kemudian bendunglah hingga air itu kembali ke dasar ladang\", dan saat itu mencapai setinggi mata kaki."},{"p":"Bukhari","n":2270,"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَافِي هَذِهِ الْآيَةِ{ وَإِنْ امْرَأَةٌ خَافَتْ مِنْ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا }قَالَتْ الرَّجُلُ تَكُونُ عِنْدَهُ الْمَرْأَةُ لَيْسَ بِمُسْتَكْثِرٍ مِنْهَا يُرِيدُ أَنْ يُفَارِقَهَا فَتَقُولُ أَجْعَلُكَ مِنْ شَأْنِي فِي حِلٍّ فَنَزَلَتْ هَذِهِ الْآيَةُ فِي ذَلِكَ","trj":"Telah menceritakan kepada kami [Muhamamad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] tentang ayat ini QS An-Nisaa: 128): (\"Apabila seorang isteri takut suaminya akan berbuat nusyuz (tidak mau menggaulinya) atau berlaku kasar terhadapnya\"), dia ('Aisyah radliallahu 'anha) berkata: \"Yaitu jika seorang suami yang memiliki isteri namun dia tidak lagi mencintai dan menggaulinya serta berkehendak untuk menceraikanya lalu isterinya berkata, \"aku persilakan kamu meninggalkan aku namun jangan ceraikan aku\", maka turunlah ayat ini\". "},{"p":"Bukhari","n":2314,"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْعَامِرِيُّ الْأُوَيْسِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ أَنَّهُ سَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّهُسَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ قَوْلِ اللَّهِ تَعَالَى{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا إِلَى وَرُبَاعَ }فَقَالَتْ يَا ابْنَ أُخْتِي هِيَ الْيَتِيمَةُ تَكُونُ فِي حَجْرِ وَلِيِّهَا تُشَارِكُهُ فِي مَالِهِ فَيُعْجِبُهُ مَالُهَا وَجَمَالُهَا فَيُرِيدُ وَلِيُّهَا أَنْ يَتَزَوَّجَهَا بِغَيْرِ أَنْ يُقْسِطَ فِي صَدَاقِهَا فَيُعْطِيهَا مِثْلَ مَا يُعْطِيهَا غَيْرُهُ فَنُهُوا أَنْ يُنْكِحُوهُنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ وَيَبْلُغُوا بِهِنَّ أَعْلَى سُنَّتِهِنَّ مِنْ الصَّدَاقِ وَأُمِرُوا أَنْ يَنْكِحُوا مَا طَابَ لَهُمْ مِنْ النِّسَاءِ سِوَاهُنَّ قَالَ عُرْوَةُ قَالَتْ عَائِشَةُ ثُمَّ إِنَّ النَّاسَ اسْتَفْتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ هَذِهِ الْآيَةِ فَأَنْزَلَ اللَّهُ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ إِلَى قَوْلِهِ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }وَالَّذِي ذَكَرَ اللَّهُ أَنَّهُ يُتْلَى عَلَيْكُمْ فِي الْكِتَابِ الْآيَةُ الْأُولَى الَّتِي قَالَ فِيهَا{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ عَائِشَةُ وَقَوْلُ اللَّهِ فِي الْآيَةِ الْأُخْرَى{ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }يَعْنِي هِيَ رَغْبَةُ أَحَدِكُمْ لِيَتِيمَتِهِ الَّتِي تَكُونُ فِي حَجْرِهِ حِينَ تَكُونُ قَلِيلَةَ الْمَالِ وَالْجَمَالِ فَنُهُوا أَنْ يَنْكِحُوا مَا رَغِبُوا فِي مَالِهَا وَجَمَالِهَا مِنْ يَتَامَى النِّسَاءِ إِلَّا بِالْقِسْطِ مِنْ أَجْلِ رَغْبَتِهِمْ عَنْهُنَّ","trj":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah Al 'Amiriy Al Uwaisiy] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Shalih] dari [Ibnu Syihab] telah menceritakan kepadaku ['Urwah] bahwa dia bertanya kepada ['Aisyah radliallahu 'anha]. Dan [Al Laits] berkata, telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] be telah menceritakan kapadaku ['Urwah bin Az Zubair] bahwa dia bertanya kepada ['Aisyah radliallahu 'anha] tentang firman Allah yang artinya: (\"Jika kamu khawatir tidak dapat berlaku adil …. seterusnya hingga …empat-empat\". (QS. An-Nisaa ayat 3), maka ia menjawab: \"Wahai anak saudariku, yang dimaksud ayat itu adalah seorang anak perempuan yatim yang berada pada asuhan walinya, hartanya ada pada walinya, dan walinya ingin memiliki harta itu dan menikahinya namun ia tidak bisa berbuat adil dalam memberikan maharnya, yaitu memberi seperti ia memberikan untuk yang lainnya, maka mereka dilarang untuk menikahinya kecuali jika mereka bisa berbuat adil pada mereka, dan mereka memberikan mahar terbaik kepadanya, mereka diperintahkan untuk menikahi wanita-wanita yang baik untuk mereka selain anak-anak yatim itu\". 'Urwah berkata, lalu 'Aisyah berkata, kemudian orang-orang meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam setelah turunnya ayat ini; wayastaftuunaka finnisaa' (dan mereka meminta fatwa kepadamu tentang para wanita) hingga firmanNya; watarghobuuna antankihuuhunna (dan kalian ingin menikahi mereka) dan yang disebutkan Allah pada firmanNya bahwa; yutla 'alaikum fil kitab (telah disebutkan untuk kalian di dalam Al Quran) ayat pertama yang Allah berfirman didalamnya ada kalimat; wa in khiftum allaa tuqsituu fil yataamaa fankihuu maa thaoba lakum minan nisaa' (jika kalian tidak bisa berbuat adil kepada anak-anak yatim, maka nikahilah wanita-wanita yang baik untuk kalian), 'Aisyah berkata, dan firman Allah pada ayat yang lain; watarghobuuna an tankihuuhunna (dan kalian ingin untuk menikahi mereka) yaitu keinginan kalian untuk menikahi anak perempuan yatim yang kalian asuh ketika ia sedikit hartanya dan kurang menarik wajahya, maka mereka dilarang untuk menikahi mereka karena semata hartanya dan kecantikannya dari anak-anak perempuan yatim kecuali dengan adil disebabkan ketidak tertarikan mereka kepada perempuan yatim itu\"."},{"p":"Bukhari","n":2497,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ وَإِنْ امْرَأَةٌ خَافَتْ مِنْ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا }قَالَتْ هُوَ الرَّجُلُ يَرَى مِنْ امْرَأَتِهِ مَا لَا يُعْجِبُهُ كِبَرًا أَوْ غَيْرَهُ فَيُرِيدُ فِرَاقَهَا فَتَقُولُ أَمْسِكْنِي وَاقْسِمْ لِي مَا شِئْتَ قَالَتْ فَلَا بَأْسَ إِذَا تَرَاضَيَا","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'ad] telah menceritakan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa ayat yang berbunyi: QS An-Nisaa: 128): (\"Apabila seorang isteri takut suaminya akan berbuat nusyuz (tidak mau menggaulinya) atau berlaku kasar terhadapnya\"), dia ('Aisyah radliallahu 'anha) berkata: \"Itu adalah seorang suami yang melihat pada isterinya apa-apa yang tidak menyenangkannya berupa pelanggaran dosa besar atau lainnya lalu dia berniat menceraikan isterinya lalu isterinya itu berkata: \"Pertahankanlah aku dan bersumpahlah kepadaku terserah apa saja yang kamu kehendaki\". 'Aisyah radliallahu 'anha berkata: \"Maka tidak berdosa bila keduanya saling ridho\"."},{"p":"Bukhari","n":2509,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ الزُّبَيْرَ كَانَ يُحَدِّثُأَنَّهُ خَاصَمَ رَجُلًا مِنْ الْأَنْصَارِ قَدْ شَهِدَ بَدْرًا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِرَاجٍ مِنْ الْحَرَّةِ كَانَا يَسْقِيَانِ بِهِ كِلَاهُمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْزُّبَيْرِ اسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ فَقَالَ يَا رَسُولَ اللَّهِ آنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اسْقِ ثُمَّ احْبِسْ حَتَّى يَبْلُغَ الْجَدْرَ فَاسْتَوْعَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَئِذٍ حَقَّهُ لِلْزُّبَيْرِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ ذَلِكَ أَشَارَ عَلَى الزُّبَيْرِ بِرَأْيٍ سَعَةٍ لَهُ وَلِلْأَنْصَارِيِّ فَلَمَّا أَحْفَظَ الْأَنْصَارِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَوْعَى لِلْزُّبَيْرِ حَقَّهُ فِي صَرِيحِ الْحُكْمِ قَالَ عُرْوَةُ قَالَ الزُّبَيْرُ وَاللَّهِ مَا أَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ إِلَّا فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }الْآيَةَ","trj":"Telah bercerita kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata telah bercerita kepadaku ['Urwah bin Az Zubair] bahwa [Az Zubair] pernah bercerita bahwa dia pernah bersengketa dengan seseorang dari kaum Anshor yang pernah ikut dalam perang Badar kepada Rasulullah shallallahu 'alaihi wasallam tentang masalah saluran air di Al Harrah dimana keduanya sama-sama saling menyiram (kebun mereka darinya) Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepada Az Zubair: \"Siramlah (kebunmu darinya) wahai Zubair lalu alirkanlah ke tetanggamu\". Maka orang Anshor itu marah seraya berkata: \"Wahai Rasulullah, Tuan bela dia karena dia anak dari bibi Tuan\". Maka wajah Rasulullah shallallahu 'alaihi wasallam berubah kemudian Beliau berkata: \"Siramlah (kebunmu) darinya kemudian tahanlah air itu hingga memenuhi kebun\". Maka Rasulullah shallallahu 'alaihi wasallam saat itu memutuskan untuk mememnuhi hak Zubair padahal sebelumnya Rasulullah shallallahu 'alaihi wasallam memberi isyarat kepada Zubair agar memberi kelapangan bagi orang Anshor itu. Ketika orang Anshor itu tidak menerima maka Rasulullah shallallahu 'alaihi wasallam mengembalikan hak Zubair sepenuhnya sesuai hukum yang semestiya. 'Urwah berkata; Az Zubair berkata: \"Demi Allah, tidaklah aku menduga ayat ini turun melainkan dalam perkara ini: (\"Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan….) Ayat 65 dari surah an-Nisaa'"},{"p":"Bukhari","n":2557,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ كَانَ عُرْوَةُ بْنُ الزُّبَيْرِ يُحَدِّثُ أَنَّهُ سَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ هِيَ الْيَتِيمَةُ فِي حَجْرِ وَلِيِّهَا فَيَرْغَبُ فِي جَمَالِهَا وَمَالِهَا وَيُرِيدُ أَنْ يَتَزَوَّجَهَا بِأَدْنَى مِنْ سُنَّةِ نِسَائِهَا فَنُهُوا عَنْ نِكَاحِهِنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ فِي إِكْمَالِ الصَّدَاقِ وَأُمِرُوا بِنِكَاحِ مَنْ سِوَاهُنَّ مِنْ النِّسَاءِ قَالَتْ عَائِشَةُ ثُمَّ اسْتَفْتَى النَّاسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ قُلْ اللَّهُ يُفْتِيكُمْ فِيهِنَّ }قَالَتْ فَبَيَّنَ اللَّهُ فِي هَذِهِ الْآيَةِ أَنَّ الْيَتِيمَةَ إِذَا كَانَتْ ذَاتَ جَمَالٍ وَمَالٍ رَغِبُوا فِي نِكَاحِهَا وَلَمْ يُلْحِقُوهَا بِسُنَّتِهَا بِإِكْمَالِ الصَّدَاقِ فَإِذَا كَانَتْ مَرْغُوبَةً عَنْهَا فِي قِلَّةِ الْمَالِ وَالْجَمَالِ تَرَكُوهَا وَالْتَمَسُوا غَيْرَهَا مِنْ النِّسَاءِ قَالَ فَكَمَا يَتْرُكُونَهَا حِينَ يَرْغَبُونَ عَنْهَا فَلَيْسَ لَهُمْ أَنْ يَنْكِحُوهَا إِذَا رَغِبُوا فِيهَا إِلَّا أَنْ يُقْسِطُوا لَهَا الْأَوْفَى مِنْ الصَّدَاقِ وَيُعْطُوهَا حَقَّهَا","trj":"Telah bercerita kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata ['Urwah bin Az Zubair] bercerita bahwa dia pernah bertanya kepada ['Aisyah radliallahu 'anha] tentaang firman Allah QS an-Nisaa' ayat 3 yang artinya: (Dan jika kamu takut tidak akan dapat berlaku adil terhadap (hak-hak) perempuan yang yatim (bilamana kamu mengawininya), maka kawinilah wanita-wanita (lain) yang kamu senangi …). 'Aisyah menjawab: \"Yang dimaksud ayat itu adalah seorang anak perempuan yatim yang berada pada asuhan walinya, lalu walinya itu tertarik dengan kecantikan dan hartanya dan berhasrat untuk mengawininya namun memberikan haknya lebih rendah dari yang biasa diberikan kepada istri-istrinya sebelumnya maka mereka dilarang menikahinya kecuali bila mereka dapat berlaku adil kepada mereka, dan mereka diperintahkan untuk menikahi wanita-wanita lain selain mereka\". 'Aisyah berkata: \"Kemudian orang-orang meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam setelah itu, maka Allah 'azza wajalla menurunkan firman-Nya QS an-Nisaa' ayat 126 yang artinya (dan mereka meminta fatwa kepadamu tentang para wanita. Katakanlah; Allah akan memberikan fatwa kepada kalian tentang mereka..) 'Aisyah berkata: \"Maka Allah menjelaskan dalam ayat ini bahwa seorang anak yatim perempuan jika memiliki kecantikan dan harta lalu walinya berhasrat menikahinya namun tidak memberikan haknya dengan melengkapi mahar sebagaimana semestinya. Namun bila anak yatim perempuan itu tidak memiliki harta dan kecantikan mereka meninggalkannya dan mencari wanita selain mereka\". Beliau bersabda: \"Sebagaimana mereka tidak menyukainya disebabkan sedikit hartanya dan tidak cantik lalu meninggalkannya maka mereka juga tidak boleh menikahinya saat tertarik kecuali bila mereka dapat berlaku adil kepadanya dengan menunaikan maharnya secara wajar serta memberikan hak-haknya\"."},{"p":"Bukhari","n":2559,"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ وَمَنْ كَانَ غَنِيًّا فَلْيَسْتَعْفِفْ وَمَنْ كَانَ فَقِيرًا فَلْيَأْكُلْ بِالْمَعْرُوفِ }قَالَتْ أُنْزِلَتْ فِي وَالِي الْيَتِيمِ أَنْ يُصِيبَ مِنْ مَالِهِ إِذَا كَانَ مُحْتَاجًا بِقَدْرِ مَالِهِ بِالْمَعْرُوفِ","trj":"Telah bercerita kepada kami ['Ubaidullah bin Isma'il] telah bercerita kepada kami [Abu Usamah] dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha] tentang firman Allah Subhanahu wa Ta'ala dalam QS an-Nisaa' ayat; 6, yang artinya (\"Dan barang siapa (di antara pemelihara itu) mampu, maka hendaklah ia menahan diri (dari memakan harta anak yatim itu) dan barang siapa yang miskin, maka bolehlah ia makan harta itu menurut yang patut\"), dia berkata: \"Ayat ini turun berkenaan dengan seorang yang memelihara anak yatim lalu ingin mengambil harta anak yatim tersebut apabila membutuhkannya sesuai dengan jumlah hartanya secara ma'ruf (yang patut)."},{"p":"Bukhari","n":2619,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُ يَقُولُلَمَّا نَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }دَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا فَجَاءَ بِكَتِفٍ فَكَتَبَهَا وَشَكَا ابْنُ أُمِّ مَكْتُومٍ ضَرَارَتَهُ فَنَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ غَيْرُ أُولِي الضَّرَرِ }","trj":"Telah bercerita kepada kami [Abu Al Walid] telah bercerita kepada kami [Syu'bah] dari [Abu Ishaq] berkata aku mendengar [Al Bara' radliallahu 'anhu] berkata; Ketika turun ayat 97 Surah an-Nisaa' yang artinya (\"Tidaklah sama orang-orang yang duduk-duduk saja (tidak ikut berperang) dari kalangan Kaum Mu'minin…\"), Rasulullah shallallahu 'alaihi wasallam memanggil Zaid, maka dia datang dengan membawa papan tulis lalu dia menulis ayat itu. Kemudian Ummu Maktum datang mengadukan alasannya, maka turunlah ayat ini (\"Tidaklah sama orang-orang yang duduk-duduk saja (tidak ikut berperang) dari kalangan Kaum Mu'minin tanpa memiliki alasan…\"), "},{"p":"Bukhari","n":2620,"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ الزُّهْرِيُّ قَالَ حَدَّثَنِي صَالِحُ بْنُ كَيْسَانَ عَنْ ابْنِ شِهَابٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ أَنَّهُ قَالَ رَأَيْتُ مَرْوَانَ بْنَ الْحَكَمِ جَالِسًا فِي الْمَسْجِدِ فَأَقْبَلْتُ حَتَّى جَلَسْتُ إِلَى جَنْبِهِ فَأَخْبَرَنَا أَنَّ زَيْدَ بْنَ ثَابِتٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْلَى عَلَيْهِ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }{ وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ }قَالَ فَجَاءَهُ ابْنُ أُمِّ مَكْتُومٍ وَهُوَ يُمِلُّهَا عَلَيَّ فَقَالَ يَا رَسُولَ اللَّهِ لَوْ أَسْتَطِيعُ الْجِهَادَ لَجَاهَدْتُ وَكَانَ رَجُلًا أَعْمَى فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفَخِذُهُ عَلَى فَخِذِي فَثَقُلَتْ عَلَيَّ حَتَّى خِفْتُ أَنَّ تَرُضَّ فَخِذِي ثُمَّ سُرِّيَ عَنْهُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ غَيْرُ أُولِي الضَّرَرِ }","trj":"Telah bercerita kepada kami ['Abdul 'Aziz bin 'Abdullah] telah bercerita kepada kami [Ibrahim bin Sa'ad Az Zuhriy] berkata telah bercerita kepadaku [Shalih bin Kaisan] dari [Ibnu Syihab] dari [Sahal bin Sa'ad As-Sa'idiy] bahwa dia berkata: \"Aku melihat [Marwan bin Al Hakam] sedang duduk di masjid lalu aku menemuinya hingga aku duduk di sampingnya lalu dia mengabarkan kepada kami bahwa [Zaid bin Tsabit] mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam membacakan ayat 97 Surah an-Nisaa' kepadanya yang artinya (\"Tidaklah sama orang-orang yang duduk-duduk saja (tidak ikut berperang) dari kalangan Kaum Mu'minin dengan orang-orang yang berjihad fii sabilillah…\"), maka datang Ibnu Ummu Maktum kepada Beliau padahal Beliau sedang membacakan ayat itu kepadaku dengan berkata: \"Wahai Rasulullah, seandainya aku mampu berjihad pasti aku akan berjihad\". Dia adalah seorang yang buta. Maka Allah Tabaaraka Wa Ta'ala menurunkan ayat kepada Rosul-Nya pada saat paha Beliau sedang berada diatas pahaku dan aku merasa berat dengan paha Beliau tersebut (karena beratnya wahyu yang Beliau terima) hingga aku khawatir pahaku retak. Kemudian Beliau tenang kembali. Maka Allah 'AZZA WAJALLA menurunkan firman-Nya (kelanjutan ayat tersebut) yang artinya: (\"Yang tanpa memiliki alasan…\")."},{"p":"Bukhari","n":3134,"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ سَعِيدَ بْنَ الْمُسَيَّبِ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَيُوشِكَنَّ أَنْ يَنْزِلَ فِيكُمْ ابْنُ مَرْيَمَ حَكَمًا عَدْلًا فَيَكْسِرَ الصَّلِيبَ وَيَقْتُلَ الْخِنْزِيرَ وَيَضَعَ الْجِزْيَةَ وَيَفِيضَ الْمَالُ حَتَّى لَا يَقْبَلَهُ أَحَدٌ حَتَّى تَكُونَ السَّجْدَةُ الْوَاحِدَةُ خَيْرًا مِنْ الدُّنْيَا وَمَا فِيهَا ثُمَّ يَقُولُ أَبُو هُرَيْرَةَ وَاقْرَءُوا إِنْ شِئْتُمْ{ وَإِنْ مِنْ أَهْلِ الْكِتَابِ إِلَّا لَيُؤْمِنَنَّ بِهِ قَبْلَ مَوْتِهِ وَيَوْمَ الْقِيَامَةِ يَكُونُ عَلَيْهِمْ شَهِيدًا }","trj":"Telah bercerita kepada kami [Ishaq] telah mengabarkan kepada kami [Ya'qub binIbrahim] telah bercerita kepada kami [bapakku] dari [Shalih] dari [Ibnu Syihab] bahwa [Sa'id bin Al Musayyab] mendengar [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam besabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, diprediksikan segera turun kepada kalian 'Isa bin Maryam sebagai hakim yang adil, dia akan menghancurkan salib, membunuh babi, membebaskan jizyah dan harta benda akan banyak tersebar sehingga tidak ada seorangpun yag mau menerima (shadaqah) hingga pada masa itu satu kali sujud lebih baik daripada dunia dan isinya\". Kemudian Abu Hurairah radliallahu 'anhu berkata; \"Bacalah firman Allah jika kamu mau; (\"Dan tidak ada satu pun dari Ahli Kitab kecuali pasti akan beriman kepadanya ('Isa 'alahis salam) sebelum kematiannya dan pada hari qiyamat nanti 'Isa akan menjadi saksi bagi mereka\"). (QS an-Nisaa ayat 159)."},{"p":"Bukhari","n":3409,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ أَوْ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى قَالَ سَلْ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ مَا أَمْرُهُمَا{ وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ لَمَّا أُنْزِلَتْ الَّتِي فِي الْفُرْقَانِ قَالَ مُشْرِكُو أَهْلِ مَكَّةَ فَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَقَدْ أَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ }الْآيَةَ فَهَذِهِ لِأُولَئِكَ وَأَمَّا الَّتِي فِي النِّسَاءِ الرَّجُلُ إِذَا عَرَفَ الْإِسْلَامَ وَشَرَائِعَهُ ثُمَّ قَتَلَ فَجَزَاؤُهُ جَهَنَّمُفَذَكَرْتُهُ لِمُجَاهِدٍ فَقَالَإِلَّا مَنْ نَدِمَ","trj":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] telah menceritakan kepadaku [Sa'id bin Jubair] -atau dia berkata, telah menceritakan kepadaku [Al Hakam] dari [Sa'id bin Jubair] berkata, - 'Abdurrahman bin Abza menyuruhku, katanya; \"Tanyalah kepada Ibnu 'Abbas tentang dua ayat ini dan apa maksudnya, yaitu yang pertama firman Allah dalam QS al Isra` ayat 33; (\"Dan janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan haq (alasan yang benar) \" dan yang kedua firman Allah dalam QS an Nisaa' ayat 93: (\"Dan barangsiapa yang membunuh orang beriman dengan sengaja...\"). Maka aku bertanya kepada [Ibnu 'Abbas], maka dia menjelaskan; Ketika turun firman Allah yang serupa ini pada surah al Furqan, orang-orang musyrik penduduk Makkah berkata; \"Sungguh kita telah membunuh jiwa yang diharamkan Allah dan kita juga menyembah selain Allah dan kita telah banyak berbuat maksiat, maka Allah menurunkan firman-Nya yang artinya: \"...kecuali siapa yang bertaubat dan beriman...\" (QS al Furqan ayat 70). Nah, ayat-ayat ini turun untuk mereka. Adapun ayat yang ada dalam surah an Nisaa' adalah bila seseorang telah mengenal Islam dan syari'atnya, kemudian dia membunuh seseorang dengan sengaja maka balasan baginya adalah neraka jahannam\". Kemudian keterangan ini aku sampaikan kepada Mujahidmaka dia berkata; \"Kecuali siapa yang menyesali perbuartannya\"."},{"p":"Bukhari","n":3490,"ar":"بَاب حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي عَبْدُ الْكَرِيمِ أَنَّهُ سَمِعَ مِقْسَمًا مَوْلَى عَبْدِ اللَّهِ بْنِ الْحَارِثِ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ سَمِعَهُ يَقُولُ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }عَنْ بَدْرٍ وَالْخَارِجُونَ إِلَى بَدْرٍ","trj":"Bab. Telah menceritakan kepadaku [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] bahwa [Ibnu Juraij] telah mengabarkan kepada mereka, katanya telah mengabarkan kepadaku ['Abdul Karim] bahwa dia mendengar [Miqsam, maula 'Abdullah bin Al Harits] menceritakan dari [Ibnu 'Abbas] bahwanya dia mendengarnya menjelaskan firman Allah dalam QS an-Nisaa' ayat 97 yang artinya (\"Tidak sama orang-orang yang duduk dari orang beriman....\".) maksudnya adalah tentang perang Badar dan orang-orang yang keluar ikut perang Badar\"."},{"p":"Bukhari","n":3545,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ يُحَدِّثُ عَنْ زَيْدِ بْنِ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أُحُدٍ رَجَعَ نَاسٌ مِمَّنْ خَرَجَ مَعَهُ وَكَانَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِرْقَتَيْنِ فِرْقَةً تَقُولُ نُقَاتِلُهُمْ وَفِرْقَةً تَقُولُ لَا نُقَاتِلُهُمْ فَنَزَلَتْ{ فَمَا لَكُمْ فِي الْمُنَافِقِينَ فِئَتَيْنِ وَاللَّهُ أَرْكَسَهُمْ بِمَا كَسَبُوا }وَقَالَ إِنَّهَا طَيْبَةُ تَنْفِي الذُّنُوبَ كَمَا تَنْفِي النَّارُ خَبَثَ الْفِضَّةِ","trj":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] aku mendengar [Abdullah bin Yazid] bercerita dari [Zaid bin Tsabit] radliallahu 'anhu, dia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam berangkat ke medan Uhud, di tengah perjalanan beberapa orang yang ikut bersama beliau kembali pulang, dan sebab itu sahabat Nabi shallallahu 'alaihi wasallam terpecah menjadi dua kelompok; kelompok yang mengatakan, \"Kami akan memerangi mereka, \" dan kelompok yang mengatakan, \"Kami tidak akan memerangi mereka.\" Maka turunlah ayat: '(Maka Mengapa kamu (terpecah) menjadi dua golongan dalam (menghadapi) orang-orang munafik, padahal Allah Telah membalikkan mereka kepada kekafiran, disebabkan usaha mereka sendiri?) ' (Qs. An Nisaa: 88), beliau bersabda: \"Sesungguhnya hal itu terdapat suatu kebaikan, yang dapat menghapuskan dosa sebagaimana api menghilangkan karat pada perak.\""},{"p":"Bukhari","n":3723,"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَمْرِو بْنِ مَيْمُونٍ أَنَّ مُعَاذًا رَضِيَ اللَّهُ عَنْهُلَمَّا قَدِمَ الْيَمَنَ صَلَّى بِهِمْ الصُّبْحَ فَقَرَأَ{ وَاتَّخَذَ اللَّهُ إِبْرَاهِيمَ خَلِيلًا }فَقَالَ رَجُلٌ مِنْ الْقَوْمِ لَقَدْ قَرَّتْ عَيْنُ أُمِّ إِبْرَاهِيمَزَادَ مُعَاذٌ عَنْ شُعْبَةَ عَنْ حَبِيبٍ عَنْ سَعِيدٍ عَنْ عَمْرٍو أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ مُعَاذًا إِلَى الْيَمَنِ فَقَرَأَ مُعَاذٌ فِي صَلَاةِ الصُّبْحِ سُورَةَ النِّسَاءِ فَلَمَّا قَالَ{ وَاتَّخَذَ اللَّهُ إِبْرَاهِيمَ خَلِيلًا }قَالَ رَجُلٌ خَلْفَهُ قَرَّتْ عَيْنُ أُمِّ إِبْرَاهِيمَ","trj":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Syu'bah] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari ['Amru bin Maimun] bahwa ketika [Mu'adz] sampai di Yaman, dia shalat shubuh bersama kaumnya dengan membaca ayat: \"Allah telah menjadikan Ibrahim sebagai kekasihnya.\" Maka berkatalah salah seorang dari kaumnya; 'Mata ibu Ibrahim telah berbinar karena bahagia.' Sedangkan di dalam riwayat lain, [Mu'adz] menambahkan dari [Syu'bah] dari [Habib] dari [Sa'id] dari [Amru] bahwa Nabi shallallahu 'alaihi wasallam mengutus [Mu'adz bin Jabal] ke Yaman. Lalu pada waktu shalat shubuh Mu'adz bin Jabal membaca surat An Nisa, tatkala sampai ayat; Allah telah menjadikan Ibrahim sebagai kekasih-Nya.\" Seseorang di belakangnya berkata; 'Mata Ibu Ibrahim telah berbinar karena bahagia.'"},{"p":"Bukhari","n":3738,"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ رَجَاءٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَآخِرُ سُورَةٍ نَزَلَتْ كَامِلَةً بَرَاءَةٌ وَآخِرُ سُورَةٍ نَزَلَتْ خَاتِمَةُ سُورَةِ النِّسَاءِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","trj":"Telah menceritakan kepadaku ['Abdullah bin Raja'] Telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Al Bara' radliallahu 'anhu] berkata; Surat yang paling terakhir kali turun secara sempurna adalah surat Al Bara'ah. Dan surat penutup yang paling terakhir kali turun adalah surat An Nisa yang berbunyi; \"Mereka meminta fatwa kepadamu (tentang kalalah). Katakanlah Allah memberi fatwa kepadamu tentang kalalah. (QS. Annisa'; 176)."},{"p":"Bukhari","n":3863,"ar":"حَدَّثَنَا حِبَّانُ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ جَلَسْتُ إِلَى مَجْلِسٍ فِيهِ عُظْمٌ مِنْ الْأَنْصَارِ وَفِيهِمْ عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى فَذَكَرْتُ حَدِيثَ عَبْدِ اللَّهِ بْنِ عُتْبَةَ فِي شَأْنِ سُبَيْعَةَ بِنْتِ الْحَارِثِ فَقَالَ عَبْدُ الرَّحْمَنِ وَلَكِنَّ عَمَّهُ كَانَ لَا يَقُولُ ذَلِكَ فَقُلْتُ إِنِّي لَجَرِيءٌ إِنْ كَذَبْتُ عَلَى رَجُلٍ فِي جَانِبِ الْكُوفَةِ وَرَفَعَ صَوْتَهُ قَالَ ثُمَّ خَرَجْتُ فَلَقِيتُ مَالِكَ بْنَ عَامِرٍ أَوْ مَالِكَ بْنَ عَوْفٍ قُلْتُ كَيْفَ كَانَ قَوْلُ ابْنِ مَسْعُودٍ فِي الْمُتَوَفَّى عَنْهَا زَوْجُهَا وَهْيَ حَامِلٌ فَقَالَ قَالَ ابْنُ مَسْعُودٍأَتَجْعَلُونَ عَلَيْهَا التَّغْلِيظَ وَلَا تَجْعَلُونَ لَهَا الرُّخْصَةَ لَنَزَلَتْ سُورَةُ النِّسَاءِ الْقُصْرَى بَعْدَ الطُّولَىوَقَالَ أَيُّوبُ عَنْ مُحَمَّدٍ لَقِيتُ أَبَا عَطِيَّةَ مَالِكَ بْنَ عَامِرٍ","trj":"Telah menceritakan kepada kami [Hibban] Telah menceritakan kepada kami [Abdullah] Telah mengabarkan kepada kami [Abdullah bin Aun] dari [Muhammad bin Sirin] dia berkata; Aku duduk di sebuah majlis yang di dalamnya ada sekelompok orang-orang Anshar, di dalamnya ada Abdurrahman bin Abu Laila, lalu aku menyebutkan Hadits Abdullah bin Utbah yang menceritakan tentang Subaiah binti Al Harits. Maka Abdurrahman bin Abu Laila berkata; 'Akan tetapi pamannya tidak mengatakan hal itu. Lalu aku katakan, aku berani bertanggung jawab jika aku berdusta tentang orang yang berada di sisi Kufah -seraya mengeraskan suaranya-. Kemudian aku keluar dan bertemu dengan [Malik bin Amir], atau Malik bin Auf. Aku berkata; Bagaimana menurut Ibnu Mas'ud tentang orang yang telah ditinggal mati oleh suaminya padahal dia dalam keadaan hamil? Dia menjawab; [Ibnu Mas'ud] berkata; 'Apakah kamu akan memberatkannya dan tidak memberinya rukhsah, padahal sungguh telah turun surat Annisa' yang pendek setelah surat yang panjang (Al Baqarah)?. [Ayyub] berkata; dari [Muhammad] Aku bertemu dengan [Abu Atiyyah Malik bin Amir]."},{"p":"Bukhari","n":3911,"ar":"حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَ يَحْيَى بَعْضُ الْحَدِيثِ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ قُلْتُ آقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ فَإِنِّي أُحِبُّ أَنْ أَسْمَعَهُ مِنْ غَيْرِي فَقَرَأْتُ عَلَيْهِ سُورَةَ النِّسَاءِ حَتَّى بَلَغْتُ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }قَالَ أَمْسِكْ فَإِذَا عَيْنَاهُ تَذْرِفَانِ","trj":"Telah menceritakan kepada kami [Shadaqah] Telah mengabarkan kepada kami [Yahya] dari [Sufyan] dari [Sulaiman] dari [Ibrahim] dari ['Abidah] dari ['Abdullah] berkata; Yahya -sebagian Hadits- dari ['Amru bin Murrah] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Bacakanlah Al Qur'an kepadaku! Aku berkata; Bagaimana aku membacakan kepadamu, padahal Al Qur'an diturunkan kepadamu? Beliau menjawab: \"Sesungguhnya aku suka mendengarkannya dari orang lain.\" Lalu aku membacakan kepada beliau surat An Nisa hingga tatkala sampai ayat; Maka bagaimanakah (halnya orang kafir nanti), apabila Kami mendatangkan seseorang saksi (rasul) dari tiap-tiap umat dan Kami mendatangkan kamu (Muhammad) sebagai saksi atas mereka itu (sebagai umatmu (An Nisa; 41), \" beliau berkata; 'Cukup.' Dan ternyata beliau mencucurkan air mata (menangis)."},{"p":"Bukhari","n":3919,"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُغِيرَةُ بْنُ النُّعْمَانِ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ قَالَآيَةٌ اخْتَلَفَ فِيهَا أَهْلُ الْكُوفَةِ فَرَحَلْتُ فِيهَا إِلَى ابْنِ عَبَّاسٍ فَسَأَلْتُهُ عَنْهَا فَقَالَ نَزَلَتْ هَذِهِ الْآيَةُ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }هِيَ آخِرُ مَا نَزَلَ وَمَا نَسَخَهَا شَيْءٌ","trj":"Telah menceritakan kepada kami [Adam bin Abu Iyas] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Mughirah bin An Nu'man] ia berkata; Aku mendengar [Sa'id bin Jubair] berkata; ada sebuah ayat yang menyebabkan penduduk Kufah berselisih tentangnya, maka aku berangkat menemui Ibnu Abbas untuk menanyakan ayat itu. Lalu [Ibnu Abbas] berkata; Yaitu ayat: \"Dan barangsiapa yang membunuh seorang mukmin dengan sengaja maka balasannya ialah Jahannam, kekal ia di dalamnya dan Allah murka kepadanya.\" (An Nisa: 93). Ayat ini adalah ayat yang terakhir turun dari surat An Nisa, tidak ada yang menghapusnya sedikitpun."},{"p":"Bukhari","n":4085,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي الْقَاسِمُ بْنُ أَبِي بَزَّةَ أَنَّهُ سَأَلَ سَعِيدَ بْنَ جُبَيْرٍهَلْ لِمَنْ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا مِنْ تَوْبَةٍ فَقَرَأْتُ عَلَيْهِ{ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }فَقَالَ سَعِيدٌ قَرَأْتُهَا عَلَى ابْنِ عَبَّاسٍ كَمَا قَرَأْتَهَا عَلَيَّ فَقَالَ هَذِهِ مَكِّيَّةٌ نَسَخَتْهَا آيَةٌ مَدَنِيَّةٌ الَّتِي فِي سُورَةِ النِّسَاءِ","trj":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] Telah mengabarkan kepada mereka dia berkata; Telah mengabarkan kepadaku [Qasim bin Abu Bazzah] bahwsanya dia bertanya [Sa'id bin Jubair] apakah ada taubat bagi orang yang telah membunuh seorang mukmin? Lalu aku membacakan ayat; dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar... (Al Furqan: 68). Maka Sa'id berkata; Aku telah membacakannya kepada [Ibnu Abbas] sebagaimana kamu membacakannya kepadaku. Dia berkata; Ayat ini turun di Makkah, telah dinasakh (dihapus) oleh ayat yang turun di Madinah yang ada di didalam surat An Nisa."},{"p":"Bukhari","n":4210,"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ الزُّهْرِيُّ حَدَّثَنَاهُ قَالَ حَدَّثَنِي أَبُو إِدْرِيسَ سَمِعَ عُبَادَةَ بْنَ الصَّامِتِ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتُبَايِعُونِي عَلَى أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَزْنُوا وَلَا تَسْرِقُوا وَقَرَأَ آيَةَ النِّسَاءِوَأَكْثَرُ لَفْظِ سُفْيَانَ قَرَأَ الْآيَةَ فَمَنْ وَفَى مِنْكُمْ فَأَجْرُهُ عَلَى اللَّهِ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَعُوقِبَ فَهُوَ كَفَّارَةٌ لَهُ وَمَنْ أَصَابَ مِنْهَا شَيْئًا مِنْ ذَلِكَ فَسَتَرَهُ اللَّهُ فَهُوَ إِلَى اللَّهِ إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ غَفَرَ لَهُ تَابَعَهُ عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ فِي الْآيَةِ","trj":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] berkata; [Az Zuhri] Telah menceritakannya kepada kami, ia berkata; telah menceritakan kepadaku [Abu Idris] bahwa telah mendengar [Ubadah bin Shamit radliallahu 'anhu] berkata; Suatu hari, kami berada di sisi Nabi shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Apakah kalian mau berbai'at kepadaku bahwa kalian tidak akan menyekutukan Allah dengan sesuatu apa pun, dan kalian tidak akan berzina dan tidak pula akan mencuri?\" kemudian beliau membaca ayat dari surat An Nisa`. Dan mayoritas redaksi Sufyan \"Ia membacakan ayat\" (Bukan ayat surat Annisa'). Barangsiapa di antara kalian yang memenuhi janjinya, maka ganjaran pahala ada di sisi Allah. Dan siapa yang melanggar satu darinya lalu ia disiksa, maka hal itu adalah kafarah baginya. Namun, siapa yang melanggar satu darinya lalu Allah menyembunyikan kesalahannya, maka dosa hal itu kembali kepada Allah, bila Dia berkehendak, maka Dia akan menyiksanya, dan bila menghendaki, Dia akan mengampuninya. Hadits ini diperkuat oleh [Abdurrazzaq] dari [Ma'mar], yakni terkait dengan ayat."},{"p":"Bukhari","n":4224,"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ قَالَ جَاءَ رَجُلٌ إِلَى ابْنِ عَبَّاسٍ وَأَبُو هُرَيْرَةَ جَالِسٌ عِنْدَهُ فَقَالَ أَفْتِنِي فِي امْرَأَةٍ وَلَدَتْ بَعْدَ زَوْجِهَا بِأَرْبَعِينَ لَيْلَةً فَقَالَ ابْنُ عَبَّاسٍ آخِرُ الْأَجَلَيْنِ قُلْتُ أَنَا{ وَأُولَاتُ الْأَحْمَالِ أَجَلُهُنَّ أَنْ يَضَعْنَ حَمْلَهُنَّ }قَالَ أَبُو هُرَيْرَةَ أَنَا مَعَ ابْنِ أَخِي يَعْنِي أَبَا سَلَمَةَ فَأَرْسَلَ ابْنُ عَبَّاسٍ غُلَامَهُ كُرَيْبًا إِلَى أُمِّ سَلَمَةَ يَسْأَلُهَا فَقَالَتْقُتِلَ زَوْجُ سُبَيْعَةَ الْأَسْلَمِيَّةِ وَهِيَ حُبْلَى فَوَضَعَتْ بَعْدَ مَوْتِهِ بِأَرْبَعِينَ لَيْلَةً فَخُطِبَتْ فَأَنْكَحَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ أَبُو السَّنَابِلِ فِيمَنْ خَطَبَهَاوَقَالَ سُلَيْمَانُ بْنُ حَرْبٍ وَأَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَ كُنْتُ فِي حَلْقَةٍ فِيهَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى وَكَانَ أَصْحَابُهُ يُعَظِّمُونَهُ فَذَكَرُوا لَهُ فَذَكَرَ آخِرَ الْأَجَلَيْنِ فَحَدَّثْتُ بِحَدِيثِ سُبَيْعَةَ بِنْتِ الْحَارِثِ عَنْ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ فَضَمَّزَ لِي بَعْضُ أَصْحَابِهِ قَالَ مُحَمَّدٌ فَفَطِنْتُ لَهُ فَقُلْتُ إِنِّي إِذًا لَجَرِيءٌ إِنْ كَذَبْتُ عَلَى عَبْدِ اللَّهِ بْنِ عُتْبَةَ وَهُوَ فِي نَاحِيَةِ الْكُوفَةِ فَاسْتَحْيَا وَقَالَ لَكِنْ عَمُّهُ لَمْ يَقُلْ ذَاكَ فَلَقِيتُ أَبَا عَطِيَّةَ مَالِكَ بْنَ عَامِرٍ فَسَأَلْتُهُ فَذَهَبَ يُحَدِّثُنِي حَدِيثَ سُبَيْعَةَ فَقُلْتُ هَلْ سَمِعْتَ عَنْ عَبْدِ اللَّهِ فِيهَا شَيْئًا فَقَالَ كُنَّا عِنْدَ عَبْدِ اللَّهِ فَقَالَ أَتَجْعَلُونَ عَلَيْهَا التَّغْلِيظَ وَلَا تَجْعَلُونَ عَلَيْهَا الرُّخْصَةَ لَنَزَلَتْ سُورَةُ النِّسَاءِ الْقُصْرَى بَعْدَ الطُّولَى{ وَأُولَاتُ الْأَحْمَالِ أَجَلُهُنَّ أَنْ يَضَعْنَ حَمْلَهُنَّ }","trj":"Telah menceritakan kepada kami [Sa'd bin Hafsh] Telah menceritakan kepada kami [Syaiban] dari [Yahya] ia berkata; Telah mengabarkan kepadaku [Abu Salamah] ia berkata; Seorang laki-laki datang kepada Ibnu Abbas sementara Abu Hurairah sedang duduk. Laki-laki itu berkata, \"Berilah fatwa kepadaku, terhadap seorang wanita yang melahirkan setelah kematian suaminya selang empat puluh malam.\" Maka [Ibnu Abbas] berkata, \"Masa Iddahnya adalah batasan yang paling terakhir (maksudnya empat bulan sepuluh hari, meskipun ia melahirkan sebelum itu).\" [Abu Hurairah] berkata; \"Kalau aku, maka aku sependapat dengan anak saudaraku, yakni Abu Salamah.\" Lalu Ibnu Abbas mengutus pembantunya, [Kuraib], kepada [Ummu Salamah] untuk bertanya kepadanya. Ummu Salamah menjawab, \"Ketika suami Subai'ah Al Aslamiyyah meninggal sementara ia dalam keadaan hamil, lalu melahirkan setelah kematian suaminya selang empat puluh malam. Ia kemudian dikhithbah, dan Rasulullah shallallahu 'alaihi wasallam menikahinya. Abu As Sanabil adalah termasuk salah seorang yang mengkhithbahnya. Dan [Sulaiman bin Harb] dan [Abu Nu'man] berkata; Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] ia berkata; Suatu ketika, aku berada dalam halaqah, dan disitu terdapat Abdurrahman bin Abu Laila, sedangkan para sahabatnya mengagungkannya. Mereka mengadukan permasalahan itu, lalu ia menyebutkan bahwa masa iddahnya adalah yang paling terakhir habis (maksudnya empat bulan sepuluh hari, meskipun ia melahirkan sebelum itu). Maka aku pun menceritakan hadits dengan hadits [Subai'ah binti Al Harits] dari [Abdullah bin Utbah]. Akhirnya sebagian sahabatnya mengerutkan dahi padaku. Muhammad berkata; Aku pun mengerti apa maksudnya. Kukatakan, \"Kalau begitu, aku adalah seorang yang nekat, bila aku berdusta atas nama Abdullah bin Utbah. Sekarang ia berada di Kufah. Maka keduanya pun malu dan berkata, \"Akan tetapi pamannya, tidak berkata demikian.\" Kemudian aku menemui [Abu 'Athiyyah Malik bin Amir] dan bertanya padanya, lalu ia pun menceritakan kepadaku hadits [Subai'ah]. Aku bertanya padanya, \"Apakah Anda mendengar sesuatu tentangnya dari Abdullah?\" Ia menjawab, \"Suatu ketika, kami berada di sisi [Abdullah], dan ia pun berkata, 'Apakah kalian akan memberatkan wanita itu, dan kalian tidak memberikan rukhshah untuknya?. Sungguh, surat An Nisa yang pendek itu turun setelah surat Albaqarah yang panjang. 'Bahwa wanita-wanita yang hamil, maka masa iddah mereka adalah ketika mereka melahirkan.'\""},{"p":"Bukhari","n":4301,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ قَالَلَمَّا نَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }{ وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ }قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْعُ لِي زَيْدًا وَلْيَجِئْ بِاللَّوْحِ وَالدَّوَاةِ وَالْكَتِفِ أَوْ الْكَتِفِ وَالدَّوَاةِ ثُمَّ قَالَ اكْتُبْ{ لَا يَسْتَوِي الْقَاعِدُونَ }وَخَلْفَ ظَهْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمْرُو بْنُ أُمِّ مَكْتُومٍ الْأَعْمَى قَالَ يَا رَسُولَ اللَّهِ فَمَا تَأْمُرُنِي فَإِنِّي رَجُلٌ ضَرِيرُ الْبَصَرِ فَنَزَلَتْ مَكَانَهَا{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }{ وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ }{ غَيْرُ أُولِي الضَّرَرِ }","trj":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isra`il] dari [Abu Ishaq] dari [Al Baraa`] ia berkata; Ketika turunnya ayat, \"LAA YASTAWIL QAA'IDUUNA MINAL MUKMINIINA WAL MUJAAHIDUUNA FI SABIILILLAH (Tidaklah sama antara orang-orang yang duduk dari kaum mukminin dengan para Mujahid yang berjuang di jalan Allah).\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Panggilkanlah Zaid bin Tsabit, dan hendaklah ia membawa alat tulis dan tinta serta tulang.\" Kemudian beliau bersabda: \"Tuliskanlah: 'LAA YASTAWIL QAA`IDUUNA...'\" Sementara saat itu, pas di belakang Rasulullah shallallahu 'alaihi wasallam ada Amru bin Ummu Maktum Al A'ma, ia berkata, \"Wahai Rasulullah, apa yang mau Anda perintahkan kepadaku? Aku adalah seorang yang buta tak bisa melihat.\" Maka turunlah ayat: \"LAA YASTAWIL QAA'IDUUNA MINAL MUKMINIINA WAL MUJAAHIDUUNA FI SABIILILLAH GHAIRA ULIDL DLARARA (Tidaklah sama antara orang-orang yang duduk dari kaum mukminin dengan para Mujahid yang berjuang di jalan Allah, kecuali bagi yang memiliki udzur yang syari'). (QS. Annisa'; 95)."},{"p":"Bukhari","n":4357,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ قُلْتُ يَا رَسُولَ اللَّهِ آقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ نَعَمْ فَقَرَأْتُ سُورَةَ النِّسَاءِ حَتَّى أَتَيْتُ إِلَى هَذِهِ الْآيَةِ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }قَالَ حَسْبُكَ الْآنَ فَالْتَفَتُّ إِلَيْهِ فَإِذَا عَيْنَاهُ تَذْرِفَانِ","trj":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari [Abidah] dari [Abdullah bin Mas'ud] ia berkata; Nabi shallallahu 'alaihi wasallam pernah bersabda kepadaku: \"Bacakanlah Al Qur`an untukku.\" Maka aku pun berkata, \"Wahai Rasulullah, apakah aku akan membacanya untuk Anda, padahal kepada Andalah alquran diturunkan?\" beliau menjawab: \"Ya.\" Lalu aku pun membacakan surat An Nisa, hingga aku sampai pada ayat: \"Dan bagaimanakah sekiranya Kami mendatangkan manusia dari seluruh umat dengan seorang saksi, lalu kami mendatangkanmu sebagai saksi atas mereka.\" Maka beliau pun bersabda padaku: \"Cukuplah.\" Lalu aku menoleh ke arah beliau dan ternyata kedua matanya meneteskan air."},{"p":"Bukhari","n":4362,"ar":"حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَ يَحْيَى بَعْضُ الْحَدِيثِ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَ الْأَعْمَشُ وَبَعْضُ الْحَدِيثِ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنْ إِبْرَاهِيمَ وَعَنْ أَبِيهِ عَنْ أَبِي الضُّحَى عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ قَالَ قُلْتُ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أَشْتَهِي أَنْ أَسْمَعَهُ مِنْ غَيْرِي قَالَ فَقَرَأْتُ النِّسَاءَ حَتَّى إِذَا بَلَغْتُ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }قَالَ لِي كُفَّ أَوْ أَمْسِكْ فَرَأَيْتُ عَيْنَيْهِ تَذْرِفَانِ","trj":"Telah menceritakan kepada kami [Shadaqah] Telah mengabarkan kepada kami [Yahya] dari [Sufyan] dari [Sulaiman] dari [Ibrahim] dari [Abidah] dari [Abdullah] - [Yahya] berkata, sebagian hadits dari [Amru bin Murrah] - ia berkata; Nabi shallallahu 'alaihi wasallam bersabda padaku.. Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari [Sufyan] dari [Al A'masy] dari [Ibrahim] dari [Abidah] dari [Abdullah] - [Al A'masy] berkata; dan sebagian hadits- Telah menceritakan kepadaku [Amru bin Murrah] dari [Ibrahim] dari [bapaknya] dari [Abu Dluhaa] dari [Abdulalh] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacakanlah Al Qur`an padaku.\" Aku pun berkata, \"Aku membacakannya untuk Anda, padahal kepada Andalah ia diturunkan?\" beliau bersabda: \"Sesungguhnya aku suka mendengarnya dari orang lain.\" Akhirnya aku pun membacakan surat An-Nisa` dan ketika sampai pada ayat: \"Dan bagaimanakah sekiranya Kami mendatangkan manusia dari seluruh umat dengan seorang saksi, lalu kami mendatangkanmu sebagai saksi atas mereka.\" Maka beliau pun bersabda padaku: \"Cukuplah.\" Lalu aku pun melihat kedua mata beliau meneteskan air."},{"p":"Bukhari","n":4371,"ar":"حَدَّثَنَا عَلِيٌّ سَمِعَ حَسَّانَ بْنَ إِبْرَاهِيمَ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ أَنَّهُ سَأَلَ عَائِشَةَعَنْ قَوْلِهِ تَعَالَى{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ مَثْنَى وَثُلَاثَ وَرُبَاعَ فَإِنْ خِفْتُمْ أَلَّا تَعْدِلُوا فَوَاحِدَةً أَوْ مَا مَلَكَتْ أَيْمَانُكُمْ ذَلِكَ أَدْنَى أَلَّا تَعُولُوا }قَالَتْ يَا ابْنَ أُخْتِي الْيَتِيمَةُ تَكُونُ فِي حَجْرِ وَلِيِّهَا فَيَرْغَبُ فِي مَالِهَا وَجَمَالِهَا يُرِيدُ أَنْ يَتَزَوَّجَهَا بِأَدْنَى مِنْ سُنَّةِ صَدَاقِهَا فَنُهُوا أَنْ يَنْكِحُوهُنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ فَيُكْمِلُوا الصَّدَاقَ وَأُمِرُوا بِنِكَاحِ مَنْ سِوَاهُنَّ مِنْ النِّسَاءِ","trj":"Telah menceritakan kepada kami [Ali] Ia telah mendengar [Hassan bin Ibrahim] dari [Yunus bin Yazid] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Urwah] bahwa ia bertanya kepada [Aisyah] tentang firman Allah Ta'ala: \"Dan jika kalian khawatir tidak bisa berlaku adil terhadap anak yatim, maka nikahilah wanita yang baik-baik, dua, tiga, atau empat, jika kalian tidak bisa berlaku adil, maka kawinilah satu saja, atau hamba sahaya kalian, itu lebih dekat agar kalian tidak melanggar batas (QS. Annisa' 3). Maka Aisyah menjelaskan, \"Wahai anak saudaraku, maksudnya adalah seorang anak perempuan yatim bertempat tinggal di rumah walinya. Lalu ia pun menginginkan harta dan juga kecantikannya. Ia ingin menikahinya dengan mahar yang sedikit, maka mereka dilarang untuk menikahinya kecuali mereka dapat berbuat adil terhadap mereka dan menyempurnakan mahar. Karena itu, mereka diperintahkan untuk menikahi wanita-wanita selain mereka.\""},{"p":"Bukhari","n":4428,"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ{ وَمَا يُتْلَى عَلَيْكُمْ فِي الْكِتَابِ فِي يَتَامَى النِّسَاءِ اللَّاتِي لَا تُؤْتُونَهُنَّ مَا كُتِبَ لَهُنَّ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }قَالَتْ هَذَا فِي الْيَتِيمَةِ الَّتِي تَكُونُ عِنْدَ الرَّجُلِ لَعَلَّهَا أَنْ تَكُونَ شَرِيكَتَهُ فِي مَالِهِ وَهُوَ أَوْلَى بِهَا فَيَرْغَبُ عَنْهَا أَنْ يَنْكِحَهَا فَيَعْضُلَهَا لِمَالِهَا وَلَا يُنْكِحَهَا غَيْرَهُ كَرَاهِيَةَ أَنْ يَشْرَكَهُ أَحَدٌ فِي مَالِهَا","trj":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah], yakni terkait dengan firman-Nya: \"WA MAA YUTLAA 'ALAIKUM FILYATAAMAAN NISAA`IL LAATII LAA TU`TUUHUNNA MAA KUTIBA LAHUNNA WA TARGHUBUUNA AN TANKIHUUHUNNA, (QS. Annisa'; 127), Ia berkata, \"Ini terkait dengan anak perempuan yatim yang berada di bawah asuhan seseorang, yang ia berharap anak perempuan yatim itu dapat menjadi syarikat dalam hartanya. Dan dia merasa bahwa dialah orang yang paling berhak akan hal itu. Karena itu ia tidak mau menikahinya sebab akan menghalangi dirinya untuk mendapatkan harta sang anak perempuan yatim. Dan ia pun tidak sudi menikahkannya dengan orang lain, karena tak suka bila ada seseorang yang turut campur dalam hartanya.\""},{"p":"Bukhari","n":5914,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَآخِرُ آيَةٍ نَزَلَتْ خَاتِمَةُ سُورَةِ النِّسَاءِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","trj":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Al Barra`] radliallahu 'anhu mengatakan; 'akhir ayat yang diturunkan adalah penutupan surat An Naisa`; 'Mereka memintamu fatwa tentang kalalah, katakanlah bahwa Allah memfatwakan kepada kalian….(QS. Annisa' 176)."},{"p":"Bukhari","n":5917,"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ قَالَ قُلْتُ لِأَبِي أُسَامَةَ حَدَّثَكُمْ إِدْرِيسُ حَدَّثَنَا طَلْحَةُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ{ وَلِكُلٍّ جَعَلْنَا مَوَالِيَ }{ وَالَّذِينَ عَاقَدَتْ أَيْمَانُكُمْ }قَالَ كَانَ الْمُهَاجِرُونَ حِينَ قَدِمُوا الْمَدِينَةَ يَرِثُ الْأَنْصَارِيُّ الْمُهَاجِرِيَّ دُونَ ذَوِي رَحِمِهِ لِلْأُخُوَّةِ الَّتِي آخَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمْ فَلَمَّا نَزَلَتْ{ وَلِكُلٍّ جَعَلْنَا مَوَالِيَ }قَالَ نَسَخَتْهَا{ وَالَّذِينَ عَاقَدَتْ أَيْمَانُكُمْ }","trj":"telah menceritakan kepadaku [Ishaq bin Ibrahim] mengatakan, aku berkata kepada [Abu Usamah], telah menceritakan kepadamu [Idris], telah menceritakan kepada kami [Thalhah] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas], mengenai ayat: \"WALIKULLIN JA'ALNAA MAWAALIYA (bagi tiap-tiap harta peninggalan dari harta yang ditinggalkan ibu bapak dan karib kerabat, Kami jadikan pewaris-pewarisnya\" (QS. ANnisa'; 33) \"WALLADZIINA 'AAQADAT AIMAANAKUM (Dan jika ada orang-orang yang kamu telah bersumpah setia dengan mereka, maka berilah kepada mereka bagiannya\" (QS. ANnisa; 33) dia berkata; 'Dahulu orang-orang muhajirin ketika datang ke Madinah, orang anshar mewarisi orang muhajirin yang bukan kerabatnya, dengan pertimbangan ukhuwah yang dibangun oleh Nabi shallallahu 'alaihi wasallam diantara mereka, maka tatkala turun ayat: \"WALIKULLIN JA'ALNAA MAWAALIYA (bagi tiap-tiap harta peninggalan dari harta yang ditinggalkan ibu bapak dan karib kerabat, Kami jadikan pewaris-pewarisnya\" (QS. Annisa'; 33), Allah menghapusnya dengan ayat: \"WALLADZIINA 'AAQADAT AIMAANAKUM (Dan jika ada orang-orang yang kamu telah bersumpah setia dengan mereka\" (QS. ANnisa; 33)."},{"p":"Bukhari","n":6116,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ كَانَ عُرْوَةُ يُحَدِّثُ أَنَّهُ سَأَلَ عَائِشَةَ{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ هِيَ الْيَتِيمَةُ فِي حَجْرِ وَلِيِّهَا فَيَرْغَبُ فِي مَالِهَا وَجَمَالِهَا فَيُرِيدُ أَنْ يَتَزَوَّجَهَا بِأَدْنَى مِنْ سُنَّةِ نِسَائِهَا فَنُهُوا عَنْ نِكَاحِهِنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ فِي إِكْمَالِ الصَّدَاقِ ثُمَّ اسْتَفْتَى النَّاسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ فَأَنْزَلَ اللَّهُ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ }فَذَكَرَ الْحَدِيثَ","trj":"Telah menceritakan kepada kami [Abul Yaman] telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] mengatakan, [Urwah] menceritakan; ia bertanya [Aisyah] tentang ayat; 'Jika kalian khawatir tidak bisa berbuat adil terhadap yatimmu, maka nikahilah wanita yang baik-baik bagimu, dua, tiga, atau empat (QS. Annisa'; 3) dia mengatakan; 'yaitu yatim dalam asuhan walinya, dan si wali tersebut kurang menyukai kecantikan dan hartanya, namun tetap akan ia nikahi dengan syarat membayar mahar serendah-rendahnya yang menyalahi adat normal. Maka mereka dilarang menikahi anak-anak yatim tersebut kecuali jika berbuat adil dengan membayar mahar secara sempurna, lantas para sahabat bertanya kepada Rasulullah shallallahu 'alaihi wasallam di kemudian hari, maka Allah menurunkan ayat; 'Mereka meminta fatwa kepadamu,,, dan seterusnya (QS. Annisa' 127), kemudian dia menyebutkan hadits."},{"p":"Bukhari","n":6533,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقُلْنَا يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ قَالَ هَلْ تُضَارُونَ فِي رُؤْيَةِ الشَّمْسِ وَالْقَمَرِ إِذَا كَانَتْ صَحْوًا قُلْنَا لَا قَالَ فَإِنَّكُمْ لَا تُضَارُونَ فِي رُؤْيَةِ رَبِّكُمْ يَوْمَئِذٍ إِلَّا كَمَا تُضَارُونَ فِي رُؤْيَتِهِمَا ثُمَّ قَالَ يُنَادِي مُنَادٍ لِيَذْهَبْ كُلُّ قَوْمٍ إِلَى مَا كَانُوا يَعْبُدُونَ فَيَذْهَبُ أَصْحَابُ الصَّلِيبِ مَعَ صَلِيبِهِمْ وَأَصْحَابُ الْأَوْثَانِ مَعَ أَوْثَانِهِمْ وَأَصْحَابُ كُلِّ آلِهَةٍ مَعَ آلِهَتِهِمْ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ وَغُبَّرَاتٌ مِنْ أَهْلِ الْكِتَابِ ثُمَّ يُؤْتَى بِجَهَنَّمَ تُعْرَضُ كَأَنَّهَا سَرَابٌ فَيُقَالُ لِلْيَهُودِ مَا كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ عُزَيْرَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ قَالُوا نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ ثُمَّ يُقَالُ لِلنَّصَارَى مَا كُنْتُمْ تَعْبُدُونَ فَيَقُولُونَ كُنَّا نَعْبُدُ الْمَسِيحَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ فَيَقُولُونَ نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ فَيُقَالُ لَهُمْ مَا يَحْبِسُكُمْ وَقَدْ ذَهَبَ النَّاسُ فَيَقُولُونَ فَارَقْنَاهُمْ وَنَحْنُ أَحْوَجُ مِنَّا إِلَيْهِ الْيَوْمَ وَإِنَّا سَمِعْنَا مُنَادِيًا يُنَادِي لِيَلْحَقْ كُلُّ قَوْمٍ بِمَا كَانُوا يَعْبُدُونَ وَإِنَّمَا نَنْتَظِرُ رَبَّنَا قَالَ فَيَأْتِيهِمْ الْجَبَّارُ فِي صُورَةٍ غَيْرِ صُورَتِهِ الَّتِي رَأَوْهُ فِيهَا أَوَّلَ مَرَّةٍ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ أَنْتَ رَبُّنَا فَلَا يُكَلِّمُهُ إِلَّا الْأَنْبِيَاءُ فَيَقُولُ هَلْ بَيْنَكُمْ وَبَيْنَهُ آيَةٌ تَعْرِفُونَهُ فَيَقُولُونَ السَّاقُ فَيَكْشِفُ عَنْ سَاقِهِ فَيَسْجُدُ لَهُ كُلُّ مُؤْمِنٍ وَيَبْقَى مَنْ كَانَ يَسْجُدُ لِلَّهِ رِيَاءً وَسُمْعَةً فَيَذْهَبُ كَيْمَا يَسْجُدَ فَيَعُودُ ظَهْرُهُ طَبَقًا وَاحِدًا ثُمَّ يُؤْتَى بِالْجَسْرِ فَيُجْعَلُ بَيْنَ ظَهْرَيْ جَهَنَّمَ قُلْنَا يَا رَسُولَ اللَّهِ وَمَا الْجَسْرُ قَالَ مَدْحَضَةٌ مَزِلَّةٌ عَلَيْهِ خَطَاطِيفُ وَكَلَالِيبُ وَحَسَكَةٌ مُفَلْطَحَةٌ لَهَا شَوْكَةٌ عُقَيْفَاءُ تَكُونُ بِنَجْدٍ يُقَالُ لَهَا السَّعْدَانُ الْمُؤْمِنُ عَلَيْهَا كَالطَّرْفِ وَكَالْبَرْقِ وَكَالرِّيحِ وَكَأَجَاوِيدِ الْخَيْلِ وَالرِّكَابِ فَنَاجٍ مُسَلَّمٌ وَنَاجٍ مَخْدُوشٌ وَمَكْدُوسٌ فِي نَارِ جَهَنَّمَ حَتَّى يَمُرَّ آخِرُهُمْ يُسْحَبُ سَحْبًا فَمَا أَنْتُمْ بِأَشَدَّ لِي مُنَاشَدَةً فِي الْحَقِّ قَدْ تَبَيَّنَ لَكُمْ مِنْ الْمُؤْمِنِ يَوْمَئِذٍ لِلْجَبَّارِ وَإِذَا رَأَوْا أَنَّهُمْ قَدْ نَجَوْا فِي إِخْوَانِهِمْ يَقُولُونَ رَبَّنَا إِخْوَانُنَا كَانُوا يُصَلُّونَ مَعَنَا وَيَصُومُونَ مَعَنَا وَيَعْمَلُونَ مَعَنَا فَيَقُولُ اللَّهُ تَعَالَى اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ دِينَارٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ وَيُحَرِّمُ اللَّهُ صُوَرَهُمْ عَلَى النَّارِ فَيَأْتُونَهُمْ وَبَعْضُهُمْ قَدْ غَابَ فِي النَّارِ إِلَى قَدَمِهِ وَإِلَى أَنْصَافِ سَاقَيْهِ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ نِصْفِ دِينَارٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ ذَرَّةٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا قَالَ أَبُو سَعِيدٍ فَإِنْ لَمْ تُصَدِّقُونِي فَاقْرَءُوا{ إِنَّ اللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍ وَإِنْ تَكُ حَسَنَةً يُضَاعِفْهَا }فَيَشْفَعُ النَّبِيُّونَ وَالْمَلَائِكَةُ وَالْمُؤْمِنُونَ فَيَقُولُ الْجَبَّارُ بَقِيَتْ شَفَاعَتِي فَيَقْبِضُ قَبْضَةً مِنْ النَّارِ فَيُخْرِجُ أَقْوَامًا قَدْ امْتُحِشُوا فَيُلْقَوْنَ فِي نَهَرٍ بِأَفْوَاهِ الْجَنَّةِ يُقَالُ لَهُ مَاءُ الْحَيَاةِ فَيَنْبُتُونَ فِي حَافَتَيْهِ كَمَا تَنْبُتُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ قَدْ رَأَيْتُمُوهَا إِلَى جَانِبِ الصَّخْرَةِ وَإِلَى جَانِبِ الشَّجَرَةِ فَمَا كَانَ إِلَى الشَّمْسِ مِنْهَا كَانَ أَخْضَرَ وَمَا كَانَ مِنْهَا إِلَى الظِّلِّ كَانَ أَبْيَضَ فَيَخْرُجُونَ كَأَنَّهُمْ اللُّؤْلُؤُ فَيُجْعَلُ فِي رِقَابِهِمْ الْخَوَاتِيمُ فَيَدْخُلُونَ الْجَنَّةَ فَيَقُولُ أَهْلُ الْجَنَّةِ هَؤُلَاءِ عُتَقَاءُ الرَّحْمَنِ أَدْخَلَهُمْ الْجَنَّةَ بِغَيْرِ عَمَلٍ عَمِلُوهُ وَلَا خَيْرٍ قَدَّمُوهُ فَيُقَالُ لَهُمْ لَكُمْ مَا رَأَيْتُمْ وَمِثْلَهُ مَعَهُوَقَالَ حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُحْبَسُ الْمُؤْمِنُونَ يَوْمَ الْقِيَامَةِ حَتَّى يُهِمُّوا بِذَلِكَ فَيَقُولُونَ لَوْ اسْتَشْفَعْنَا إِلَى رَبِّنَا فَيُرِيحُنَا مِنْ مَكَانِنَا فَيَأْتُونَ آدَمَ فَيَقُولُونَ أَنْتَ آدَمُ أَبُو النَّاسِ خَلَقَكَ اللَّهُ بِيَدِهِ وَأَسْكَنَكَ جَنَّتَهُ وَأَسْجَدَ لَكَ مَلَائِكَتَهُ وَعَلَّمَكَ أَسْمَاءَ كُلِّ شَيْءٍ لِتَشْفَعْ لَنَا عِنْدَ رَبِّكَ حَتَّى يُرِيحَنَا مِنْ مَكَانِنَا هَذَا قَالَ فَيَقُولُ لَسْتُ هُنَاكُمْ قَالَ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ أَكْلَهُ مِنْ الشَّجَرَةِ وَقَدْ نُهِيَ عَنْهَا وَلَكِنْ ائْتُوا نُوحًا أَوَّلَ نَبِيٍّ بَعَثَهُ اللَّهُ إِلَى أَهْلِ الْأَرْضِ فَيَأْتُونَ نُوحًا فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ سُؤَالَهُ رَبَّهُ بِغَيْرِ عِلْمٍ وَلَكِنْ ائْتُوا إِبْرَاهِيمَ خَلِيلَ الرَّحْمَنِ قَالَ فَيَأْتُونَ إِبْرَاهِيمَ فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ ثَلَاث�� كَلِمَاتٍ كَذَبَهُنَّ وَلَكِنْ ائْتُوا مُوسَى عَبْدًا آتَاهُ اللَّهُ التَّوْرَاةَ وَكَلَّمَهُ وَقَرَّبَهُ نَجِيًّا قَالَ فَيَأْتُونَ مُوسَى فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ قَتْلَهُ النَّفْسَ وَلَكِنْ ائْتُوا عِيسَى عَبْدَ اللَّهِ وَرَسُولَهُ وَرُوحَ اللَّهِ وَكَلِمَتَهُ قَالَ فَيَأْتُونَ عِيسَى فَيَقُولُ لَسْتُ هُنَاكُمْ وَلَكِنْ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدًا غَفَرَ اللَّهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ فَيَأْتُونِي فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي فَيَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ أَيْضًا يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّانِيَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّالِثَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَهْ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَقَدْ سَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ حَتَّى مَا يَبْقَى فِي النَّارِ إِلَّا مَنْ حَبَسَهُ الْقُرْآنُ أَيْ وَجَبَ عَلَيْهِ الْخُلُودُ قَالَ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ عَسَى أَنْ يَبْعَثَكَ رَبُّكَ مَقَامًا مَحْمُودًا }قَالَ وَهَذَا الْمَقَامُ الْمَحْمُودُ الَّذِي وُعِدَهُ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Allaits bin Sa'd] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Zaid] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudzri] berkata, \"Kami bertanya, \"Ya Rasulullah, apakah kita akan melihat Tuhan kita pada hari kiamat?\" Nabi balik bertanya: \"Apakah kalian merasa kesulitan melihat matahari dan bulan ketika terang benderang?\" kami menjawab, \"Tidak.\" Nabi meneruskan: \"Begitulah kalian tidak kesulitan melihat melihat Tuhan kalian ketika itu, selain sebagaimana kesulitan kalian melihat keduanya.\" Kemudian beliau berkata: \"Lantas ada seorang penyeru memanggil-manggil, \"Hendaklah setiap kaum pergi menemui yang disembahnya!\" Maka pemuja salib pergi bersama salib mereka, dan pemuja patung menemui patung-patung mereka, dan setiap pemuja Tuhan bersama tuhan-tuhan mereka hingga tinggal orang-orang yang menyembah Allah, entah baik atau durhaka dan ahli kitab terdahulu. Kemudian jahannam didatangkan dan dipasang, ia seolah-olah fatamorgana, lantas orang-orang yahudi ditanya, \"Apa yang dahulu kalian sembah?\" Mereka menjawab, \"Kami dahulu menyembah Uzair anak Allah.\" Lalu ada suara, \"Kalian dusta! Allah sama sekali tidak mempunyai isteri dan tidak pula anak.\" Lalu apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin jika Engkau memberi kami minuman!\" Lantas ada suara, \"Minumlah kalian!\" Lalu mereka berjatuhan di neraka jahannam. Lantas orang-orang Nashara diseru, \"Apa yang kalian dahulu sembah?\" Mereka menjawab, \"Kami dahulu menyembah Isa al Masih, anak Anak Allah.\" Mereka dijawab, \"Kamu semua bohong! Allah sama sekali tidak mempunyai isteri atau bahkan anak, dan apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin agar Engkau memberi kami minuman!\" Lalu dijawab, \"Minumlah kalian!\" Dan langsung mereka berjatuhan di neraka jahannam hingga tersisa manusia yang menyembah Allah, entah yang baik atau berbuat durhaka. Mereka ditanya, \"Apa yang menyebabkan kalian tertahan padahal manusia lainnya sudah pergi?\" Mereka menjawab, \"Kami memisahkan diri dari mereka dan kami adalah manusia yang paling membutuhkan-Nya, kami dengar ada seorang juru seru menyerukan diri, \"Hendaklah setiap kaum menemui yang mereka sembah! Hanyasanya kami menunggu-nunggu Tuhan kami.\" Beliau melanjutkan, \"Lantas Allah (Al jabbar) mendatangi mereka dengan bentuk yang belum pernah mereka lihat pertama kali, lalu Allah firmankan: 'Akulah Tuhan kalian.' Mereka menjawab, 'Engkau adalah rabb kami, dan tidak ada yang berani mengajak-Nya bicara selain para nabi shallallahu 'alaihi wasallam, lantas para nabi berkata, 'Bukankah di antara kalian dan Allah ada tanda yang kalian mengenalnya? ' Mereka menjawab, 'Ya, yaitu betis, ' maka Allah pun menyingkap betis-Nya sehingga setiap mukmin bersujud kepada-Nya. Lalu tersisalah orang-orang yang sujud kepada Allah karena riya dan sum'ah sehingga ia pergi sujud dan punggungnya kembali menjadi satu bagian, kemudian titian (jembatan) jahannam didatangkan dan dipasang antara dua tepi jahannam, kami bertanya, 'Wahai Rasulullah, memang jembatan jahannam tersebut misterinya apa? ' Nabi menjawab: 'Jembatan itu bisa menggelincirkan, menjatuhkan, ada pengait-pengait besi, ada duri-duri yang lebar dan tajam, durinya besok yang terbuat dari kayu berduri namanya Sa'dan (kayu berduri tajam). Orang mukmin yang melewatinya sedemikian cepat, ada yang bagaikan kedipan mata, ada yang bagaikan kilat, ada yang bagaikan angin, dan ada yang bagaikan kuda pilihan. Ada yang bagaikan kuda tunggangan, ada yang selamat dengan betul-betul terselamatkan, namun ada juga yang selamat setelah tercabik-cabik oleh besi-besi pengait itu, atau terlempar karenanya di neraka jahannam, hingga manusia terakhir kali melewati dengan diseret seret, dan kalian tidak bisa sedemikian gigihnya menyumpahiku terhadap kebenaran yang jelas bagi kalian daripada terhadap seorang mukmin ketika itu kepada Allah Al Jabbar. Jika mereka melihat bahwasanya mereka telah selamat di kalangan teman-teman mereka, mereka berkata, 'Ya Tuhan kami, sesungguhnya kawan-kawan kami mendirikn shalat bersama kami dan berpuasa bersama kami, dan beramal bersama kami! ' Allah Ta'ala berfirman, 'Pergilah kalian, siapa diantara kalian dapatkan dalam hatinya masih ada seberat dinar keimanan, maka keluarkanlah dia', dan Allah mengharamkan bentuk mereka dalam neraka. Maka mereka datangi kawan-kawan mereka sedang sebagian mereka telah terendam dalam neraka ada yang sampai telapak kakinya, setengah betisnya, sehingga mereka keluarkan siapa saja yang mereka, kemudian mereka kembali dan Allah berkata, 'Pergilah kalian sekali lagi, dan siapa yang kalian temukan dalam hatinya seberat atom keimanan, maka keluarkanlah dia.' Maka mereka keluarkan siapa saja yang mereka kenal.\" Rasulullah berkata: 'Jika kalian tidak mempercayaiku, maka bacalah: '(Allah tidak menzhalimi seberat biji sawi pun, jika ada kebaikan, maka Allah melipatgandakan balasannya) ' (Qs. An nisaa': 40), maka para nabi shallallahu 'alaihi wasallam, malaikat dan orang-orang yang beriman, kesemuanya memberi syafaat. Kemudian Allah Al Jabbar berkata, syafaat-Ku masih ada. Lantas Allah menggenggam segenggam dari neraka dan mengentaskan beberapa kaum yang mereka telah terbakar, lantas mereka dilempar ke sebuah sungai di pintu surga yang namanya 'Sungai kehidupan' sehingga mereka tumbuh dalam kedua tepinya sebagaimana biji-bijian tumbuh dalam genangan sungai yang kalian sering melihatnya di samping batu karang dan samping pohon, apa yang diantaranya condong kepada matahari, maka berwarna hijau, dan apa yang diantaranya condong kepada bayangan, maka berwarna putih, lantas mereka muncul seolah-olah mutiara dan dalam tengkuk mereka terdapat cincin-cincin. Mereka kemudian masuk surga hingga penghuni surga berkata, 'Mereka adalah 'utaqa' Ar Rahman (orang-orang yang dibebaskan Arrahman), Allah memasukkan mereka bukan karena amal yang mereka lakukan, dan bukan pula karena kebaikan yang mereka persembahkan sehingga mereka memperoleh jawaban 'Bagimu yang kau lihat dan semisalnya'.\" [Hajjaj bin Minhal] berkata; telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dari [Anas] radliyallahu'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: 'Pada hari kiamat nanti orang-orang mukmin ditahan hingga yang demikian menjadikan mereka sedih. Mereka katakan, 'Duh, sekiranya kita meminta syafaat kepada Tuhan kami sehingga Dia menjadikan kita merasa nyaman dari tempat kita ini.' Mereka pun mendatangi Adam dan berkata, 'Engkau hai Adam, Engkau adalah nenek moyang seluruh manusia, Allah menciptamu dengan tangan-Nya, menjadikan surga sebagai tempat hunianmu dan menjadikan malaikat bertunduk sujud kepadamu, Allah juga mengajarimu nama-nama segala sesuatu agar engkau bisa memberi syafaat kepada kami disisi Tuhanmu sehingga engkau bisa memberi kenyamanan di tempat kami ini. Namun Adam hanya menjawab, 'Disini saya tak berhak memberi syafaat untuk kalian'.\" Rasulullah melanjutkan: \"Lantas Adam mengingatkan kesalahan yang pernah dilakukannya, yaitu memakan pohon larangan padahal telah dilarang, dan ia katakan 'Coba kalian datangi Nuh, sebab ia adalah nabi shallallahu 'alaihi wasallam pertama-tama yang Allah utus kepada penduduk bumi.' Mereka pun mendatangi Nuh, namun Nuh juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', dan Nuh menyebutkan kesalahan yang pernah dilakukannya, yaitu bertanya kepada Rabbnya dengan tanpa ilmu sambil ia katakan, 'Cobalah kalian datangi Ibrahim, sebab ia adalah Khalilurrahman (kekasih Arrahman).\" Rasulullah melanjutkan lagi kisahnya: \"Mereka pun mendatangi Ibrahim, hanya Ibrahim juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', Ibrahim lantas menyebutkan kesalahannya, yaitu tiga kebohongan yang pernah dilakukannya sambil berkata, 'Cobalah kalian datangi Musa, seorang hamba yang Allah memberinya taurat, mengajaknya bicara dan mendekatkannya kepada-Nya sedekat-dekatnya'.\" Rasulullah lanjutkan: \"Mereka pun mendatangi Musa, hanya Musa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil Musa mengingatkan kesalahan yang pernah dilakukannya, yaitu membunuh jiwa tanpa alasan yang dibenarkan, sambil ia katakan, 'Coba kalian datangi Isa, seorang hamba Allah dan rasul-Nya, ruh Allah dan kalimah-Nya. Merekapun mendatangi Isa, namun 'Isa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil ia katakan 'Cobalah kalian datangi Muhammad Shallallahu'alaihiwasallam, seorang hamba yang Allah telah mengampuni dosanya yang terdahulu dan yang akan datang.' Lantas mereka mendatangi aku (Muhammad) dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud, Allah lalu membiarkan aku sekehendak Dia membiarkaku. Allah lantas berkata, 'Angkat kepalamu hai Muhammad, katakanlah, engkau didengar, mintailah syafaat, engkau diberi syafaat, mintalah, engkau diberi.' Aku lalu angkat kepalaku dan aku memuji Tuhanku dengan pujian yang Ia ajarkannya kepadaku, kemudian aku memberi syafaat dan Dia memberiku batasan. Kemudian aku keluar dan memasukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku juga mendengarnya menyebutkan, \"Aku lalu keluar, kemudian aku keluarkan mereka dari neraka dan kumasukkan ke dalam surga. Setelah itu aku kembali untuk kali kedua dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan untuk menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud. Allah lantas membiarkanku sekehendak Allah membiarkan, kemudian Allah berkata, 'Angkatlah kepalamu hai Muhammad dan katakanlah engkau akan didengar, dan berilah syafaat engkau akan diberi syafaat, dan mintalah engkau akan diberi.' Aku lalu angkat kepalaku dan memanjatkan pujian dan pujaan terhadap tuhanku sebagaimana yang diajakrkan-Nya kepadaku. Kemudian aku memberi syafaat, dan Ia memberiku batasan sehingga aku keluar dan aku masukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, \"Dan aku berangkat sehingga aku keluarkan mereka dari neraka, lalu mereka aku masukkan ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, 'Maka aku berangkat dan aku keluarkan mereka dari neraka, untuk kemudian aku masukkan mereka ke dalam surga, hingga tidak tersisa dalam neraka selain yang digi ditahan oleh alquran, atau maksudnya ia wajib abadi, kemudian beliau membaca ayat ini '(semoga Tuhanmu membangkitkankmu di tempat yang terpuji) ' (Qs. Al Isra': 79). Nabi mengatakan, \"Inilah maqam terpuji yang dijanjikan untuk nabi shallallahu 'alaihi wasallam kalian.\""},{"p":"Darimi","n":46,"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا زَمْعَةُ عَنْ سَلَمَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ جَلَسَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْتَظِرُونَهُ فَخَرَجَ حَتَّى إِذَا دَنَا مِنْهُمْ سَمِعَهُمْ يَتَذَاكَرُونَ فَتَسَمَّعَ حَدِيثَهُمْ فَإِذَا بَعْضُهُمْ يَقُولُ عَجَبًا إِنَّ اللَّهَ اتَّخَذَ مِنْ خَلْقِهِ خَلِيلًا فَإِبْرَاهِيمُ خَلِيلُهُ وَقَالَ آخَرُ مَاذَا بِأَعْجَبَ مِنْ { وَكَلَّمَ اللَّهُ مُوسَى تَكْلِيمًا } وَقَالَ آخَرُ فَعِيسَى كَلِمَةُ اللَّهِ وَرُوحُهُ وَقَالَ آخَرُ وَآدَمُ اصْطَفَاهُ اللَّهُ فَخَرَجَ عَلَيْهِمْ فَسَلَّمَ وَقَالَ قَدْ سَمِعْتُ كَلَامَكُمْ وَعَجَبَكُمْ أَنَّ إِبْرَاهِيمَ خَلِيلُ اللَّهِ وَهُوَ كَذَلِكَ وَمُوسَى نَجِيُّهُ وَهُوَ كَذَلِكَ وَعِيسَى رُوحُهُ وَكَلِمَتُهُ وَهُوَ كَذَلِكَ وَآدَمُ اصْطَفَاهُ اللَّهُ تَعَالَى وَهُوَ كَذَلِكَ أَلَا وَأَنَا حَبِيبُ اللَّهِ وَلَا فَخْرَ وَأَنَا حَامِلُ لِوَاءِ الْحَمْدِ يَوْمَ الْقِيَامَةِ تَحْتَهُ آدَمُ فَمَنْ دُونَهُ وَلَا فَخْرَ وَأَنَا أَوَّلُ شَافِعٍ وَأَوَّلُ مُشَفَّعٍ يَوْمَ الْقِيَامَةِ وَلَا فَخْرَ وَأَنَا أَوَّلُ مَنْ يُحَرِّكُ بِحَلَقِ الْجَنَّةِ وَلَا فَخْرَ فَيَفْتَحُ اللَّهُ فَيُدْخِلُنِيهَا وَمَعِي فُقَرَاءُ الْمُؤْمِنِينَ وَلَا فَخْرَ وَأَنَا أَكْرَمُ الْأَوَّلِينَ وَالْآخِرِينَ عَلَى اللَّهِ وَلَا فَخْرَ","trj":"Telah mengabarkan kepada kami [Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Zam'ah] dari [Salamah] dari ['Ikrimah] dari [Ibnu Abbas] Radliyallahu'anhu ia berkata; Orang-orang dari sahabat Nabi shallallahu 'alaihi wasallam duduk menunggu beliau. Kemudian beliau keluar dan tatkala dekat dengan mereka beliau mendengar mereka sedang menyebut-nyebut nama beliau shallallahu 'alaihi wasallam. Lalu beliau mendengarkan percakapan mereka dengan baik, maka diantara mereka ada yang berkata; \"Sungguh sangat mengherankan bahwasannya Allah Subhanahu wa Ta'ala menjadikan dari makhluk-Nya Sebagai sahabat karib-Nya, dan Ibrahim adalah sahabat karib Allah Subhanahu wa Ta'ala yang lain berkata; Mana yang lebih mengherankan dari ayat, WA KALLAMA ALLAHU MUSA TAKLIIMAA Dan Allah telah berbicara kepada Nabi Musa dengan langsung (Qs. An Nisaa`/4: 164) sementara yang lainnya lagi berkata; Sedangkan Isa adalah Kalimat Allah Subhanahu wa Ta'ala dan Ruh Nya, yang lainnya pun ikut berkata; Sementara Adam telah disucikan Allah Subhanahu wa Ta'ala. Lalu beliau keluar menemui mereka dan mengucapkan salam, lalu bersabda: \"Saya telah mendengarkan percakapan kalian dan keheranan bahwa Ibrahim adalah sahabat karib Allah Subhanahu wa Ta'ala, dan memang demikian, Musa orang yang diajak langsung berbicara dengan-Nya dan memang demikian, dan Isa adalah Ruh dan Kalimat-Nya dan memang demikian, dan Adam Allah Subhanahu wa Ta'ala telah memilihnya dan memang demikian, ketahuilah bahwa saya adalah habibullah (manusia kecintaan Allah) dan tiada kesombongan, aku adalah pembawa panji pujian di hari kiamat yang membawai Adam dan para nabi sesudahnya dan tiada kesombongan, dan aku adalah orang pertama yang memberi dan yang diberi syafa`at pada hari kiamat dan tidak ada kesombongan, dan saya adalah orang pertama yang menggerakkan tali pintu surga dan tidak ada kesombongan, kemudian Allah Subhanahu wa Ta'ala membukakan pintunya dan memasukkan saya ke dalamnya, saya masuk bersama orang-orang miskin dari kaum muslimin dan tidak ada kesombongan, serta saya adalah orang yang paling mulia dari orang-orang terdahulu dan orang-orang yang datang belakangan di sisi Allah Subhanahu wa Ta'ala dan tidak ada kesombongan\". "},{"p":"Darimi","n":794,"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي مِجْلَزٍ عَنْ ابْنِ عَبَّاسٍ فِي قَوْلِهِ { وَلَا جُنُبًا إِلَّا عَابِرِي سَبِيلٍ } قَالَ هُوَ الْمُسَافِرُ","trj":"Telah mengabarkan kepada kami [Muslim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Abu Mijlaz] dari [Ibnu Abbas] tentang firman-Nya: '((jangan pula hampiri masjid) sedang ia dalam keadaan junub, kecuali sekedar berlalu saja) ' (Qs. An Nisa: 43), ia berkata: \"Yaitu musafir.\" "},{"p":"Darimi","n":796,"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ وَأَبُو نُعَيْمٍ عَنْ شَرِيكٍ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ أَبِي عُبَيْدَةَ قَالَ الْجُنُبُ يَمُرُّ فِي الْمَسْجِدِ وَلَا يَقْعُدُ فِيهِ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ { وَلَا جُنُبًا إِلَّا عَابِرِي سَبِيلٍ }","trj":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] dan [Abu Nu'aim] dari [Syarik] dari [Abdul Karim Al Jazari] dari [Abu 'Ubaidah] ia berkata, \"Orang yang sedang junub boleh melewati masjid, tetapi ia tidak boleh duduk di dalamnya.\" Kemudian ia membaca ayat ini: '(jangan pula hampiri masjid) sedang ia dalam keadaan junub, kecuali sekedar berlalu saja) ' (Qs. An Nisaa: 43)."},{"p":"Darimi","n":1113,"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَ قُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ قَالَ اللَّهُ تَعَالَى { أَنْ تَقْصُرُوا مِنْ الصَّلَاةِ إِنْ خِفْتُمْ } فَقَدْ أَمِنَ النَّاسُ قَالَ عَجِبْتُ مِمَّا عَجِبْتَ مِنْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَةٌ تَصَدَّقَ اللَّهُ بِهَا عَلَيْكُمْ فَاقْبَلُوهَا","trj":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Abu 'Ammar] dari [Abdullah bin Babaih] dari [Ya'la bin Umayyah] ia berkata, \"Aku katakan kepada [Umar bin Al Khathab, \"Allah Ta'ala berfirman: '(Kamu men-qashar sembahyang(mu), jika kamu takut) ' (Qs. An Nisa: 101). Sementara orang-orang sekarang telah merasa aman?\" Umar menjawab, \"Aku juga pernah heran sebagaimana engkau heran. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah sedekah yang telah Allah berikan kepada kalian, maka terimalah sedekah-Nya.\""},{"p":"Darimi","n":1750,"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ وَحَجَّاجٌ قَالَا حَدَّثَنَا شُعْبَةُ قَالَ أَنْبَأَنَا أَبُو إِسْحَقَ قَالَ سَمِعْتُ أَبَا عُبَيْدَةَ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ قَالَ عَلَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُطْبَةَ الْحَاجَةِ الْحَمْدُ لِلَّهِ أَوْ إِنَّ الْحَمْدَ لِلَّهِ نَحْمَدُهُ وَنَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَقْرَأُ ثَلَاثَ آيَاتٍ { يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ } { يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا } { يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا يُصْلِحْ لَكُمْ أَعْمَالَكُمْ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْ وَمَنْ يُطِعْ اللَّهَ وَرَسُولَهُ فَقَدْ فَازَ فَوْزًا عَظِيمًا } ثُمَّ يَتَكَلَّمُ بِحَاجَتِهِ","trj":"Telah menceritakan kepada kami [Abu Al Walid] dan [Hajjaj] keduanya berkata; telah menceritakan kepada kami [Syu'bah] ia berkata; telah memberitakan kepada kami [Abu Ishaq] ia berkata; Aku mendengar [Abu 'Ubaidah] menceritakan dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam mengajarkan kepada kami khutbah hajah, yaitu; \"Al HAMDULILLAAHI atau INNAL HAMDA LILLAAHI NAHMADUHU WA NASTA'IINUHU WA NASTAGHFIRUHU WA NA'UUDZU BILLAAHI MIN SYURUURI ANFUSINAA, MAN YAHDIHILLAAHU FALAA MUDHILLA LAHU WA MAN YUDHLIL FALAA HAADIYA LAHU. ASYHADU AN LAA ILAAHA ILLALLAAH WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUHU (segala puji bagi Allah, atau sesungguhnya segala puji bagi Allah, kita memujiNya, memohon pertolongan, serta ampunan kepadaNya, dan kita berlindung kepada Allah dari keburukan diri kita, barangsiapa yang Allah beri petunjuk maka tidak ada yang dapat menyesatkannya, dan barangsiapa yang Allah sesatkan maka tidak ada yang dapat memberinya petunjuk. Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah, dan aku bersaksi bahwa Mummad adalah hamba dan utusanNya.. Kemudian membaca tiga ayat, yaitu; Hai orang-orang yang beriman, bertakwalah kepada Allah sebenar-benar takwa kepada-Nya; dan janganlah sekali-kali kamu mati melainkan dalam keadaan beragama Islam. QS Ali Imran; 102. Hai sekalian manusia, bertakwalah kepada Tuhan-mu yang telah menciptakan kamu dari seorang diri, dan dari padanya, Allah menciptakan isterinya.\" QS An Nisa`; 1. Hai orang-orang yang beriman, bertakwalah kamu kepada Allah dan katakanlah perkataan yang benar, niscaya Allah memperbaiki bagimu amalan-amalanmu dan mengampuni bagimu dosa-dosamu. Dan barangsiapa mentaati Allah dan Rasul-Nya, maka sesungguhnya ia telah mendapat kemenangan yang besar. QS Al Ahzab; 70-71. Kemudian mengatakan kebutuhannya."},{"p":"Darimi","n":1958,"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ أَنْبَأَنَا أَبُو إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ يَقُولُ لَمَّا نَزَلَتْ هَذِهِ الْآيَةُ { لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ } دَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا فَجَاءَ بِكَتِفٍ فَكَتَبَهَا وَشَكَا ابْنُ أُمِّ مَكْتُومٍ ضَرَارَتَهُ فَنَزَلَتْ { لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ غَيْرُ أُولِي الضَّرَرِ }","trj":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah], ia berkata; telah memberitakan kepada kami [Abu Ishaq], ia berkata; aku mendengar [Al Bara`] berkata; \"Ketika turun ayat: \" Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang)...\" QS An Nisa`; 95. Rasulullah shallallahu 'alaihi wasallam memanggil Zaid, kemudian ia datang dengan membawa tulang pundak binatang, lalu Zaid menulis ayat tersebut. Sementara Ibnu Ummi Maktum dating mengadu akan kebutaannya. Kemudian turunlah ayat: \" Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) yang tidak mempunyai 'uzur.\" QS An Nisa'; 95."},{"p":"Darimi","n":2744,"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ { إِذَا حَضَرَ أَحَدَكُمْ الْمَوْتُ إِنْ تَرَكَ خَيْرًا الْوَصِيَّةُ لِلْوَالِدَيْنِ وَالْأَقْرَبِينَ } فَأَمَرَ أَنْ يُوصِيَ لِوَالِدَيْهِ وَأَقَارِبِهِ ثُمَّ نُسِخَ بَعْدَ ذَلِكَ فِي سُورَةِ النِّسَاءِ فَجَعَلَ لِلْوَالِدَيْنِ نَصِيبًا مَعْلُومًا وَأَلْحَقَ لِكُلِّ ذِي مِيرَاثٍ نَصِيبَهُ مِنْهُ وَلَيْسَتْ لَهُمْ وَصِيَّةٌ فَصَارَتْ الْوَصِيَّةُ لِمَنْ لَا يَرِثُ مِنْ قَرِيبٍ وَغَيْرِهِ","trj":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammam] dari [Qatadah] ia berkata tentang firman-Nya: '(Apabila seorang di antara kamu kedatangan (tanda-tanda) maut, jika ia meninggalkan harta yang banyak, berwasiat untuk ibu-bapak dan karib kerabatnya) '. (Qs. Al Baqarah: 180), Allah memerintahkan agar berwasiat kepada kedua orang tua dan karib kerabatnya. Kemudian hukum ini dihapus dengan ayat di dalam surat An Nisaa`. Dia menetapkan bahwa kedua orang tua telah mendapatkan bagian yang telah ditentukan, dan memberikan warisan kepada setiap orang yang berhak mendapat warisan dari harta warisannya, dan tidak ada lagi wasiat bagi mereka. Wasiat hanya diberikan kepada orang-orang yang tidak berhak mewarisi baik dari kerabat maupun lainnya.\""},{"p":"Ibnu Majah","n":1985,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَوَاللَّهِ لَمَنْ شَاءَ لَاعَنَّاهُ لَأُنْزِلَتْ سُورَةُ النِّسَاءِ الْقُصْرَى بَعْدَ أَرْبَعَةِ أَشْهُرٍ وَعَشْرًا","trj":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Muslim] dari [Masruq] dari [Abdullah bin Mas'ud] ia berkata, \"Demi Allah, bagi siapa yang ingin maka kami akan mengutuknya. Sungguh telah turun surat An Nisa Al Qushra '(Setelah empat bulan sepuluh hari) '.\""},{"p":"Ibnu Majah","n":2681,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ الْيَعْمُرِيِّأَنَّ عُمَرَ بْنَ الْخَطَّابِ قَامَ خَطِيبًا يَوْمَ الْجُمُعَةِ أَوْ خَطَبَهُمْ يَوْمَ الْجُمُعَةِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ إِنِّي وَاللَّهِ مَا أَدَعُ بَعْدِي شَيْئًا هُوَ أَهَمُّ إِلَيَّ مِنْ أَمْرِ الْكَلَالَةِ وَقَدْ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا أَغْلَظَ لِي فِي شَيْءٍ مَا أَغْلَظَ لِي فِيهَا حَتَّى طَعَنَ بِإِصْبَعِهِ فِي جَنْبِي أَوْ فِي صَدْرِي ثُمَّ قَالَ يَا عُمَرُ تَكْفِيكَ آيَةُ الصَّيْفِ الَّتِي نَزَلَتْ فِي آخِرِ سُورَةِ النِّسَاءِ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Sa'id] dari [Qatadah] dari [Salim bin Abu Ja'ad] dari [Ma'dan bin Abu Thalhah Al Ya'muri]; \"Sesungguhnya ['Umar bin Khaththab] berdiri sambil berpidato di hari jum'at atau ia menyampaikan khutbah kepada Masyarakat di hari jum'at. la memuji kepada Allah lalu berkata; 'Sesungguhnya aku Demi Allah! Tidak ada hal sama sekali yang aku tinggalkan yang sangat penting, yang aku perhatikan daripada masalah kalalah, aku telah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, seperti halnya dalam masalah ini, hingga Rasulullah shallallahu 'alaihi wasallam menusuk jarinya di pinggangku atau di dadaku, lalu bersabda: 'Wahai 'Umar! Cukup bagimu ayat shaif yang diturunkan di akhir surat An-Nisa.'\""},{"p":"Ibnu Majah","n":2683,"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُمَرِضْتُ فَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي هُوَ وَأَبُو بَكْرٍ مَعَهُ وَهُمَا مَاشِيَانِ وَقَدْ أُغْمِيَ عَلَيَّ فَتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَبَّ عَلَيَّ مِنْ وَضُوئ��هِ فَقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ أَصْنَعُ كَيْفَ أَقْضِي فِي مَالِي حَتَّى نَزَلَتْ آيَةُ الْمِيرَاثِ فِي آخِرِ النِّسَاءِ{ وَإِنْ كَانَ رَجُلٌ يُورَثُ كَلَالَةً }وَ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Hisyam bin Ammar]; telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Al Munkadir], ia mendengar [Jabir bin 'Abdullah] berkata; \"Aku sedang sakit lalu Rasulullah shallallahu 'alaihi wasallam bersama Abu bakar datang menjengukku, keduanya datang dengan berjalan kaki. Saat itu aku sedang dalam keadaan pingsan. Rasulullah shallallahu 'alaihi wasallam kemudian berwudlu lalu ia menyiramkan bekas air wudlunya kepadaku dan aku katakan; 'Wahai Rasulullah! Apa yang harus aku perbuat? Apa yang harus aku putuskan pada hartaku? Sampai turun ayat mengenai harta warisan di akhir surat An-Nisa yang berbunyi: 'Apabila seorang laki-laki mewariskan kalalah.' Dan ayat: 'Mereka meminta fatwa kepadamu (wahai Muhammad), katakanlah: 'Allah Subhanahu Wa Ta'ala memberi fatwa kepada kalian mengenai kalalah'.\""},{"p":"Ibnu Majah","n":4145,"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ فَقَرَأْتُ عَلَيْهِ بِسُورَةِ النِّسَاءِ حَتَّى إِذَا بَلَغْتُ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }فَنَظَرْتُ إِلَيْهِ فَإِذَا عَيْنَاهُ تَدْمَعَانِ","trj":"Telah menceritakan kepada kami [Al Hannad bin As Sarri] telah menceritakan kepada kami [Abu Al Ahwash] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah bersabda kepadaku: \"Bacakanlah (ayat) untukku! \" Maka saya membaca surat An Nisaa, ketika sampai ayat: '(Maka bagaimanakah (halnya orang kafir nanti), apabila kami mendatangkan seseorang saksi (rasul) dari tiap-tiap umat dan kami mendatangkan kamu (Muhammad) sebagai saksi atas mereka itu (sebagai umatmu) ' (Qs. An Nisaa: 41), maka saya melihat kedua air mata beliau meneteskan air mata.\""},{"p":"Malik","n":951,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ أَنَّ عُمَرَ بْنَ الْخَطَّابِسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْكَلَالَةِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْفِيكَ مِنْ ذَلِكَ الْآيَةُ الَّتِي أُنْزِلَتْ فِي الصَّيْفِ آخِرَ سُورَةِ النِّسَاءِ","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Zaid bin Aslam] bahwa [Umar bin Khattab] pernah bertanya kepada Rasulullah Shalla Allahu 'alaihi wa sallam mengenai kalalah. Rasulullah Shalla Allahu 'alaihi wa sallam lalu bersabda kepadanya: \"Cukup bagimu mengenai hal itu dengan sebuah ayat yang diturunkan saat musim panas' yaitu di akhir surat An Nisa'.\" "},{"p":"Muslim","n":219,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَيُوشِكَنَّ أَنْ يَنْزِلَ فِيكُمْ ابْنُ مَرْيَمَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَكَمًا مُقْسِطًا فَيَكْسِرَ الصَّلِيبَ وَيَقْتُلَ الْخِنْزِيرَ وَيَضَعَ الْجِزْيَةَ وَيَفِيضُ الْمَالُ حَتَّى لَا يَقْبَلَهُ أَحَدٌو حَدَّثَنَاه عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ ح و حَدَّثَنِيهِ حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنِي يُونُسُ ح و حَدَّثَنَا حَسَنٌ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ عَنْ يَعْقُوبَ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ كُلُّهُمْ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ وَفِي رِوَايَةِ ابْنِ عُيَيْنَةَ إِمَامًا مُقْسِطًا وَحَكَمًا عَدْلًا وَفِي رِوَايَةِ يُونُسَ حَكَمًا عَادِلًا وَلَمْ يَذْكُرْ إِمَامًا مُقْسِطًا وَفِي حَدِيثِ صَالِحٍ حَكَمًا مُقْسِطًا كَمَا قَالَ اللَّيْثُ وَفِي حَدِيثِهِ مِنْ الزِّيَادَةِ وَحَتَّى تَكُونَ السَّجْدَةُ الْوَاحِدَةُ خَيْرًا مِنْ الدُّنْيَا وَمَا فِيهَا ثُمَّ يَقُولُا أَبُو هُرَيْرَةَ اقْرَءُوا إِنْ شِئْتُمْ{ وَإِنْ مِنْ أَهْلِ الْكِتَابِ إِلَّا لَيُؤْمِنَنَّ بِهِ قَبْلَ مَوْتِهِ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits]. (dalam jalur lain disebutkan) Dan telah menceritakan kepada kami [Muhammad bin Rumh] telah mengabarkan kepada kami [al-Laits] dari [Ibnu Syihab] dari [Ibnu al-Musayyab] bahwa dia mendengar [Abu Hurairah] mengatakan, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya! Sungguh, kedatangan Isa bin Mariam kepada kalian untuk menjadi hakim secara adil akan segera tiba. Dia akan mematahkan salib, membunuh babi serta menghapuskan jizyah (dari orang kafir). Harta akan melimpah ruah, sehingga tidak ada seorang pun yang ingin menerimanya.\" Dan telah menceritakannya kepada kami [Abdul A'la bin Hammad] dan [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] mereka berkata; telah menceritakan kepada kami [Sufyan bin Uyainah]. (dalam riwayat lain disebutkan) Dan telah menceritakannya kepadaku tentangnya [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahab] dia berkata, telah menceritakan kepadaku [Yunus]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Hasan al-Hulwani] dan ['Abd bin Humaid] dari [Ya'qub bin Ibrahim bin Sa'id] telah menceritakan kepada kami [ayahku] dari [Shalih] seluruhnya dari [Az-Zuhri] dengan isnad ini. Dan dalam riwayat Ibnu Uyainah disebutkan, \"Sebagai imam yang adil dan hakim yang adil.\" Sedangkan dalam riwayat Yunus, \"Sebagai hakim yang adil, \" dan tidak menyebutkan, \"imam yang adil.\" Sedangkan dalam riwayat Shalih, \"Hakim yang adil.\" Sebagaimana dikatakan al-Laits, dan dalam haditsnya terdapat tambahan, \"hingga satu sujud lebih baik daripada dunia dan seisinya.\" Kemudian Abu Hurairah berkata, \"Bacalah jika kalian berkehendak: '(Tidak ada seorang pun dari Ahli Kitab, kecuali akan beriman kepadanya (Isa) sebelum kematiannya) ' (Qs. an-Nisaa': 159)."},{"p":"Muslim","n":266,"ar":"و حَدَّثَنِي سُوَيْدُ بْنُ سَعِيدٍ قَالَ حَدَّثَنِي حَفْصُ بْنُ مَيْسَرَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ نَاسًا فِي زَمَنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ قَالَ هَلْ تُضَارُّونَ فِي رُؤْيَةِ الشَّمْسِ بِالظَّهِيرَةِ صَحْوًا لَيْسَ مَعَهَا سَحَابٌ وَهَلْ تُضَارُّونَ فِي رُؤْيَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ صَحْوًا لَيْسَ فِيهَا سَحَابٌ قَالُوا لَا يَا رَسُولَ اللَّهِ قَالَ مَا تُضَارُّونَ فِي رُؤْيَةِ اللَّهِ تَبَارَكَ وَتَعَالَى يَوْمَ الْقِيَامَةِ إِلَّا كَمَا تُضَارُّونَ فِي رُؤْيَةِ أَحَدِهِمَا إِذَا كَانَ يَوْمُ الْقِيَامَةِ أَذَّنَ مُؤَذِّنٌ لِيَتَّبِعْ كُلُّ أُمَّةٍ مَا كَانَتْ تَعْبُدُ فَلَا يَبْقَى أَحَدٌ كَانَ يَعْبُدُ غَيْرَ اللَّهِ سُبْحَانَهُ مِنْ الْأَصْنَامِ وَالْأَنْصَابِ إِلَّا يَتَسَاقَطُونَ فِي النَّارِ حَتَّى إِذَا لَمْ يَبْقَ إِلَّا مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ وَفَاجِرٍ وَغُبَّرِ أَهْلِ الْكِتَابِ فَيُدْعَى الْيَهُودُ فَيُقَالُ لَهُمْ مَا كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ عُزَيْرَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ مَا اتَّخَذَ اللَّهُ مِنْ صَاحِبَةٍ وَلَا وَلَدٍ فَمَاذَا تَبْغُونَ قَالُوا عَطِشْنَا يَا رَبَّنَا فَاسْقِنَا فَيُشَارُ إِلَيْهِمْ أَلَا تَرِدُونَ فَيُحْشَرُونَ إِلَى النَّارِ كَأَنَّهَا سَرَابٌ يَحْطِمُ بَعْضُهَا بَعْضًا فَيَتَسَاقَطُونَ فِي النَّارِ ثُمَّ يُدْعَى النَّصَارَى فَيُقَالُ لَهُمْ مَا كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ الْمَسِيحَ ابْنَ اللَّهِ فَيُقَالُ لَهُمْ كَذَبْتُمْ مَا اتَّخَذَ اللَّهُ مِنْ صَاحِبَةٍ وَلَا وَلَدٍ فَيُقَالُ لَهُمْ مَاذَا تَبْغُونَ فَيَقُولُونَ عَطِشْنَا يَا رَبَّنَا فَاسْقِنَا قَالَ فَيُشَارُ إِلَيْهِمْ أَلَا تَرِدُونَ فَيُحْشَرُونَ إِلَى جَهَنَّمَ كَأَنَّهَا سَرَابٌ يَحْطِمُ بَعْضُهَا بَعْضًا فَيَتَسَاقَطُونَ فِي النَّارِ حَتَّى إِذَا لَمْ يَبْقَ إِلَّا مَنْ كَانَ يَعْبُدُ اللَّهَ تَعَالَى مِنْ بَرٍّ وَفَاجِرٍ أَتَاهُمْ رَبُّ الْعَالَمِينَ سُبْحَانَهُ وَتَعَالَى فِي أَدْنَى صُورَةٍ مِنْ الَّتِي رَأَوْهُ فِيهَا قَالَ فَمَا تَنْتَظِرُونَ تَتْبَعُ كُلُّ أُمَّةٍ مَا كَانَتْ تَعْبُدُ قَالُوا يَا رَبَّنَا فَارَقْنَا النَّاسَ فِي الدُّنْيَا أَفْقَرَ مَا كُنَّا إِلَيْهِمْ وَلَمْ نُصَاحِبْهُمْ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ نَعُوذُ بِاللَّهِ مِنْكَ لَا نُشْرِكُ بِاللَّهِ شَيْئًا مَرَّتَيْنِ أَوْ ثَلَاثًا حَتَّى إِنَّ بَعْضَهُمْ لَيَكَادُ أَنْ يَنْقَلِبَ فَيَقُولُ هَلْ بَيْنَكُمْ وَبَيْنَهُ آيَةٌ فَتَعْرِفُونَهُ بِهَا فَيَقُولُونَ نَعَمْ فَيُكْشَفُ عَنْ سَاقٍ فَلَا يَبْقَى مَنْ كَانَ يَسْجُدُ لِلَّهِ مِنْ تِلْقَاءِ نَفْسِهِ إِلَّا أَذِنَ اللَّهُ لَهُ بِالسُّجُودِ وَلَا يَبْقَى مَنْ كَانَ يَسْجُدُ اتِّقَاءً وَرِيَاءً إِلَّا جَعَلَ اللَّهُ ظَهْرَهُ طَبَقَةً وَاحِدَةً كُلَّمَا أَرَادَ أَنْ يَسْجُدَ خَرَّ عَلَى قَفَاهُ ثُمَّ يَرْفَعُونَ رُءُوسَهُمْ وَقَدْ تَحَوَّلَ فِي صُورَتِهِ الَّتِي رَأَوْهُ فِيهَا أَوَّلَ مَرَّةٍ فَقَالَ أَنَا رَبُّكُمْ فَيَقُولُونَ أَنْتَ رَبُّنَا ثُمَّ يُضْرَبُ الْجِسْرُ عَلَى جَهَنَّمَ وَتَحِلُّ الشَّفَاعَةُ وَيَقُولُونَ اللَّهُمَّ سَلِّمْ سَلِّمْ قِيلَ يَا رَسُولَ اللَّهِ وَمَا الْجِسْرُ قَالَ دَحْضٌ مَزِلَّةٌ فِيهِ خَطَاطِيفُ وَكَلَالِيبُ وَحَسَكٌ تَكُونُ بِنَجْدٍ فِيهَا شُوَيْكَةٌ يُقَالُ لَهَا السَّعْدَانُ فَيَمُرُّ الْمُؤْمِنُونَ كَطَرْفِ الْعَيْنِ وَكَالْبَرْقِ وَكَالرِّيحِ وَكَالطَّيْرِ وَكَأَجَاوِيدِ الْخَيْلِ وَالرِّكَابِ فَنَاجٍ مُسَلَّمٌ وَمَخْدُوشٌ مُرْسَلٌ وَمَكْدُوسٌ فِي نَارِ جَهَنَّمَ حَتَّى إِذَا خَلَصَ الْمُؤْمِنُونَ مِنْ النَّارِ فَوَالَّذِي نَفْسِي بِيَدِهِ مَا مِنْكُمْ مِنْ أَحَدٍ بِأَشَدَّ مُنَاشَدَةً لِلَّهِ فِي اسْتِقْصَاءِ الْحَقِّ مِنْ الْمُؤْمِنِينَ لِلَّهِ يَوْمَ الْقِيَامَةِ لِإِخْوَانِهِمْ الَّذِينَ فِي النَّارِ يَقُولُونَ رَبَّنَا كَانُوا يَصُومُونَ مَعَنَا وَيُصَلُّونَ وَيَحُجُّونَ فَيُقَالُ لَهُمْ أَخْرِجُوا مَنْ عَرَفْتُمْ فَتُحَرَّمُ صُوَرُهُمْ عَلَى النَّارِ فَيُخْرِجُونَ خَلْقًا كَثِيرًا قَدْ أَخَذَتْ النَّارُ إِلَى نِصْفِ سَاقَيْهِ وَإِلَى رُكْبَتَيْهِ ثُمَّ يَقُولُونَ رَبَّنَا مَا بَقِيَ فِيهَا أَحَدٌ مِمَّنْ أَمَرْتَنَا بِهِ فَيَقُولُ ارْجِعُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ دِينَارٍ مِنْ خَيْرٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ خَلْقًا كَثِيرًا ثُمَّ يَقُولُونَ رَبَّنَا لَمْ نَذَرْ فِيهَا أَحَدًا مِمَّنْ أَمَرْتَنَا ثُمَّ يَقُولُ ارْجِعُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ نِصْفِ دِينَارٍ مِنْ خَيْرٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ خَلْقًا كَثِيرًا ثُمَّ يَقُولُونَ رَبَّنَا لَمْ نَذَرْ فِيهَا مِمَّنْ أَمَرْ��َنَا أَحَدًا ثُمَّ يَقُولُ ارْجِعُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ ذَرَّةٍ مِنْ خَيْرٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ خَلْقًا كَثِيرًا ثُمَّ يَقُولُونَ رَبَّنَا لَمْ نَذَرْ فِيهَا خَيْرًا وَكَانَ أَبُو سَعِيدٍ الْخُدْرِيُّ يَقُولُ إِنْ لَمْ تُصَدِّقُونِي بِهَذَا الْحَدِيثِ فَاقْرَءُوا إِنْ شِئْتُمْ{ إِنَّ اللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍ وَإِنْ تَكُ حَسَنَةً يُضَاعِفْهَا وَيُؤْتِ مِنْ لَدُنْهُ أَجْرًا عَظِيمًا }فَيَقُولُ اللَّهُ عَزَّ وَجَلَّ شَفَعَتْ الْمَلَائِكَةُ وَشَفَعَ النَّبِيُّونَ وَشَفَعَ الْمُؤْمِنُونَ وَلَمْ يَبْقَ إِلَّا أَرْحَمُ الرَّاحِمِينَ فَيَقْبِضُ قَبْضَةً مِنْ النَّارِ فَيُخْرِجُ مِنْهَا قَوْمًا لَمْ يَعْمَلُوا خَيْرًا قَطُّ قَدْ عَادُوا حُمَمًا فَيُلْقِيهِمْ فِي نَهَرٍ فِي أَفْوَاهِ الْجَنَّةِ يُقَالُ لَهُ نَهَرُ الْحَيَاةِ فَيَخْرُجُونَ كَمَا تَخْرُجُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ أَلَا تَرَوْنَهَا تَكُونُ إِلَى الْحَجَرِ أَوْ إِلَى الشَّجَرِ مَا يَكُونُ إِلَى الشَّمْسِ أُصَيْفِرُ وَأُخَيْضِرُ وَمَا يَكُونُ مِنْهَا إِلَى الظِّلِّ يَكُونُ أَبْيَضَ فَقَالُوا يَا رَسُولَ اللَّهِ كَأَنَّكَ كُنْتَ تَرْعَى بِالْبَادِيَةِ قَالَ فَيَخْرُجُونَ كَاللُّؤْلُؤِ فِي رِقَابِهِمْ الْخَوَاتِمُ يَعْرِفُهُمْ أَهْلُ الْجَنَّةِ هَؤُلَاءِ عُتَقَاءُ اللَّهِ الَّذِينَ أَدْخَلَهُمْ اللَّهُ الْجَنَّةَ بِغَيْرِ عَمَلٍ عَمِلُوهُ وَلَا خَيْرٍ قَدَّمُوهُ ثُمَّ يَقُولُ ادْخُلُوا الْجَنَّةَ فَمَا رَأَيْتُمُوهُ فَهُوَ لَكُمْ فَيَقُولُونَ رَبَّنَا أَعْطَيْتَنَا مَا لَمْ تُعْطِ أَحَدًا مِنْ الْعَالَمِينَ فَيَقُولُ لَكُمْ عِنْدِي أَفْضَلُ مِنْ هَذَا فَيَقُولُونَ يَا رَبَّنَا أَيُّ شَيْءٍ أَفْضَلُ مِنْ هَذَا فَيَقُولُ رِضَايَ فَلَا أَسْخَطُ عَلَيْكُمْ بَعْدَهُ أَبَدًاقَالَ مُسْلِم قَرَأْتُ عَلَى عِيسَى بْنِ حَمَّادٍ زُغْبَةَ الْمِصْرِيِّ هَذَا الْحَدِيثَ فِي الشَّفَاعَةِ وَقُلْتُ لَهُ أُحَدِّثُ بِهَذَا الْحَدِيثِ عَنْكَ أَنَّكَ سَمِعْتَ مِنَ اللَّيْثِ بْنِ سَعْدٍ فَقَالَ نَعَمْ قُلْتُ لِعِيسَى بْنِ حَمَّادٍ أَخْبَرَكُمُ اللَّيْثُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ أَنَرَى رَبَّنَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ تُضَارُّونَ فِي رُؤْيَةِ الشَّمْسِ إِذَا كَانَ يَوْمٌ صَحْوٌ قُلْنَا لَا وَسُقْتُ الْحَدِيثَ حَتَّى انْقَضَى آخِرُهُ وَهُوَ نَحْوُ حَدِيثِ حَفْصِ بْنِ مَيْسَرَةَ وَزَادَ بَعْدَ قَوْلِهِ بِغَيْرِ عَمَلٍ عَمِلُوهُ وَلَا قَدَمٍ قَدَّمُوهُ فَيُقَالُ لَهُمْ لَكُمْ مَا رَأَيْتُمْ وَمِثْلُهُ مَعَهُ قَالَ أَبُو سَعِيدٍ بَلَغَنِي أَنَّ الْجِسْرَ أَدَقُّ مِنْ الشَّعْرَةِ وَأَحَدُّ مِنْ السَّيْفِ وَلَيْسَ فِي حَدِيثِ اللَّيْثِ فَيَقُولُونَ رَبَّنَا أَعْطَيْتَنَا مَا لَمْ تُعْطِ أَحَدًا مِنْ الْعَالَمِينَ وَمَا بَعْدَهُ فَأَقَرَّ بِهِ عِيسَى بْنُ حَمَّادٍ و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ بِإِسْنَادِهِمَا نَحْوَ حَدِيثِ حَفْصِ بْنِ مَيْسَرَةَ إِلَى آخِرِهِ وَقَدْ زَادَ وَنَقَصَ شَيْئًا","trj":"Dan telah menceritakan kepadaku [Suwaid bin Sa'id] dia berkata, telah menceritakan kepadaku [Hafsh bin maisarah] dari [Zaid bin Aslam] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudri] bahwa sekelompok manusia pada zaman Rasulullah shallallahu 'alaihi wasallam bertanya, 'Wahai Rasulullah! Apakah kami melihat Rabb kami pada Hari Kiamat?\" Beliau menjawab, \"Apakah kalian berdesak-desakan dalam melihat matahari di siang hari yang terang tanpa awan?\" Mereka menjawab, \"Tidak wahai Rasulullah.\" Beliau pun berkata, \"Apakah kalian berdesak-desakan dalam melihat bulan di malam purnama yang tidak ada awannya?\" Mereka menjawab, \"Tidak.\" Lalu beliau bersabda: \"Tidaklah kalian berdesak-desakan dalam melihat Rabb kalian, melainkan sebagaimana kalian (tidak) berdesak-desakan dalam melihat salah satu dari keduanya. Pada hari kiamat, seorang penyeru akan menyerukan 'Hendaklah setiap umat mengikuti sesuatu yang dahulu mereka sembah', hingga tidaklah ada seorang pun yang menyembah selain Allah berupa berhala, dan patung melainkan mereka akan terjerumus ke dalam neraka, hingga tidak ada yang tersisa seorang pun kecuali orang yang menyembah Allah; baik itu orang yang baik dan buruk, dan sisa Ahli Kitab, lalu orang Yahudi dipanggil dan ditanyakan kepada mereka, 'Apa yang dahulu kalian sembah? ' Mereka menjawab, 'Kami dahulu menyembah Uzair, putera Allah.' Maka dikatakan, 'Kalian telah berdusta, Allah tidak menjadikan isteri dan anak. Lalu apa yang kalian inginkan? ' Mereka menjawab, 'Kami haus wahai Rabb kami, maka berilah kami minum.' Lalu mereka diberi isyarat pada sesuatu yang membuat mereka hilang dahaganya, mereka kemudian digiring hingga ke neraka, seakan-akan fatamorgana, sebagian memukul sebagian yang lain, lalu mereka terjerumus ke dalam neraka.' Kemudian kaum Nashrani dipanggil, lalu mereka ditanya, 'Apa yang dahulu kalian sembah? ' mereka menjawab, 'Kami dahulu menyembah al-Masih, putera Allah.' Lalu dikatakan kepada mereka, 'Kalian telah berbohong. Allah tidak mengambil istri dan anak.' Maka dikatakan kepada mereka, 'Apa yang kalian inginkan? ' Mereka menjawab, 'Kami haus wahai Rabb kami, berilah kami minum.' Beliau bersabda: \"Lalu diisyaratkan kepada mereka. 'Tidakkah kalian minum.' dan mereka dikumpulkan di neraka Jahannam, seakan-akan neraka tersebut fatamorgana yang mana sebagian mereka memukul sebagian yang lain, lalu jatuh ke dalam neraka, hingga tidak tersisa melainkan orang yang menyembah Allah dari kalangan orang baik dan orang fajir. Allah lalu mendatangi mereka dalam bentuk yang paling ringan yang dapat mereka lihat. Allah berfirman; “apa yang kalian tunggu, padahal setiap umat mengikuti apa yang mereka sembah?.” Mereka berkata; “wahai Rabb kami, kami memisahkan diri dari manusia di dunia ketika kami membutuhkan apa yang kami butuhkan kepada mereka, akan tetapi kami tidak berteman dengan mereka.” Maka Allah berfirman; “aku adalah rabb kalian.” Maka mereka berkata; “aku berlindung kepada Allah dari-Mu, kami tidak akan menyekutukan Allah dengan sesuatupun.” Mereka ucapakan dua kalia atau tiga kali, sehingga sebagian mereka hampir-hampir berbalik, maka Allah bertanya; “apakah diantara kalian dan Dia mempunyai tanda-tanda, yang dapat kalian kenal dengan tanda-tanda itu?” mereka menjawab; “ya” maka di singkaplah betis-Nya, sehingga tidak tersisa orang yang sebelumnya bersujud kepada Allah dari dalam dirinya (ikhlas) kecuali Allah izinkan baginya untuk bersujud. Dan tidak tersisa orang yang sebelumnya bersujud karena ego dan riya` kecuali Allah jadikan punggungnya menjadi satu lipatan, setiap kali hendak bersujud maka dia tersungkur diatas tengkuknya. Kemudian mereka mengangkat kepala  mereka dan Allah telah berubah ke bentuk yang dapat mereka lihat pertama kalinya, Allah berfirman:v “aku adalah Rabb kalian.” Maka mereka berkata; “Engkau Rabb kami.” Kemudian di bentangkan jembatan di atas Jahannam, dan berlakulah syafa'at pada saat itu, mereka berguman; “ya Allah, selamatkanlah, selamatkanlah.” Ada yang bertanya; 'wahai Rasulullah, apakah jembatan itu?” beliau menjawab; “tempat yang licin yang dapat menggelincirkan, disana terdapat besi-besi pencakar, besi-besi pengait dan duri besi yang terbuat dari pohon-pohon berduri. Maka orang-orang mu'min akan melewatinya seperti kedipan mata, seperti kilat, seperti angin, seperti burung, seperti kuda-kuda yang berlari kencang, dan hewan tunggangan. Maka orang muslim akan ada yang selamat, ada yang tercabik-cabik tertunda dan ada yang terlempar kedalam neraka jahannam. Sehingga ketika orang-orang mu'min terbebas dari neraka, maka demi Dzat yang jiwaku berada ditangan-Nya, tidaklah salah seorang dari kalian yang begitu gigih memohon kepada Allah didalam menuntut al haq  pada hari kiamat untuk saudara-saudaranya yang berada di dalam neraka, mereka berseru; wahai rabb kami, mereka selalu berpuasa bersama kami, salat bersama kami, dan berhaji bersama kami.” Maka dikatakan kepada mereka; “keluarkanlah orang-orang yang kalian ketahui.” Maka bentuk-bentuk mereka hitam kelam karena terpanggang api neraka, kemudian mereka mengeluarkan begitu banyak orang yang telah di makan neraka sampai pada pertengahan betisnya dan sampai kedua lututnya. Kemudian mereka berkata; “ wahai rabb kami tidak tersisa lagi seseorang pun yang telah engkau perintahkan kepada kami.” Kemudian Allah berfirman; “kembalilah kalian, maka barangsiapa yang kalian temukan didalam hatinya kebaikan seberat dinar, maka keluarkanlah dia.” Mereka pun mengeluarkan jumlah yang begitu banyak, kemudian mereka berkata; “wahai rabb kami, kami tidak meninggalkan di dalamnya seorangpun yang telah Engkau perintahkan kepada kami.” Kemudian Allah berfirman; “kembalilah kalian, maka barangsiapa yang kalian temukan didalam hatinya kebaikan seberat setengah dinar, maka keluarkanlah dia.” Maka mereka pun mengeluarkan jumlah yang banyak. Kemudian mereka berkata lagi; “wahai Rabb kami, kami tidak menyisakan di dalamnya seorang pun yang telah Engkau perintahkan kepada kami.” Kemudian Allah berfirman; “kembalilah kalian, maka siapa saja yang kalian temukan didalam hatinya kebaikan seberat biji jagung, keluarkanlah.” Maka merekapun kembali mengeluarkan jumlah yang begitu banyak. Kemudian mereka berkata; “wahai Rabb kami, kami tidak menyisakan di dalamnya kebaikan sama sekali.” Abu Sa'id al Khudri berkata, \"Jika kalian tidak mempercayai hadits ini silahkan kalian baca ayat: (Sesungguhnya Allah tidak menganiaya seseorang walaupun sebesar zarrah, dan jika ada kebajikan sebesar zarrah, niscaya Allah akan melipat gandakannya dan memberikan dari sisi-Nya pahala yang besar.) (Qs. An Nisa: 40). Allah lantas berfirman: \"Para Malaikat, Nabi dan orang-orang yang beriman telah memberi syafaat, sekarang yang belum memberikan syafaat adalah Dzat Yang Maha Pengasih.\" Kemudian Allah menggenggam satu genggaman dari dalam neraka, dari dalam tersebut Allah mengeluarkan suatu kaum yang sama sekali tidak melakukan kebaikan, dan mereka pun sudah berbentuk seperti arang hitam. Allah kemudian melemparkan mereka ke dalam sungai di depan surga yang disebut dengan sungai kehidupan. Mereka kemudian keluar dari dalam sungai layaknya biji yang tumbuh di aliran sungai, tidakkah kalian lihat ia tumbuh (merambat) di bebatuan atau pepohonan mengejar (sinar) matahari. Kemudian mereka (yang tumbuh layaknya biji) ada yang berwarna kekuningan dan kehijauan, sementara yang berada di bawah bayangan akan berwarna putih.\" Para sahabat kemudian bertanya, \"Seakan-akan baginda sedang menggembala di daerah orang-orang badui?' Beliau melanjutkan: \"Mereka kemudian keluar seperti mutiara, sementara di lutut-lutut mereka terdapat cincin yang bisa diketahui oleh penduduk surga. Dan mereka adalah orang-orang yang Allah merdekakan dan Allah masukkan ke dalam surga tanpa dengan amalan dan kebaikan sama sekali. Allah kemudian berkata: \"Masuklah kalian ke dalam surga. Apa yang kalian lihat maka itu akan kalian miliki.\" Mereka pun menjawab, \"Wahai Rabb kami, sungguh Engkau telah memberikan kepada kami sesuatu yang belum pernah Engkau berikan kepada seorang pun dari penduduk bumi.\" Allah kemudian berkata: \"(Bahkan) apa yang telah Kami siapkan untuk kalian lebih baik dari ini semua.\" Mereka kembali berkata, \"Wahai Rabb, apa yang lebih baik dari ini semua!\" Allah menjawab: \"Ridla-Ku, selamanya Aku tidak akan pernah murka kepada kalian.\" Muslim berkata, \"Aku membacakan hadits ini di hadapan [Isa bin Hammad Zughbah al Mishri] berkenaan dengan syafaat. Aku katakan kepadanya, \"Aku sampaikan hadits ini darimu, bahwa engkau pernah mendengar dari [Laits bin Sa'd] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Zaid bin Aslam] dari [Atha bin Yasar] dari [Abu Sa'id Al Khudri] bahwasanya ia berkata, \"Wahai Rasulullah, apakah kami akan melihat Rabb kami?\" Rasulullah Shallallahu 'alaihi wa Sallam balik bertanya: \"Apakah kalian mendapatkan bahaya dalam melihat matahari di hari yang cerah?\" kami menjawab; 'Tidak.\" Kemudian aku melanjutkan hadits tersebut hingga selesai. Dan hadits tersebut semisal hadits Hafsh bin Maisarah.\" Dan ia menambahkan setelah perkataannya, \"tanpa dengan amalan dan kebaikan sama sekali.\" Kemudian dikatakan kepada mereka, \"Bagi kalian apa yang kalian lihat dan seperti itu bersamanya.\" Abu Sa'id berkata, \"telah sampai kepadaku bahwa jembatan lebih kecil dari rambut dan lebih tajam dari pedang.\"  Dan dalam hadits Laits tidak ada redaksi: \"Mereka berkata, 'Wahai rabb kami, engkau telah memberikan kepada kami sesuatu yang tidak diberikan kepada seorang pun di atas alam.\" Dan kalimat setelahnya. Dan Isa bin Hammad menyepakatinya.\" Telah menceritakannya kepada kami [Abu bakar bin Abu Syaibah] telah menceritakan kepada kami [Ja'far bin Aun] telah menceritakan kepada kami [Hisyam bin Sa'd] telah menceritakan kepada kami [Zaid bin Aslam] sama dengan isnad keduanya seperti hadits Hafsh bin Maisarah, sampai kepada kalimat yang terakhir, dan di sana terdapat penambahan dan pengurangan.\""},{"p":"Muslim","n":858,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ خَطَبَ يَوْمَ الْجُمُعَةِ فَذَكَرَ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرَ أَبَا بَكْرٍ قَالَ إِنِّي رَأَيْتُ كَأَنَّ دِيكًا نَقَرَنِي ثَلَاثَ نَقَرَاتٍ وَإِنِّي لَا أُرَاهُ إِلَّا حُضُورَ أَجَلِي وَإِنَّ أَقْوَامًا يَأْمُرُونَنِي أَنْ أَسْتَخْلِفَ وَإِنَّ اللَّهَ لَمْ يَكُنْ لِيُضَيِّعَ دِينَهُ وَلَا خِلَافَتَهُ وَلَا الَّذِي بَعَثَ بِهِ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ عَجِلَ بِي أَمْرٌ فَالْخِلَافَةُ شُورَى بَيْنَ هَؤُلَاءِ السِّتَّةِ الَّذِينَ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَنْهُمْ رَاضٍ وَإِنِّي قَدْ عَلِمْتُ أَنَّ أَقْوَامًا يَطْعَنُونَ فِي هَذَا الْأَمْرِ أَنَا ضَرَبْتُهُمْ بِيَدِي هَذِهِ عَلَى الْإِسْلَامِ فَإِنْ فَعَلُوا ذَلِكَ فَأُولَئِكَ أَعْدَاءُ اللَّهِ الْكَفَرَةُ الضُّلَّالُ ثُمَّ إِنِّي لَا أَدَعُ بَعْدِي شَيْئًا أَهَمَّ عِنْدِي مِنْ الْكَلَالَةِمَا رَاجَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَيْءٍ مَا رَاجَعْتُهُ فِي الْكَلَالَةِ وَمَا أَغْلَظَ لِي فِي شَيْءٍ مَا أَغْلَظَ لِي فِيهِ حَتَّى طَعَنَ بِإِصْبَعِهِ فِي صَدْرِي فَقَالَ يَا عُمَرُ أَلَا تَكْفِيكَ آيَةُ الصَّيْفِ الَّتِي فِي آخِرِ سُورَةِ النِّسَاءِ وَإِنِّي إِنْ أَعِشْ أَقْضِ فِيهَا بِقَضِيَّةٍ يَقْضِي بِهَا مَنْ يَقْرَأُ الْقُرْآنَ وَمَنْ لَا يَقْرَأُ الْقُرْآنَ ثُمَّ قَالَ اللَّهُمَّ إِنِّي أُشْهِدُكَ عَلَى أُمَرَاءِ الْأَمْصَارِ وَإِنِّي إِنَّمَا بَعَثْتُهُمْ عَلَيْهِمْ لِيَعْدِلُوا عَلَي��هِمْ وَلِيُعَلِّمُوا النَّاسَ دِينَهُمْ وَسُنَّةَ نَبِيِّهِمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَقْسِمُوا فِيهِمْ فَيْئَهُمْ وَيَرْفَعُوا إِلَيَّ مَا أَشْكَلَ عَلَيْهِمْ مِنْ أَمْرِهِمْ ثُمَّ إِنَّكُمْ أَيُّهَا النَّاسُ تَأْكُلُونَ شَجَرَتَيْنِ لَا أَرَاهُمَا إِلَّا خَبِيثَتَيْنِ هَذَا الْبَصَلَ وَالثُّومَ لَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَجَدَ رِيحَهُمَا مِنْ الرَّجُلِ فِي الْمَسْجِدِ أَمَرَ بِهِ فَأُخْرِجَ إِلَى الْبَقِيعِ فَمَنْ أَكَلَهُمَا فَلْيُمِتْهُمَا طَبْخًاحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ قَالَ ح و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ كِلَاهُمَا عَنْ شَبَابَةَ بْنِ سَوَّارٍ قَالَ حَدَّثَنَا شُعْبَةُ جَمِيعًا عَنْ قَتَادَةَ فِي هَذَا الْإِسْنَادِ مِثْلَهُ","trj":"Telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Salim bin Abi al-Ja'd] dari [Ma'dan bin Abi Thalhah] \"Bahwa [Umar bin al-Khaththab] radhiyallahu'anhu berkhuthbah pada hari Jum'at, lalu dia menyebutkan Nabi Allah Shallallahu'alaihiwasallam, dan menyebutkan Abu Bakar. Dia berkata, 'Sesungguhnya aku berfirasat seakan-akan ayam jago mamatukku tiga kali, dan menurut firasatku, itu tidak lain (tanda) kehadiran ajalku. Dan sekelompok kaum menyuruhku untuk menunjukkan penggantiku. Dan Allah tidak berkehendak menghilangkan agamaNya dan tidak pula khilafahnya (maka aku boleh memutuskan penggantiku atau tidak sebagaimana Nabi Shallallahu'alaihiwasallam), dan tidak pula ajaran yang dibawa oleh NabiNya Shallallahu'alaihiwasallam. Jika kematian datang segera menjemputku, maka kekhilafahan adalah dipilih dengan cara musyawarah di antara enam orang yang Rasulullah Shallallahu'alaihiwasallam wafat dalam keadaan ridha kepada mereka. Dan sesungguhnya aku telah mengetahui bahwa sekelompok kaum ada yang merusak masalah ini. Saya terpaksa memukul mereka dengan tanganku ini atas dasar Islam. Jika mereka melakukan hal ini maka mereka itulah musuh Allah yang kafir lagi sesat. Kemudian aku tidak meninggalkan setelahku sesuatu yang lebih penting bagiku daripada pembahasan kalalah (orang yang meninggal tidak meninggalkan anak dan orang tua). Aku tidak pernah mendebat Rasulullah Shallallahu'alaihiwasallam sebagaimana aku mendebat beliau tentang masalah kalalah. Dan tidak pernah aku ngotot dalam suatu masalah sebagaimana aku ngotot dalam masalah kalalah hingga dia menusukku dengan jarinya ke dadaku. Beliau bersabda, 'Wahai Umar tidak cukupkah ayat Shaif yang berada pada akhir ayat dari surat an-Nisa', ' dan sesungguhnya aku jika masih hidup niscaya aku memutuskannya dengan keputusan orang yang pernah membaca al-Qur'an maupun yang tidak membaca al-Qur'an. Kemudian Rasulullah berkata, 'Ya Allah, sesungguhnya aku bersaksi kepadamu atas pemimpin-pemimpin. Dan hanyasanya aku mengutus mereka untuk rakyat dengan tujuan agar mereka berbuat adil atas mereka, dan agar mereka mengajari manusia tentang agama mereka dan sunnah Nabi Shallallahu'alaihiwasallam, membagi harta fai' di antara mereka, dan untuk mengajukan perkara yang sulit atas mereka untuk diajukan kepadaku. Kemudian kalian wahai manusia telah memakan dua pohon yang aku memandangnya sebagai pohon yang busuk yaitu bawang merah dan putih. Sungguh aku melihat Rasulullah Shallallahu'alaihiwasallam apabila mendapatkan baunya dari seorang laki-laki di masjid niscaya dia menyuruh pergi, lalu dia dikeluarkan ke al-Baqi'. Barangsiapa yang memakan keduanya, hendaklah dia menghilangkan baunya dengan cara dimasak.\" Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] telah menceritakan kepada kami [Ismail Ibnu Ulayyah] dari [Sa'id bin Abi 'Arubah] dia berkata --Lewat jalur periwayatan lain-- dan telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim] keduanya meriwayatkan dari [Syababah bin Sawwar] dia berkata, telah menceritakan kepada kami [Syu'bah] semuanya meriwayatkan dari [Qatadah] dalam isnad ini hadits semisalnya."},{"p":"Muslim","n":1067,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَزُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا وَقَالَ الْآخَرُونَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَقُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَقْصُرُوا مِنْ الصَّلَاةِ إِنْ خِفْتُمْ أَنْ يَفْتِنَكُمْ الَّذِينَ كَفَرُوا }فَقَدْ أَمِنَ النَّاسُ فَقَالَ عَجِبْتُ مِمَّا عَجِبْتَ مِنْهُ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ صَدَقَةٌ تَصَدَّقَ اللَّهُ بِهَا عَلَيْكُمْ فَاقْبَلُوا صَدَقَتَهُو حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمنِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَ قُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ بِمِثْلِ حَدِيثِ ابْنِ إِدْرِيسَ","trj":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] dan [Zuhair bin Harb] dan [Ishaq bin Ibrahim]. Ishaq mengatakan; telah mengabarkan kepada kami, sedangkan yang lainnya mengatakan; telah menceritakan kepada kami [Abdullah bin Idris] dari [Ibnu Juraij] dari [Ibnu Abu Ammar] dari [Abdullah bin Babaihi] dari [Ya'la bin 'Umayyah], katanya; \"Aku berkata kepada [Umar bin Khattab] mengenai ayat yang berbunyi Tak ada dosa atasmu meng-qashar shalat, jika kamu khawatir terhadap orang-orang kafir yang hendak memberi cobaan kepadamu.\" QS. Annisa'; 101, sementara manusia saat ini dalam kondisi aman (maksudnya tidak dalam kondisi perang).\" Umar menjawab; \"Sungguh aku juga pernah penasaran tentang ayat itu sebagaimana kamu penasaran, lalu aku tanyakan kepada Rasulullah shallallahu 'alaihi wasallam tentang ayat tersebut, beliau lalu menjawab: \"Itu (mengqashar shalat) adalah sedekah yang Allah berikan kepada kalian. Oleh karena itu, terimalah sedekah-Nya.\" Dan telah menceritakan kepada kami [Muhammad bin Abu Bakr Al Muqaddami], telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] katanya; telah menceritakan kepadaku [Abdurrahman bin Abdullah bin Abu 'Ammar] dari [Abdullah bin Babaihi], dari [Ya'la bin 'Umayyah] katanya; Aku pernah bertanya kepada [Umar bin Khatthab] semisal hadis Ibnu Idris."},{"p":"Muslim","n":1210,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو مُعَاوِيَةَ ح و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ جَمِيعًا عَنْ جَرِيرٍ كُلُّهُمْ عَنْ الْأَعْمَشِ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَافْتَتَحَ الْبَقَرَةَ فَقُلْتُ يَرْكَعُ عِنْدَ الْمِائَةِ ثُمَّ مَضَى فَقُلْتُ يُصَلِّي بِهَا فِي رَكْعَةٍ فَمَضَى فَقُلْتُ يَرْكَعُ بِهَا ثُمَّ افْتَتَحَ النِّسَاءَ فَقَرَأَهَا ثُمَّ افْتَتَحَ آلَ عِمْرَانَ فَقَرَأَهَا يَقْرَأُ مُتَرَسِّلًا إِذَا مَرَّ بِآيَةٍ فِيهَا تَسْبِيحٌ سَبَّحَ وَإِذَا مَرَّ بِسُؤَالٍ سَأَلَ وَإِذَا مَرَّ بِتَعَوُّذٍ تَعَوَّذَ ثُمَّ رَكَعَ فَجَعَلَ يَقُولُ سُبْحَانَ رَبِّيَ الْعَظِيمِ فَكَانَ رُكُوعُهُ نَحْوًا مِنْ قِيَامِهِ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ قَامَ طَوِيلًا قَرِيبًا مِمَّا رَكَعَ ثُمَّ سَجَدَ فَقَالَ سُبْحَانَ رَبِّيَ الْأَعْلَى فَكَانَ سُجُودُهُ قَرِيبًا مِنْ قِيَامِهِقَالَ وَفِي حَدِيثِ جَرِيرٍ مِنْ الزِّيَادَةِ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا لَكَ الْحَمْدُ","trj":"Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Mu'awiyah] -dalam jalur lain- Dan telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim] semuanya dari [Jarir] mereka semua dari [Al A'masy] -dalam jalur lain- telah menceritakan kepada kami [Ibnu Numair] -dan lafazh ini adalah darinya- telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dari [Sa'id bin Ubaidah] dari [Al Mustaurid bin Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] ia berkata; Pada suatu malam, saya shalat (Qiyamul Lail) bersama Rasulullah shallallahu 'alaihi wasallam, lalu beliau mulai membaca surat Al Baqarah. Kemudian saya pun berkata (dalam hati bahwa beliau) akan ruku' pada ayat yang ke seratus. Kemudian (seratus ayat pun) berlalu, lalu saya berkata (dalam hati bahwa) beliau akan shalat dengan (surat itu) dalam satu raka'at. Namun (surat Al Baqarah pun) berlalu, maka saya berkata (dalam hati bahwa) beliau akan segera sujud. Ternyata beliau melanjutkan dengan mulai membaca surat An Nisa` hingga selesai membacanya. Kemudian beliau melanjutkan ke surat Ali Imran hingga selesai hingga beliau selesai membacanya. Bila beliau membaca ayat tasbih, beliau bertasbih dan bila beliau membaca ayat yang memerintahkan untuk memohon, beliau memohon, dan bila beliau membaca ayat ta'awwudz (ayat yang memerintahkan untuk memohon perlindungan) beliau memohon perlindungan. Kemudian beliau ruku'. Dalam ruku', beliau membaca: \"SUBHAANA RABBIYAL 'AZHIIM (Maha Suci Tuhanku yang Maha Agung).\" Dan lama beliau ruku' hampir sama dengan berdirinya. Kemudian beliau membaca: \"SAMI'ALLAHU LIMAN HAMIDAH (Maha Mendengar Allah akan orang yang memuji-Nya).\" Kemudian beliau berdiri dan lamanya berdiri lebih kurang sama dengan lamanya ruku'. Sesudah itu beliau sujud, dan dalam sujud beliau membaca: \"SUBHAANA RABBIYAL A'LAA (Maha Suci Tuhanku Yang Maha Tinggi).\" Lama beliau sujud hampir sama dengan lamanya berdiri. Sementara di dalam hadits Jarir terdapat tambahan; Beliau membaca: \"SAMI'ALLAHU LIMAN HAMIDAH RABBANAA LAKAL HAMDU (Allah Maha Mendengar akan orang yang memuji-Nya, Ya Tuhan kami bagi-Mu segala puji).\""},{"p":"Muslim","n":1251,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ جَمِيعًا عَنْ حَفْصٍ قَالَ أَبُو بَكْرٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ الْقُرْآنَ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أَشْتَهِي أَنْ أَسْمَعَهُ مِنْ غَيْرِي فَقَرَأْتُ النِّسَاءَ حَتَّى إِذَا بَلَغْتُ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }رَفَعْتُ رَأْسِي أَوْ غَمَزَنِي رَجُلٌ إِلَى جَنْبِي فَرَفَعْتُ رَأْسِي فَرَأَيْتُ دُمُوعَهُ تَسِيلُحَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ وَمِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ جَمِيعًا عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ وَزَادَ هَنَّادٌ فِي رِوَايَتِهِ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ اقْرَأْ عَلَيَّ","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] semuanya dari [Hafsh] -[Abu Bakr]- berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al A'masy] dari [Ibrahim] dari [Abidah] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Bacakanlah Al Qur`an kepadaku.\" Abdullah berkata; saya bertanya, \"Wahai Rasulullah, apakah saya membacakannya kepada Anda, sementara Al Qur`an diturunkan kepada Anda?\" beliau bersabda: \"Saya suka untuk mendengarnya dari orang lain.\" Maka saya pun membaca surat An Nisa`, hingga (bacaanku) sampai pada ayat: \"Dan kami mendatangkan kamu (Muhammad) sebagai saksi atas mereka itu (sebagai umatmu).\" Aku mengangkat kepalaku -atau- seorang laki-laki datang ke sampingku, dan aku pun mengangkat kepala, maka aku melihat air mata beliau menetes. Telah menceritakan kepada kami [Hannad bin As Sariy] dan [Mindab bin Harits At Tamimi] semuanya dari [Ali bin Mushir] dari [Al A'masy] dengan isnad ini. Hannad menambahkan dalam riwayatnya; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku sementara beliau berada di atas mimbar: \"Bacakanlah (Al Qur`an) untukku.\""},{"p":"Muslim","n":1252,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنِي مِسْعَرٌ وَقَالَ أَبُو كُرَيْبٍ عَنْ مِسْعَرٍ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ إِبْرَاهِيمَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَبْدِ اللَّهِ بْنِ مَسْعُودٍ اقْرَأْ عَلَيَّ قَالَ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أُحِبُّ أَنْ أَسْمَعَهُ مِنْ غَيْرِي قَالَ فَقَرَأَ عَلَيْهِ مِنْ أَوَّلِ سُورَةِ النِّسَاءِ إِلَى قَوْلِهِ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }فَبَكَىقَالَ مِسْعَرٌ فَحَدَّثَنِي مَعْنٌ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَبِيهِ عَنْ ابْنِ مَسْعُودٍ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهِيدًا عَلَيْهِمْ مَا دُمْتُ فِيهِمْ أَوْ مَا كُنْتُ فِيهِمْ شَكَّ مِسْعَرٌ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata, telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepadaku [Mis'ar] - [Abu Kuraib] - berkata, dari [Mis'ari] dari [Amru bin Murrah] dari [Ibrahim] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda kepada [Abdullah bin Mas'ud]: \"Bacakanlah Al Qur`an kepadaku.\" Abdullah bertanya, \"Apakah saya akan membacakannya kepada Anda, sementara Al Qur`an diturunkan kepada Anda?\" beliau bersabda: \"Saya suka untuk mendengarnya dari orang lain.\" Maka Abdullah bin Mas'ud pun membaca ayat pertama surat An Nisa` hingga ayat: \"Maka bagaimanakah (halnya orang kafir nanti), apabila kami mendatangkan seseorang saksi (rasul) dari tiap-tiap umat dan kami mendatangkan kamu (Muhammad) sebagai saksi atas mereka itu (sebagai umatmu).\" Maka beliau pun menangis. [Mis'ar] berkata; telah menceritakan kepadaku [Ma'n] dari [Ja'far bin Amru bin Huraits] dari [bapaknya] dari [Ibnu Mas'ud] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda kepada: \"(Saya) menjadi saksi, selama aku hidup di tengah-tengah mereka. -atau- selama aku masih berada di tengah-tengah mereka.\" Mis'ar ragu (diantara dua pernyataan tersebut)."},{"p":"Muslim","n":2802,"ar":"حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدِ بْنِ بُكَيْرٍ النَّاقِدُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَمَرِضْتُ فَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ يَعُودَانِي مَاشِيَيْنِ فَأُغْمِيَ عَلَيَّ فَتَوَضَّأَ ثُمَّ صَبَّ عَلَيَّ مِنْ وَضُوئِهِ فَأَفَقْتُ قُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ أَقْضِي فِي مَالِي فَلَمْ يَرُدَّ عَلَيَّ شَيْئًا حَتَّى نَزَلَتْ آيَةُ الْمِيرَاثِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","trj":"Telah menceritakan kepada kami [Amru bin Muhammad bin Bukair An Naqid] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Muhammad bin Al Munkadir] dia mendengar [Jabir bin Abdullah] berkata, \"Saat aku sakit Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar menjengukku dengan berjalan kaki, dan saat itu aku sedang pingsan. Lalu beliau berwudlu dan memercikkan air wudlunya kepadaku sehingga aku pun sadar. Kemudian aku berkata, \"Wahai Rasulullah, bagaimana seharusnya saya mengatur hartaku?\" Sedikitpun beliau tidak menjawabnya, hingga turunlah ayat tentang waris: '(Mereka meminta fatwa kepadamu (wahai Muhammad) tentang kalalah (yaitu seseorang yang meninggal dunia tanpa meninggalkan ayah dan anak), katakanlah, Allah lah yang memberi fatwa kepadamu tentang kalalah…) ' (Qs. An Nisaa: 176)."},{"p":"Muslim","n":2803,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمِ بْنِ مَيْمُونٍ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَعَادَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ فِي بَنِي سَلِمَةَ يَمْشِيَانِ فَوَجَدَنِي لَا أَعْقِلُ فَدَعَا بِمَاءٍ فَتَوَضَّأَ ثُمَّ رَشَّ عَلَيَّ مِنْهُ فَأَفَقْتُ فَقُلْتُ كَيْفَ أَصْنَعُ فِي مَالِي يَا رَسُولَ اللَّهِ فَنَزَلَتْ{ يُوصِيكُمُ اللَّهُ فِي أَوْلَادِكُمْ لِلذَّكَرِ مِثْلُ حَظِّ الْأُنْثَيَيْنِ }","trj":"Telah menceritakan kepadaku [Muhammad bin Hatim bin Maimun] telah menceritakan kepada kami [Hajjaj bin Muhammad] telah menceritakan kepada kami [Ibnu Juraij] dia berkata, telah mengabarkan kepadaku [Ibnu Al Munkadir] dari [Jabir bin Abdullah] dia berkata, \"Saat aku sakit di kampung bani Salamah, Nabi shallallahu 'alaihi wasallam dan Abu Bakar menjengukku dengan berjalan kaki, dan beliau mendapatiku dalam keadaan pingsan. Kemudian beliau meminta air untuk berwudlu, lalu beliau memercikkannya kepadaku hingga aku pun tersadar. Aku lalu berkata, \"Bagaimana seharusnya saya mengatur hartaku wahai Rasulullah?\" maka turunlah ayat: '(Allah menetapkan bagimu tentang warisan untuk anak-anakmu, bagian satu anak laki-laki sama dengan bagian dua anak perempuan….) ' (Qs. An Nisaa; 11)."},{"p":"Muslim","n":2805,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُادَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَرِيضٌ لَا أَعْقِلُ فَتَوَضَّأَ فَصَبُّوا عَلَيَّ مِنْ وَضُوئِهِ فَعَقَلْتُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا يَرِثُنِي كَلَالَةٌ فَنَزَلَتْ آيَةُ الْمِيرَاثِفَقُلْتُ لِمُحَمَّدِ بْنِ الْمُنْكَدِرِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }قَالَ هَكَذَا أُنْزِلَتْ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ وَأَبُو عَامِرٍ الْعَقَدِيُّ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ كُلُّهُمْ عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ فِي حَدِيثِ وَهْبِ بْنِ جَرِيرٍ فَنَزَلَتْ آيَةُ الْفَرَائِضِ وَفِي حَدِيثِ النَّضْرِ وَالْعَقَدِيِّ فَنَزَلَتْ آيَةُ الْفَرْضِ وَلَيْسَ فِي رِوَايَةِ أَحَدٍ مِنْهُمْ قَوْلُ شُعْبَةَ لِابْنِ الْمُنْكَدِرِ","trj":"Telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Muhammad bin Al Munkadir] dia berkata, aku mendengar [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam menjengukku ketika aku sakit tak sadarkan diri, lalu beliau berwudlu dan memercikkan air wudlunya kepadaku, sehingga aku pun sadar. Kemudian aku berkata, \"Wahai Rasulullah, bagaimana aku mewariskan harta peninggalan? Maka turunlah ayat tentang warisan.\" Aku (Syu'bah) bertanya kepada [Muhammad bin Munkadir], \"Apakah (yang turun) YASTAFTUUNAKA QULILLAH YUFTIIKUM FIL KALAALAH (Mereka meminta fatwa kepadamu (tentang kalalah). Katakanlah: \"Allah memberi fatwa kepadamu tentang kalalah) '? (Qs. An Nisaa: 176). Dia menjawab, \"Seperti inilah ayat ini diturunkan.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [An Nadlr bin Syumail] dan [Abu Amir Al 'Aqadi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Mutsanna] telah menceritakan kepada kami [Wahb bin Jarir] semuanya dari [Syu'bah] dengan isnad ini dalam haditsnya Wahb bin Jarir, disebutkan, 'lalu turunkah ayat faraidl (pembagian harta warisan).' Sedangkan dalam hadits An Nadlr dan Al 'Aqadi, disebutkan, 'Lalu turunlah ayat fardl.' Dan dalam riwayat mereka berdua (tidak disebutkan) perkataan Syu'bah kepada Ibnu Munkadir.\""},{"p":"Muslim","n":2806,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَأَنَّ عُمَرَ بْنَ الْخَطَّابِ خَطَبَ يَوْمَ جُمُعَةٍ فَذَكَرَ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرَ أَبَا بَكْرٍ ثُمَّ قَالَ إِنِّي لَا أَدَعُ بَعْدِي شَيْئًا أَهَمَّ عِنْدِي مِنْ الْكَلَالَةِ مَا رَاجَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَيْءٍ مَا رَاجَعْتُهُ فِي الْكَلَالَةِ وَمَا أَغْلَظَ لِي فِي شَيْءٍ مَا أَغْلَظَ لِي فِيهِ حَتَّى طَعَنَ بِإِصْبَعِهِ فِي صَدْرِي وَقَالَ يَا عُمَرُ أَلَا تَكْفِيكَ آيَةُ الصَّيْفِ الَّتِي فِي آخِرِ سُورَةِ النِّسَاءِ وَإِنِّي إِنْ أَعِشْ أَقْضِ فِيهَا بِقَضِيَّةٍ يَقْضِي بِهَا مَنْ يَقْرَأُ الْقُرْآنَ وَمَنْ لَا يَقْرَأُ الْقُرْآنَو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ ح و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ رَافِعٍ عَنْ شَبَابَةَ بْنِ سَوَّارٍ عَنْ شُعْبَةَ كِلَاهُمَا عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ نَحْوَهُ","trj":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddami] dan [Muhammad bin Mutsanna] dan ini adalah lafadz Ibnu Mutsanna, keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Salim bin Abu Al Ja'd] dari [Ma'dan bin Abu Thalhah] bahwa [Umar bin Khatthab] berkhutbah pada hari Jum'at, kemudian dia menyanjung Nabi Allah shallallahu 'alaihi wasallam dan Abu Bakar, lalu dia berkata, \"Sesungguhnya saya tidak akan meninggalkan sesuatu yang menurutku lebih penting daripada kalalah. Saya tidak pernah mengulang-ulang konsultasi kepada Rasulullah shallallahu 'alaihi wasallam tentang sesuatu yang melebihi konsultasiku kepadanya tentang kalalah, beliau juga tidak pernah bersikap keras terhadap suatu hal melebihi sikap kerasnya kepadaku dalam masalah kalalah, sampai-sampai beliau menekankan jari-jarinya ke dadaku sambil bersabda: \"Wahai Umar, belum cukupkah bagimu ayat shaif yang terdapat pada akhir dari surat An Nisaa'? Seandainya saya masih hidup, maka saya akan menetapkan masalah kalalah dengan suatu ketetapan yang diputuskan oleh orang yang membaca Al Qur'an dan orang yang tidak membaca Al Qur'an.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Sa'id bin Abu 'Arubah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim] dan [Ibnu Rafi'] dari [Syababah bin Sawwar] dari [Syu'bah] keduanya dari [Qatadah] dengan isnad ini, seperti hadits tersebut.\" "},{"p":"Muslim","n":2807,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا وَكِيعٌ عَنْ ابْنِ أَبِي خَالِدٍ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَآخِرُ آيَةٍ أُنْزِلَتْ مِنْ الْقُرْآنِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","trj":"Telah menceritakan kepada kami [Ali bin Khasyram] telah mengabarkan kepada kami [Waki'] dari [Ibnu Abu Khalid] dari [Abu Ishaq] dari [Al Barra'] dia berkata, \"Ayat Al Qur'an yang terakhir diturunkan adalah 'YASTAFTUUNAKA QULILLAHU YUFTIIKUM FIL KALAALAH (Mereka meminta fatwa kepadamu (tentang kalalah). Katakanlah: \"Allah memberi fatwa kepadamu tentang kalalah…) ' (Qs. An Nisaa: 176)."},{"p":"Muslim","n":2810,"ar":"حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ أَبِي السَّفَرِ عَنْ الْبَرَاءِ قَالَآخِرُ آيَةٍ أُنْزِلَتْ يَسْتَفْتُونَكَ","trj":"Telah menceritakan kepada kami [Amru An Naqid] telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Malik bin Mighwal] dari [Abu Safar] dari [Barra'] dia berkata, \"Ayat yang terakhir kali turun adalah YASTAFTUUNAKA (surat An Nisaa).\""},{"p":"Muslim","n":3183,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَهَارُونُ بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا حَجَّاحُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍنَزَلَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنْكُمْ }فِي عَبْدِ اللَّهِ بْنِ حُذَافَةَ بْنِ قَيْسِ بْنِ عَدِيٍّ السَّهْمِيِّ بَعَثَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍأَخْبَرَنِيهِ يَعْلَى بْنُ مُسْلِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ","trj":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Harun bin Abdullah] keduanya berkata; telah menceritakan kepada kami [Hajjaj bin Muhahammad] dia berkata; [Ibnu Juraij] berkata (Ayat): '(Hai orang-orang yang beriman, ta'atilah Allah dan ta'atilah Rasul (Nya), dan ulil amri di antara kamu …) ' (Qs. An Nisaa': 59), turun berkenaan dengan Abdullah bin Hudzafah bin Qais bin 'Adiy As Sahmiy, ketika Nabi shallallahu 'alaihi wasallam mengutusnya dalam sebuah ekspedisi militer.\" [Ya'la bin Muslim] memberitahukan hadits ini kepadaku, dari [Sa'id bin Jubair] dari [Ibnu Abbas].\""},{"p":"Muslim","n":3196,"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ زُهَيْرٌ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ رَبِّ الْكَعْبَةِ قَالَ دَخَلْتُ الْمَسْجِدَ فَإِذَا عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ الْعَاصِ جَالِسٌ فِي ظِلِّ الْكَعْبَةِ وَالنَّاسُ مُجْتَمِعُونَ عَلَيْهِ فَأَتَيْتُهُمْ فَجَلَسْتُ إِلَيْهِ فَقَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَنَزَلْنَا مَنْزِلًا فَمِنَّا مَنْ يُصْلِحُ خِبَاءَهُ وَمِنَّا مَنْ يَنْتَضِلُ وَمِنَّا مَنْ هُوَ فِي جَشَرِهِ إِذْ نَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ جَامِعَةً فَاجْتَمَعْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ لَمْ يَكُنْ نَبِيٌّ قَبْلِي إِلَّا كَانَ حَقًّا عَلَيْهِ أَنْ يَدُلَّ أُمَّتَهُ عَلَى خَيْرِ مَا يَعْلَمُهُ لَهُمْ وَيُنْذِرَهُمْ شَرَّ مَا يَعْلَمُهُ لَهُمْ وَإِنَّ أُمَّتَكُمْ هَذِهِ جُعِلَ عَافِيَتُهَا فِي أَوَّلِهَا وَسَيُصِيبُ آخِرَهَا بَلَاءٌ وَأُمُورٌ تُنْكِرُونَهَا وَتَجِيءُ فِتْنَةٌ فَيُرَقِّقُ بَعْضُهَا بَعْضًا وَتَجِيءُ الْفِتْنَةُ فَيَقُولُ الْمُؤْمِنُ هَذِهِ مُهْلِكَتِي ثُمَّ تَنْكَشِفُ وَتَجِيءُ الْفِتْنَةُ فَيَقُولُ الْمُؤْمِنُ هَذِهِ هَذِهِ فَمَنْ أَحَبَّ أَنْ يُزَحْزَحَ عَنْ النَّارِ وَيُدْخَلَ الْجَنَّةَ فَلْتَأْتِهِ مَنِيَّتُهُ وَهُوَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَلْيَأْتِ إِلَى النَّاسِ الَّذِي يُحِبُّ أَنْ يُؤْتَى إِلَيْهِ وَمَنْ بَايَعَ إِمَامًا فَأَعْطَاهُ صَفْقَةَ يَدِهِ وَثَمَرَةَ قَلْبِهِ فَلْيُطِعْهُ إِنْ اسْتَطَاعَ فَإِنْ جَاءَ آخَرُ يُنَازِعُهُ فَاضْرِبُوا عُنُقَ الْآخَرِفَدَنَوْتُ مِنْهُ فَقُلْتُ لَهُ أَنْشُدُكَ اللَّهَ آنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَهْوَى إِلَى أُذُنَيْهِ وَقَلْبِهِ بِيَدَيْهِ وَقَالَ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي فَقُلْتُ لَهُ هَذَا ابْنُ عَمِّكَ مُعَاوِيَةُ يَأْمُرُنَا أَنْ نَأْكُلَ أَمْوَالَنَا بَيْنَنَا بِالْبَاطِلِ وَنَقْتُلَ أَنْفُسَنَا وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَأْكُلُوا أَمْوَالَكُمْ بَيْنَكُمْ بِالْبَاطِلِ إِلَّا أَنْ تَكُونَ تِجَارَةً عَنْ تَرَاضٍ مِنْكُمْ وَلَا تَقْتُلُوا أَنْفُسَكُمْ إِنَّ اللَّهَ كَانَ بِكُمْ رَحِيمًا }قَالَ فَسَكَتَ سَاعَةً ثُمَّ قَالَ أَطِعْهُ فِي طَاعَةِ اللَّهِ وَاعْصِهِ فِي مَعْصِيَةِ اللَّهِ و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالُوا حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ كِلَاهُمَا عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ نَحْوَهُ و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو الْمُنْذِرِ إِسْمَعِيلُ بْنُ عُمَرَ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي السَّفَرِ عَنْ عَامِرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ رَبِّ الْكَعْبَةِ الصَّائِدِيِّ قَالَ رَأَيْتُ جَمَاعَةً عِنْدَ الْكَعْبَةِ فَذَكَرَ نَحْوَ حَدِيثِ الْأَعْمَشِ","trj":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim], Ishaq berkata; telah mengabarkan kepada kami, sedangkan Zuhair berkata; telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Zaid bin Wahb] dari [Abdurrahman bin Abd Rabbil Ka'bah] dia berkata, \"Ketika saya masuk masjid, maka terlihat olehku [Abdullah bin 'Amru bin 'Ash] duduk di bawah naungan ka'bah di kelilingi orang banyak. Lalu aku datangi mereka dan duduk di dekat Abadullah. Dia berkata, \"Kami pernah mengadakan suatu perjalanan bersama Rasulullah shallallahu 'alaihi wasallam, lalu di suatu tempat pemberhentian kami berhenti. Sebagian kami ada yang memperbaiki tempat tidur, sebagian lagi berlatih memanah, sebagian lagi memberi makan hewan dan sebagainya. Tiba-tiba terdengar utusan Rasulullah shallallahu 'alaihi wasallam menyeru, memanggil kami untuk shalat berjama'ah, lalu kami berkumpul di dekat beliau. Beliau bersabda: \"Para Nabi sebelum saya diutus menuntun umatnya kepada kebaikan yang telah diajarkan Allah kepada mereka, dan memingatkan bahaya yang mengancam mereka. Ummatku yang sempurna dan selamat ialah angkatan yang pertama-tama, angkatan sesudah itu akan ditimpa berbagai cobaan berupa hal-hal yang tidak disenanginya, seperti timbulnya fitnah. Di mana-mana sebagian mereka menghina sebagian yang lain, oleh karena itu timbullah bencana. Orang-orang mukmin berkata, 'Inilah kiranya yang membinasakanku', Setelah hilang bencana tersebut, timbul pula bencana yang lain. Dan orang mukmin berkata, 'Ini..! Ini..!\" Siapa yang ingin bebas dari neraka dan ingin masuk ke surga, hendaklah dia menemui kematiannya dalam keimanan kepada Allah dan hari akhirat, dan hendaklah dia berjasa kepada ummat manusia sesuai dengan yang diinginkan oleh masyarakat itu. Siapa yang baik dengan seorang pemimpin (penguasa) lalu dia memenuhi bai'atnya dengan sepenuh hati, hendaklah dia mematuhi pemimpin itu semampunya. Jika yang lain datang memberontak, penggallah lehernya.\" Abdurrahman berkata, \"Aku lebih mendekat lagi kepada 'Amru, lalu saya berkata, \"Dengan nama Allah, saya bertanya kepada anda, 'Apakah kamu mendengar sendiri hadits ini dari Rasulullah shallallahu 'alaihi wasallam? ' dia menunjuk tangannya ke telinga dan hatinya seraya berkata, \"Saya mendengarnya dengan kedua telingaku dan kusimpan ke dalam hatiku.\" Lalu kukatakan kepadanya, \"Ini anak pamanmu, Mu'awiyah! Dia menyuruh kami memakan harta sesama dengan cara yang haram dan memerintahkan untuk saling membunuh sesama. Padahal Allah telah berfirman: '(Wahai orang-orang yang beriman, janganlah kamu memakan harta sesamamu dengan cara yang haram, kecuali berjual beli dengan cara suka sama suka sesamamu, dan janganlah kamu membunuh saudaramu (sesama muslim). Sesungguhnya Allah Maha penyayang kepadamu) ' (Qs. An Nisaa`: 29). 'Amru diam sebentar kemudian dia berkata, \"Patuhilah perintahnya bila sesuai dengan perintah Allah dan langgarlah perintahnya bila melanggar perintah Allah!\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ibnu Numair] serta [Abu Sa'id Al Asyaj] mereka berkata; telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah] keduanya dari [Al A'masy] dengan isnad seperti ini.\" Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu Al Mundzir Isma'il bin 'Umar] telah menceritakan kepada kami [Yunus bin Abu Ishaq Al Hamdani] telah menceritakan kepada kami [Abdullah bin Abu As Safar] dari ['Amir] dari [Abdurrahman bin Abd Rabbil Ka'bah Ash Sha`idi] dia berkata, \"Saya melihat sekelompok orang di sisi Ka'bah…kemudian dia menyebutkan seperti hadits Al A'masy.\""},{"p":"Muslim","n":3276,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ أَنَّهُ سَمِعَ الْبَرَاءَ يَقُولُا فِي هَذِهِ الْآيَةِ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا فَجَاءَ بِكَتِفٍ يَكْتُبُهَا فَشَكَا إِلَيْهِ ابْنُ أُمِّ مَكْتُومٍ ضَرَارَتَهُ فَنَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ غَيْرُ أُولِي الضَّرَرِ }قَالَ شُعْبَةُ وَأَخْبَرَنِي سَعْدُ بْنُ إِبْرَاهِيمَ عَنْ رَجُلٍ عَنْ زَيْدِ بْنِ ثَابِتٍ فِي هَذِهِ الْآيَةِ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }بِمِثْلِ حَدِيثِ الْبَرَاءِ و قَالَ ابْنُ بَشَّارٍ فِي رِوَايَتِهِ سَعْدُ بْنُ إِبْرَاهِيمَ عَنْ أَبِيهِ عَنْ رَجُلٍ عَنْ زَيْدِ بْنِ ثَابِتٍ","trj":"Telah menceritakan kepada kami [Muhammad bin Mutsanna] dan [Muhammad bin Basysyar] dan ini adalah lafadz Ibnu Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] bahwa dia pernah mendengar [Al Barra] berkomentar sehubungan dengan ayat ini: '(Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) dengan orang-orang yang berjihad di jalan Allah …) ' (Qs. An Nisaa: 95), dan orang-orang yang berjihad di jalan Allah, kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan Zaid bin Tsabit untuk menulis ayat tersebut. Lalu Zaid datang dengan membawa tulang (pundak) kambing untuk menulis ayat tersebut. Tiba-tiba datanglah Ibnu Ummi Maktum mengadukan kesulitannya, tidak dapat turut berperang karena buta. Kemudian turunlah ayat: '(Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) yang tidak mempunyai 'uzur dengan orang-orang yang berjihad di jalan Allah…) ' [Syu'bah] berkata; dan telah mengabarkan kepadaku [Sa'd bin Ibrahim] dari [seorang laki-laki] dari [Zaid bin Tsabit] berhubungan dengan ayat ini: '(Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) …) ' seperti hadits Al Barra.\" Dan [Ibnu Basysyar] menyebutkan dalam riwayatnya; [Sa'd bin Ibrahim] dari [ayahnya] dari [seorang laki-laki] dari [Zaid bin Tsabit].\""},{"p":"Muslim","n":3277,"ar":"و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ بِشْرٍ عَنْ مِسْعَرٍ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ الْبَرَاءِ قَالَلَمَّا نَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }كَلَّمَهُ ابْنُ أُمِّ مَكْتُومٍ فَنَزَلَتْ{ غَيْرُ أُولِي الضَّرَرِ }","trj":"Dan telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Ibnu Bisyr] dari [Mis'ar] telah menceritakan kepadaku [Abu Ishaq] dari [Al Barra] dia berkata, \"Tatkala turunnya ayat: '(Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) …' (Qs. An Nisaa: 95), lalu Ibnu Ummi Maktum protes, maka setelah itu turunlah: '(yang tidak mempunyai 'uzur).\""},{"p":"Muslim","n":4329,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبْي شَيْبَةَ كِلَاهُمَا عَنْ ابْنِ عُيَيْنَةَ وَاللَّفْظُ لِقُتَيْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ مُحَيْصِنٍ شَيْخٍ مِنْ قُرَيْشٍ سَمِعَ مُحَمَّدَ بْنَ قَيْسِ بْنِ مَخْرَمَةَ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا نَزَلَتْ{ مَنْ يَعْمَلْ سُوءًا يُجْزَ بِهِ }بَلَغَتْ مِنْ الْمُسْلِمِينَ مَبْلَغًا شَدِيدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَارِبُوا وَسَدِّدُوا فَفِي كُلِّ مَا يُصَابُ بِهِ الْمُسْلِمُ كَفَّارَةٌ حَتَّى النَّكْبَةِ يُنْكَبُهَا أَوْ الشَّوْكَةِ يُشَاكُهَاقَالَ مُسْلِم هُوَ عُمَرُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ مُحَيْصِنٍ مِنْ أَهْلِ مَكَّةَ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Abu Bakr bin Abu Syaibah] keduanya dari [Ibnu 'Uyainah] dan lafazh ini milik Qutaibah; Telah menceritakan kepada kami [Sufyan] dari [Ibnu Muhaishin] seorang syaikh dari bangsa Quraisy, dia mendengar [Muhammad bin Qais bin Makhramah] bercerita dari [Abu Hurairah] dia berkata; \"Tatkala telah turun ayat yang mengatakan: \"Ketika turun ayat Al Qur'an yang berbunyi Barang siapa berbuat kejelekan, niscaya ia akan dibalas dengan kejelekan (siksa) (Qs. An-Nisaa'(4): 123), maka kaum muslimin pun merasa prihatin. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: 'Janganlah kalian berlebihan, tempuhlah kejujuran dan perbaikilah dirimu. Sesungguhnya setiap musibah yang menimpa seorang muslim itu adalah sebagai penghapus dosa, termasuk pula jika ia terantuk batu ataupun tertusuk duri.' Muslim berkata; 'Dia adalah Umar bin Abdurrahman bin Muhshin dari penduduk Makkah."},{"p":"Muslim","n":4626,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَدِيٍّ وَهُوَ ابْنُ ثَابِتٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ يُحَدِّثُ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى أُحُدٍ فَرَجَعَ نَاسٌ مِمَّنْ كَانَ مَعَهُ فَكَانَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمْ فِرْقَتَيْنِ قَالَ بَعْضُهُمْ نَقْتُلُهُمْ وَقَالَ بَعْضُهُمْ لَا فَنَزَلَتْ{ فَمَا لَكُمْ فِي الْمُنَافِقِينَ فِئَتَيْنِ }و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ ح و حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ حَدَّثَنَا غُنْدَرٌ كِلَاهُمَا عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ نَحْوَهُ","trj":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] dia berkata; aku mendengar ['Abdullah bin Yazid] bercerita dari [Zaid bin Tsabit] bahwa ketika Nabi shallallahu 'alaihi wasallam berangkat ke medan perang Uhud, beberapa orang yang ikut berangkat bersama-sama beliau pulang kembali di tengah perjalanan. Karena itu, para sahabat Nabi shallallahu 'alaihi wasallam berbeda pendapat mengenai mereka menjadi dua golongan: Sebagian mengatakan mereka harus diperangi dan sebagian lagi mengatakan jangan diperangi. Karena itu, turunlah ayat: 'Mengapa kamu menjadi dua golongan dalam (menghadapi) orang-orang munafik…' (QS. An Nisaa (4): 88). Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Yahya bin Sa'id] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepadaku [Abu Bakr bin Nafi'] telah menceritakan kepada kami [Ghundar] keduanya dari [Syu'bah] melalui sanad ini dengan Hadits yang serupa."},{"p":"Nasa'i","n":1116,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَاسْتَفْتَحَ بِسُورَةِ الْبَقَرَةِ فَقَرَأَ بِمِائَةِ آيَةٍ لَمْ يَرْكَعْ فَمَضَى قُلْتُ يَخْتِمُهَا فِي الرَّكْعَتَيْنِ فَمَضَى قُلْتُ يَخْتِمُهَا ثُمَّ يَرْكَعُ فَمَضَى حَتَّى قَرَأَ سُورَةَ النِّسَاءِ ثُمَّ قَرَأَ سُورَةَ آلِ عِمْرَانَ ثُمَّ رَكَعَ نَحْوًا مِنْ قِيَامِهِ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ سُبْحَانَ رَبِّيَ الْعَظِيمِ سُبْحَانَ رَبِّيَ الْعَظِيمِ ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا لَكَ الْحَمْدُ وَأَطَالَ الْقِيَامَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ يَقُولُ فِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى سُبْحَانَ رَبِّيَ الْأَعْلَى سُبْحَانَ رَبِّيَ الْأَعْلَى لَا يَمُرُّ بِآيَةِ تَخْوِيفٍ أَوْ تَعْظِيمٍ لِلَّهِ عَزَّ وَجَلَّ إِلَّا ذَكَرَهُ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Jarir] dari [Al A'masy] dari [Sa'ad bin 'Ubaidah] dari [Al Mustaurid bin Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] dia berkata; \"Pada suatu malam aku mengerjakan shalat bersama Rasulullah Shallallahu'alaihiwasallam, beliau mulai dengan membaca surat Al Baqarah. Beliau telah membaca seratus ayat dan belum ruku lalu tetap membacanya.\" Hudzaifah berkata; \"Beliau menyelesaikannya pada dua rakaat, lantas berlalu.\" Hudzaifah berkata lagi; \"Beliau menyelesaikannya kemudian ruku' dan terus berlalu hinggga beliau membaca surat An-Nisaa', kemudian membaca surat Ali 'Imraan, lalu ruku' yang lamanya seperti berdiri. Saat ruku' beliau mengucapkan, 'Subhana rabbiyal 'adzimi, subhana rabbiyal 'adzimi, subhana rabbiyal 'adzimi (Maha suci Tuhan-ku yang Maha Agung) '. Lalu beliau mengangkat kepala sambil mengucapkan, 'Sami'allahu liman hamidah rabbana lakal hamdu (Allah Maha mendengar orang yang memuji-Nya, segala puji untuk-Mu) '. Beliau memperpanjang berdirinya kemudian sujud, dan beliau memperlama sujudnya sambil mengucapkan, 'Subhana rabbiyal a'laa, subhana rabbiyal a'laa, subhana rabbiyal a'laa (Maha Suci Tuhanku yang Maha Tinggi) '. Beliau Shallallahu'alaihiwasallam tidak melalui ayat ancaman atau pengagungan Allah Azza wa Jalla kecuali beliau Shallallahu'alaihiwasallam berdzikir kepada-Nya.\""},{"p":"Nasa'i","n":1378,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ يُحَدِّثُ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَّمَنَا خُطْبَةَ الْحَاجَةِ الْحَمْدُ لِلَّهِ نَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا وَسَيِّئَاتِ أَعْمَالِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَقْرَأُ ثَلَاثَ آيَاتٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَثَّ مِنْهُمَا رِجَالًا كَثِيرًا وَنِسَاءً وَاتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ وَالْأَرْحَامَ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا }قَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو عُبَيْدَةَ لَمْ يَسْمَعْ مِنْ أَبِيهِ شَيْئًا وَلَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَلَا عَبْدُ الْجَبَّارِ بْنُ وَائِلِ بْنِ حُجْرٍ","trj":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Abu Ishaq] menceritakan dari [Abu 'Ubaidah] dari ['Abdullah] dari Nabi Shalallahu 'Alaihi Wa Sallam. Abdullah berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam telah mengajarkan Khutbah Hajah kepada kami, yaitu, 'Segala puji bagi Allah, kita memohon pertolongan dan ampunan kepadanya, berlindung kepadanya dari kejahatan jiwa kami dan kejelekan perbuatan-perbuatan kami. Barang siapa yang diberikan petunjuk oleh Allah, maka tidak akan ada yang bisa menyesatkannya. Barangsiapa yang telah Allah sesatkan, maka tidak akan ada yang bisa memberinya petunjuk. Aku bersaksi tiada tuhan (yang berhak disembah) kecuali Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusannya'. Kemudian beliau membaca tiga ayat berikut ini: 'Wahai orang-orang yang beriman, bertakwalah kepada Allah dengan sebenar-benar takwa kepadanya, dan janganlah kamu mati melainkan dalam keadaan beragama Islam'. (Qs. Ali 'Imran (3): 102). 'Hai kalian manusia, bertakwalah kepada tuhanmu yang telah menciptakanmu dari diri yang satu, dan daripadanya Allah menciptakan istrinya, dan daripada keduanya Allah memperkembangbiakan laki-laki dan perempuan yang banyak, dan bertakwalah kepada Allah dengan (mempergunakan) nama-Nya kamu saling meminta satu dengan yang lain, dan (periharalah) hubungan Silaturrahim. Sesungguhnya Allah selalu menjaga dan mengawasimu'.\"(Qs. An-Nisaa'(4): 1). 'Hai orang-orang yang beriman, bertakwalah kepada Allah dan katakanlah perkataan yang benar'.\"(Qs. Al Ahzaab (33): 70). Abu Abdurrahman berkata; Abu Ubaidah tidak pernah mendengar dari Bapaknya sedikitpun, demikian juga Abdurrahman bin Abdullah bin Mas'ud dan Abdul Jabbar bin Wa'il bin Hujr. "},{"p":"Nasa'i","n":1407,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ ابْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَقُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَقْصُرُوا مِنْ الصَّلَاةِ إِنْ خِفْتُمْ أَنْ يَفْتِنَكُمْ الَّذِينَ كَفَرُوا }فَقَدْ أَمِنَ النَّاسُ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ عَجِبْتُ مِمَّا عَجِبْتَ مِنْهُ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ صَدَقَةٌ تَصَدَّقَ اللَّهُ بِهَا عَلَيْكُمْ فَاقْبَلُوا صَدَقَتَهُ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdullah bin Idris] dia berkata; telah memberitakan kepada kami [Ibnu Juraij] dari [Ibnu Abu 'Ammar] dari ['Abdullah bin Babaih] dari [Ya'la bin Umayyah] dia berkata;? ku pernah bertanya kepada ['Umar bin Al Khaththab] tentang ayat, 'Tidaklah apa-apa bagi kalian untuk mengqashar/meringkas shalat jika kalian takut (khawatir) diserang orang-orang kafir'. (Qs. An-Nisaa' (4): 101), bukankah sekarang manusia sudah merasa aman?!\" Lalu Umar menjawab, \"Aku juga heran seperti kamu, dan aku juga pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam seperti itu? Beliau menjawab: 'Itu sedekah yang Allah sedekahkan kepada kalian, maka terimalah sedekah-Nya'.\""},{"p":"Nasa'i","n":1614,"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَافْتَتَحَ الْبَقَرَةَ فَقُلْتُ يَرْكَعُ عِنْدَ الْمِائَةِ فَمَضَى فَقُلْتُ يَرْكَعُ عِنْدَ الْمِائَتَيْنِ فَمَضَى فَقُلْتُ يُصَلِّي بِهَا فِي رَكْعَةٍ فَمَضَى فَافْتَتَحَ النِّسَاءَ فَقَرَأَهَا ثُمَّ افْتَتَحَ آلَ عِمْرَانَ فَقَرَأَهَا يَقْرَأُ مُتَرَسِّلًا إِذَا مَرَّ بِآيَةٍ فِيهَا تَسْبِيحٌ سَبَّحَ وَإِذَا مَرَّ بِسُؤَالٍ سَأَلَ وَإِذَا مَرَّ بِتَعَوُّذٍ تَعَوَّذَ ثُمَّ رَكَعَ فَقَالَ سُبْحَانَ رَبِّيَ الْعَظِيمِ فَكَانَ رُكُوعُهُ نَحْوًا مِنْ قِيَامِهِ ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَكَانَ قِيَامُهُ قَرِيبًا مِنْ رُكُوعِهِ ثُمَّ سَجَدَ فَجَعَلَ يَقُولُ سُبْحَانَ رَبِّيَ الْأَعْلَى فَكَانَ سُجُودُهُ قَرِيبًا مِنْ رُكُوعِهِ","trj":"Telah mengabarkan kepada kami [Al Husain bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdullah bin Numair] dia berkata; telah menceritakan kepada kami [Al A'masy] dari [Sa'd bin 'Ubaidah] dari [Al Mustaurid bin Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] dia berkata; \"Aku pernah shalat dengan Rasulullah shallallahu 'alaihi wasallam pada suatu malam, beliau memulainya dengan membaca surah Al Baqarah. Lalu aku berkata dalam hatiku; -Mungkin- beliau akan ruku' pada ayat ke seratus. Namun beliau malah meneruskannya'. Aku berkata dalam hatiku, '-Mungkin- beliau akan ruku' saat dua ratus ayat, namun beliau malah meneruskannya'. Aku berkata dalam hatiku, 'Beliau shalat dengan surat Al Baqarah dalam satu rakaat. Kemudian beliau meneruskan (shalatnya), dan memulainya dengan membaca surah An Nisaa'. Beliau membacanya (hingga selesai), kemudian memulai lagi dengan surah Ali 'Imraan, dan beliau membacanya (hingga selesai) dengan perlahan-perlahan. Jika beliau menjumpai ayat tasbih maka beliau bertasbih (memuji Allah), jika beliau menjumpai ayat yang menganjurkan untuk meminta maka beliau pun meminta (kepada Allah), dan jika beliau menjumpai ayat yang berkenaan dengan memohon perlindungan maka beliau memohon perlindungan. Kemudian beliau ruku dengan membaca subhana rabbiyal 'azhimi (Maha Suci Tuhanku yang Maha Agung), yang (karenanya) ruku beliau sama dengan (lamanya) berdiri. Kemudian beliau mengangkat kepalanya, lalu mengucapkan Sami'allahu liman Hamidah (Allah Maha Mendengar orang yang memuji-Nya). Dan (lamanya) berdiri beliau sama dengan (lamanya) beliau ruku'. Kemudian beliau sujud dengan membaca subhana rabbiyal a'laa (Maha Suci Tuhanku Yang Maha Tinggi). Sujud beliau sama dengan (lamanya) ruku' beliau.\""},{"p":"Nasa'i","n":1677,"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي مِجْلَزٍ أَنَّ أَبَا مُوسَىكَانَ بَيْنَ مَكَّةَ وَالْمَدِينَةِ فَصَلَّى الْعِشَاءَ رَكْعَتَيْنِ ثُمَّ قَامَ فَصَلَّى رَكْعَةً أَوْتَرَ بِهَا فَقَرَأَ فِيهَا بِمِائَةِ آيَةٍ مِنْ النِّسَاءِ ثُمَّ قَالَ مَا أَلَوْتُ أَنْ أَضَعَ قَدَمَيَّ حَيْثُ وَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدَمَيْهِ وَأَنَا أَقْرَأُ بِمَا قَرَأَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepada kami [Abu An Nu'man] dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ashim Al Ahwal] dari [Abu Mijlaz] bahwasanya [Abu Musa] pernah berada di antara Makkah dan Madinah, dia shalat Isya' dua rakaat, kemudian berdiri, lalu shalat satu rakaat sebagai witir dengan membaca seratus ayat dari surah An-Nisaa'. Kemudian dia berkata: \"Aku tidak menyia-nyiakan untuk menapakkan telapak kakiku dimana Rasulullah shallallahu 'alaihi wasallam menapakkan telapak kakinya, dan aku membaca sebagaimana Rasulullah shallallahu 'alaihi wasallam membacanya.\""},{"p":"Nasa'i","n":3509,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ قَالَ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ عَطَاءٍ وَهُوَ ابْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَقْرَبُوا مَالَ الْيَتِيمِ إِلَّا بِالَّتِي هِيَ أَحْسَنُ }وَ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ اجْتَنَبَ النَّاسُ مَالَ الْيَتِيمِ وَطَعَامَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَشَكَوْا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَيَسْأَلُونَكَ عَنْ الْيَتَامَى قُلْ إِصْلَاحٌ لَهُمْ خَيْرٌ إِلَى قَوْلِهِ لَأَعْنَتَكُمْ }","trj":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] berkata; telah menceritakan kepada kami [Muhammad bin Ash Shalt] berkata; telah menceritakan kepada kami [Abu Kudainah] dari ['Atha] -yaitu Ibnu As Saib- dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Tatkala turun ayat: '(Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat) ' (Qs. Al Israa': 34), serta '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ibnu Abbas berkata, \"Maka orang-orang menjauhi harta anak yatim dan makanannya, sehingga hal tersebut terasa berat atas orang-orang muslim. Maka mereka mengadukan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, kemudian Allah menurunkan ayat: '(Dan mereka bertanya kepadamu tentang anak yatim, katakalah: \"Mengurus urusan mereka secara patut adalah baik, dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu; dan Allah mengetahui siapa yang membuat kerusakan dari yang mengadakan perbaikan. Dan jikalau Allah menghendaki, niscaya Dia dapat mendatangkan kesulitan kepadamu) ' (Qs. Al Baqarah: 220)."},{"p":"Nasa'i","n":3510,"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عِمْرَانُ بْنُ عُيَيْنَةَ قَالَ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ كَانَ يَكُونُ فِي حَجْرِ الرَّجُلِ الْيَتِيمُ فَيَعْزِلُ لَهُ طَعَامَهُ وَشَرَابَهُ وَآنِيَتَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَإِنْ تُخَالِطُوهُمْ فَإِخْوَانُكُمْ }فِي الدِّينِ فَأَحَلَّ لَهُمْ خُلْطَتَهُمْ","trj":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Imran bin 'Uyainah] berkata; telah menceritakan kepada kami ['Atha bin As Saib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] mengenaii firman Allah: '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ia berkata, \"Dahulu terdapat seorang anak yatim dalam pemeliharaan seorang laki-laki, kemudian laki-laki tersebut menjauhi makanan serta minuman dan bejananya, sehingga hal tersebut terasa berat bagi orang-orang muslim. Kemudian Allah 'azza wajalla menurunkan ayat: '(dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu) ' (Qs. Al Baqarah: 220), yaitu seagama, maka Allah pun menghalalkan bagi mereka untuk bergaul dengan mereka.\""},{"p":"Nasa'i","n":5051,"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى وَالْحَارِثُ بْنُ مِسْكِينٍ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ وَاللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُ عَنْ الزُّبَيْرِ بْنِ الْعَوَّامِأَنَّهُ خَاصَمَ رَجُلًا مِنْ الْأَنْصَارِ قَدْ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِرَاجِ الْحَرَّةِ كَانَا يَسْقِيَانِ بِهِ كِلَاهُمَا النَّخْلَ فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ عَلَيْهِ فَأَبَى عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ وَقَالَ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا زُبَيْرُ اسْقِ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِ فَاسْتَوْفَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ حَقَّهُ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ ذَلِكَ أَشَارَ عَلَى الزُّبَيْرِ بِرَأْيٍ فِيهِ السَّعَةُ لَهُ وَلِلْأَنْصَارِيِّ فَلَمَّا أَحْفَظَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَنْصَارِيُّ اسْتَوْفَى لِلزُّبَيْرِ حَقَّهُ فِي صَرِيحِ الْحُكْمِقَالَ الزُّبَيْرُ لَا أَحْسَبُ هَذِهِ الْآيَةَ أُنْزِلَتْ إِلَّا فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }وَأَحَدُهُمَا يَزِيدُ عَلَى صَاحِبِهِ فِي الْقِصَّةِ","trj":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] dan [Al Harits bin Miskin] dari [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Yunus bin Yazid] dan [Al Laits bin Sa'd] dari [Ibnu Syihab] bahwa ['Urwah Ibnu Az Zubair] menceritakan kepadanya, bahwa [Abdullah bin Az Zubair] menceritakan kepadanya, bahwa [Az Zubair bin 'Awwam] pernah berselisih dengan seorang laki-laki Anshar yang pernah ikut perang badar bersama Rasulullah shallallahu 'alaihi wasallam dalam masalah mata air harrah yang biasa mereka gunakan untuk mengairi kebun kurma mereka. Laki-laki Anshar itu berkata; \"Biarkanlah air itu mengalir.\" Namun Az Zubair menolaknya. Rasulullah shallallahu 'alaihi wasallam kemudian berkata kepada Az Zubair: \"Wahai Zubair, airilah kebunmu. Setelah itu berikanlah kepada tetanggamu.\" Orang Anshar itu marah dan berkata; \"Wahai Rasulullah, apakah karena ia anak pamanmu?\" maka menjadi merahlah wajah Rasulullah shallallahu 'alaihi wasallam, beliau kemudian bersabda: \"Wahai Zubair, airilah kebunmu. Setelah itu tahanlah airnya hingga ia kembali ke dalam tanah.\" Lantas Rasulullah shallallahu 'alaihi wasallam memenuhi haknya Zubair. Padahal sebelum itu, Rasulullah shallallahu 'alaihi wasallam memberi isyarat kepada Zubair untuk berlaku fleksibel baik untuknya maupun untuk laki-laki Anshar itu. Ketika laki-laki Anshar itu marah kepada Rasulullah shallallahu 'alaihi wasallam, beliau hanya memenuhi haknya Zubair dalam putusannya.\" Az Zubair berkata; \"Aku tidak berpendapat kecuali ayat ini hanya turun berkenaan dengan kasus itu: ' Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan.\" QS An Nisa`; 65"},{"p":"Nasa'i","n":5060,"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّهُ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُأَنَّ رَجُلَا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا النَّخْلَ فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ فَأَبَى عَلَيْهِ فَاخْتَصَمُوا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ فَقَالَ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا زُبَيْرُ اسْقِ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِقَالَ الزُّبَيْرُ إِنِّي أَحْسَبُ أَنَّ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ }الْآيَةَ","trj":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] Bahwasanya ia menceritakan kepadanya, bahwa [Abdullah bin Az Zubair] menceritakan kepadanya, bahwa ada seorang laki-laki Anshar yang berselisih dengan Az Zubair mengadu kepada Rasulullah shallallahu 'alaihi wasallam, yakni dalam masalah mata air Al Harrah yang biasa mereka gunakan untuk mengairi pohon kurma. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Wahai Zubair, airilah (kebun milikmu), setelah itu alirkanlah air itu untuk tetanggamu.\" Laki-laki Anshar itu pun marah, ia lalu berkata, \"Wahai Rasulullah, apakah karena ia anak pamanmu!\" Maka menjadi merahlah wajah Rasulullah shallallahu 'alaihi wasallam, beliau kemudian bersabda: \"Wahai Zubair, airilah (kebunmu), setelah itu tahanlah hingga airnya kembali ke dalam tanah.\" Az Zubair berkata, \"Aku kira ayat ini turun berkenaan dengan peristiwa itu: ' Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman.\" QS An Nisa`; 65."},{"p":"Nasa'i","n":5180,"ar":"أَخْبَرَنَا أَبُو بَكْرٍ أَحْمَدُ بْنُ مُحَمَّدِ بْنِ إِسْحَقَ السُّنِّيُّ قِرَاءَةً عَلَيْهِ فِي بَيْتِهِ قَالَ أَنْبَأَنَا الْإِمَامُ أَبُو عَبْدِ الرَّحْمَنِ أَحْمَدُ بْنُ شُعَيْبٍ النَّسَائِيُّ رَحِمَهُ اللَّهُ تَعَالَى قَالَ أَنْبَأَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ أَنْبَأَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ قَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شَافِيًا فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْبَقَرَةِ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شَافِيًا فَنَزَلَتْ الْآيَةُ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَكَانَ مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَقَامَ الصَّلَاةَ نَادَى لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شَافِيًا فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْمَائِدَةِ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَلَمَّا بَلَغَ فَهَلْ أَنْتُمْ مُنْتَهُونَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ انْتَهَيْنَا انْتَهَيْنَا","trj":"Telah mengabarkan kepada kami Abu Bakr Ahmad bin Muhammad bin Ishaq As Sunni -dengan membaca dihadapannya di rumah miliknya- ia berkata; telah memberitakan kepada kami Imam Abu Abdurrahman Ahmad bin Syu'aib An Nasa`i rahimahullahu Ta'ala, ia berkata; telah memberitakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Ubaidullah bin Musa] ia berkata; telah memberitakan kepada kami [Isra'il] dari [Abu Ishaq] dari [Abu Maisarah] dari [Umar radliallahu 'anhu] ia berkata; \"Ketika turun ayat yang mengharamkan khamer, Umar berdoa; \"Ya Allah, berilah penjelasan kepada kami tentang khamer dengan penjelasan yang memadahi!\" Maka turunlah ayat yang terdapat dalam surat Al Baqarah. Lalu Umar dipanggil dan ayat tersebut dibacakan kepadanya. Umar lalu berdoa lagi; \"Ya Allah, berilah penjelasan kepada kami tentang khamer dengan penjelasan yang memadahi!\" Maka turunlah ayat yang terdapat dalam surat An Nisa`: 'Hai orang-orang yang beriman, janganlah kamu shalat sedang kamu dalam keadaan mabuk…'. Jika waktu shalat tiba, penyeru Rasulullah shallallahu 'alaihi wasallam biasa menyerukan 'Janganlah kamu shalat, sedangkan kami dalam keadaan mabuk'. Lalu Umar dipanggil dan ayat tersebut dibacakan kepadanya. Setelah itu Umar berdoa lagi; \"Ya Allah, berilah penjelasan kepada kami tentang khamer dengan penjelasan yang memadahi!\" Maka turunlah ayat yang terdapat dalam surat Al Maidah. Umar pun dipanggil dan ayat tersebut dibacakan kepadanya, ketika sampai, Maka berhentilah kamu (dari mengerjakan pekerjaan itu, Lantas Umar radliallahu 'anhu berkata; \"Kami berhenti, kami berhenti!.\""},{"p":"Tirmidzi","n":514,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّاسِ فَأَطَالَ الْقِرَاءَةَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ رَأْسَهُ فَأَطَالَ الْقِرَاءَةَ هِيَ دُونَ الْأُولَى ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الْأَوَّلِ ثُمَّ رَفَعَ رَأْسَهُ فَسَجَدَ ثُمَّ فَعَلَ مِثْلَ ذَلِكَ فِي الرَّكْعَةِ الثَّانِيَةِقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَبِهَذَا الْحَدِيثِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ يَرَوْنَ صَلَاةَ الْكُسُوفِ أَرْبَعَ رَكَعَاتٍ فِي أَرْبَعِ سَجَدَاتٍ قَالَ الشَّافِعِيُّ يَقْرَأُ فِي الرَّكْعَةِ الْأُولَى بِأُمِّ الْقُرْآنِ وَنَحْوًا مِنْ سُورَةِ الْبَقَرَةِ سِرًّا إِنْ كَانَ بِالنَّهَارِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ رَأْسَهُ بِتَكْبِيرٍ وَثَبَتَ قَائِمًا كَمَا هُوَ وَقَرَأَ أَيْضًا بِأُمِّ الْقُرْآنِ وَنَحْوًا مِنْ آلِ عِمْرَانَ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ رَأْسَهُ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ سَجَدَ سَجْدَتَيْنِ تَامَّتَيْنِ وَيُقِيمُ فِي كُلِّ سَجْدَةٍ نَحْوًا مِمَّا أَقَامَ فِي رُكُوعِهِ ثُمَّ قَامَ فَقَرَأَ بِأُمِّ الْقُرْآنِ وَنَحْوًا مِنْ سُورَةِ النِّسَاءِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ رَأْسَهُ بِتَكْبِيرٍ وَثَبَتَ قَائِمًا ثُمَّ قَرَأَ نَحْوًا مِنْ سُورَةِ الْمَائِدَةِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ تَشَهَّدَ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu As Syawarib] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] bahwa dia berkata, telah terjadi gerhana pada masa Rasulullah shallallahu 'alaihi wasallam, kemudian Rasulullah shallallahu 'alaihi wasallam shalat bersama manusia dengan memanjangkan bacaan shalat, beliau kemudian ruku' dan memanjangkan ruku'nya, lalu beliau mengangkat kepala dan memanjangkan bacaan shalat, namun tidak seperti (lebih singkat) dari yang pertama. Kemudian beliau ruku' dan memanjangkan ruku'nya namun tidak seperti yang pertama. Kemudian beliau mengangkat kepala lalu sujud, kemudian beliau melakukan seperti itu diraka'at kedua. Abu Isa berkata, ini adalah hadits hasan shahih, dengan hadits ini pula Syafi'i, Ahamad dan Ishaq berpendapat bahwa shalat gerhana itu empat kali ruku' dan empat kali sujud. Syafi'i berkata, pada raka'at pertama membaca surat Al Fatehah dan surat yang sepadan dengan surat Al Baqarah. Beliau membaca dengan suara pelan jika di siang hari (gerhana matahari), kemudian ruku' yang panjang seperti membaca bacaan, kemudian mengangkat kepala dengan mengucapkan takbir dan berdiri sebagaimana mestinya, kemudian membaca surat Al Fatihah lagi dan membaca surat yang sepadan dengan surat Ali Imran, lalu memanjangkan ruku'nya seperti ketika membaca bacaan. Kemudian mengangat kepala, lantas membaca sami'allahu liman hamidah, kemudian sujud dua kali dengan sempurna. Setiap sujud beliau berhenti sebagaimana berhenti ketika ruku', kemudian berdiri sambil membaca Al Fatehah dan surat yang sepadan dengan surat An Nisaa', kemudian memanjangan ruku' seperti membaca bacaan. Kemudian mengangkat kepala dengan mengucapkan takbir, lantas berdiri dengan membaca bacaan yang sepadan dengan surat Al Maidah, kemudian memanjangkan ruku'nya seperti ketika membaca bacaan. Kemudian mengangkat kepala dan membaca sami'allahu liman hamidah, kemudian sujud dua kali lalu membaca tahiyyat dan salam."},{"p":"Tirmidzi","n":1593,"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ائْتُونِي بِالْكَتِفِ أَوْ اللَّوْحِ فَكَتَبَ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }وَعَمْرُو بْنُ أُمِّ مَكْتُومٍ خَلْفَ ظَهْرِهِ فَقَالَ هَلْ لِي مِنْ رُخْصَةٍ فَنَزَلَتْ{ غَيْرُ أُولِي الضَّرَرِ }وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَجَابِرٍ وَزَيْدِ بْنِ ثَابِتٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي إِسْحَقَ وَقَدْ رَوَى شُعْبَةُ وَالثَّوْرِيُّ عَنْ أَبِي إِسْحَقَ هَذَا الْحَدِيثَ","trj":"Telah menceritakan kepada kami [Nashr bin Ali Al jahdhami] berkata, telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Bapaknya] dari [Abu Ishaq] dari [Al Barra` bin Azib] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berikan aku lembaran itu.\" Beliau kemudian menulis '(Tidaklah sama antara mu'min yang duduk (yang tidak ikut berperang)) ' -Qs. An Nisa: 95-, sementara Amru bin Ummi Maktum berada di belakang beliau. Amru berkata, \"Apakah ada keringanan untukku?\" lalu turunlah ayat: '(selain orang yang mempunyai 'uzur) ' -Qs. An Nisa: 95-Dalam bab ini juga ada hadits dari Ibnu Abbas, Jabir dan Zaid bin Tsabit. Hadits ini derajatnya hasan shahih, tetapi hadits ini termasuk hadits gharib riwayat Sulaiman At Taimi dari Abu Ishaq. [Syu'bah] dan [Ats Tsauri] juga meriwayatkan hadits ini dari [Abu Ishaq].\""},{"p":"Tirmidzi","n":1595,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ حَدَّثَنَا الْحَجَّاجُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ جُرَيْجٍفِي قَوْلِهِ{ أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنْكُمْ }قَالَ عَبْدُ اللَّهِ بْنُ حُذَافَةَ بْنِ قَيْسِ بْنِ عَدِيٍّ السَّهْمِيُّ بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى سَرِيَّةٍأَخْبَرَنِيهِ يَعْلَى بْنُ مُسْلِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ ابْنِ جُرَيْجٍ","trj":"Telah menceritakan kepada kami [Muhammad bin Yahya An Naisaburi] berkata, telah menceritakan kepada kami [Al Hajjaj bin Muhammad] berkata, telah menceritakan kepada kami [Ibnu Juraij] berkata, \"Firman Allah: '(ta'atilah Allah dan ta'atilah Rasul (Nya), dan ulil amri (pemimpin) di antara kamu) ' -Qs. An Nisa: 59- Abdullah bin Hudzafah bin Qais bin Adi As Sahmi diutus oleh Rasulullah shallallahu 'alaihi wasallam dalam sebuah ekspedisi, [Ya'la bin Muslim] mengabarkannya kepadaku dari [Sa'id bin Jubair], dari [Ibnu Abbas].\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih gharib, dan kami tidak mengetahuinya kecuali dari hadits Ibnu Juraij.\""},{"p":"Tirmidzi","n":2020,"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ أَنَّهُ قَالَإِنَّكُمْ تَقْرَءُونَ هَذِهِ الْآيَةَ{ مِنْ بَعْدِ وَصِيَّةٍ تُوصُونَ بِهَا أَوْ دَيْنٍ }وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالدَّيْنِ قَبْلَ الْوَصِيَّةِ وَإِنَّ أَعْيَانَ بَنِي الْأُمِّ يَتَوَارَثُونَ دُونَ بَنِي الْعَلَّاتِ الرَّجُلُ يَرِثُ أَخَاهُ لِأَبِيهِ وَأُمِّهِ دُونَ أَخِيهِ لِأَبِيهِحَدَّثَنَا بُنْدَارٌ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا زَكَرِيَّا بْنُ أَبِي زَائِدَةَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","trj":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami [Yazid bin Harun]; telah mengabarkan kepada kami [Sufyan] dari [Abu Ishaq] dari [Al Harits] dari ['Ali] bahwasanya dia berkata; Sesungguhnya kalian telah sering membaca ayat ini, \"MIM BA'DI WASHIYYATIN TUUSHUUNA BIHAA AUW DA`IN.\" setelah (dipenuhi) wasiat yang mereka buat atau (dan setelah dbayar) utangnya) (QS. An Nisaa`: 12) Dan sesungguhnya Rasulullah shallallahu 'alaihi wasallam lebih dahulu mengedepankan pembayaran hutang sebelum wasiat. Sesungguhnya saudara-saudara kandung saling mewarisi lain halnya dengan saudara-saudara yang tidak sekandung. Seorang laki-laki mewarisi saudaranya sebapak dan seibuknya, namun saudaranya sebapak tidak demikian. Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami [Yazid bin Harun]; telah mengabarkan kepada kami [Zakariya bin Abu Zaidah] dari [Abu Ishaq] dari [Al Harits] dari ['Ali] dari Nabi shallallahu 'alaihi wasallam sepertinya."},{"p":"Tirmidzi","n":2043,"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا الْأَشْعَثُ بْنُ جَابِرٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ حَدَّثَهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الرَّجُلَ لَيَعْمَلُ وَالْمَرْأَةُ بِطَاعَةِ اللَّهِ سِتِّينَ سَنَةً ثُمَّ يَحْضُرُهُمَا الْمَوْتُ فَيُضَارَّانِ فِي الْوَصِيَّةِ فَتَجِبُ لَهُمَا النَّارُ ثُمَّ قَرَأَ عَلَيَّ أَبُو هُرَيْرَةَ{ مِنْ بَعْدِ وَصِيَّةٍ يُوصَى بِهَا أَوْ دَيْنٍ غَيْرَ مُضَارٍّ وَصِيَّةً مِنْ اللَّهِ إِلَى قَوْلِهِ ذَلِكَ الْفَوْزُ الْعَظِيمُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَنَصْرُ بْنُ عَلِيٍّ الَّذِي رَوَى عَنْ الْأَشْعَثِ بْنِ جَابِرٍ هُوَ جَدُّ نَصْرِ بْنِ عَلِيٍّ الْجَهْضَمِيِّ","trj":"Telah menceritakan kepada kami [Nashr bin 'Ali Al Jahdhami]; telah menceritakan kepada kami ['Abdush Shamad bin 'Abdul Warits]; telah menceritakan kepada kami [Nashr bin 'Ali]; telah menceritakan kepada kami [Al Asy'ats bin Jabir] dari [Syahr bin Hausyab] dari [Abu Hurairah] bahwasanya dia menceritakan kepadanya dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang lelaki dan perempuan bisa jadi beramal ketaatan kepada Allah selama enam puluh tahun, kemudian ketika tiba ajal keduanya melakukan sesuatu yang membahayakan bagi ahli waritsnya, sehingga mengharuskan keduanya masuk ke dalam neraka.\" Kemudian Abu Hurairah membacakan ayat kepadaku: \"MIM BA'DI WASIYYATIY YUUSHAA BIHAA AU DAININ GHAIRA MUDLAARRIW WASIYYATAM MINALLAAH (sesudah dipenuhi wasiat yang dibuat olehnya atau sesudah dibayar hutangnya dengan tidak memberi mudharat kepada ahli waris. (Allah menetapkan yang demikian itu sebagai) syari`at yang benar-benar dari Allah).\" (QS An Nisa': 12) sampai firman Allah, \"DZALIKAL FAUZUL 'ADZIIM (dan itulah kemenangan yang besar).\" (QS An Nisa': 13) Abu Isa berkata; Hadits ini adalah hasan shahih gharib, adapun Nashr bin Ali yang meriwayatkan dari Ats'ats bin Jabir dia adalah kakeknya Nahsr bin Ali Al Jahdlami."},{"p":"Tirmidzi","n":2830,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَال سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُمَرِضْتُ فَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي وَقَدْ أُغْمِيَ عَلَيَّ فَلَمَّا أَفَقْتُ قُلْتُ كَيْفَ أَقْضِي فِي مَالِي فَسَكَتَ عَنِّي حَتَّى نَزَلَتْ{ يُوصِيكُمُ اللَّهُ فِي أَوْلَادِكُمْ لِلذَّكَرِ مِثْلُ حَظِّ الْأُنْثَيَيْنِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ حَدَّثَنَا الْفَضْلُ بْنُ الصَّبَّاحِ الْبَغْدَادِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَفِي حَدِيثِ الْفَضْلِ بْنِ الصَّبَّاحِ كَلَامٌ أَكْثَرُ مِنْ هَذَا","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Muhammad bin Al Munkadir] ia berkata; Aku mendengar [Jabir bin Abdullah] berkata; \"Rasulullah shallallahu 'alaihi wasallam datang menjengukku ketika aku sakit dan jatuh pingsan. Setelah siuman, aku bertanya; \"Bagaimana aku akan menunaikan semua hartaku?\" beliau terdiam, akhirnya turunlah ayat: Allah mensyari'atkan bagimu tentang (pembagian pusaka untuk) anak-anakmu. Yaitu, bagian seorang anak lelaki sama dengan bagian dua orang anak perempuan. QS An-Nisa`: 11. Abu Isa mengatakan bahwa hadits ini hasan shahih. Dan telah meriwayatkan lebih dari satu orang dari Muhammad bin Al Munkadir, telah menceritakan kepada kami [Al Fadlal bin Ash Shabbah] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Munkadir] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam seperti itu, dan di dalam hadits Al Fadlal bin Ash Shabbah perkataannya lebih banyak dari ini."},{"p":"Tirmidzi","n":2831,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ عَنْ أَبِي الْخَلِيلِ عَنْ أَبِي عَلْقَمَةَ الْهَاشِمِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَلَمَّا كَانَ يَوْمُ أَوْطَاسٍ أَصَبْنَا نِسَاءً لَهُنَّ أَزْوَاجٌ فِي الْمُشْرِكِينَ فَكَرِهَهُنَّ رِجَالٌ مِنَّا فَأَنْزَلَ اللَّهُ{ وَالْمُحْصَنَاتُ مِنْ النِّسَاءِ إِلَّا مَا مَلَكَتْ أَيْمَانُكُمْ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Habban bin HIilal] telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dari [Abu Al Khalil] dari [Abu 'Alqamah Al Hasyimi] dari [Abu Sa'id Al Khudri] ia berkata; \"Ketika terjadi perang Authas, kami menggauli para wanita (tawanan) yang memiliki suami kaum musyrikin, maka sebagian orang diantara kami membenci mereka. Lalu Allah menurunkan ayat: Dan (diharamkan juga kamu mengawini) wanita yang bersuami, kecuali budak-budak yang kamu miliki. QS An-Nisa`: 24. Abu Isa mengatakan bahwa hadits ini hasan shahih."},{"p":"Tirmidzi","n":2835,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أُمِّ سَلَمَةَ أَنَّهَا قَالَتْيَغْزُو الرِّجَالُ وَلَا تَغْزُو النِّسَاءُ وَإِنَّمَا لَنَا نِصْفُ الْمِيرَاثِ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ وَلَا تَتَمَنَّوْا مَا فَضَّلَ اللَّهُ بِهِ بَعْضَكُمْ عَلَى بَعْضٍ }قَالَ مُجَاهِدٌ وَأَنْزَلَ فِيهَا{ إِنَّ الْمُسْلِمِينَ وَالْمُسْلِمَاتِ }وَكَانَتْ أُمُّ سَلَمَةَ أَوَّلَ ظَعِينَةٍ قَدِمَتْ الْمَدِينَةَ مُهَاجِرَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ مُرْسَلٌ وَرَوَاهُ بَعْضُهُمْ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ مُرْسَلٌ أَنَّ أُمَّ سَلَمَةَ قَالَتْ كَذَا وَكَذَا","trj":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] dari [Ummu Salamah] ia berkata; \"Laki-laki pergi berperang, sedangkan wanita tidak berperang, dan (bagian) kami hanya setengah dari harta warisan.\" lalu Allah menurunkan Dan janganlah kamu iri hati terhadap apa yang dikaruniakan Allah kepada sebahagian kamu lebih banyak dari sebahagian yang lain QS An-Nisa`: 32, Mujahid mengatakan; Berkenaan dengan hal itu, ayat berikut turun Sesungguhnya laki-laki dan perempuan yang muslim, laki-laki dan perempuan yang mu'min. QS An-Nisa`: 35, Ummu Salamah adalah seorang wanita pertama kali ikut berhijrah ke Madinah. Abu Isa mengatakan bahwa hadits ini mursal."},{"p":"Tirmidzi","n":2837,"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ فَقُلْتُ يَا رَسُولَ اللَّهِ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أُحِبُّ أَنْ أَسْمَعَهُ مِنْ غَيْرِي فَقَرَأْتُ سُورَةَ النِّسَاءِ حَتَّى إِذَا بَلَغْتُ{ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }قَالَ فَرَأَيْتُ عَيْنَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَهْمِلَانِقَالَ أَبُو عِيسَى هَذَا أَصَحُّ مِنْ حَدِيثِ أَبِي الْأَحْوَصِ حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ نَحْوَ حَدِيثِ مُعَاوِيَةَ بْنِ هِشَامٍ","trj":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah menceritakan kepada kami [Sufyan Ats Tsauri] dari [Al A'masy] dari [Ibrahim] dari ['Abidah] dari [Abdullah] ia berkata; Rasulullah Shallallahu 'alahi wasallam bersabda kepadaku: \"Bacalah (al Qur'an) untukku.\" Aku menjawab; \"Wahai Rasulullah, haruskah aku membacanya, sementara (Al Qur'an) diturunkan kepadamu?\" beliau bersabda: \"Aku lebih senang mendengarnya dari orang lain.\" lalu kubaca surat an Nisa`, ketika sampai pada ayat Dan Kami mendatangkan kamu (Muhammad) sebagai saksi atas mereka itu (sebagai umatmu). QS An-Nisa`: 41, kulihat kedua matanya berlinang air mata.\" Abu Isa berkata; Hadits ini lebih shahih dari hadits Al Ahwash. Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengabarkan kepada kami [Ibnu Al Mubarak] dari [Sufyan] dari [Al A'masy] seperti hadits Mu'awiyah bin Hisyam."},{"p":"Tirmidzi","n":2838,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدٍ عَنْ أَبِي جَعْفَرٍ الرَّازِيِّ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَصَنَعَ لَنَا عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ طَعَامًا فَدَعَانَا وَسَقَانَا مِنْ الْخَمْرِ فَأَخَذَتْ الْخَمْرُ مِنَّا وَحَضَرَتْ الصَّلَاةُ فَقَدَّمُونِي فَقَرَأْتُ قُلْ يَا أَيُّهَا الْكَافِرُونَ لَا أَعْبُدُ مَا تَعْبُدُونَ وَنَحْنُ نَعْبُدُ مَا تَعْبُدُونَ قَالَ فَأَنْزَلَ اللَّهُ تَعَالَى{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى حَتَّى تَعْلَمُوا مَا تَقُولُونَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Abdurahman bin Sa'd] dari [Abu Ja'far Ar Razi] dari [Atha` bin As Sa`ib] dari [Abu Abdurrahman As Sulami] dari [Ali bin Abu Thalib] ia berkata; \"Abdurrahman bin 'Auf pernah membuatkan makanan dan menyajikan khamr untuk kami, sampai kami (mabuk) karenanya. Ketika waktu shalat telah tiba, mereka mendorongku (menjadi imam), kemudian aku membaca; Katakanlah (Muhammad): Hai orang-orang kafir, aku tidak akan menyembah apa yang kalian sembah, dan kami akan menyembah apa yang kalian sembah.\" lalu Allah menurunkan (ayat): \"Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk, sehingga kamu mengerti apa yang kamu ucapkan.\" QS An-Nisa`: 43. Abu Isa mengatakan bahwa hadits ini hasan shahih gharib."},{"p":"Tirmidzi","n":2839,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّهُ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُأَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا النَّخْلَ فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ فَأَبَى عَلَيْهِ فَاخْتَصَمُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ اسْقِ يَا زُبَيْرُ وَأَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ وَقَالَ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَغَيَّرَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا زُبَيْرُ اسْقِ وَاحْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجُدُرِ فَقَالَ الزُّبَيْرُ وَاللَّهِ إِنِّي لَأَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }الْآيَةَقَالَ أَبُو عِيسَى سَمِعْت مُحَمَّدًا يَقُولُ قَدْ رَوَى ابْنُ وَهْبٍ هَذَا الْحَدِيثَ عَنْ اللَّيْثِ بْنِ سَعْدٍ وَيُونُسُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ نَحْوَ هَذَا الْحَدِيثِ وَرَوَى شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ الزُّبَيْرِ وَلَمْ يَذْكُرْ فِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ","trj":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari ['Urwah bin Zubair] menceritakan bahwa [Abdullah bin Zubair] bercerita kepadanya, bahwa seorang Anshar bersengketa dengan Zubair tentang aliran air untuk dipakai menyirami pohon kurma, orang Anshar itu berkata; \"Biarkan air itu mengalir.\" Namun Zubair enggan (tidak menghiraukannya). Kemudian mereka mengadu kepada Rasulullah Shallallahu 'alahi wasallam, beliau bersabda kepada Zubair: \"Wahai Zubair siramlah, dan alirkanlah air kepada tetanggamu.\" Orang Anshar itu marah dan berkata; \"Wahai Rasulullah, apa dia sepupu anda?\" (mendengar hal itu) berubahlah wajah beliau sambil bersabda: \"Wahai Zubair, siramlah dan tahanlah air itu kembali ke kebun.\" Demi Allah aku menganggap ayat ini turun berkaitan dengan peristiwa itu, Maka demi Rabbmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan. QS An-Nisa`: 65. Abu Isa berkata; \"Aku mendengar Muhammad berkata; [Ibnu Wahab] meriwayatkan hadits ini dari [Al Laits bin Sa'd] dan [Yunus] dari [Az Zuhri] dari ['Urwah] dari [Abdullah bin Az Zubair] seperti hadits ini. [Syu'aib bin Abu Hamzah] meriwayatkan dari [Az Zuhri] dari ['Urwah] dari [Az Zubair] tanpa menyebut: \"Dari Abdullah bin Az Zubair.\""},{"p":"Tirmidzi","n":2845,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ أَبِي مَيْسَرَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَاللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ }الْآيَةَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ ثُمَّ قَالَ اللَّهُمَّ بَيِّنَ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا يُرِيدُ الشَّيْطَانُ أَنْ يُوقِعَ بَيْنَكُمْ الْعَدَاوَةَ وَالْبَغْضَاءَ فِي الْخَمْرِ وَالْمَيْسِرِ إِلَى قَوْلِهِ فَهَلْ أَنْتُمْ مُنْتَهُونَ }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ انْتَهَيْنَا انْتَهَيْنَاقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ إِسْرَائِيلَ هَذَا الْحَدِيثُ مُرْسَلٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَمْرِو بْنِ شُرَحْبِيلَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَذَكَرَ نَحْوَهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ يُوسُفَ","trj":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Syurahbil Abu Maisarah] dari [Umar bin Al Khaththab] ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Baqarah; Mereka bertanya kepadamu tentang khamer dan judi. QS Al Baqarah: 219, lalu Umar dipanggil dan dibacakan kepadanya. Setelah itu ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat An Nisa` Hai orang-orang yang beriman, janganlah kamu mendekati shalat sedang kamu mabuk QS An Nisa`: 43. Selanjutnya ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Mai`idah Sesungguhnya syaitan itu bermaksud hendak menimbulkan permusuhan dan kebencian di antara kamu lantaran (meminum) khamar dan berjudi itu, -sampai firmanNya- maka berhentilah kamu (dari mengerjakan pekerjaan itu) QS Al Ma`idah: 91. Umar lalu berkata; \"Kami berhenti, kami berhenti.\" Abu Isa berkata; Hadits ini juga diriwayatkan dari Isra`il secara mursal. Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Abu Maisarah 'Amru bin Syurahbil] bahwa [Umar bin Al Khaththab] berkata; \"Ya Allah, Ya Allah, berilah kami penjelasan tentang khamar dengan penjelasan yang memadai.\" Lalu ia menyebutkan seperti di atas, namun hadits ini lebih shahih dari hadits Muhammad bin Yusuf."}]};
